def _assurance_onboarding_payload(*, assurance: AssuranceConfig | None = None) -> dict[str, Any]:
    configured_profiles = list(assurance.proof_profiles) if assurance is not None else []
    configured_requirements = list(assurance.requirements) if assurance is not None else []
    subsystem_profiles = list(assurance.subsystem_profiles) if assurance is not None else []
    host_refs = []
    if assurance is not None:
        host_refs = [ref for ref in [assurance.decision_record_target, assurance.invariant_registry, assurance.risk_registry] if ref]
        for requirement in configured_requirements:
            host_refs.extend(requirement.authority_refs)
        for profile in subsystem_profiles:
            host_refs.extend(profile.requirement_refs)
        host_refs = _dedupe(host_refs)
    has_test_policy = bool(assurance.test_data_policy) if assurance is not None else False
    any_configured = bool(configured_profiles or configured_requirements or subsystem_profiles or host_refs or has_test_policy)
    usable = bool((configured_profiles or configured_requirements or subsystem_profiles) and (host_refs or has_test_policy))
    status = "usable" if usable else "partial" if any_configured else "absent"
    return {
        "status": status,
        "command": "agentic-workspace defaults --section assurance_onboarding --format json",
        "report_command": "agentic-workspace report --target ./repo --section closeout_trust --format json",
        "proof_command": "agentic-workspace proof --target ./repo --changed <paths> --format json",
        "jumpstart_route": "Use workspace-setup-jumpstart after setup discovery; seed only profiles supported by inspected host repo evidence.",
        "rule": "Host repos own assurance truth; Agentic Workspace only routes levels, gates, refs, proof profiles, and compact evidence state.",
        "configured_profile_count": len(configured_profiles),
        "configured_requirement_count": len(configured_requirements),
        "configured_subsystem_profile_count": len(subsystem_profiles),
        "host_ref_count": len(host_refs),
        "has_test_data_policy": has_test_policy,
        "candidate_seed_surfaces": [
            ".agentic-workspace/config.toml [assurance.proof_profiles]",
            ".agentic-workspace/config.toml [assurance.requirements]",
            ".agentic-workspace/config.toml [assurance.subsystem_profiles]",
        ],
        "seed_questions": [
            "Which host-owned source declares the risk, requirement, or review burden?",
            "Which changed paths or ownership subsystem ids should activate it?",
            "What evidence label must exist before broad claims are honest?",
            "Which proof profile or verification protocol should be selected, if any?",
            "What claim boundary remains when the evidence is missing?",
        ],
        "smallest_useful_config": [
            "[assurance]",
            'default_level = "medium"',
            'decision_record_target = "docs/decisions/"',
            "",
            "[assurance.proof_profiles.example]",
            'required_commands = ["uv run pytest tests -q"]',
            "optional_commands = []",
            "review_aids = []",
            "",
            "[assurance.subsystem_profiles.example-subsystem]",
            'assurance_level = "high"',
            'requirement_refs = ["docs/requirements.md#example"]',
            'required_evidence = ["requirement_grounding"]',
            'force = "required-before-closeout"',
        ],
        "states": {
            "absent": "no host assurance profile is configured; low-risk installs stay cheap",
            "partial": "some assurance fields exist, but add host-owned refs, evidence labels, or test-data policy before relying on them",
            "usable": "at least one proof profile, assurance requirement, or subsystem profile is tied to host-owned authority or test-data policy",
        },
    }


def _assurance_disposition_payload(value: Any) -> dict[str, Any]:
    if value is None:
        return {"status": "none"}
    return {
        "status": "recorded",
        "reason": str(getattr(value, "reason", "")),
        "owner": str(getattr(value, "owner", "")),
    }


def _assurance_requirement_payloads(config: WorkspaceConfig | None) -> list[dict[str, Any]]:
    requirements = list(config.assurance.requirements) if config is not None else []
    payloads: list[dict[str, Any]] = []
    for requirement in requirements:
        payloads.append(
            {
                "id": requirement.id,
                "level": requirement.level,
                "applies_to_paths": list(requirement.applies_to_paths),
                "applies_to_task_markers": list(requirement.applies_to_task_markers),
                "applies_to_planning_refs": list(requirement.applies_to_planning_refs),
                "applies_to_proof_profiles": list(requirement.applies_to_proof_profiles),
                "applies_to_risk_refs": list(requirement.applies_to_risk_refs),
                "applies_to_invariant_refs": list(requirement.applies_to_invariant_refs),
                "authority_refs": list(requirement.authority_refs),
                "required_evidence": list(requirement.required_evidence),
                "proof_profile": requirement.proof_profile,
                "workflow_obligation_refs": list(requirement.workflow_obligation_refs),
                "review_owner": requirement.review_owner,
                "force": requirement.force,
                "blocking_claims": list(requirement.blocking_claims),
                "waiver": _assurance_disposition_payload(requirement.waiver),
                "dismissal": _assurance_disposition_payload(requirement.dismissal),
                "notes": requirement.notes,
            }
        )
    return payloads


def _assurance_subsystem_profile_payloads(config: WorkspaceConfig | None) -> list[dict[str, Any]]:
    profiles = list(config.assurance.subsystem_profiles) if config is not None else []
    payloads: list[dict[str, Any]] = []
    for profile in profiles:
        payloads.append(
            {
                "id": profile.id,
                "subsystem_id": profile.id,
                "level": profile.assurance_level,
                "scope_refs": list(profile.scope_refs),
                "requirement_refs": list(profile.requirement_refs),
                "required_evidence": list(profile.required_evidence),
                "proof_profile": profile.proof_profile,
                "workflow_obligation_refs": list(profile.workflow_obligation_refs),
                "review_owner": profile.review_owner,
                "force": profile.force,
                "blocking_claims": list(profile.blocked_without_evidence),
                "claim_boundary": profile.claim_boundary,
                "notes": profile.notes,
            }
        )
    return payloads


def _assurance_level_rank(level: str) -> int:
    return {"low": 0, "medium": 1, "high": 2, "critical": 3}.get(str(level).strip(), 0)


def _assurance_profile_scope_tokens(profile: dict[str, Any]) -> set[str]:
    subsystem_id = str(profile.get("subsystem_id") or profile.get("id") or "").strip()
    tokens = {subsystem_id, f"subsystem:{subsystem_id}", f"ownership.subsystems.{subsystem_id}"}
    tokens.update(str(item).strip() for item in _list_payload(profile.get("scope_refs")) if str(item).strip())
    return {token for token in tokens if token}


def _subsystem_assurance_payload(
    *,
    config: WorkspaceConfig | None,
    target_root: Path | None,
    changed_paths: list[str] | None,
    active_planning_record: dict[str, Any] | None,
    planning_facts: dict[str, Any] | None = None,
) -> dict[str, Any]:
    configured = _assurance_subsystem_profile_payloads(config)
    ownership_subsystems = _load_ownership_subsystems(target_root=target_root)
    declared_subsystem_ids = {
        str(subsystem.get("id") or "").strip() for subsystem in ownership_subsystems if str(subsystem.get("id") or "").strip()
    }
    invalid_profiles = [
        {
            "id": str(profile.get("subsystem_id") or profile.get("id") or "").strip(),
            "reason": "subsystem profile id is not declared in .agentic-workspace/OWNERSHIP.toml [[subsystems]]",
            "surface": ".agentic-workspace/config.toml [assurance.subsystem_profiles]",
            "authority_surface": ".agentic-workspace/OWNERSHIP.toml [[subsystems]]",
        }
        for profile in configured
        if str(profile.get("subsystem_id") or profile.get("id") or "").strip()
        and str(profile.get("subsystem_id") or profile.get("id") or "").strip() not in declared_subsystem_ids
    ]
    invalid_profile_ids = {str(profile.get("id") or "").strip() for profile in invalid_profiles if str(profile.get("id") or "").strip()}
    active_configured = [
        profile
        for profile in configured
        if str(profile.get("subsystem_id") or profile.get("id") or "").strip()
        and str(profile.get("subsystem_id") or profile.get("id") or "").strip() in declared_subsystem_ids
    ]
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    ownership_matches = (
        _subsystem_matches_for_changed_paths(target_root=target_root, changed_paths=normalized_paths)
        if target_root is not None
        else {
            "kind": "agentic-workspace/subsystem-ownership-selection/v1",
            "status": "unavailable",
            "matched_subsystems": [],
        }
    )
    matched_subsystems = [item for item in _list_payload(ownership_matches.get("matched_subsystems")) if isinstance(item, dict)]
    matched_tokens = {
        token
        for subsystem in matched_subsystems
        for token in (
            str(subsystem.get("id") or "").strip(),
            f"subsystem:{str(subsystem.get('id') or '').strip()}",
            f"ownership.subsystems.{str(subsystem.get('id') or '').strip()}",
        )
        if token and not token.endswith(".")
    }
    plan_scope = set()
    if isinstance(active_planning_record, dict):
        plan_scope.update(_plan_exact_list(active_planning_record, "canonical_core.touched_scope", "touched_paths"))
        plan_scope.update(_plan_exact_list(active_planning_record, "execution_bounds.allowed paths"))
        plan_scope.update(str(item).strip() for item in _list_payload(active_planning_record.get("subsystems")) if str(item).strip())
    profile_matches: list[dict[str, Any]] = []
    facts = planning_facts if isinstance(planning_facts, dict) else _assurance_requirement_planning_facts(active_planning_record)
    evidence_by_requirement = facts.get("evidence_by_requirement", {}) if isinstance(facts, dict) else {}
    for profile in active_configured:
        scope_tokens = _assurance_profile_scope_tokens(profile)
        matched_scope_tokens = sorted(scope_tokens & matched_tokens)
        matched_plan_scope = sorted(scope_tokens & plan_scope)
        if not matched_scope_tokens and not matched_plan_scope:
            continue
        subsystem_id = str(profile.get("subsystem_id") or profile.get("id") or "").strip()
        requirement_id = f"subsystem:{subsystem_id}"
        evidence_present = []
        if isinstance(evidence_by_requirement, dict):
            evidence_present = [
                str(item).strip()
                for item in _list_payload(evidence_by_requirement.get(requirement_id, evidence_by_requirement.get(subsystem_id, [])))
                if str(item).strip()
            ]
        required_evidence = [str(item).strip() for item in _list_payload(profile.get("required_evidence")) if str(item).strip()]
        missing_evidence = [item for item in required_evidence if item not in evidence_present]
        matched_subsystem = next((item for item in matched_subsystems if str(item.get("id") or "").strip() == subsystem_id), {})
        matched_paths = [str(path) for path in _list_payload(matched_subsystem.get("matched_paths")) if str(path).strip()]
        applies_because = _dedupe(
            [
                *(f"changed path matched subsystem {subsystem_id}" for _ in matched_scope_tokens[:1]),
                *(f"active plan scope matched {item}" for item in matched_plan_scope),
            ]
        )
        activation_evidence = _activation_kind_facts(paths=matched_paths, source=f"changed path matched subsystem {subsystem_id}")
        state = "satisfied" if not missing_evidence else "review-required" if profile.get("review_owner") else "missing-evidence"
        profile_matches.append(
            {
                **profile,
                "requirement_id": requirement_id,
                "subsystem": {
                    "id": subsystem_id,
                    "matched_paths": matched_paths,
                    "matched_patterns": _list_payload(matched_subsystem.get("matched_patterns")),
                    "owns": _list_payload(matched_subsystem.get("owns")),
                    "does_not_own": _list_payload(matched_subsystem.get("does_not_own")),
                },
                "applies_because": applies_because,
                "activation_kinds": sorted(
                    {str(item.get("activation_kind")) for item in activation_evidence if item.get("activation_kind")}
                ),
                "activation_evidence": activation_evidence,
                "evidence_status": {
                    "requirement_id": requirement_id,
                    "state": state,
                    "level": str(profile.get("level", DEFAULT_ASSURANCE_LEVEL)),
                    "applies_because": applies_because,
                    "activation_kinds": sorted(
                        {str(item.get("activation_kind")) for item in activation_evidence if item.get("activation_kind")}
                    ),
                    "activation_evidence": activation_evidence,
                    "authority_refs": _list_payload(profile.get("requirement_refs")),
                    "required_evidence": required_evidence,
                    "evidence_present": evidence_present,
                    "missing_evidence": missing_evidence,
                    "waiver": {"status": "none"},
                    "dismissal": {"status": "none"},
                    "proof_profile": profile.get("proof_profile"),
                    "workflow_obligation_refs": _list_payload(profile.get("workflow_obligation_refs")),
                    "review_owner": profile.get("review_owner"),
                    "force": str(profile.get("force", "recommended")),
                    "blocking_claims": _list_payload(profile.get("blocking_claims")),
                    "claim_boundary": profile.get("claim_boundary"),
                    "subsystem_id": subsystem_id,
                    "next_action": {
                        "id": "record-subsystem-assurance-evidence" if missing_evidence else "none",
                        "why": "Subsystem-scoped assurance evidence is missing before broad subsystem claims."
                        if missing_evidence
                        else "No missing subsystem assurance evidence is currently projected.",
                    },
                },
            }
        )
    effective_level = "none"
    if profile_matches:
        effective_level = max(
            (str(profile.get("level", DEFAULT_ASSURANCE_LEVEL)) for profile in profile_matches), key=_assurance_level_rank
        )
    missing_required = [
        profile
        for profile in profile_matches
        if _as_dict(profile.get("evidence_status")).get("state") in {"missing-evidence", "review-required"}
        and str(profile.get("force", "recommended")) in {"required-before-closeout", "blocking"}
    ]
    return {
        "kind": "agentic-workspace/subsystem-assurance/v1",
        "status": "attention"
        if missing_required
        else "matched"
        if profile_matches
        else "configured"
        if active_configured
        else "invalid-config"
        if invalid_profiles
        else "absent",
        "configured_count": len(configured),
        "active_configured_count": len(active_configured),
        "invalid_profile_count": len(invalid_profiles),
        "invalid_profiles": invalid_profiles,
        "warnings": [
            f"assurance.subsystem_profiles.{profile_id} is ignored because {profile_id!r} is not declared in .agentic-workspace/OWNERSHIP.toml [[subsystems]]."
            for profile_id in sorted(invalid_profile_ids)
        ],
        "matched_count": len(profile_matches),
        "effective_assurance_level": effective_level,
        "matched_subsystem_ids": [str(profile.get("subsystem_id")) for profile in profile_matches],
        "matched_profiles": profile_matches,
        "evidence_status": [_as_dict(profile.get("evidence_status")) for profile in profile_matches],
        "required_evidence": _dedupe(
            [
                str(item).strip()
                for profile in profile_matches
                for item in _list_payload(profile.get("required_evidence"))
                if str(item).strip()
            ]
        ),
        "missing_evidence": _dedupe(
            [
                str(item).strip()
                for profile in profile_matches
                for item in _list_payload(_as_dict(profile.get("evidence_status")).get("missing_evidence"))
                if str(item).strip()
            ]
        ),
        "requirement_refs": _dedupe(
            [
                str(item).strip()
                for profile in profile_matches
                for item in _list_payload(profile.get("requirement_refs"))
                if str(item).strip()
            ]
        ),
        "blocked_claims": _dedupe(
            [
                str(item).strip()
                for profile in profile_matches
                for item in _list_payload(profile.get("blocking_claims"))
                if str(item).strip()
            ]
        ),
        "claim_boundaries": _dedupe(
            [str(profile.get("claim_boundary")).strip() for profile in profile_matches if str(profile.get("claim_boundary") or "").strip()]
        ),
        "ownership_selection": ownership_matches,
        "rule": "Subsystem assurance profiles are scoped by existing ownership subsystem ids; AW surfaces obligations and evidence gaps but does not certify subsystem safety or compliance.",
    }


def _assurance_requirement_planning_facts(active_planning_record: dict[str, Any] | None) -> dict[str, Any]:
    if not isinstance(active_planning_record, dict):
        return {
            "refs": [],
            "proof_profiles": [],
            "risk_refs": [],
            "invariant_refs": [],
            "evidence_by_requirement": {},
        }
    adaptive = active_planning_record.get("adaptive_assurance", {})
    adaptive = adaptive if isinstance(adaptive, dict) else {}
    refs: list[str] = []
    for raw in (
        active_planning_record.get("id"),
        active_planning_record.get("title"),
        active_planning_record.get("surface"),
        active_planning_record.get("next_action"),
    ):
        if str(raw).strip():
            refs.append(str(raw).strip())
    refs.extend(str(item).strip() for item in _list_payload(active_planning_record.get("minimal_refs")) if str(item).strip())
    refs.extend(str(item).strip() for item in _list_payload(active_planning_record.get("traceability_refs")) if str(item).strip())
    refs.extend(str(item).strip() for item in _list_payload(adaptive.get("requirement_refs")) if str(item).strip())
    refs.extend(str(item).strip() for item in _list_payload(active_planning_record.get("assurance_requirement_refs")) if str(item).strip())
    proof_profiles = [str(item).strip() for item in _list_payload(adaptive.get("proof_profiles")) if str(item).strip()]
    risk_refs = [str(item).strip() for item in _list_payload(active_planning_record.get("risk_registry_refs")) if str(item).strip()]
    invariant_refs = [str(item).strip() for item in _list_payload(active_planning_record.get("invariant_refs")) if str(item).strip()]
    raw_evidence = active_planning_record.get("assurance_evidence", {})
    evidence_by_requirement: dict[str, list[str]] = {}
    if isinstance(raw_evidence, dict):
        for requirement_id, evidence in raw_evidence.items():
            if isinstance(evidence, dict):
                values = evidence.get("evidence_present", evidence.get("present", evidence.get("evidence", [])))
            else:
                values = evidence
            evidence_by_requirement[str(requirement_id)] = [str(item).strip() for item in _list_payload(values) if str(item).strip()]
    if isinstance(raw_evidence, list):
        for item in raw_evidence:
            if not isinstance(item, dict):
                continue
            requirement_id = str(item.get("requirement_id", "")).strip()
            if not requirement_id:
                continue
            values = item.get("evidence_present", item.get("present", item.get("evidence", [])))
            evidence_by_requirement[requirement_id] = [str(value).strip() for value in _list_payload(values) if str(value).strip()]
    return {
        "refs": _dedupe(refs),
        "proof_profiles": _dedupe(proof_profiles),
        "risk_refs": _dedupe(risk_refs),
        "invariant_refs": _dedupe(invariant_refs),
        "evidence_by_requirement": evidence_by_requirement,
    }


def _load_assurance_evidence_records(*, target_root: Path | None) -> dict[str, Any]:
    if target_root is None:
        return {
            "kind": "agentic-workspace/assurance-evidence-records/v1",
            "status": "unavailable",
            "path": ASSURANCE_EVIDENCE_RECORDS_RELATIVE_PATH.as_posix(),
            "records": [],
            "evidence_by_requirement": {},
        }
    path = target_root / ASSURANCE_EVIDENCE_RECORDS_RELATIVE_PATH
    if not path.exists():
        return {
            "kind": "agentic-workspace/assurance-evidence-records/v1",
            "status": "absent",
            "path": ASSURANCE_EVIDENCE_RECORDS_RELATIVE_PATH.as_posix(),
            "records": [],
            "evidence_by_requirement": {},
            "record_shape": {
                "fields": [
                    "requirement_id",
                    "evidence_label",
                    "status",
                    "source_kind",
                    "command",
                    "review_ref",
                    "changed_paths",
                    "recorded_by",
                ],
                "rule": "Record compact evidence labels and refs only; do not store raw command transcripts.",
            },
        }
    try:
        payload = json.loads(path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError) as exc:
        return {
            "kind": "agentic-workspace/assurance-evidence-records/v1",
            "status": "invalid",
            "path": ASSURANCE_EVIDENCE_RECORDS_RELATIVE_PATH.as_posix(),
            "records": [],
            "evidence_by_requirement": {},
            "error": str(exc),
        }
    if not isinstance(payload, dict):
        return {
            "kind": "agentic-workspace/assurance-evidence-records/v1",
            "status": "invalid",
            "path": ASSURANCE_EVIDENCE_RECORDS_RELATIVE_PATH.as_posix(),
            "records": [],
            "evidence_by_requirement": {},
            "error": "record must be a JSON object",
        }
    records: list[dict[str, Any]] = []
    invalid_records: list[dict[str, Any]] = []
    evidence_by_requirement: dict[str, list[str]] = {}
    raw_records = payload.get("records", payload.get("items", []))
    for index, item in enumerate(_list_payload(raw_records)):
        if not isinstance(item, dict):
            invalid_records.append({"index": index, "reason": "record must be an object"})
            continue
        requirement_id = str(item.get("requirement_id") or "").strip()
        evidence_label = str(item.get("evidence_label") or item.get("label") or "").strip()
        status = str(item.get("status") or "satisfied").strip()
        if not requirement_id or not evidence_label or status not in {"satisfied", "reviewed", "waived", "stale"}:
            invalid_records.append(
                {
                    "index": index,
                    "missing_or_invalid_fields": [
                        field
                        for field, value in {
                            "requirement_id": requirement_id,
                            "evidence_label": evidence_label,
                            "status": status if status in {"satisfied", "reviewed", "waived", "stale"} else "",
                        }.items()
                        if not value
                    ],
                }
            )
            continue
        normalized = {
            "requirement_id": requirement_id,
            "evidence_label": evidence_label,
            "status": status,
            "source_kind": str(item.get("source_kind") or "agent-recorded").strip(),
            "command": str(item.get("command") or "").strip(),
            "review_ref": str(item.get("review_ref") or "").strip(),
            "changed_paths": [
                str(path).strip().replace("\\", "/") for path in _list_payload(item.get("changed_paths")) if str(path).strip()
            ],
            "recorded_by": str(item.get("recorded_by") or "").strip(),
        }
        records.append(normalized)
        if status in {"satisfied", "reviewed", "waived"}:
            evidence_by_requirement.setdefault(requirement_id, [])
            if evidence_label not in evidence_by_requirement[requirement_id]:
                evidence_by_requirement[requirement_id].append(evidence_label)
    return {
        "kind": "agentic-workspace/assurance-evidence-records/v1",
        "status": "invalid" if invalid_records else "recorded",
        "path": ASSURANCE_EVIDENCE_RECORDS_RELATIVE_PATH.as_posix(),
        "records": records,
        "record_count": len(records),
        "invalid_records": invalid_records,
        "evidence_by_requirement": evidence_by_requirement,
        "rule": "Evidence records are agent-populated labels and refs; AW uses them as evidence inputs but does not decide acceptance.",
    }


def _merge_evidence_by_requirement(*evidence_maps: Any) -> dict[str, list[str]]:
    merged: dict[str, list[str]] = {}
    for evidence_map in evidence_maps:
        if not isinstance(evidence_map, dict):
            continue
        for requirement_id, values in evidence_map.items():
            key = str(requirement_id).strip()
            if not key:
                continue
            merged.setdefault(key, [])
            for value in _list_payload(values):
                text = str(value).strip()
                if text and text not in merged[key]:
                    merged[key].append(text)
    return merged


def _activation_kind_for_path(path: str) -> str:
    normalized = path.replace("\\", "/").strip("/")
    name = Path(normalized).name
    if normalized.startswith((".agentic-workspace/local/", "scratch/")):
        return "setup-local-state"
    if normalized.startswith(("generated/", "docs/reference/")):
        return "generated-projection"
    if normalized.startswith("docs/") or normalized.endswith((".md", ".rst")):
        return "docs-manual-review"
    if name.startswith("test_") and normalized.endswith(".py") and ("/tests/" in f"/{normalized}" or normalized.startswith("tests/")):
        return "test-evidence"
    if normalized.endswith((".py", ".ts", ".tsx", ".js", ".jsx", ".go", ".rs", ".java", ".cs", ".rb", ".php")):
        return "source-behavior"
    if normalized.startswith((".agentic-workspace/", "tools/setup-findings.json")):
        return "setup-local-state"
    return "unknown"


def _activation_kind_facts(*, paths: list[str], source: str) -> list[dict[str, Any]]:
    return [
        {
            "path": path,
            "activation_kind": _activation_kind_for_path(path),
            "source": source,
        }
        for path in paths
    ]


def _assurance_requirement_match(
    *,
    requirement: dict[str, Any],
    changed_paths: list[str] | None,
    task_text: str | None,
    planning_facts: dict[str, Any],
) -> tuple[bool, list[str], list[dict[str, Any]]]:
    applies_because: list[str] = []
    activation_facts: list[dict[str, Any]] = []
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    for path in normalized_paths:
        for pattern in _list_payload(requirement.get("applies_to_paths")):
            pattern_text = str(pattern).strip()
            if pattern_text and fnmatch.fnmatch(path, pattern_text):
                applies_because.append(f"changed path matched {pattern_text}")
                activation_facts.extend(_activation_kind_facts(paths=[path], source=f"changed path matched {pattern_text}"))
    normalized_task = (task_text or "").lower()
    for marker in _list_payload(requirement.get("applies_to_task_markers")):
        marker_text = str(marker).strip()
        if marker_text and marker_text.lower() in normalized_task:
            applies_because.append(f"task marker matched {marker_text}")
    for field_name, fact_name, label in (
        ("applies_to_planning_refs", "refs", "planning ref"),
        ("applies_to_proof_profiles", "proof_profiles", "proof profile"),
        ("applies_to_risk_refs", "risk_refs", "risk ref"),
        ("applies_to_invariant_refs", "invariant_refs", "invariant ref"),
    ):
        configured = {str(item).strip() for item in _list_payload(requirement.get(field_name)) if str(item).strip()}
        facts = {str(item).strip() for item in _list_payload(planning_facts.get(fact_name)) if str(item).strip()}
        for matched in sorted(configured & facts):
            applies_because.append(f"{label} matched {matched}")
    applies_because = _dedupe(applies_because)
    return (bool(applies_because), applies_because, activation_facts)


def _assurance_status_for_requirement(
    *,
    requirement: dict[str, Any],
    applies_because: list[str],
    planning_facts: dict[str, Any],
    activation_facts: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    required_evidence = [str(item).strip() for item in _list_payload(requirement.get("required_evidence")) if str(item).strip()]
    evidence_by_requirement = planning_facts.get("evidence_by_requirement", {})
    evidence_present = []
    if isinstance(evidence_by_requirement, dict):
        evidence_present = [
            str(item).strip()
            for item in _list_payload(evidence_by_requirement.get(str(requirement.get("id", "")), []))
            if str(item).strip()
        ]
    missing_evidence = [item for item in required_evidence if item not in evidence_present]
    waiver = requirement.get("waiver", {}) if isinstance(requirement.get("waiver"), dict) else {}
    dismissal = requirement.get("dismissal", {}) if isinstance(requirement.get("dismissal"), dict) else {}
    state = "satisfied" if not missing_evidence else "missing-evidence"
    if dismissal.get("status") == "recorded":
        state = "dismissed"
        missing_evidence = []
    elif waiver.get("status") == "recorded":
        state = "waived"
        missing_evidence = []
    elif missing_evidence and requirement.get("review_owner"):
        state = "review-required"
    return {
        "requirement_id": str(requirement.get("id", "")),
        "state": state,
        "level": str(requirement.get("level", DEFAULT_ASSURANCE_LEVEL)),
        "applies_because": applies_because,
        "activation_kinds": sorted({str(item.get("activation_kind")) for item in activation_facts or [] if item.get("activation_kind")}),
        "activation_evidence": activation_facts or [],
        "authority_refs": _list_payload(requirement.get("authority_refs")),
        "required_evidence": required_evidence,
        "evidence_present": evidence_present,
        "missing_evidence": missing_evidence,
        "waiver": waiver if waiver else {"status": "none"},
        "dismissal": dismissal if dismissal else {"status": "none"},
        "proof_profile": requirement.get("proof_profile"),
        "workflow_obligation_refs": _list_payload(requirement.get("workflow_obligation_refs")),
        "review_owner": requirement.get("review_owner"),
        "force": str(requirement.get("force", "recommended")),
        "blocking_claims": _list_payload(requirement.get("blocking_claims")),
        "next_action": {
            "id": "record-assurance-evidence" if missing_evidence else "none",
            "why": "Required assurance evidence is missing before broad completion claims."
            if missing_evidence
            else "No missing assurance evidence is currently projected.",
        },
    }


def _assurance_requirements_report_payload(
    *,
    config: WorkspaceConfig | None,
    target_root: Path | None = None,
    active_planning_record: dict[str, Any] | None = None,
    task_text: str | None = None,
    changed_paths: list[str] | None = None,
) -> dict[str, Any]:
    configured = _assurance_requirement_payloads(config)
    planning_facts = _assurance_requirement_planning_facts(active_planning_record)
    evidence_records = _load_assurance_evidence_records(target_root=target_root)
    planning_facts = {
        **planning_facts,
        "evidence_by_requirement": _merge_evidence_by_requirement(
            planning_facts.get("evidence_by_requirement"), evidence_records.get("evidence_by_requirement")
        ),
    }
    subsystem_assurance = _subsystem_assurance_payload(
        config=config,
        target_root=target_root,
        changed_paths=changed_paths,
        active_planning_record=active_planning_record,
        planning_facts=planning_facts,
    )
    matching: list[dict[str, Any]] = []
    active: list[dict[str, Any]] = []
    evidence_status: list[dict[str, Any]] = []
    for requirement in configured:
        matched, applies_because, activation_facts = _assurance_requirement_match(
            requirement=requirement,
            changed_paths=changed_paths,
            task_text=task_text,
            planning_facts=planning_facts,
        )
        status = _assurance_status_for_requirement(
            requirement=requirement,
            applies_because=applies_because,
            planning_facts=planning_facts,
            activation_facts=activation_facts,
        )
        matching.append(
            {
                "id": requirement["id"],
                "matched": matched,
                "applies_because": applies_because,
                "activation_kinds": sorted({str(item.get("activation_kind")) for item in activation_facts if item.get("activation_kind")}),
                "activation_evidence": activation_facts,
                "non_match_reason": "" if matched else "no configured activation signal matched current work",
                "level": requirement["level"],
                "force": requirement["force"],
                "blocking_claims": requirement["blocking_claims"],
            }
        )
        if matched:
            active.append(
                {
                    **requirement,
                    "applies_because": applies_because,
                    "activation_kinds": sorted(
                        {str(item.get("activation_kind")) for item in activation_facts if item.get("activation_kind")}
                    ),
                    "activation_evidence": activation_facts,
                    "authority_boundary": _authority_boundary_payload(
                        surface="assurance_requirements.requirement",
                        observed_by_aw=[
                            f"configured assurance requirement {requirement['id']}",
                            *applies_because,
                        ],
                        recommended_by_aw=["honor configured evidence/review/claim-boundary obligations before closeout"],
                        agent_owned_decisions=[
                            "whether the current task intent is satisfied",
                            "whether evidence is sufficient to claim completion",
                        ],
                        human_owned_decisions=["waiver, dismissal, or acceptance when required evidence is unavailable"],
                        rule="Assurance task-marker matches are explicit config evidence; AW reports configured pressure and does not decide user intent.",
                    ),
                }
            )
            evidence_status.append(status)
    for profile in _list_payload(subsystem_assurance.get("matched_profiles")):
        if not isinstance(profile, dict):
            continue
        subsystem_id = str(profile.get("subsystem_id") or profile.get("id") or "").strip()
        requirement_id = str(profile.get("requirement_id") or f"subsystem:{subsystem_id}")
        profile_status = _as_dict(profile.get("evidence_status"))
        active.append(
            {
                "id": requirement_id,
                "level": str(profile.get("level", DEFAULT_ASSURANCE_LEVEL)),
                "applies_to_paths": [],
                "applies_to_task_markers": [],
                "applies_to_planning_refs": [],
                "applies_to_proof_profiles": [],
                "applies_to_risk_refs": [],
                "applies_to_invariant_refs": [],
                "authority_refs": _list_payload(profile.get("requirement_refs")),
                "required_evidence": _list_payload(profile.get("required_evidence")),
                "proof_profile": profile.get("proof_profile"),
                "workflow_obligation_refs": _list_payload(profile.get("workflow_obligation_refs")),
                "review_owner": profile.get("review_owner"),
                "force": str(profile.get("force", "recommended")),
                "blocking_claims": _list_payload(profile.get("blocking_claims")),
                "waiver": {"status": "none"},
                "dismissal": {"status": "none"},
                "notes": profile.get("notes"),
                "source": "subsystem_assurance",
                "subsystem_id": subsystem_id,
                "subsystem": profile.get("subsystem", {}),
                "claim_boundary": profile.get("claim_boundary"),
                "applies_because": _list_payload(profile.get("applies_because")),
                "activation_kinds": _list_payload(profile.get("activation_kinds")),
                "activation_evidence": _list_payload(profile.get("activation_evidence")),
                "authority_boundary": _authority_boundary_payload(
                    surface="assurance_requirements.subsystem_profile",
                    observed_by_aw=[
                        f"configured subsystem assurance profile {subsystem_id}",
                        *_list_payload(profile.get("applies_because")),
                    ],
                    recommended_by_aw=["honor subsystem-scoped evidence and claim-boundary obligations before closeout"],
                    agent_owned_decisions=[
                        "whether the current task intent is satisfied",
                        "whether evidence is sufficient to claim subsystem-scoped completion",
                    ],
                    human_owned_decisions=["waiver, acceptance, or final subsystem safety/compliance claims"],
                    rule="Subsystem assurance matches are scoped through host-owned ownership subsystems; AW reports obligations and does not certify safety.",
                ),
            }
        )
        if profile_status:
            evidence_status.append(profile_status)
    required_missing = [
        item
        for item in evidence_status
        if item.get("state") in {"missing-evidence", "review-required"}
        and str(item.get("force", "recommended")) in {"required-before-closeout", "blocking"}
    ]
    return {
        "kind": "agentic-workspace/assurance-requirements/v1",
        "status": "attention"
        if required_missing
        else "matched"
        if active
        else "configured"
        if configured or subsystem_assurance.get("configured_count")
        else "absent",
        "rule": "Repo-declared assurance requirements are domain-generic routing and claim-boundary facts; AW does not certify compliance.",
        "authority_boundary": _authority_boundary_payload(
            surface="assurance_requirements",
            observed_by_aw=["repo-declared assurance configuration", "changed-path/task-marker/planning match facts"],
            recommended_by_aw=["carry configured evidence, review-owner, and blocking-claim obligations into proof and closeout"],
            agent_owned_decisions=[
                "semantic user-intent acceptance",
                "whether proof and evidence justify a completion claim",
            ],
            human_owned_decisions=["waiver, dismissal, or final acceptance for configured assurance exceptions"],
            rule="Assurance requirements are configured claim-boundary evidence; AW does not classify the task's semantic intent.",
        ),
        "configured_count": len(configured) + int(subsystem_assurance.get("configured_count", 0) or 0),
        "configured_requirement_count": len(configured),
        "configured_subsystem_profile_count": subsystem_assurance.get("configured_count", 0),
        "active_count": len(active),
        "missing_required_evidence_count": len(required_missing),
        "configured": configured,
        "active": active,
        "evidence_status": evidence_status,
        "evidence_records": {
            "status": evidence_records.get("status", "unavailable"),
            "path": evidence_records.get("path", ASSURANCE_EVIDENCE_RECORDS_RELATIVE_PATH.as_posix()),
            "record_count": evidence_records.get("record_count", 0),
            "invalid_records": evidence_records.get("invalid_records", []),
            "records": evidence_records.get("records", []),
            "rule": evidence_records.get(
                "rule",
                "Evidence records are compact agent-populated labels and refs; AW does not decide acceptance.",
            ),
        },
        "subsystem_assurance": subsystem_assurance,
        "match_evidence": {
            "observed_scope_source": ", ".join(
                source
                for source, present in (
                    ("changed paths", bool(changed_paths)),
                    ("task text", bool(task_text)),
                    ("active planning", bool(active_planning_record)),
                )
                if present
            )
            or "no active planning record, task text, or changed paths",
            "match_count": len(active),
            "matching": matching,
            "subsystem_profile_match_count": subsystem_assurance.get("matched_count", 0),
        },
        "supported_blocking_claims": list(SUPPORTED_ASSURANCE_REQUIREMENT_BLOCKING_CLAIMS),
    }


def _compact_assurance_requirements(value: Any) -> dict[str, Any]:
    if not isinstance(value, dict):
        return {"status": "absent", "active_count": 0}
    active = value.get("active", [])
    active = active if isinstance(active, list) else []
    evidence_status = value.get("evidence_status", [])
    evidence_status = evidence_status if isinstance(evidence_status, list) else []
    subsystem_assurance = _as_dict(value.get("subsystem_assurance"))
    required_missing = [
        item for item in evidence_status if isinstance(item, dict) and item.get("state") in {"missing-evidence", "review-required"}
    ]
    return {
        "status": value.get("status", "absent"),
        "configured_count": value.get("configured_count", 0),
        "active_count": value.get("active_count", 0),
        "missing_required_evidence_count": value.get("missing_required_evidence_count", 0),
        "active": [
            {
                key: item.get(key)
                for key in (
                    "id",
                    "level",
                    "applies_because",
                    "authority_refs",
                    "required_evidence",
                    "proof_profile",
                    "review_owner",
                    "force",
                    "blocking_claims",
                )
                if isinstance(item, dict) and key in item
            }
            for item in active[:3]
            if isinstance(item, dict)
        ],
        "subsystem_assurance": {
            "status": subsystem_assurance.get("status", "absent"),
            "matched_count": subsystem_assurance.get("matched_count", 0),
            "effective_assurance_level": subsystem_assurance.get("effective_assurance_level", "none"),
            "matched_subsystem_ids": subsystem_assurance.get("matched_subsystem_ids", []),
            "missing_evidence": subsystem_assurance.get("missing_evidence", []),
            "blocked_claims": subsystem_assurance.get("blocked_claims", []),
        },
        "evidence_status": [
            {
                key: item.get(key)
                for key in ("requirement_id", "state", "missing_evidence", "waiver", "dismissal", "next_action")
                if key in item
            }
            for item in required_missing[:3]
        ],
        "detail_command": "agentic-workspace report --target ./repo --section assurance_requirements --format json",
    }


def _compact_verification(value: Any) -> dict[str, Any]:
    if not isinstance(value, dict):
        return {"status": "absent", "active_count": 0}
    active = value.get("active_protocols", [])
    active = active if isinstance(active, list) else []
    evidence_status = value.get("evidence_status", [])
    evidence_status = evidence_status if isinstance(evidence_status, list) else []
    evidence_strategy = value.get("evidence_strategy", {})
    evidence_strategy = evidence_strategy if isinstance(evidence_strategy, dict) else {}
    proof_governance = evidence_strategy.get("proof_governance", {})
    proof_governance = proof_governance if isinstance(proof_governance, dict) else {}
    proof_decision = evidence_strategy.get("proof_decision", {})
    proof_decision = proof_decision if isinstance(proof_decision, dict) else {}
    regression_sprawl = evidence_strategy.get("regression_sprawl", {})
    regression_sprawl = regression_sprawl if isinstance(regression_sprawl, dict) else {}
    return {
        "kind": value.get("kind", "agentic-workspace/verification/v1"),
        "status": value.get("status", "absent"),
        "configured": bool(value.get("configured")),
        "protocol_count": value.get("protocol_count", 0),
        "active_count": value.get("active_count", 0),
        "active_protocols": [
            {
                key: item.get(key)
                for key in ("id", "title", "applies_because", "expected_evidence", "review_owner", "scenario_refs", "evidence_bundle_ids")
                if isinstance(item, dict) and key in item
            }
            for item in active[:3]
            if isinstance(item, dict)
        ],
        "evidence_status": [
            {
                key: item.get(key)
                for key in ("protocol_id", "state", "missing_evidence", "evidence_bundle_ids", "residual_risk", "claim_boundaries")
                if isinstance(item, dict) and key in item
            }
            for item in evidence_status[:3]
            if isinstance(item, dict)
        ],
        "proof_governance": {
            "status": proof_governance.get("status", "unavailable"),
            "decision_authority": proof_governance.get("decision_authority", "agent"),
            "available_decisions": proof_governance.get("available_decisions", []),
        },
        "proof_decision": {
            "status": proof_decision.get("status", "missing"),
            "missing_fields": proof_decision.get("missing_fields", []),
            "invalid_fields": proof_decision.get("invalid_fields", []),
            "lifecycle": proof_decision.get("lifecycle", {}),
        },
        "regression_sprawl": {
            "status": regression_sprawl.get("status", "unavailable"),
            "proof_decision_status": regression_sprawl.get("proof_decision_status", "missing"),
            "missing_or_incomplete_proof_decision": regression_sprawl.get("missing_or_incomplete_proof_decision", False),
            "ordinary_test_function_count": regression_sprawl.get("ordinary_test_function_count", 0),
            "likely_fixture_variant_group_count": regression_sprawl.get("likely_fixture_variant_group_count", 0),
        },
        "detail_command": "agentic-workspace report --target ./repo --section verification --format json",
    }


def _applicable_intent_durable_outcomes_payload(applicable: dict[str, Any]) -> list[dict[str, Any]]:
    outcomes: list[dict[str, Any]] = []
    raw_outcomes = _list_payload(
        applicable.get("durable_outcomes") or applicable.get("resolved_outcomes") or applicable.get("durable_outcome_evidence")
    )
    for index, raw in enumerate(raw_outcomes, start=1):
        if not isinstance(raw, dict):
            continue
        outcome = str(raw.get("outcome") or raw.get("type") or raw.get("status") or "accepted-interpretation").strip()
        summary = str(raw.get("summary") or raw.get("decision") or raw.get("reason") or "").strip()
        owner = str(raw.get("owner") or raw.get("accepted_by") or raw.get("waived_by") or raw.get("review_owner") or "").strip()
        owner_surface = str(raw.get("owner_surface") or raw.get("surface") or raw.get("source") or "").strip()
        evidence_anchor = str(raw.get("evidence_anchor") or raw.get("evidence") or raw.get("locator") or "").strip()
        status = str(raw.get("record_status") or raw.get("state") or "recorded").strip()
        resolves = _dedupe(
            [
                str(item).strip()
                for item in (
                    _list_payload(raw.get("resolves"))
                    + _list_payload(raw.get("resolves_conflicts"))
                    + _list_payload(raw.get("resolves_missing_authority"))
                    + _list_payload(raw.get("resolves_manual_verification"))
                )
                if str(item).strip()
            ]
        )
        outcomes.append(
            {
                "id": str(raw.get("id") or f"durable-outcome-{index}"),
                "outcome": outcome,
                "status": status,
                "summary": summary,
                "owner": owner or "human/domain owner",
                "owner_surface": owner_surface or "Planning, Verification, assurance, docs/config, or issue evidence",
                "evidence_anchor": evidence_anchor or "durable outcome record",
                "stale_when": str(raw.get("stale_when") or raw.get("stale") or "owner surface changes or later evidence supersedes it"),
                "reopen_trigger": str(raw.get("reopen_trigger") or raw.get("reopen_when") or "affected intent, owner, or evidence changes"),
                "affected_claims": _dedupe([str(item).strip() for item in _list_payload(raw.get("affected_claims")) if str(item).strip()]),
                "resolves": resolves,
                "closeout_effect": str(
                    raw.get("closeout_effect")
                    or (
                        "deferred-with-owner"
                        if outcome == "deferred-with-owner"
                        else "satisfies recorded applicable-intent obligation for resolved items"
                    )
                ),
            }
        )
    return outcomes


def _applicable_intent_resolved_items(durable_outcomes: list[dict[str, Any]]) -> set[str]:
    resolved: set[str] = set()
    unresolved_states = {"", "pending", "missing", "rejected", "stale", "superseded"}
    for outcome in durable_outcomes:
        if not isinstance(outcome, dict):
            continue
        if str(outcome.get("status") or "").strip() in unresolved_states:
            continue
        resolved.update(str(item).strip() for item in _list_payload(outcome.get("resolves")) if str(item).strip())
    return resolved


def _applicable_intent_source_projection_payload(
    *,
    target_root: Path,
    active_planning_record: dict[str, Any] | None = None,
    assurance_requirements: dict[str, Any] | None = None,
    verification: dict[str, Any] | None = None,
    standing_intent: dict[str, Any] | None = None,
    durable_intent: dict[str, Any] | None = None,
    external_work_reconciliation: dict[str, Any] | None = None,
    memory_consult: dict[str, Any] | None = None,
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> dict[str, Any]:
    active_planning_record = _as_dict(active_planning_record)
    assurance_requirements = _as_dict(assurance_requirements)
    verification = _as_dict(verification)
    standing_intent = _as_dict(standing_intent)
    durable_intent = _as_dict(durable_intent)
    external_work_reconciliation = _as_dict(external_work_reconciliation)
    memory_consult = _as_dict(memory_consult)
    sources: list[dict[str, Any]] = []

    def add_source(
        *,
        source_id: str,
        source_type: str,
        owner_surface: str,
        authority_class: str,
        evidence_anchor: str,
        match_evidence: list[str] | None = None,
        freshness: str = "current",
        trust: str = "unverified",
        next_read: str = "",
        owner: str = "agent",
        status: str = "present",
    ) -> None:
        if not source_id or any(item.get("id") == source_id for item in sources):
            return
        sources.append(
            {
                "id": source_id,
                "source_type": source_type,
                "owner_surface": owner_surface,
                "authority_class": authority_class,
                "freshness": freshness,
                "trust": trust,
                "status": status,
                "structural_match_evidence": _dedupe([str(item) for item in (match_evidence or []) if str(item).strip()]),
                "evidence_anchor": evidence_anchor,
                "next_read": next_read,
                "resolution_owner": owner,
            }
        )

    requested_outcome = str(
        active_planning_record.get("requested_outcome")
        or _as_dict(active_planning_record.get("canonical_core")).get("requested_outcome")
        or _as_dict(active_planning_record.get("delegated_judgment")).get("requested outcome")
        or _as_dict(active_planning_record.get("delegated_judgment")).get("requested_outcome")
        or ""
    ).strip()
    active_plan_path = str(active_planning_record.get("source_path") or active_planning_record.get("path") or "").strip()
    if requested_outcome or active_planning_record:
        add_source(
            source_id="planning.active",
            source_type="Planning",
            owner_surface=active_plan_path or ".agentic-workspace/planning/state.toml",
            authority_class="authoritative",
            freshness="current",
            trust="current",
            evidence_anchor=requested_outcome or "active Planning record",
            match_evidence=["active Planning record selected for current work"],
            next_read="agentic-workspace summary --target ./repo --format json",
            owner="agent",
        )
    for ref in _list_payload(active_planning_record.get("references")):
        if not isinstance(ref, dict):
            continue
        target = str(ref.get("target") or ref.get("label") or "").strip()
        if not target:
            continue
        add_source(
            source_id=f"planning.reference.{_decision_slug(target)}",
            source_type="issue" if "github" in target.lower() or "#" in target else "Planning",
            owner_surface=active_plan_path or ".agentic-workspace/planning/execplans",
            authority_class="authoritative",
            freshness="current",
            trust="current",
            evidence_anchor=target,
            match_evidence=[str(ref.get("role") or "active Planning reference")],
            next_read=str(ref.get("locator") or "agentic-workspace summary --target ./repo --format json"),
            owner="agent",
        )

    memory_index = target_root / ".agentic-workspace" / "memory" / "repo" / "index.md"
    memory_manifest = target_root / ".agentic-workspace" / "memory" / "repo" / "manifest.toml"
    if memory_index.exists():
        add_source(
            source_id="memory.repo.index",
            source_type="Memory",
            owner_surface=".agentic-workspace/memory/repo/index.md",
            authority_class="learned",
            freshness="current" if memory_manifest.exists() else "unverified",
            trust="advisory",
            evidence_anchor="repo Memory index is present",
            match_evidence=_list_payload(memory_consult.get("read_first")) or ["Memory index route is available"],
            next_read=".agentic-workspace/memory/repo/index.md",
            owner="agent",
        )

    if standing_intent:
        add_source(
            source_id="standing_intent.effective",
            source_type="docs/contracts",
            owner_surface=".agentic-workspace/docs/standing-intent-contract.md",
            authority_class="advisory",
            freshness="current",
            trust="advisory",
            evidence_anchor=str(
                _as_dict(standing_intent.get("effective_view")).get("rule") or standing_intent.get("status") or "standing intent available"
            ),
            match_evidence=["standing intent report is available"],
            next_read="agentic-workspace report --target ./repo --section standing_intent --format json",
            owner="agent",
        )
    if durable_intent and durable_intent.get("status") not in {None, "", "absent"}:
        add_source(
            source_id="durable_intent.projection",
            source_type="docs/contracts",
            owner_surface=".agentic-workspace/system-intent/",
            authority_class="authoritative",
            freshness="current",
            trust="current",
            evidence_anchor=str(durable_intent.get("status")),
            match_evidence=["durable intent projection is present"],
            next_read="agentic-workspace report --target ./repo --section durable_intent --format json",
            owner="agent",
        )

    for requirement in _list_payload(assurance_requirements.get("active")):
        if not isinstance(requirement, dict):
            continue
        requirement_id = str(requirement.get("id") or "assurance-requirement").strip()
        add_source(
            source_id=f"assurance.{requirement_id}",
            source_type="assurance",
            owner_surface=".agentic-workspace/config.toml [assurance.requirements]",
            authority_class="configured",
            freshness="current",
            trust="configured",
            evidence_anchor=requirement_id,
            match_evidence=_list_payload(requirement.get("applies_because")),
            next_read="agentic-workspace report --target ./repo --section assurance_requirements --format json",
            owner=str(requirement.get("review_owner") or "human/domain owner"),
        )
    for protocol in _list_payload(verification.get("active_protocols")):
        if not isinstance(protocol, dict):
            continue
        protocol_id = str(protocol.get("id") or "verification-protocol").strip()
        add_source(
            source_id=f"verification.{protocol_id}",
            source_type="Verification",
            owner_surface=".agentic-workspace/verification/manifest.toml",
            authority_class="verification-owned",
            freshness="current",
            trust="configured",
            evidence_anchor=protocol_id,
            match_evidence=_list_payload(protocol.get("applies_because")),
            next_read="agentic-workspace report --target ./repo --section verification --format json",
            owner=str(protocol.get("review_owner") or "agent"),
        )

    external_state = _as_dict(external_work_reconciliation.get("external_work_state"))
    if external_work_reconciliation and external_work_reconciliation.get("status") not in {None, "", "absent", "unavailable"}:
        add_source(
            source_id="external_work.reconciliation",
            source_type="issue",
            owner_surface=".agentic-workspace/local/cache/external-intent-evidence.json",
            authority_class="configured",
            freshness=str(external_state.get("freshness") or "current"),
            trust=str(external_work_reconciliation.get("trust") or "unverified"),
            evidence_anchor=str(external_work_reconciliation.get("status")),
            match_evidence=["external work cache/reconciliation is available"],
            next_read="agentic-workspace report --target ./repo --section external_work_reconciliation --format json",
            owner="agent",
        )

    planning_applicable = _applicable_intent_status_payload(
        active_planning_record=active_planning_record,
        verification=verification,
        assurance_requirements=assurance_requirements,
    )
    durable_outcomes = [item for item in _list_payload(planning_applicable.get("durable_outcomes")) if isinstance(item, dict)]
    conflicts = [str(item) for item in _list_payload(planning_applicable.get("conflicts")) if str(item).strip()]
    missing_authority = [str(item) for item in _list_payload(planning_applicable.get("missing_authority")) if str(item).strip()]
    manual_required = [str(item) for item in _list_payload(planning_applicable.get("manual_verification_needed")) if str(item).strip()]
    stale_or_superseded: list[dict[str, str]] = []
    for source in sources:
        if source.get("freshness") in {"stale", "superseded"}:
            stale_or_superseded.append(
                {
                    "source_id": str(source.get("id")),
                    "freshness": str(source.get("freshness")),
                    "owner_surface": str(source.get("owner_surface")),
                }
            )

    conflict_status = (
        "conflict-blocking-closeout"
        if conflicts
        else "clarification-required"
        if missing_authority or manual_required
        else "possible-conflict"
        if stale_or_superseded
        else "none"
    )
    manual_verification = [
        {
            "id": f"manual-{index}",
            "status": "required",
            "summary": item,
            "owner": "human/domain owner",
            "evidence_anchor": "assurance, Verification, or Planning applicable_intents",
            "closeout_effect": "blocks or caveats broad/full closeout until verified, accepted, waived, or deferred",
        }
        for index, item in enumerate(manual_required, start=1)
    ]
    durable_outcome_routing = [
        {
            "outcome": "clarified-intent",
            "owner_surface": "Planning parent acceptance, decision fact, docs/config, or issue comment",
            "retain": "summary plus evidence anchor; no raw transcript",
            "stale_when": "the clarified owner surface changes or a later human instruction supersedes it",
        },
        {
            "outcome": "accepted-interpretation",
            "owner_surface": "Planning closeout evidence or decision record",
            "retain": "accepted interpretation, owner, evidence, and scope",
            "stale_when": "acceptance owner, subsystem contract, or proof boundary changes",
        },
        {
            "outcome": "waiver",
            "owner_surface": "assurance waiver, Verification known gap, closeout evidence, or issue comment",
            "retain": "waiver reason, owner, affected claims, and reopen trigger",
            "stale_when": "waived requirement changes or evidence becomes available",
        },
        {
            "outcome": "deferred-with-owner",
            "owner_surface": "Planning residual work, issue follow-up, or Verification known gap",
            "retain": "owner, trigger, blocked claims, and next inspection route",
            "stale_when": "owner accepts, rejects, or supersedes the deferred outcome",
        },
    ]
    blocked_claims = _dedupe(
        [str(item) for item in _list_payload(planning_applicable.get("blocked_claims")) if str(item).strip()]
        or (["claim-work-complete", "close-parent-lane"] if conflict_status != "none" else [])
    )
    return {
        "kind": "agentic-workspace/applicable-intent-sources/v1",
        "status": "attention" if conflict_status != "none" else "present" if sources else "guidance-only",
        "source_count": len(sources),
        "sources": sources,
        "authority_vocabulary": {
            "authority_classes": [
                "authoritative",
                "configured",
                "learned",
                "advisory",
                "human-owned",
                "compliance-owned",
                "verification-owned",
                "unknown",
            ],
            "freshness_trust_states": ["current", "stale", "superseded", "unverified", "conflicting", "absent-required"],
            "conflict_states": ["none", "possible-conflict", "conflict-blocking-closeout", "clarification-required"],
            "manual_verification_states": [
                "not-applicable",
                "required",
                "verified",
                "accepted-by-owner",
                "waived-with-reason",
                "deferred-with-owner",
                "blocked-pending-clarification",
                "stale-or-needs-reverification",
            ],
        },
        "conflict_status": conflict_status,
        "conflicts": conflicts,
        "missing_authority": missing_authority,
        "stale_or_superseded": stale_or_superseded,
        "manual_verification": manual_verification,
        "durable_outcomes": durable_outcomes,
        "resolved_outcome_count": len(durable_outcomes),
        "durable_outcome_routing": durable_outcome_routing,
        "blocked_claims": blocked_claims,
        "closeout_blocked": conflict_status != "none",
        "closeout_status": planning_applicable,
        "next_actions": [
            "Resolve conflicts through the smallest durable owner before broad closeout."
            if conflict_status != "none"
            else "Use sources as read-first evidence when agent judgment finds them relevant.",
            _command_with_cli_invoke(
                command="agentic-workspace report --target ./repo --section closeout_report --format json",
                cli_invoke=cli_invoke,
            ),
        ],
        "authority_boundary": _authority_boundary_payload(
            surface="applicable_intent",
            observed_by_aw=[
                "active Planning records",
                "Memory index/manifest presence",
                "standing and durable intent projections",
                "assurance requirement matches",
                "Verification protocol/gap matches",
                "external work reconciliation availability",
            ],
            recommended_by_aw=["read structurally matched sources and route durable clarification or waiver outcomes"],
            agent_owned_decisions=["semantic applicability of each source", "which source governs when meanings conflict"],
            human_owned_decisions=["domain/compliance acceptance, waiver, or clarification"],
            rule="AW assembles structural/configured evidence; it does not infer or resolve semantic intent.",
        ),
        "rule": "Use this projection for broad, architectural, compliance-relevant, or subsystem-affecting work; do not force it onto small direct work.",
    }


def _assurance_requirements_with_verification(assurance_requirements: dict[str, Any], verification: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(assurance_requirements, dict) or not isinstance(verification, dict):
        return assurance_requirements
    evidence_status = assurance_requirements.get("evidence_status", [])
    if not isinstance(evidence_status, list):
        return assurance_requirements
    protocols = [item for item in _list_payload(verification.get("active_protocols")) if isinstance(item, dict)]
    protocol_status = {
        str(item.get("protocol_id", "")): item for item in _list_payload(verification.get("evidence_status")) if isinstance(item, dict)
    }
    known_gaps_by_protocol: dict[str, list[dict[str, Any]]] = {}
    for gap in _list_payload(verification.get("active_known_gaps")):
        if not isinstance(gap, dict):
            continue
        protocol_id = str(gap.get("protocol_id", "")).strip()
        if protocol_id:
            known_gaps_by_protocol.setdefault(protocol_id, []).append(gap)
    enriched_status: list[Any] = []
    for status in evidence_status:
        if not isinstance(status, dict):
            enriched_status.append(status)
            continue
        requirement_id = str(status.get("requirement_id", "")).strip()
        required_evidence = {str(item).strip() for item in _list_payload(status.get("required_evidence")) if str(item).strip()}
        matched_protocols: list[dict[str, Any]] = []
        matched_known_gaps: list[dict[str, Any]] = []
        for protocol in protocols:
            protocol_requirement_refs = {str(item).strip() for item in _list_payload(protocol.get("assurance_requirement_refs"))}
            protocol_evidence = {str(item).strip() for item in _list_payload(protocol.get("expected_evidence"))}
            applies_because = " ".join(str(item) for item in _list_payload(protocol.get("applies_because")))
            if (
                (requirement_id and requirement_id in protocol_requirement_refs)
                or (requirement_id and f"assurance requirement matched {requirement_id}" in applies_because)
                or bool(required_evidence & protocol_evidence)
            ):
                protocol_id = str(protocol.get("id", "")).strip()
                protocol_known_gaps = known_gaps_by_protocol.get(protocol_id, [])
                matched_known_gaps.extend(protocol_known_gaps)
                matched_protocols.append(
                    {
                        "protocol_id": protocol_id,
                        "title": protocol.get("title"),
                        "review_owner": protocol.get("review_owner"),
                        "state": protocol_status.get(protocol_id, {}).get("state", "matched"),
                        "missing_evidence": protocol_status.get(protocol_id, {}).get("missing_evidence", []),
                        "evidence_bundle_ids": protocol_status.get(protocol_id, {}).get("evidence_bundle_ids", []),
                        "known_gap_ids": [str(gap.get("id")) for gap in protocol_known_gaps if gap.get("id")],
                    }
                )
        if matched_protocols:
            verification_blocked_claims = _dedupe(
                [
                    str(claim).strip()
                    for gap in matched_known_gaps
                    for claim in _list_payload(gap.get("blocked_claims"))
                    if str(claim).strip()
                ]
            )
            status = {
                **status,
                "verification_protocols": matched_protocols,
                "verification_missing_evidence": _dedupe(
                    [
                        str(item).strip()
                        for protocol in matched_protocols
                        for item in _list_payload(protocol.get("missing_evidence"))
                        if str(item).strip()
                    ]
                ),
            }
            if matched_known_gaps:
                status = {
                    **status,
                    "verification_known_gaps": [
                        {
                            "id": gap.get("id"),
                            "protocol_id": gap.get("protocol_id"),
                            "reason": gap.get("reason"),
                            "owner": gap.get("owner"),
                            "blocked_claims": _list_payload(gap.get("blocked_claims")),
                            "residual_risk": gap.get("residual_risk"),
                            "reopen_trigger": gap.get("reopen_trigger"),
                        }
                        for gap in matched_known_gaps
                    ],
                    "verification_blocked_claims": verification_blocked_claims,
                }
                if status.get("state") not in {"waived", "dismissed"} and verification_blocked_claims:
                    status = {**status, "state": "review-required"}
        enriched_status.append(status)
    return {
        **assurance_requirements,
        "evidence_status": enriched_status,
    }


