_MERGE_CONFLICT_MARKERS = ("<<<<<<< ", "=======", ">>>>>>> ")
_MERGE_CONFLICT_EXTENSIONS = {".toml", ".json", ".md", ".txt"}


def _is_workspace_local_scratch_path(*, path: Path, target_root: Path) -> bool:
    try:
        relative = path.relative_to(target_root).as_posix()
    except ValueError:
        return False
    scratch_root = WORKSPACE_LOCAL_SCRATCH_ROOT_PATH.as_posix().rstrip("/")
    return relative == scratch_root or relative.startswith(f"{scratch_root}/")


def _workspace_merge_conflict_findings(*, target_root: Path) -> list[dict[str, Any]]:
    workspace_root = target_root / ".agentic-workspace"
    if not workspace_root.exists():
        return []
    findings: list[dict[str, Any]] = []
    for path in sorted(workspace_root.rglob("*")):
        if _is_workspace_local_scratch_path(path=path, target_root=target_root):
            continue
        if not path.is_file() or path.suffix.lower() not in _MERGE_CONFLICT_EXTENSIONS:
            continue
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        if not any((marker in text for marker in _MERGE_CONFLICT_MARKERS)):
            continue
        relative = path.relative_to(target_root).as_posix()
        findings.append(_workspace_merge_conflict_finding(relative))
    return findings


def _workspace_merge_conflict_finding(relative_path: str) -> dict[str, Any]:
    if relative_path in {".agentic-workspace/config.toml", ".agentic-workspace/OWNERSHIP.toml"}:
        return {
            "path": relative_path,
            "surface_class": "workspace_policy",
            "owner": "repo",
            "fault_class": "ambiguous_ownership",
            "invariant": "workspace.policy_conflict_reviewed",
            "message": "Workspace config or ownership surface contains git merge conflict markers.",
            "risk": "manual review required; policy and ownership conflicts are high-impact semantic conflicts",
            "do_not": "Do not resolve config or ownership conflicts by blind regeneration or by committing local-only preferences.",
        }
    if relative_path == ".agentic-workspace/config.local.toml.example":
        return {
            "path": relative_path,
            "surface_class": "local_config_example",
            "owner": "workspace",
            "fault_class": "ambiguous_ownership",
            "invariant": "workspace.policy_conflict_reviewed",
            "message": "Local config example contains git merge conflict markers.",
            "risk": "manual review required; preserve portable examples and keep user-specific local config out of shared state",
            "do_not": "Do not copy user-specific config.local.toml values into the shared example while resolving the conflict.",
        }
    if relative_path.endswith("/state.toml") and relative_path.startswith(".agentic-workspace/planning/"):
        return {
            "path": relative_path,
            "surface_class": "planning_live_state",
            "owner": "planning",
            "fault_class": "agent_operation_fault",
            "invariant": "planning.live_state_conflict_resolved",
            "message": "Live Planning state contains git merge conflict markers.",
            "risk": "manual review required; live state selects future work and must preserve intentional active/queued items",
            "do_not": "Do not delete state.toml or recreate active work from memory as the first recovery step.",
        }
    if relative_path.startswith(".agentic-workspace/planning/execplans/"):
        return {
            "path": relative_path,
            "surface_class": "planning_execplan",
            "owner": "planning",
            "fault_class": "agent_operation_fault",
            "invariant": "planning.execplan_conflict_resolved",
            "message": "Planning execplan contains git merge conflict markers.",
            "risk": "manual review required; preserve the bounded implementation contract before continuing",
            "do_not": "Do not replace the execplan with a new freehand plan unless the conflicting intent has been preserved.",
        }
    if relative_path.startswith(".agentic-workspace/memory/repo/"):
        return {
            "path": relative_path,
            "surface_class": "durable_memory_note",
            "owner": "memory",
            "fault_class": "agent_operation_fault",
            "invariant": "memory.note_conflict_resolved",
            "message": "Durable Memory surface contains git merge conflict markers.",
            "risk": "manual review required; preserve durable facts and split broad notes when conflicts recur",
            "do_not": "Do not treat durable Memory as active task state or discard one side without checking whether it records reusable knowledge.",
        }
    generated_hint = "generated" if "generated" in relative_path or relative_path.endswith(".report.json") else "workspace_surface"
    return {
        "path": relative_path,
        "surface_class": generated_hint,
        "owner": "workspace",
        "fault_class": "generated_artifact_drift" if generated_hint == "generated" else "agent_operation_fault",
        "invariant": "workspace.merge_conflict_resolved",
        "message": "Agentic Workspace surface contains git merge conflict markers.",
        "risk": "manual review required unless a canonical source and safe rerender command are known",
        "do_not": "Do not blindly regenerate repo-owned content; first identify the authoritative source for the conflicted surface.",
    }


def _workspace_agents_template(
    *,
    selected_modules: list[str],
    descriptors: dict[str, ModuleDescriptor],
    agent_instructions_file: str = DEFAULT_AGENT_INSTRUCTIONS_FILE,
    workflow_artifact_profile: str = DEFAULT_WORKFLOW_ARTIFACT_PROFILE,
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> str:
    _ = workflow_artifact_profile
    _ = selected_modules
    _ = descriptors
    lines = [
        "# Agent Instructions",
        "",
        "Authority marker:",
        "",
        "- authority: adapter",
        f"- canonical_source: `.agentic-workspace/config.toml` and `{cli_invoke} start --target . --format json`",
        "- safe_to_edit: true",
        "- refresh_command: null",
        "",
        workspace_pointer_block(cli_invoke=cli_invoke),
    ]
    return "\n".join(lines) + "\n"


def _replace_or_insert_fenced_block(*, text: str, block: str, start_marker: str, end_marker: str) -> tuple[str, bool]:
    fenced_re = re.compile(re.escape(start_marker) + ".*?" + re.escape(end_marker), re.DOTALL)
    existing = fenced_re.search(text)
    if existing:
        current = existing.group(0).strip()
        if current == block:
            return (text, False)
        return (fenced_re.sub(block, text, count=1), True)
    stripped = text.lstrip()
    if stripped.startswith("# "):
        lines = text.splitlines()
        if len(lines) == 1:
            return (f"{lines[0]}\n\n{block}\n", True)
        return ("\n".join([lines[0], "", block, *lines[1:]]) + "\n", True)
    prefix = "" if not text else text.rstrip() + "\n\n"
    return (prefix + block + "\n", True)


def _remove_fenced_block(*, text: str, start_marker: str, end_marker: str) -> tuple[str, bool]:
    fenced_re = re.compile("\\n?" + re.escape(start_marker) + ".*?" + re.escape(end_marker) + "\\n?", re.DOTALL)
    updated, count = fenced_re.subn("\n", text, count=1)
    if count == 0:
        return (text, False)
    updated = re.sub("\\n{3,}", "\n\n", updated).lstrip("\n")
    if updated and (not updated.endswith("\n")):
        updated += "\n"
    return (updated, True)


def _local_agent_indirection_is_current(*, target_root: Path, agents_relative: Path, agents_text: str, cli_invoke: str) -> bool:
    if LOCAL_AGENT_REFERENCE_LINE not in agents_text:
        return False
    if not _has_local_only_workspace_state(target_root=target_root):
        return False
    local_agents_path = target_root / LOCAL_AGENT_INSTRUCTIONS_FILE
    if not local_agents_path.is_file():
        return False
    return workspace_pointer_block(cli_invoke=cli_invoke) in local_agents_path.read_text(encoding="utf-8")


def _workspace_managed_agent_instructions_path(config: WorkspaceConfig) -> Path:
    return Path(".agentic-workspace") / Path(config.agent_instructions_file)


def _workspace_managed_agent_instructions_text(*, config: WorkspaceConfig) -> str:
    cli = config.cli_invoke
    return "\n".join(
        [
            "# Agent Instructions for .agentic-workspace",
            "",
            "Authority marker:",
            "",
            "- authority: workspace-managed-local-adapter",
            f"- canonical_source: `.agentic-workspace/config.toml` and `{cli} start --target . --format json`",
            "- safe_to_edit: false",
            f"- refresh_command: `{cli} init --target . --format json` or `{cli} upgrade --target . --format json`",
            "",
            "This directory contains Agentic Workspace managed workflow, planning, memory, ownership, and state surfaces.",
            "",
            "Before editing inside `.agentic-workspace/`:",
            "",
            f'- Use `{cli} start --target . --task "<task>" --format json` for routing.',
            (
                f"- Use `{cli} summary --target . --format json`, "
                f'`{cli} implement --changed <paths> --task "<task>" --format json`, and '
                f"`{cli} proof --changed <paths> --format json` before opening broad raw state."
            ),
            f"- Use `{cli} planning ...` and `{cli} memory ...` commands for structured Planning and Memory mutations when a command exists.",
            "- Do not hand-edit structured state such as Planning execplans, Planning state, Memory indexes, ownership ledgers, or config when a package CLI command exists.",
            (
                "- Raw structured edits are only fallback or repair work; after any fallback edit, run "
                f"`{cli} summary --target . --format json` and "
                f"`{cli} doctor --target . --modules planning,memory --format json` as applicable."
            ),
            "- If a needed managed-state mutation has no command, route or file an improvement issue for a command-owned path instead of making manual edits routine.",
            "",
        ]
    )


def _sync_workspace_managed_agent_instructions(
    *, target_root: Path, config: WorkspaceConfig, dry_run: bool, apply: bool
) -> tuple[list[dict[str, str]], list[dict[str, str]]]:
    relative = _workspace_managed_agent_instructions_path(config)
    path = target_root / relative
    rendered = _workspace_managed_agent_instructions_text(config=config)
    existing = path.read_text(encoding="utf-8") if path.exists() else None
    if existing == rendered:
        return (
            [
                {
                    "kind": "current",
                    "path": relative.as_posix(),
                    "detail": "managed .agentic-workspace local instructions already current",
                }
            ],
            [],
        )
    if apply:
        if not dry_run:
            path.parent.mkdir(parents=True, exist_ok=True)
            path.write_text(rendered, encoding="utf-8")
        return (
            [
                {
                    "kind": _write_action_kind(dry_run=dry_run, existing=existing),
                    "path": relative.as_posix(),
                    "detail": "refresh managed .agentic-workspace local instructions for command-owned state edits",
                }
            ],
            [],
        )
    action = {
        "kind": "missing" if existing is None else "warning",
        "path": relative.as_posix(),
        "detail": "managed .agentic-workspace local instructions missing"
        if existing is None
        else "managed .agentic-workspace local instructions stale",
    }
    warning = {
        "path": relative.as_posix(),
        "message": action["detail"],
    }
    return ([action], [warning])


def _workspace_status_report(
    *, target_root: Path, selected_modules: list[str], descriptors: dict[str, ModuleDescriptor], command_name: str, config: WorkspaceConfig
) -> dict[str, Any]:
    actions: list[dict[str, str]] = []
    warnings: list[dict[str, str]] = []
    agents_relative = Path(config.agent_instructions_file)
    for relative in WORKSPACE_PAYLOAD_FILES:
        path = target_root / relative
        exists = path.exists()
        actions.append(
            {
                "kind": "current" if exists else "missing",
                "path": relative.as_posix(),
                "detail": "required workspace file present" if exists else "required workspace file missing",
            }
        )
        if not exists:
            warnings.append({"path": relative.as_posix(), "message": "required workspace file missing"})
        local_actions, local_warnings = _sync_workspace_managed_agent_instructions(
            target_root=target_root, config=config, dry_run=False, apply=False
        )
        actions.extend(local_actions)
        warnings.extend(local_warnings)
    if _has_local_only_workspace_state(target_root=target_root):
        actions.append(
            {
                "kind": "warning",
                "path": LOCAL_ONLY_STATE_FILE.as_posix(),
                "detail": "local-only workspace state present; checked-in adoption is available",
            }
        )
        warnings.append(
            {
                "path": LOCAL_ONLY_STATE_FILE.as_posix(),
                "message": "local-only workspace state present; run upgrade --adopt-local-only --dry-run to inspect checked-in adoption.",
            }
        )
    scratch_path = target_root / WORKSPACE_LOCAL_SCRATCH_ROOT_PATH
    actions.append(
        {
            "kind": "current" if scratch_path.is_dir() else "available",
            "path": WORKSPACE_LOCAL_SCRATCH_ROOT_PATH.as_posix(),
            "detail": "gitignored local scratch space for temporary agent working files",
        }
    )
    agents_path = target_root / agents_relative
    if not agents_path.exists():
        actions.append({"kind": "missing", "path": agents_relative.as_posix(), "detail": "root startup entrypoint missing"})
        warnings.append({"path": agents_relative.as_posix(), "message": "root startup entrypoint missing"})
        repair_actions, manual_review_actions, repair_plan = _workspace_repair_payload(
            target_root=target_root, actions=actions, warnings=warnings, command_name=command_name, cli_invoke=config.cli_invoke
        )
        return _workspace_report(
            target_root=target_root,
            message=f"{command_name.title()} report",
            dry_run=False,
            actions=actions,
            warnings=warnings,
            repair_actions=repair_actions,
            manual_review_actions=manual_review_actions,
            repair_plan=repair_plan,
        )
    agents_text = agents_path.read_text(encoding="utf-8")
    expected_pointer_block = workspace_pointer_block(cli_invoke=config.cli_invoke)
    if expected_pointer_block in agents_text:
        actions.append({"kind": "current", "path": agents_relative.as_posix(), "detail": "workspace workflow pointer block present"})
    elif _local_agent_indirection_is_current(
        target_root=target_root, agents_relative=agents_relative, agents_text=agents_text, cli_invoke=config.cli_invoke
    ):
        actions.append(
            {
                "kind": "current",
                "path": agents_relative.as_posix(),
                "detail": "local startup indirection points to AGENTS.local.md workspace workflow block",
            }
        )
    else:
        actions.append({"kind": "warning", "path": agents_relative.as_posix(), "detail": "workspace workflow pointer block missing"})
        warnings.append({"path": agents_relative.as_posix(), "message": "workspace workflow pointer block missing"})
    for module_name in selected_modules:
        for block in descriptors[module_name].root_agents_cleanup_blocks:
            if block.block not in agents_text:
                continue
            actions.append(
                {
                    "kind": "warning",
                    "path": agents_relative.as_posix(),
                    "detail": f"redundant top-level {block.label} still present; shared workspace workflow should delegate to module-specific guidance",
                }
            )
            warnings.append({"path": agents_relative.as_posix(), "message": f"redundant top-level {block.label} still present"})
    policy_actions, policy_warnings = _sync_update_policy_actions(
        target_root=target_root, selected_modules=selected_modules, dry_run=False, command_name=command_name, config=config, apply=False
    )
    actions.extend(policy_actions)
    warnings.extend(policy_warnings)
    for config_warning in config.warnings:
        warnings.append({"path": config.path.as_posix() if config.path else ".agentic-workspace/config.toml", "message": config_warning})
    if command_name == "doctor":
        integrity_errors = doctor.check_contract_integrity()
        for error in integrity_errors:
            warnings.append({"path": "src/agentic_workspace/contracts/", "message": f"contract drift: {error}"})
    repair_actions, manual_review_actions, repair_plan = _workspace_repair_payload(
        target_root=target_root, actions=actions, warnings=warnings, command_name=command_name, cli_invoke=config.cli_invoke
    )
    return _workspace_report(
        target_root=target_root,
        message=f"{command_name.title()} report",
        dry_run=False,
        actions=actions,
        warnings=warnings,
        repair_actions=repair_actions,
        manual_review_actions=manual_review_actions,
        repair_plan=repair_plan,
    )


def _write_action_kind(*, dry_run: bool, existing: str | None) -> str:
    if dry_run:
        return "would create" if existing is None else "would update"
    return "created" if existing is None else "updated"


def _is_retired_generated_llms_adapter(text: str) -> bool:
    lowered = text.lower()
    return (
        "canonical_source: `generated/workspace/python/cli.py:_external_agent_handoff_text`" in lowered
        or "generated compatibility adapter" in lowered
        or "agent entrypoint router" in lowered
    )


def _write_generated_text(*, destination: Path, text: str, dry_run: bool) -> None:
    if dry_run:
        return
    destination.parent.mkdir(parents=True, exist_ok=True)
    destination.write_text(text, encoding="utf-8")


LOCAL_AGENT_INSTRUCTIONS_FILE = Path("AGENTS.local.md")
LOCAL_AGENT_REFERENCE_LINE = f"Follow instructions in `{LOCAL_AGENT_INSTRUCTIONS_FILE.as_posix()}` if present."
EXTERNAL_INTENT_CACHE_RELATIVE_PATH = Path(".agentic-workspace") / "local" / "cache" / "external-intent-evidence.json"
EXTERNAL_INTENT_PLANNING_RELATIVE_PATH = Path(".agentic-workspace") / "planning" / "external-intent-evidence.json"
TEST_STRATEGY_DISPOSITIONS_RELATIVE_PATH = Path(".agentic-workspace") / "verification" / "test-strategy-dispositions.json"
TEST_SUITE_BUDGET_RELATIVE_PATH = Path(".agentic-workspace") / "verification" / "test-suite-budget.json"
ASSURANCE_EVIDENCE_RECORDS_RELATIVE_PATH = Path(".agentic-workspace") / "verification" / "assurance-evidence-records.json"
EXTERNAL_INTENT_CACHE_CLOSED_RETENTION_DAYS = 7
LOCAL_ONLY_IGNORE_BLOCK = "# Agentic Workspace local-only storage\n.agentic-workspace/\nAGENTS.local.md\n"
LEGACY_LOCAL_ONLY_IGNORE_BLOCKS = ("# Agentic Workspace local-only storage\n.agentic-workspace/\n",)
REPO_OWNED_LOCAL_IGNORE_BLOCK = "# Agentic Workspace local runtime state\n.agentic-workspace/local/\n"
LOCAL_ONLY_STATE_FILE = Path(".agentic-workspace") / "LOCAL-ONLY.toml"


def _repo_git_dir(repo_root: Path) -> Path:
    git_path = repo_root / ".git"
    if git_path.is_dir():
        return git_path
    if git_path.is_file():
        gitdir_text = git_path.read_text(encoding="utf-8").strip()
        if gitdir_text.lower().startswith("gitdir:"):
            gitdir_value = gitdir_text.split(":", 1)[1].strip()
            gitdir_path = Path(gitdir_value)
            return gitdir_path if gitdir_path.is_absolute() else (repo_root / gitdir_path).resolve()
    raise WorkspaceUsageError("Could not resolve the repository git directory for local-only residue management.")


def _local_only_exclude_path(*, repo_root: Path) -> Path:
    return _repo_git_dir(repo_root) / "info" / "exclude"


def _local_only_state_text() -> str:
    return "\n".join(("schema_version = 1", 'mode = "local-only"', 'repo_hook = ".git/info/exclude"', ""))


def _local_only_state_path(*, target_root: Path) -> Path:
    return target_root / LOCAL_ONLY_STATE_FILE


def _has_local_only_workspace_state(*, target_root: Path) -> bool:
    state_path = _local_only_state_path(target_root=target_root)
    if not state_path.is_file():
        return False
    try:
        state_text = state_path.read_text(encoding="utf-8")
    except OSError:
        return False
    return re.search(r'^\s*mode\s*=\s*"local-only"\s*$', state_text, flags=re.MULTILINE) is not None


def _local_agent_instructions_text(*, cli_invoke: str = DEFAULT_CLI_INVOKE) -> str:
    lines = [
        "# Local Agent Instructions",
        "",
        "Authority marker:",
        "",
        "- authority: local-adapter",
        f"- canonical_source: `.agentic-workspace/config.toml` and `{cli_invoke} start --target . --format json`",
        "- safe_to_edit: true",
        "- refresh_command: null",
        "",
        workspace_pointer_block(cli_invoke=cli_invoke),
    ]
    return "\n".join(lines) + "\n"


def _ensure_local_agent_reference_text(text: str) -> tuple[str, bool]:
    if LOCAL_AGENT_REFERENCE_LINE in text:
        return (text, False)
    if not text:
        return (LOCAL_AGENT_REFERENCE_LINE + "\n", True)
    lines = text.splitlines()
    trailing_newline = text.endswith("\n")
    if lines and lines[0].startswith("# "):
        insert_at = 1
        while insert_at < len(lines) and lines[insert_at] == "":
            insert_at += 1
        lines[insert_at:insert_at] = ["", LOCAL_AGENT_REFERENCE_LINE]
        updated = "\n".join(lines)
    else:
        updated = LOCAL_AGENT_REFERENCE_LINE + "\n\n" + text.rstrip("\n")
    return (updated + ("\n" if trailing_newline or not updated.endswith("\n") else ""), True)


def _remove_local_agent_reference_text(text: str) -> tuple[str, bool]:
    pattern = re.compile("\\n?" + re.escape(LOCAL_AGENT_REFERENCE_LINE) + "\\n?", re.MULTILINE)
    updated, count = pattern.subn("\n", text, count=1)
    if count == 0:
        return (text, False)
    updated = re.sub("\\n{3,}", "\n\n", updated).lstrip("\n")
    if updated and (not updated.endswith("\n")):
        updated += "\n"
    return (updated, True)


def _sync_local_agent_startup(
    *, repo_root: Path, reference_file: Path, dry_run: bool, replace_reference_file: bool, cli_invoke: str
) -> list[dict[str, str]]:
    actions: list[dict[str, str]] = []
    local_path = repo_root / LOCAL_AGENT_INSTRUCTIONS_FILE
    rendered_local = _local_agent_instructions_text(cli_invoke=cli_invoke)
    existing_local = local_path.read_text(encoding="utf-8") if local_path.exists() else None
    if existing_local == rendered_local:
        actions.append(
            {"kind": "current", "path": LOCAL_AGENT_INSTRUCTIONS_FILE.as_posix(), "detail": "local startup instructions already current"}
        )
    else:
        if not dry_run:
            local_path.write_text(rendered_local, encoding="utf-8")
        actions.append(
            {
                "kind": _write_action_kind(dry_run=dry_run, existing=existing_local),
                "path": LOCAL_AGENT_INSTRUCTIONS_FILE.as_posix(),
                "detail": "refresh local startup instructions with the managed workspace workflow pointer",
            }
        )
    reference_path = repo_root / reference_file
    existing_reference = reference_path.read_text(encoding="utf-8") if reference_path.exists() else ""
    if replace_reference_file:
        updated_reference = LOCAL_AGENT_REFERENCE_LINE + "\n"
        changed = existing_reference != updated_reference
    else:
        updated_reference, changed = _ensure_local_agent_reference_text(existing_reference)
    if changed:
        if not dry_run:
            reference_path.write_text(updated_reference, encoding="utf-8")
        actions.append(
            {
                "kind": _write_action_kind(dry_run=dry_run, existing=existing_reference if reference_path.exists() else None),
                "path": reference_file.as_posix(),
                "detail": "refresh root startup entrypoint as a tiny local reference"
                if replace_reference_file
                else "add tiny local startup reference to AGENTS.local.md",
            }
        )
    else:
        actions.append({"kind": "current", "path": reference_file.as_posix(), "detail": "tiny local startup reference already present"})
    return actions


def _remove_local_agent_startup(*, repo_root: Path, reference_file: Path, dry_run: bool, cli_invoke: str) -> list[dict[str, str]]:
    actions: list[dict[str, str]] = []
    local_path = repo_root / LOCAL_AGENT_INSTRUCTIONS_FILE
    if not local_path.exists():
        actions.append(
            {"kind": "skipped", "path": LOCAL_AGENT_INSTRUCTIONS_FILE.as_posix(), "detail": "local startup instructions already absent"}
        )
    elif local_path.read_text(encoding="utf-8") != _local_agent_instructions_text(cli_invoke=cli_invoke):
        actions.append(
            {
                "kind": "manual review",
                "path": LOCAL_AGENT_INSTRUCTIONS_FILE.as_posix(),
                "detail": "local startup instructions differ from the managed local-only payload",
            }
        )
    else:
        if not dry_run:
            local_path.unlink()
        actions.append(
            {
                "kind": "would remove" if dry_run else "removed",
                "path": LOCAL_AGENT_INSTRUCTIONS_FILE.as_posix(),
                "detail": "remove managed local startup instructions",
            }
        )
    reference_path = repo_root / reference_file
    if not reference_path.exists():
        actions.append({"kind": "skipped", "path": reference_file.as_posix(), "detail": "root startup reference already absent"})
    else:
        existing_reference = reference_path.read_text(encoding="utf-8")
        updated_reference, changed = _remove_local_agent_reference_text(existing_reference)
        if changed:
            if not dry_run:
                reference_path.write_text(updated_reference, encoding="utf-8")
            actions.append(
                {
                    "kind": "would update" if dry_run else "updated",
                    "path": reference_file.as_posix(),
                    "detail": "remove tiny local startup reference",
                }
            )
        else:
            actions.append({"kind": "skipped", "path": reference_file.as_posix(), "detail": "root startup reference was not present"})
    return actions


def _write_local_only_state(*, target_root: Path, dry_run: bool) -> dict[str, str]:
    state_path = _local_only_state_path(target_root=target_root)
    rendered_text = _local_only_state_text()
    existing_text = state_path.read_text(encoding="utf-8") if state_path.exists() else None
    if existing_text == rendered_text:
        return {"kind": "current", "path": LOCAL_ONLY_STATE_FILE.as_posix(), "detail": "local-only package-owned state already current"}
    if not dry_run:
        state_path.parent.mkdir(parents=True, exist_ok=True)
        state_path.write_text(rendered_text, encoding="utf-8")
    return {
        "kind": "would create" if dry_run and existing_text is None else "would update" if dry_run else "created",
        "path": LOCAL_ONLY_STATE_FILE.as_posix(),
        "detail": "record local-only package-owned state inside the workspace tree",
    }


def _ensure_local_scratch(*, target_root: Path, dry_run: bool) -> dict[str, str]:
    scratch_path = target_root / WORKSPACE_LOCAL_SCRATCH_ROOT_PATH
    if scratch_path.is_dir():
        return {
            "kind": "current",
            "path": WORKSPACE_LOCAL_SCRATCH_ROOT_PATH.as_posix(),
            "detail": "local scratch space ready for temporary agent working files",
        }
    if not dry_run:
        scratch_path.mkdir(parents=True, exist_ok=True)
    return {
        "kind": "would create" if dry_run else "created",
        "path": WORKSPACE_LOCAL_SCRATCH_ROOT_PATH.as_posix(),
        "detail": "create gitignored local scratch space for temporary agent working files",
    }


def _remove_local_only_state(*, target_root: Path, dry_run: bool) -> dict[str, str]:
    state_path = _local_only_state_path(target_root=target_root)
    if not state_path.exists():
        return {"kind": "skipped", "path": LOCAL_ONLY_STATE_FILE.as_posix(), "detail": "no local-only package-owned state to remove"}
    if not dry_run:
        state_path.unlink()
    return {
        "kind": "would remove" if dry_run else "removed",
        "path": LOCAL_ONLY_STATE_FILE.as_posix(),
        "detail": "remove the local-only package-owned state file",
    }


def _append_local_only_git_exclude(*, repo_root: Path, dry_run: bool) -> dict[str, str]:
    exclude_path = _local_only_exclude_path(repo_root=repo_root)
    existing_text = exclude_path.read_text(encoding="utf-8") if exclude_path.exists() else ""
    if LOCAL_ONLY_IGNORE_BLOCK in existing_text:
        return {"kind": "current", "path": ".git/info/exclude", "detail": "local-only workspace storage already ignored"}
    updated_text = existing_text.rstrip()
    addition = "\n" + LOCAL_ONLY_IGNORE_BLOCK
    rendered_text = updated_text + addition if updated_text else addition.lstrip("\n")
    if not dry_run:
        exclude_path.parent.mkdir(parents=True, exist_ok=True)
        exclude_path.write_text(rendered_text, encoding="utf-8")
    return {
        "kind": "would create" if dry_run and (not exclude_path.exists()) else "would update" if dry_run else "created",
        "path": ".git/info/exclude",
        "detail": "record .agentic-workspace/ in git-local exclude metadata for local-only workspace storage",
    }


def _remove_local_only_git_exclude(*, repo_root: Path, dry_run: bool) -> dict[str, str]:
    exclude_path = _local_only_exclude_path(repo_root=repo_root)
    existing_text = exclude_path.read_text(encoding="utf-8") if exclude_path.exists() else ""
    if LOCAL_ONLY_IGNORE_BLOCK not in existing_text:
        return {"kind": "skipped", "path": ".git/info/exclude", "detail": "no local-only workspace ignore block to remove"}
    rendered_text = existing_text.replace(LOCAL_ONLY_IGNORE_BLOCK, "")
    if not rendered_text.strip():
        if not dry_run:
            exclude_path.write_text("", encoding="utf-8")
        return {
            "kind": "would remove" if dry_run else "removed",
            "path": ".git/info/exclude",
            "detail": "remove the local-only workspace ignore block and leave the git-local exclude file empty",
        }
    if not dry_run:
        exclude_path.write_text(rendered_text, encoding="utf-8")
    return {
        "kind": "would update" if dry_run else "updated",
        "path": ".git/info/exclude",
        "detail": "remove the local-only workspace ignore block",
    }


def _remove_legacy_local_only_gitignore(*, repo_root: Path, dry_run: bool) -> dict[str, str]:
    gitignore_path = repo_root / ".gitignore"
    existing_text = gitignore_path.read_text(encoding="utf-8") if gitignore_path.exists() else ""
    removable_blocks = (LOCAL_ONLY_IGNORE_BLOCK, *LEGACY_LOCAL_ONLY_IGNORE_BLOCKS)
    matched_block = next((block for block in removable_blocks if block in existing_text), None)
    if matched_block is None:
        return {"kind": "skipped", "path": ".gitignore", "detail": "no legacy local-only workspace ignore block to remove"}
    rendered_text = existing_text.replace(matched_block, "")
    if not rendered_text.strip():
        if not dry_run and gitignore_path.exists():
            gitignore_path.unlink()
        return {
            "kind": "would remove" if dry_run else "removed",
            "path": ".gitignore",
            "detail": "remove the legacy local-only workspace ignore block and the empty .gitignore file",
        }
    if not dry_run:
        gitignore_path.write_text(rendered_text, encoding="utf-8")
    return {
        "kind": "would update" if dry_run else "updated",
        "path": ".gitignore",
        "detail": "remove the legacy local-only workspace ignore block",
    }


def _ensure_repo_owned_local_gitignore(*, target_root: Path, dry_run: bool) -> dict[str, str]:
    gitignore_path = target_root / ".gitignore"
    existing_text = gitignore_path.read_text(encoding="utf-8") if gitignore_path.exists() else ""
    if re.search(r"(?m)^\.agentic-workspace/local/?$", existing_text):
        return {"kind": "current", "path": ".gitignore", "detail": "repo-owned local runtime state already ignored"}
    rendered_text = existing_text.rstrip()
    addition = "\n" + REPO_OWNED_LOCAL_IGNORE_BLOCK
    rendered_text = rendered_text + addition if rendered_text else addition.lstrip("\n")
    if not dry_run:
        gitignore_path.write_text(rendered_text, encoding="utf-8")
    return {
        "kind": "would create" if dry_run and (not gitignore_path.exists()) else "would update" if dry_run else "created",
        "path": ".gitignore",
        "detail": "record .agentic-workspace/local/ as repo-owned ignored runtime state",
    }


def _managed_workspace_config_header(*, cli_invoke: str) -> str:
    return "\n".join(
        [
            "# Agentic Workspace managed config.",
            "# Edit this file directly only when changing repo-owned policy.",
            f"# Reference: {WORKSPACE_CONFIG_CONTRACT_DOC}",
            f"# Check resolved config: {cli_invoke} config --target . --format json",
        ]
    )


def _seeded_workspace_config_text(*, config: WorkspaceConfig, enabled_modules: list[str]) -> str:
    lines = [
        _managed_workspace_config_header(cli_invoke=config.cli_invoke),
        "",
        "schema_version = 1",
        "",
        "[modules]",
        "enabled = " + json.dumps(enabled_modules),
        "",
        "[workspace]",
        f"agent_instructions_file = {json.dumps(config.agent_instructions_file)}",
        f"workflow_artifact_profile = {json.dumps(config.workflow_artifact_profile)}",
    ]
    return "\n".join(lines).rstrip() + "\n"


def _set_enabled_modules_action(*, target_root: Path, enabled_modules: list[str], dry_run: bool) -> dict[str, str]:
    config_path = target_root / WORKSPACE_CONFIG_PATH
    if not config_path.exists():
        return {
            "kind": "skipped",
            "path": WORKSPACE_CONFIG_PATH.as_posix(),
            "detail": "workspace config will be seeded with enabled modules",
        }
    text = config_path.read_text(encoding="utf-8")
    rendered = "enabled = " + json.dumps(enabled_modules)
    if re.search(r"(?ms)^\[modules\]\s*.*?^enabled\s*=", text):
        new_text = re.sub(r"(?m)^enabled\s*=.*$", rendered, text, count=1)
    elif "[modules]" in text:
        new_text = re.sub(r"(?m)^\[modules\]\s*$", f"[modules]\n{rendered}", text, count=1)
    else:
        insert = f"\n[modules]\n{rendered}\n"
        match = re.search(r"(?m)^\[workspace\]\s*$", text)
        if match:
            new_text = text[: match.start()] + insert + "\n" + text[match.start() :]
        else:
            new_text = text.rstrip() + "\n\n" + insert.lstrip()
    if new_text == text:
        return {
            "kind": "current",
            "path": WORKSPACE_CONFIG_PATH.as_posix(),
            "detail": "modules.enabled already matches requested repo intent",
        }
    if not dry_run:
        config_path.write_text(new_text, encoding="utf-8")
    return {
        "kind": "would update" if dry_run else "updated",
        "path": WORKSPACE_CONFIG_PATH.as_posix(),
        "detail": "set repo-owned [modules].enabled module intent",
    }


def _seed_workspace_config_action(
    *,
    target_root: Path,
    resolved_preset: str | None,
    dry_run: bool,
    command_name: str,
    local_only_repo_root: Path | None,
    config: WorkspaceConfig,
    selected_modules: list[str],
) -> dict[str, str] | None:
    if command_name != "init" or local_only_repo_root is not None:
        return None
    config_path = target_root / WORKSPACE_CONFIG_PATH
    if config_path.exists():
        return {
            "kind": "current",
            "path": WORKSPACE_CONFIG_PATH.as_posix(),
            "detail": "workspace config already present; preserved repo-owned policy",
        }
    if not dry_run:
        config_path.parent.mkdir(parents=True, exist_ok=True)
        config_path.write_text(_seeded_workspace_config_text(config=config, enabled_modules=selected_modules), encoding="utf-8")
    return {
        "kind": "would create" if dry_run else "created",
        "path": WORKSPACE_CONFIG_PATH.as_posix(),
        "detail": "seed schema-valid workspace config with managed config header and repo-local reference",
    }


def _seed_checked_in_adoption_config_action(
    *, target_root: Path, selected_modules: list[str], dry_run: bool, config: WorkspaceConfig
) -> dict[str, str]:
    config_path = target_root / WORKSPACE_CONFIG_PATH
    if config_path.exists():
        return {
            "kind": "current",
            "path": WORKSPACE_CONFIG_PATH.as_posix(),
            "detail": "workspace config already present; preserved repo-owned policy during checked-in adoption",
        }
    if not dry_run:
        config_path.parent.mkdir(parents=True, exist_ok=True)
        config_path.write_text(_seeded_workspace_config_text(config=config, enabled_modules=selected_modules), encoding="utf-8")
    return {
        "kind": "would create" if dry_run else "created",
        "path": WORKSPACE_CONFIG_PATH.as_posix(),
        "detail": "seed schema-valid workspace config for checked-in adoption",
    }


def _workspace_init_or_upgrade_report(
    *,
    target_root: Path,
    local_only_repo_root: Path | None,
    selected_modules: list[str],
    resolved_preset: str | None,
    descriptors: dict[str, ModuleDescriptor],
    dry_run: bool,
    inspection_mode: str,
    command_name: str,
    config: WorkspaceConfig,
    to_payload_target: bool = False,
    footprint_profile: str | None = None,
    module_reports: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    del footprint_profile, module_reports
    actions: list[dict[str, str]] = []
    warnings: list[dict[str, str]] = []
    conservative = inspection_mode != "install" and command_name == "init"
    config_action = _seed_workspace_config_action(
        target_root=target_root,
        resolved_preset=resolved_preset,
        dry_run=dry_run,
        command_name=command_name,
        local_only_repo_root=local_only_repo_root,
        config=config,
        selected_modules=selected_modules,
    )
    if config_action is not None:
        actions.append(config_action)
    elif command_name in {"init", "install"} and local_only_repo_root is None:
        config_modules = selected_modules
        if command_name == "install":
            ordered_names = _ordered_module_names(descriptors)
            requested = set(config.enabled_modules) | set(selected_modules)
            config_modules = [module_name for module_name in ordered_names if module_name in requested]
        actions.append(_set_enabled_modules_action(target_root=target_root, enabled_modules=config_modules, dry_run=dry_run))
    for relative in WORKSPACE_PAYLOAD_FILES:
        destination = target_root / relative
        source_bytes = _workspace_payload_bytes_for_target(relative, target_root=target_root)
        existing = destination.exists()
        if not existing:
            if not dry_run:
                destination.parent.mkdir(parents=True, exist_ok=True)
                destination.write_bytes(source_bytes)
            actions.append(
                {
                    "kind": "would create" if dry_run else "created",
                    "path": relative.as_posix(),
                    "detail": "install workspace shared-layer file",
                }
            )
            continue
        if destination.read_bytes() == source_bytes:
            actions.append(
                {
                    "kind": "current",
                    "path": relative.as_posix(),
                    "detail": _workspace_payload_current_detail(relative=relative, target_root=target_root),
                }
            )
            continue
        if conservative:
            actions.append(
                {
                    "kind": "manual review",
                    "path": relative.as_posix(),
                    "detail": "existing workspace shared-layer file differs from managed payload",
                }
            )
            continue
        if not dry_run:
            destination.write_bytes(source_bytes)
        actions.append(
            {
                "kind": "would update" if dry_run else "updated",
                "path": relative.as_posix(),
                "detail": "refresh workspace shared-layer file from package payload while preserving host-owned subsystem overlay"
                if relative == Path(".agentic-workspace/OWNERSHIP.toml") and not _is_agentic_workspace_source_checkout(target_root)
                else "refresh workspace shared-layer file from package payload",
            }
        )
    actions.append(_write_payload_provenance_action(target_root=target_root, dry_run=dry_run, force=to_payload_target))
    local_agent_actions, local_agent_warnings = _sync_workspace_managed_agent_instructions(
        target_root=target_root,
        config=config,
        dry_run=dry_run,
        apply=command_name in {"init", "upgrade"},
    )
    actions.extend(local_agent_actions)
    warnings.extend(local_agent_warnings)
    agents_relative = Path(config.agent_instructions_file)
    agents_path = target_root / agents_relative
    rendered_agents = _workspace_agents_template(
        selected_modules=selected_modules,
        descriptors=descriptors,
        agent_instructions_file=config.agent_instructions_file,
        workflow_artifact_profile=config.workflow_artifact_profile,
        cli_invoke=config.cli_invoke,
    )
    existing_agents = agents_path.read_text(encoding="utf-8") if agents_path.exists() else None
    if local_only_repo_root is not None:
        actions.extend(
            _sync_local_agent_startup(
                repo_root=local_only_repo_root,
                reference_file=agents_relative,
                dry_run=dry_run,
                replace_reference_file=inspection_mode == "install",
                cli_invoke=config.cli_invoke,
            )
        )
    elif inspection_mode == "install":
        if existing_agents != rendered_agents:
            if not dry_run:
                agents_path.parent.mkdir(parents=True, exist_ok=True)
                agents_path.write_text(rendered_agents, encoding="utf-8")
            actions.append(
                {
                    "kind": _write_action_kind(dry_run=dry_run, existing=existing_agents),
                    "path": agents_relative.as_posix(),
                    "detail": "refresh composed root startup entrypoint for selected workspace modules",
                }
            )
        else:
            actions.append(
                {"kind": "current", "path": agents_relative.as_posix(), "detail": "composed root startup entrypoint already current"}
            )
    else:
        base_text = existing_agents or rendered_agents
        updated_text, changed = _replace_or_insert_fenced_block(
            text=base_text,
            block=workspace_pointer_block(cli_invoke=config.cli_invoke),
            start_marker=WORKSPACE_WORKFLOW_MARKER_START,
            end_marker=WORKSPACE_WORKFLOW_MARKER_END,
        )
        cleanup_blocks = [block for module_name in selected_modules for block in descriptors[module_name].root_agents_cleanup_blocks]
        for cleanup_block in cleanup_blocks:
            updated_text, block_changed = _remove_fenced_block(
                text=updated_text, start_marker=cleanup_block.start_marker, end_marker=cleanup_block.end_marker
            )
            changed = changed or block_changed
        if changed:
            if not dry_run:
                agents_path.parent.mkdir(parents=True, exist_ok=True)
                agents_path.write_text(updated_text, encoding="utf-8")
            actions.append(
                {
                    "kind": _write_action_kind(dry_run=dry_run, existing=existing_agents),
                    "path": agents_relative.as_posix(),
                    "detail": "patched the shared workspace workflow pointer into the root startup file without replacing repo-owned content",
                }
            )
        elif existing_agents is not None:
            actions.append(
                {
                    "kind": "current",
                    "path": agents_relative.as_posix(),
                    "detail": "workflow pointer blocks already present in the root startup file",
                }
            )
    default_agents_relative = Path(DEFAULT_AGENT_INSTRUCTIONS_FILE)
    default_agents_path = target_root / default_agents_relative
    if (
        agents_relative != default_agents_relative
        and DEFAULT_AGENT_INSTRUCTIONS_FILE not in config.detected_agent_instructions_files
        and default_agents_path.exists()
    ):
        if not dry_run:
            default_agents_path.unlink()
        actions.append(
            {
                "kind": "would remove" if dry_run else "removed",
                "path": default_agents_relative.as_posix(),
                "detail": "remove redundant default startup entrypoint because a different canonical startup file is configured",
            }
        )
    legacy_llms_path = target_root / "llms.txt"
    if legacy_llms_path.exists():
        legacy_llms_text = legacy_llms_path.read_text(encoding="utf-8")
        if _is_retired_generated_llms_adapter(legacy_llms_text):
            if not dry_run:
                legacy_llms_path.unlink()
            actions.append(
                {
                    "kind": "would remove" if dry_run else "removed",
                    "path": "llms.txt",
                    "detail": "remove retired generated llms.txt adapter; AGENTS.md is the startup surface and docs/agentic-workspace-install.md is the public install handoff",
                }
            )
        else:
            actions.append(
                {
                    "kind": "manual review",
                    "path": "llms.txt",
                    "detail": "legacy llms.txt exists but is not recognized as the retired generated adapter",
                }
            )
    if local_only_repo_root is None:
        actions.append(_ensure_repo_owned_local_gitignore(target_root=target_root, dry_run=dry_run))
    actions.append(_ensure_local_scratch(target_root=target_root, dry_run=dry_run))
    policy_actions, policy_warnings = _sync_update_policy_actions(
        target_root=target_root, selected_modules=selected_modules, dry_run=dry_run, command_name=command_name, config=config, apply=True
    )
    actions.extend(policy_actions)
    warnings.extend(policy_warnings)
    verification_next_action = _verification_manifest_next_action(target_root=target_root, selected_modules=selected_modules, config=config)
    if verification_next_action is not None:
        actions.append(verification_next_action)
    if local_only_repo_root is not None:
        actions.append(_write_local_only_state(target_root=target_root, dry_run=dry_run))
        actions.append(_remove_legacy_local_only_gitignore(repo_root=local_only_repo_root, dry_run=dry_run))
        actions.append(_append_local_only_git_exclude(repo_root=local_only_repo_root, dry_run=dry_run))
    return _workspace_report(
        target_root=target_root, message=f"{command_name.title()} report", dry_run=dry_run, actions=actions, warnings=warnings
    )


def _workspace_uninstall_report(
    *,
    target_root: Path,
    selected_modules: list[str],
    descriptors: dict[str, ModuleDescriptor],
    dry_run: bool,
    config: WorkspaceConfig,
    local_only_repo_root: Path | None = None,
) -> dict[str, Any]:
    actions: list[dict[str, str]] = []
    warnings: list[dict[str, str]] = []
    removable_candidates: list[Path] = []
    ambiguous_payloads: list[Path] = []
    if local_only_repo_root is None:
        remaining = set(config.enabled_modules) - set(selected_modules)
        ordered_remaining = [module_name for module_name in _ordered_module_names(descriptors) if module_name in remaining]
        actions.append(_set_enabled_modules_action(target_root=target_root, enabled_modules=ordered_remaining, dry_run=dry_run))
    for relative in WORKSPACE_PAYLOAD_FILES:
        destination = target_root / relative
        if not destination.exists():
            actions.append({"kind": "skipped", "path": destination.as_posix(), "detail": "already absent"})
            continue
        if destination.read_bytes() == _workspace_payload_bytes_for_target(relative, target_root=target_root):
            removable_candidates.append(relative)
            continue
        ambiguous_payloads.append(relative)
        actions.append(
            {
                "kind": "manual review",
                "path": relative.as_posix(),
                "detail": "local workspace shared-layer file differs from managed payload; remove manually if intended",
            }
        )
    if ambiguous_payloads:
        for relative in removable_candidates:
            actions.append(
                {
                    "kind": "skipped",
                    "path": relative.as_posix(),
                    "detail": "blocked by ambiguous workspace shared-layer ownership; review before destructive uninstall",
                }
            )
        removable: list[Path] = []
    else:
        removable = list(removable_candidates)
        for relative in removable:
            actions.append(
                {
                    "kind": "would remove" if dry_run else "removed",
                    "path": relative.as_posix(),
                    "detail": "matches managed workspace payload content",
                }
            )
    if not dry_run:
        for relative in removable:
            destination = target_root / relative
            if destination.exists():
                destination.unlink()
        _prune_empty_parent_dirs(target_root=target_root, relatives=removable)
        if local_only_repo_root is not None:
            actions.append(_remove_local_only_state(target_root=target_root, dry_run=dry_run))
            local_workspace_root = target_root / ".agentic-workspace"
            if local_workspace_root.exists():
                shutil.rmtree(local_workspace_root)
    if local_only_repo_root is not None:
        if dry_run and target_root.exists():
            actions.append({"kind": "would remove", "path": ".agentic-workspace", "detail": "remove the local-only workspace tree"})
        actions.extend(
            _remove_local_agent_startup(
                repo_root=local_only_repo_root,
                reference_file=Path(config.agent_instructions_file),
                dry_run=dry_run,
                cli_invoke=config.cli_invoke,
            )
        )
        actions.append(_remove_local_only_git_exclude(repo_root=local_only_repo_root, dry_run=dry_run))
        actions.append(_remove_legacy_local_only_gitignore(repo_root=local_only_repo_root, dry_run=dry_run))
    return _workspace_report(target_root=target_root, message="Uninstall report", dry_run=dry_run, actions=actions, warnings=warnings)


def _module_arg_text(module_arg: str | list[str] | None) -> str | None:
    if module_arg is None:
        return None
    if isinstance(module_arg, list):
        tokens: list[str] = []
        for item in module_arg:
            tokens.extend(token.strip() for token in str(item).split(",") if token.strip())
        return ",".join(tokens)
    return str(module_arg)


def _selected_modules(
    *,
    command_name: str,
    preset_name: str | None,
    module_arg: str | list[str] | None,
    target_root: Path,
    descriptors: dict[str, ModuleDescriptor],
    config: WorkspaceConfig,
) -> tuple[list[str], str | None]:
    ordered_module_names = _ordered_module_names(descriptors)
    module_arg_text = _module_arg_text(module_arg)
    if preset_name and module_arg_text:
        raise ModuleSelectionError("Use --modules; --preset is no longer supported.")
    if preset_name:
        raise ModuleSelectionError("--preset is no longer supported; use --modules or [modules].enabled.")
    if module_arg_text:
        requested = _parse_modules(module_arg_text, ordered_module_names=ordered_module_names)
        return ([module_name for module_name in ordered_module_names if module_name in requested], None)
    enabled = [module_name for module_name in ordered_module_names if module_name in set(config.enabled_modules)]
    return (enabled, None)


def _ordered_module_names(descriptors: dict[str, ModuleDescriptor]) -> list[str]:
    return [
        descriptor.name for descriptor in sorted(descriptors.values(), key=lambda descriptor: (descriptor.selection_rank, descriptor.name))
    ]


def _feature_tier_payload(
    *,
    selected_modules: list[str],
    installed_modules: list[str] | None = None,
    resolved_preset: str | None = None,
    config: WorkspaceConfig | None = None,
    compact: bool = False,
) -> dict[str, Any]:
    active_modules = installed_modules if installed_modules is not None else selected_modules
    active_source = "installed_modules" if installed_modules is not None else "selected_modules"
    active = {
        "id": "enabled-modules",
        "label": "Enabled modules",
        "modules": list(active_modules),
        "activation": "Repo intent comes from [modules].enabled; installed files are separate state evidence.",
        "source": active_source,
    }
    cli_invoke = config.cli_invoke if config is not None else DEFAULT_CLI_INVOKE
    payload: dict[str, Any] = {
        "schema_version": "workspace-module-enablements/v1",
        "compatibility_status": "renamed-from-feature-tier",
        "canonical_surface": f"{cli_invoke} config --target ./repo --select workspace.enabled_modules --format json",
        "active": active,
        "default_rule": "Fresh init enables core planning and memory unless --modules or modules.enabled says otherwise.",
        "detail_command": f"{cli_invoke} modules --target ./repo --format json",
    }
    if compact:
        payload["advanced_features_enabled_count"] = len(config.advanced_features) if config is not None else 0
        return payload
    payload["advanced_policy"] = _advanced_feature_policy_payload(config=config, include_catalog=True)
    return payload


def _advanced_feature_policy_payload(*, config: WorkspaceConfig | None, include_catalog: bool = False) -> dict[str, Any]:
    enabled = list(config.advanced_features) if config is not None else []
    cli_invoke = config.cli_invoke if config is not None else DEFAULT_CLI_INVOKE
    payload: dict[str, Any] = {
        "schema_version": "workspace-advanced-feature-policy/v1",
        "enabled_features": enabled,
        "enabled_source": config.advanced_features_source if config is not None else "product-default",
        "default_rule": "Advanced host-repo diagnostics are opt-in; source-checkout-only maintainer tooling is not a shipped core module.",
        "ordinary_startup_rule": "Use start, summary, report, defaults, and proof first; inspect advanced review or external-adapter diagnostics only by selector or explicit enabled feature.",
        "config_field": "workspace.advanced_features",
        "detail_command": f"{cli_invoke} modules --target ./repo --format json",
    }
    if include_catalog:
        payload["available_features"] = [
            {
                "id": str(item.get("id", "")),
                "label": str(item.get("label", item.get("id", ""))),
                "tier": str(item.get("tier", "reusable-diagnostics")),
                "default_enabled": bool(item.get("default_enabled", False)),
                "activation": str(item.get("activation", "")),
                "default_surface_policy": str(item.get("default_surface_policy", "")),
                "selector_hint": str(item.get("selector_hint", "")),
            }
            for item in _ADVANCED_FEATURE_ENTRIES
        ]
    return payload


def _context_router_family_payload(*, cli_invoke: str = DEFAULT_CLI_INVOKE, compact: bool = False) -> dict[str, Any]:
    views = [
        {
            "view": "start",
            "command": _command_with_cli_invoke(command="agentic-workspace start --target ./repo --format json", cli_invoke=cli_invoke),
            "use_when": "repo entry",
        },
        {
            "view": "summary",
            "command": _command_with_cli_invoke(command="agentic-workspace summary --format json", cli_invoke=cli_invoke),
            "use_when": "active work or handoff",
        },
        {
            "view": "report",
            "command": _command_with_cli_invoke(command="agentic-workspace report --target ./repo --format json", cli_invoke=cli_invoke),
            "use_when": "diagnostics or sections",
        },
        {
            "view": "defaults",
            "command": _command_with_cli_invoke(
                command="agentic-workspace defaults --section <section> --format json", cli_invoke=cli_invoke
            ),
            "use_when": "policy or defaults",
        },
        {
            "view": "preflight",
            "command": _command_with_cli_invoke(command="agentic-workspace preflight --format json", cli_invoke=cli_invoke),
            "use_when": "takeover or recovery",
        },
    ]
    payload: dict[str, Any] = {
        "kind": "workspace-context-router-family/v1",
        "rule": "Use the smallest view that answers the question.",
        "first_view": "start",
        "views": views,
    }
    if not compact:
        payload["non_goal"] = "Do not add a new command layer or require agents to run every view."
    return payload


def _parse_modules(module_arg: str, *, ordered_module_names: list[str]) -> set[str]:
    tokens = [token.strip() for token in module_arg.split(",") if token.strip()]
    if not tokens:
        raise ModuleSelectionError("--modules requires at least one module token.")
    if tokens == ["none"]:
        return set()
    if "none" in tokens:
        raise ModuleSelectionError("--modules none must be used by itself.")
    unknown = [token for token in tokens if token not in ordered_module_names]
    if unknown:
        supported = ", ".join(ordered_module_names)
        unknown_text = ", ".join(sorted(set(unknown)))
        raise ModuleSelectionError(f"Unknown module token(s): {unknown_text}. Supported modules: {supported}.")
    return set(tokens)


def _validate_selected_module_contract(*, selected_modules: list[str], descriptors: dict[str, ModuleDescriptor]) -> None:
    selected_set = set(selected_modules)
    for module_name in selected_modules:
        descriptor = descriptors[module_name]
        missing = [dependency for dependency in descriptor.dependencies if dependency not in selected_set]
        if missing:
            missing_text = ", ".join(missing)
            raise ModuleSelectionError(f"Module '{module_name}' requires: {missing_text}.")
        conflicts = [conflict for conflict in descriptor.conflicts if conflict in selected_set]
        if conflicts:
            conflict_text = ", ".join(conflicts)
            raise ModuleSelectionError(f"Module '{module_name}' conflicts with: {conflict_text}.")


def _resolve_target_root(target: str | None) -> Path:
    return Path(target).resolve() if target else Path.cwd().resolve()


def _validate_target_root(*, command_name: str, target_root: Path, local_only: bool = False) -> None:
    if not target_root.exists():
        raise WorkspaceUsageError(f"Target path does not exist: {target_root}")
    if not target_root.is_dir():
        raise WorkspaceUsageError(f"Target path is not a directory: {target_root}")
    if (
        command_name in {"init", "install", "status", "doctor", "upgrade", "uninstall"}
        and (not local_only)
        and (not _is_git_repo_root(target_root))
    ):
        raise WorkspaceUsageError("Target must be a git repository root with a .git directory or file.")


def _is_git_repo_root(target_root: Path) -> bool:
    return (target_root / ".git").exists()


def _run_init(
    *,
    target_root: Path,
    local_only_repo_root: Path | None,
    selected_modules: list[str],
    resolved_preset: str | None,
    descriptors: dict[str, ModuleDescriptor],
    dry_run: bool,
    force_adopt: bool,
    non_interactive: bool,
    print_prompt: bool,
    write_prompt: str | None,
    config: WorkspaceConfig,
    footprint_profile: str | None = None,
    mirror_payload: bool = False,
) -> dict[str, Any]:
    del footprint_profile, mirror_payload
    inspection = _inspect_repo_state(
        target_root=target_root, selected_modules=selected_modules, descriptors=descriptors, force_adopt=force_adopt, config=config
    )
    module_command = "install" if inspection.mode == "install" else "adopt"
    reports = [
        _normalize_module_report_startup_paths(
            _invoke_module_command(
                command_name=module_command,
                module_name=module_name,
                descriptor=descriptors[module_name],
                target_root=target_root,
                dry_run=dry_run,
                force=False,
            ),
            target_root=target_root,
            config=config,
        )
        for module_name in selected_modules
    ]
    reports.append(
        _workspace_init_or_upgrade_report(
            target_root=target_root,
            local_only_repo_root=local_only_repo_root,
            selected_modules=selected_modules,
            resolved_preset=resolved_preset,
            descriptors=descriptors,
            dry_run=dry_run,
            inspection_mode=inspection.mode,
            command_name="init",
            config=config,
        )
    )
    effective_config = config
    if not dry_run:
        effective_config = config_lib.load_workspace_config(target_root=target_root, valid_presets=set(descriptors))
    summary = _build_init_summary(
        target_root=target_root,
        selected_modules=selected_modules,
        resolved_preset=resolved_preset,
        descriptors=descriptors,
        inspection=inspection,
        reports=reports,
        config=effective_config,
    )
    summary["non_interactive"] = non_interactive
    prompt_text = _build_handoff_prompt(summary)
    prompt_path = _default_handoff_prompt_path(target_root=target_root) if summary["prompt_requirement"] != "none" else None
    handoff_record = _build_bootstrap_handoff_record(summary) if summary["prompt_requirement"] != "none" else None
    handoff_record_path = _default_handoff_record_path(target_root=target_root) if handoff_record is not None else None
    if write_prompt:
        prompt_path = Path(write_prompt).expanduser().resolve()
    if prompt_path is not None and (write_prompt or not dry_run):
        _write_prompt_file(prompt_path=prompt_path, prompt_text=prompt_text, dry_run=dry_run)
    if handoff_record is not None and handoff_record_path is not None and (not dry_run):
        _write_json_file(destination=handoff_record_path, payload=handoff_record, dry_run=dry_run)
    proof_route_hints = _proof_route_hints_payload(target_root=target_root)
    proof_route_hints_path = _proof_route_hints_path(target_root=target_root)
    should_write_proof_route_hints = bool(proof_route_hints["hints"]) or proof_route_hints_path.exists()
    if not dry_run and should_write_proof_route_hints:
        _write_json_file(destination=proof_route_hints_path, payload=proof_route_hints, dry_run=dry_run)
    payload: dict[str, Any] = summary | {
        "dry_run": dry_run,
        "non_interactive": non_interactive,
        "module_reports": reports,
        "config": _config_payload(config=effective_config),
        "proof_route_hints": {
            "path": PROOF_ROUTE_HINTS_PATH.as_posix(),
            "hint_count": len(proof_route_hints["hints"]),
            "written": not dry_run and should_write_proof_route_hints,
            "rule": proof_route_hints["rule"],
            "learning_policy": proof_route_hints["learning_policy"],
        },
    }
    should_include_prompt = print_prompt or prompt_path is not None or summary["prompt_requirement"] != "none"
    if should_include_prompt:
        payload["handoff_prompt"] = prompt_text
    if prompt_path is not None:
        payload["handoff_prompt_path"] = prompt_path.as_posix()
        payload["next_steps"].append(f"Review the written handoff prompt at {prompt_path.as_posix()}.")
    if handoff_record is not None and handoff_record_path is not None:
        payload["handoff_record"] = handoff_record
        payload["handoff_record_path"] = handoff_record_path.as_posix()
        payload["next_steps"].append(f"Review the structured handoff record at {handoff_record_path.as_posix()}.")
    return payload


def _inspect_repo_state(
    *, target_root: Path, selected_modules: list[str], descriptors: dict[str, ModuleDescriptor], force_adopt: bool, config: WorkspaceConfig
) -> RepoInspection:
    workflow_surfaces = _module_workflow_surfaces(selected_modules=selected_modules, descriptors=descriptors)
    generated_artifacts = _module_generated_artifacts(selected_modules=selected_modules, descriptors=descriptors)
    startup_surfaces = [Path(name) for name in config.detected_agent_instructions_files]
    detected_workflow_surfaces = [path.as_posix() for path in [*workflow_surfaces, *startup_surfaces] if (target_root / path).exists()]
    detected_state_surfaces = [path.as_posix() for path in WORKSPACE_HANDOFF_SURFACES if (target_root / path).exists()]
    detected_surfaces = _dedupe([*detected_workflow_surfaces, *detected_state_surfaces])
    preserved_existing = [path for path in detected_surfaces if path not in generated_artifacts]
    partial_state: list[str] = []
    for module_name in selected_modules:
        descriptor = descriptors[module_name]
        installed = descriptor.detector(target_root)
        hits = [marker.as_posix() for marker in descriptor.install_signals if (target_root / marker).exists()]
        if hits and (not installed):
            partial_state.extend(hits)
    placeholders = _detect_placeholder_surfaces(target_root=target_root, surfaces=detected_surfaces)
    overlap_count = len(preserved_existing)
    managed_root_present = (target_root / ".agentic-workspace").exists()
    repo_state, mode, inferred_policy = _classify_repo_state(
        force_adopt=force_adopt,
        managed_root_present=managed_root_present,
        overlap_count=overlap_count,
        workflow_overlap_count=len(detected_workflow_surfaces),
        startup_surface_count=len(config.detected_agent_instructions_files),
        handoff_surface_count=sum((1 for surface in detected_state_surfaces if surface == WORKSPACE_BOOTSTRAP_HANDOFF_PATH.as_posix())),
        partial_state=partial_state,
        placeholders=placeholders,
    )
    prompt_requirement = _prompt_requirement_for_mode(mode=mode, partial_state=partial_state, placeholders=placeholders)
    needs_review = [f"{path}: partial module state detected" for path in _dedupe(partial_state)]
    if mode == "adopt_high_ambiguity":
        needs_review.extend((f"{path}: reconcile existing workflow surface ownership" for path in preserved_existing))
    return RepoInspection(
        repo_state=repo_state,
        inferred_policy=inferred_policy,
        mode=mode,
        prompt_requirement=prompt_requirement,
        detected_surfaces=detected_surfaces,
        preserved_existing=_dedupe(preserved_existing),
        needs_review=_dedupe(needs_review),
        placeholders=_dedupe(placeholders),
    )


def _classify_repo_state(
    *,
    force_adopt: bool,
    managed_root_present: bool,
    overlap_count: int,
    workflow_overlap_count: int,
    startup_surface_count: int,
    handoff_surface_count: int,
    partial_state: list[str],
    placeholders: list[str],
) -> tuple[str, str, str]:
    if partial_state or placeholders:
        return ("partial_or_placeholder_state", "adopt_high_ambiguity", "require_explicit_handoff")
    if not overlap_count and (not force_adopt):
        return ("blank_or_unmanaged_repo", "install", "install_direct")
    if (
        startup_surface_count >= 2
        or overlap_count >= 4
        or (managed_root_present and overlap_count >= 2)
        or (handoff_surface_count >= 2)
        or (handoff_surface_count >= 1 and workflow_overlap_count >= 1)
    ):
        return ("docs_heavy_existing_repo", "adopt_high_ambiguity", "require_explicit_handoff")
    return ("light_existing_workflow", "adopt", "preserve_existing_and_adopt")


def _prompt_requirement_for_mode(*, mode: str, partial_state: list[str], placeholders: list[str]) -> str:
    prompt_requirement = {"install": "none", "adopt": "recommended", "adopt_high_ambiguity": "required"}[mode]
    if partial_state or placeholders:
        return "required"
    return prompt_requirement


def _detect_placeholder_surfaces(*, target_root: Path, surfaces: list[str]) -> list[str]:
    placeholders: list[str] = []
    for surface in surfaces:
        path = target_root / surface
        if not path.is_file():
            continue
        try:
            text = path.read_text(encoding="utf-8")
        except UnicodeDecodeError:
            continue
        if PLACEHOLDER_RE.search(text):
            placeholders.append(path.relative_to(target_root).as_posix())
    return placeholders


_WORKSPACE_ABSENCE_PATTERNS = (
    re.compile("\\bdoes\\s+not\\s+use\\s+agentic\\s+workspace\\b", re.IGNORECASE),
    re.compile("\\bno\\s+agentic\\s+workspace\\b", re.IGNORECASE),
    re.compile("\\bagentic\\s+workspace\\s+is\\s+not\\s+(?:installed|used|enabled)\\b", re.IGNORECASE),
)


def _detect_workspace_absence_contradictions(*, target_root: Path, surfaces: list[str]) -> list[str]:
    contradictions: list[str] = []
    for surface in surfaces:
        path = target_root / surface
        if not path.is_file():
            continue
        try:
            text = path.read_text(encoding="utf-8")
        except UnicodeDecodeError:
            continue
        repo_owned_text = _without_workspace_workflow_fence(text)
        if any((pattern.search(repo_owned_text) for pattern in _WORKSPACE_ABSENCE_PATTERNS)):
            contradictions.append(
                f"{Path(surface).as_posix()}: preserved repo-owned instructions claim Agentic Workspace is absent; reconcile or remove stale absence wording"
            )
    return contradictions


def _workspace_absence_startup_review(*, target_root: Path, config: WorkspaceConfig) -> dict[str, Any]:
    contradictions = _detect_workspace_absence_contradictions(
        target_root=target_root, surfaces=[config.agent_instructions_file, *config.detected_agent_instructions_files]
    )
    if not contradictions:
        return {"status": "clean", "items": []}
    items: list[dict[str, str]] = []
    for contradiction in contradictions:
        path, _, detail = contradiction.partition(": ")
        items.append(
            {
                "path": path,
                "issue": detail or contradiction,
                "action": "reconcile stale no-workspace wording in repo-owned instructions after Agentic Workspace adoption",
            }
        )
    return {
        "status": "attention",
        "items": items,
        "rule": "Resolve contradictory no-workspace wording before relying on startup instructions.",
    }


def _without_workspace_workflow_fence(text: str) -> str:
    return re.sub(f"{re.escape(WORKSPACE_WORKFLOW_MARKER_START)}.*?{re.escape(WORKSPACE_WORKFLOW_MARKER_END)}", "", text, flags=re.DOTALL)


def _build_init_summary(
    *,
    target_root: Path,
    selected_modules: list[str],
    resolved_preset: str | None,
    descriptors: dict[str, ModuleDescriptor],
    inspection: RepoInspection,
    reports: list[dict[str, Any]],
    config: WorkspaceConfig,
) -> dict[str, Any]:
    created: list[str] = []
    updated_managed: list[str] = []
    preserved_existing = list(inspection.preserved_existing)
    needs_review = list(inspection.needs_review)
    needs_review.extend(
        _detect_workspace_absence_contradictions(
            target_root=target_root, surfaces=[config.agent_instructions_file, *config.detected_agent_instructions_files]
        )
    )
    placeholders = list(inspection.placeholders)
    generated_artifacts: list[str] = []
    for report in reports:
        descriptor = descriptors.get(str(report.get("module", "")))
        module_generated_artifacts = {path.as_posix() for path in descriptor.generated_artifacts} if descriptor else set()
        for action in report.get("actions", []):
            relative_path = _display_path(action.get("path", "."), target_root)
            detail = str(action.get("detail", ""))
            kind = str(action.get("kind", ""))
            if _is_generated_artifact(relative_path=relative_path, detail=detail, generated_artifacts=module_generated_artifacts):
                _append_unique(generated_artifacts, relative_path)
            if _is_placeholder_issue(detail=detail):
                _append_unique(placeholders, relative_path)
            if kind in {"created", "copied", "would create", "would copy"}:
                _append_unique(created, relative_path)
                continue
            if kind in {"updated", "overwritten", "would update", "would overwrite"}:
                _append_unique(updated_managed, relative_path)
                continue
            if kind == "skipped":
                _append_unique(preserved_existing, relative_path)
                continue
            if kind in {"manual review", "missing", "warning"}:
                _append_unique(needs_review, _format_issue(relative_path=relative_path, detail=detail))
        for warning in report.get("warnings", []):
            relative_path = _display_path(warning.get("path", "."), target_root)
            message = str(warning.get("message", "needs review"))
            if _is_placeholder_issue(detail=message):
                _append_unique(placeholders, relative_path)
            _append_unique(needs_review, _format_issue(relative_path=relative_path, detail=message))
    prompt_requirement = inspection.prompt_requirement
    if placeholders or any((": partial module state detected" in issue for issue in needs_review)):
        prompt_requirement = "required"
    elif prompt_requirement == "none" and (preserved_existing or needs_review):
        prompt_requirement = "recommended"
    return {
        "command": "init",
        "target": target_root.as_posix(),
        "modules": selected_modules,
        "preset": resolved_preset,
        "agent_instructions_file": config.agent_instructions_file,
        "workflow_artifact_profile": config.workflow_artifact_profile,
        "intent": _bootstrap_intent_payload(selected_modules=selected_modules, resolved_preset=resolved_preset),
        "repo_state": inspection.repo_state,
        "inferred_policy": inspection.inferred_policy,
        "mode": inspection.mode,
        "prompt_requirement": prompt_requirement,
        "detected_surfaces": inspection.detected_surfaces,
        "created": _dedupe(created),
        "updated_managed": _dedupe(updated_managed),
        "preserved_existing": _dedupe(preserved_existing),
        "needs_review": _dedupe(needs_review),
        "placeholders": _dedupe(placeholders),
        "generated_artifacts": _dedupe(generated_artifacts),
        "validation": _validation_commands(target_root=target_root),
        "next_steps": _init_next_steps(
            target_root=target_root,
            repo_state=inspection.repo_state,
            inferred_policy=inspection.inferred_policy,
            mode=inspection.mode,
            prompt_requirement=prompt_requirement,
            needs_review=needs_review,
            placeholders=placeholders,
            agent_instructions_file=config.agent_instructions_file,
        ),
    }


def _run_lifecycle_command(
    *,
    command_name: str,
    target_root: Path,
    local_only_repo_root: Path | None,
    selected_modules: list[str],
    resolved_preset: str | None,
    descriptors: dict[str, ModuleDescriptor],
    dry_run: bool,
    non_interactive: bool,
    config: WorkspaceConfig,
    compact_status: bool = True,
    module_scope_explicit: bool = False,
    to_payload_target: bool = False,
    footprint_profile: str | None = None,
    mirror_payload: bool = False,
) -> dict[str, Any]:
    if command_name == "upgrade" and local_only_repo_root is None and _has_local_only_workspace_state(target_root=target_root):
        local_only_repo_root = target_root
    resolved_footprint_profile = _workspace_runtime_core._resolve_bootstrap_footprint_profile(
        target_root=target_root, requested_profile=footprint_profile, mirror_payload=mirror_payload
    )
    if command_name == "install" and _workspace_runtime_core._uses_minimal_bootstrap_footprint(resolved_footprint_profile):
        return _workspace_runtime_core._run_lifecycle_command(
            command_name=command_name,
            target_root=target_root,
            local_only_repo_root=local_only_repo_root,
            selected_modules=selected_modules,
            resolved_preset=resolved_preset,
            descriptors=descriptors,
            dry_run=dry_run,
            non_interactive=non_interactive,
            config=config,
            compact_status=compact_status,
            module_scope_explicit=module_scope_explicit,
            to_payload_target=to_payload_target,
            footprint_profile=resolved_footprint_profile,
            mirror_payload=mirror_payload,
        )
    registry = _module_registry(descriptors=descriptors, target_root=target_root)
    reports = [
        _normalize_module_report_startup_paths(
            _invoke_module_command(
                command_name=command_name,
                module_name=module_name,
                descriptor=descriptors[module_name],
                target_root=target_root,
                dry_run=dry_run,
                force=False,
            ),
            target_root=target_root,
            config=config,
        )
        for module_name in selected_modules
    ]
    if command_name in {"status", "doctor"}:
        reports.append(
            _workspace_status_report(
                target_root=target_root,
                selected_modules=selected_modules,
                descriptors=descriptors,
                command_name=command_name,
                config=config,
            )
        )
    elif command_name == "upgrade":
        reports.append(
            _workspace_init_or_upgrade_report(
                target_root=target_root,
                local_only_repo_root=local_only_repo_root,
                selected_modules=selected_modules,
                resolved_preset=resolved_preset,
                descriptors=descriptors,
                dry_run=dry_run,
                inspection_mode="upgrade",
                command_name=command_name,
                config=config,
                to_payload_target=to_payload_target,
                footprint_profile=resolved_footprint_profile,
            )
        )
    elif command_name == "install":
        reports.append(
            _workspace_init_or_upgrade_report(
                target_root=target_root,
                local_only_repo_root=local_only_repo_root,
                selected_modules=selected_modules,
                resolved_preset=resolved_preset,
                descriptors=descriptors,
                dry_run=dry_run,
                inspection_mode="install",
                command_name=command_name,
                config=config,
                footprint_profile=resolved_footprint_profile,
                module_reports=reports,
            )
        )
    elif command_name == "uninstall":
        reports.append(
            _workspace_uninstall_report(
                target_root=target_root,
                selected_modules=selected_modules,
                descriptors=descriptors,
                dry_run=dry_run,
                config=config,
                local_only_repo_root=local_only_repo_root,
            )
        )
    if command_name in {"status", "doctor"} and _workspace_runtime_core._minimal_bootstrap_footprint_detected(target_root=target_root):
        reports = [_workspace_runtime_core._filter_minimal_bootstrap_module_report(report) for report in reports]
    summary = _summarise_reports(target_root=target_root, reports=reports, descriptors=descriptors, command_name=command_name)
    warnings: list[str] = []
    placeholders: list[str] = []
    stale_generated_surfaces: list[str] = []
    warnings.extend(summary["warnings"])
    placeholders.extend(summary["placeholders"])
    stale_generated_surfaces.extend(summary["stale_generated_surfaces"])
    cli_compatibility = _cli_compatibility_payload(config=config, compact=True)
    installed_state_compatibility = _installed_state_compatibility_payload(
        config=config,
        selected_modules=selected_modules,
        installed_modules=[entry.name for entry in registry if entry.installed],
        cli_compatibility=cli_compatibility,
        summary=summary,
        compact=True,
    )
    cli_compatibility_warnings = _cli_compatibility_warning_messages(cli_compatibility)
    warnings.extend(cli_compatibility_warnings)
    selected_set = set(selected_modules)
    enabled_set = set(config.enabled_modules)
    installed_set = {entry.name for entry in registry if entry.installed}
    missing_enabled_modules = [module_name for module_name in selected_modules if module_name not in installed_set]
    residue_modules = (
        [] if module_scope_explicit else [entry.name for entry in registry if entry.installed and entry.name not in enabled_set]
    )
    for module_name in missing_enabled_modules:
        warnings.append(f"enabled module '{module_name}' is not installed")
    for module_name in residue_modules:
        warnings.append(f"installed module '{module_name}' is not enabled; treat it as residue, not repo intent")
    payload: dict[str, Any] = {
        "command": command_name,
        "target": target_root.as_posix(),
        "invoked_cli_identity": _invoked_cli_identity_payload(target_root=target_root, compact=True),
        "cli_compatibility": cli_compatibility,
        "installed_state_compatibility": installed_state_compatibility,
        "modules": selected_modules,
        "enabled_modules": selected_modules,
        "installed_modules": [entry.name for entry in registry if entry.installed],
        "missing_enabled_modules": missing_enabled_modules,
        "residue_modules": residue_modules,
        "preset": resolved_preset,
        "dry_run": dry_run,
        "non_interactive": non_interactive,
        "health": "healthy" if not warnings else "attention-needed",
        "created": summary["created"],
        "updated_managed": summary["updated_managed"],
        "preserved_existing": summary["preserved_existing"],
        "needs_review": summary["needs_review"],
        "generated_artifacts": summary["generated_artifacts"],
        "warnings": warnings,
        "placeholders": placeholders,
        "stale_generated_surfaces": stale_generated_surfaces,
        "registry": [
            {
                "name": entry.name,
                "description": entry.description,
                "kind": entry.kind,
                "default_enabled": entry.default_enabled,
                "commands": list(entry.lifecycle_commands),
                "lifecycle_hook_expectations": list(entry.lifecycle_hook_expectations),
                "autodetects_installation": entry.autodetects_installation,
                "installed": entry.installed,
                "enabled": entry.name in selected_set,
                "current": bool(entry.installed and entry.name in selected_set and entry.name not in stale_generated_surfaces),
                "state": (
                    "current"
                    if entry.installed and entry.name in selected_set and entry.name not in stale_generated_surfaces
                    else "missing"
                    if entry.name in selected_set and not entry.installed
                    else "residue"
                    if entry.installed and entry.name not in selected_set
                    else "available"
                ),
                "dry_run_commands": list(entry.dry_run_commands),
                "force_commands": list(entry.force_commands),
                "capabilities": list(entry.capabilities),
                "dependencies": list(entry.dependencies),
                "conflicts": list(entry.conflicts),
                "result_contract": {
                    "schema_version": entry.result_contract.schema_version,
                    "guaranteed_fields": list(entry.result_contract.guaranteed_fields),
                    "action_fields": list(entry.result_contract.action_fields),
                    "warning_fields": list(entry.result_contract.warning_fields),
                },
            }
            for entry in registry
        ],
        "next_steps": _lifecycle_next_steps(
            command_name=command_name, target_root=target_root, warnings=warnings, cli_invoke=config.cli_invoke
        ),
        "reports": reports,
        "config": _config_payload(config=config),
    }
    if cli_compatibility_warnings:
        payload["executable_drift_warnings"] = cli_compatibility_warnings
    if installed_state_compatibility.get("status") != "compatible":
        payload["health"] = "attention-needed"
    payload["lifecycle_plan"] = _lifecycle_plan_payload(
        payload=payload,
        command_name=command_name,
        target_root=target_root,
        selected_modules=selected_modules,
        dry_run=dry_run,
        local_only=local_only_repo_root is not None,
        cli_invoke=_lifecycle_cli_invoke(config=config),
    )
    if command_name in {"status", "doctor"}:
        payload["scoped_health"] = _scoped_lifecycle_health_payload(payload)
    if command_name in {"status", "doctor"}:
        repair_actions, manual_review_actions = _aggregate_repair_actions_from_reports(
            reports, target_root=target_root, cli_invoke=config.cli_invoke, command_name=command_name
        )
        if command_name == "doctor":
            cli_review_action = _cli_compatibility_manual_review_action(
                target_root=target_root, cli_invoke=config.cli_invoke, cli_compatibility=cli_compatibility
            )
            if cli_review_action is not None:
                manual_review_actions.insert(0, cli_review_action)
            if repair_actions or manual_review_actions:
                payload["health"] = "attention-needed"
        payload["repair_actions"] = repair_actions
        payload["manual_review_actions"] = manual_review_actions
        payload["repair_plan"] = _repair_plan_payload(
            command_name=command_name, repair_actions=repair_actions, manual_review_actions=manual_review_actions
        )
        payload["payload_closure_plan"] = _payload_doctor_closure_plan(
            command_name=command_name,
            target_root=target_root,
            selected_modules=selected_modules,
            installed_state_compatibility=installed_state_compatibility,
            repair_actions=repair_actions,
            manual_review_actions=manual_review_actions,
            reports=reports,
            cli_invoke=config.cli_invoke,
        )
        closure_primary = _as_dict(payload["payload_closure_plan"].get("primary_next_action"))
        actionability = derive_actionability(
            command_name=command_name,
            health=str(payload.get("health") or "unknown"),
            warnings=_list_payload(payload.get("warnings")),
            repair_actions=repair_actions,
            manual_review_actions=manual_review_actions,
            proposed_next_action=closure_primary,
            claim_limits=_list_payload(payload.get("needs_review")),
        )
        payload["actionability"] = actionability
        payload["action_required"] = actionability["action_required"]
        payload["next_action"] = actionability["next_action"]
        if compact_status and command_name in {"status", "doctor"}:
            payload = _compact_status_payload(payload, cli_invoke=config.cli_invoke)
    return payload


def _lifecycle_diagnostic_detail_command(*, command_name: str, cli_invoke: str) -> str:
    return _command_with_cli_invoke(
        command=f"agentic-workspace {command_name} --target ./repo --verbose --format json", cli_invoke=cli_invoke
    )


def _lifecycle_diagnostic_select_command(*, command_name: str, selector: str, cli_invoke: str) -> str:
    return _command_with_cli_invoke(
        command=f"agentic-workspace {command_name} --target ./repo --select {selector} --format json", cli_invoke=cli_invoke
    )


def _compact_installed_state_summary(installed_state: Any, *, command_name: str, cli_invoke: str) -> dict[str, Any] | None:
    if not isinstance(installed_state, dict):
        return None
    action_state = installed_state.get("action_state", {})
    if not isinstance(action_state, dict):
        action_state = {}
    payload_state = installed_state.get("payload", {})
    if not isinstance(payload_state, dict):
        payload_state = {}
    target_state = payload_state.get("target", {})
    if not isinstance(target_state, dict):
        target_state = {}
    repair_route = installed_state.get("repair_route", {})
    if not isinstance(repair_route, dict):
        repair_route = {}
    action_effect = installed_state.get("action_effect", {})
    if not isinstance(action_effect, dict):
        action_effect = {}
    summary: dict[str, Any] = {
        "kind": "agentic-workspace/installed-state-summary/v1",
        "status": installed_state.get("status", "unknown"),
        "action_state": action_state.get("state", action_state.get("status", "unknown")),
        "payload_status": payload_state.get("status", "unknown"),
        "provenance_drift": payload_state.get("provenance_drift", "unknown"),
        "target_status": target_state.get("status", "not-configured"),
        "repair_route_status": repair_route.get("status", "not-required"),
        "selector": "installed_state_compatibility",
        "select_command": _lifecycle_diagnostic_select_command(
            command_name=command_name, selector="installed_state_compatibility", cli_invoke=cli_invoke
        ),
        "detail_command": _lifecycle_diagnostic_detail_command(command_name=command_name, cli_invoke=cli_invoke),
    }
    next_action = installed_state.get("next_action")
    if isinstance(next_action, dict):
        summary["next_action"] = {
            key: next_action.get(key) for key in ("action", "summary", "command", "run") if next_action.get(key) not in (None, "", [], {})
        }
    if str(summary["status"]) != "compatible" or str(summary["action_state"]) != "no_repair_needed":
        summary["action_required"] = str(summary["repair_route_status"]) not in {"not-required", "none", ""}
        summary["action_effect"] = {
            key: action_effect.get(key)
            for key in ("force", "allowed_now", "blocked_until_reconciled", "claim_boundary", "resolution_command")
            if action_effect.get(key) not in (None, "", [], {})
        }
    else:
        summary["action_required"] = False
    return summary


def _compact_payload_closure_summary(payload_closure_plan: Any, *, command_name: str, cli_invoke: str) -> dict[str, Any] | None:
    if not isinstance(payload_closure_plan, dict):
        return None
    action_state = payload_closure_plan.get("action_state", {})
    if not isinstance(action_state, dict):
        action_state = {}
    surface_classes = payload_closure_plan.get("surface_classes", [])
    compact_surfaces: list[dict[str, Any]] = []
    if isinstance(surface_classes, list):
        for surface in surface_classes:
            if not isinstance(surface, dict):
                continue
            compact_surfaces.append(
                {key: surface.get(key) for key in ("id", "status", "action_required") if surface.get(key) not in (None, "", [], {})}
            )
    primary_next_action = payload_closure_plan.get("primary_next_action", {})
    if not isinstance(primary_next_action, dict):
        primary_next_action = {}
    summary: dict[str, Any] = {
        "kind": "agentic-workspace/payload-closure-summary/v1",
        "status": payload_closure_plan.get("status", "unknown"),
        "action_state": action_state.get("state", action_state.get("status", "unknown")),
        "payload_action_required": bool(payload_closure_plan.get("payload_action_required")),
        "surface_statuses": compact_surfaces,
        "selector": "payload_closure_plan",
        "select_command": _lifecycle_diagnostic_select_command(
            command_name=command_name, selector="payload_closure_plan", cli_invoke=cli_invoke
        ),
        "detail_command": _lifecycle_diagnostic_detail_command(command_name=command_name, cli_invoke=cli_invoke),
    }
    if primary_next_action:
        summary["primary_next_action"] = {
            key: primary_next_action.get(key)
            for key in ("action", "summary", "command", "run")
            if primary_next_action.get(key) not in (None, "", [], {})
        }
    return summary


def _compact_status_payload(payload: dict[str, Any], *, cli_invoke: str) -> dict[str, Any]:
    reports = payload.get("reports", [])
    compact_reports = []
    if isinstance(reports, list):
        for report in reports:
            if not isinstance(report, dict):
                continue
            actions = report.get("actions", [])
            warnings = report.get("warnings", [])
            compact_actions = []
            if isinstance(actions, list):
                for action in actions[:3]:
                    if isinstance(action, dict):
                        compact_actions.append(
                            {
                                key: action.get(key)
                                for key in ("kind", "path", "detail", "category", "remediation_kind")
                                if action.get(key) not in (None, "")
                            }
                        )
            compact_reports.append(
                {
                    "module": report.get("module", ""),
                    "message": report.get("message", ""),
                    "action_count": len(actions) if isinstance(actions, list) else 0,
                    "actions": compact_actions,
                    "warning_count": len(warnings) if isinstance(warnings, list) else 0,
                    "warnings": warnings[:3] if isinstance(warnings, list) else [],
                    "detail_section": "reports",
                }
            )
    config_payload = payload.get("config", {})
    compact_config = {}
    if isinstance(config_payload, dict):
        workspace = config_payload.get("workspace", {})
        compact_workspace = {}
        if isinstance(workspace, dict):
            compact_workspace = {
                key: workspace.get(key)
                for key in (
                    "enabled_modules",
                    "agent_instructions_file",
                    "workflow_artifact_profile",
                    "improvement_latitude",
                    "optimization_bias",
                    "cli_invoke",
                )
            }
        compact_config = {
            "config_path": config_payload.get("config_path"),
            "exists": config_payload.get("exists"),
            "warnings": config_payload.get("warnings", []),
            "workspace": compact_workspace,
            "detail_command": _command_with_cli_invoke(
                command="agentic-workspace config --target ./repo --format json", cli_invoke=cli_invoke
            ),
        }
    registry = payload.get("registry", [])
    compact_registry = []
    if isinstance(registry, list):
        compact_registry = [
            {"name": entry.get("name", ""), "installed": entry.get("installed", False)} for entry in registry if isinstance(entry, dict)
        ]
    payload = dict(payload)
    command_name = str(payload.get("command", "status") or "status")
    installed_state_compatibility = payload.get("installed_state_compatibility")
    payload_closure_plan = payload.get("payload_closure_plan")
    payload["reports"] = compact_reports
    payload["config"] = compact_config
    payload["registry"] = compact_registry
    installed_state_summary = _compact_installed_state_summary(
        installed_state_compatibility, command_name=command_name, cli_invoke=cli_invoke
    )
    if installed_state_summary is not None:
        payload["installed_state_summary"] = installed_state_summary
        payload.pop("installed_state_compatibility", None)
    payload_closure_summary = _compact_payload_closure_summary(payload_closure_plan, command_name=command_name, cli_invoke=cli_invoke)
    if payload_closure_summary is not None:
        payload["payload_closure_summary"] = payload_closure_summary
        payload.pop("payload_closure_plan", None)
    detail_selectors = [
        key
        for key, value in (
            ("installed_state_compatibility", installed_state_compatibility),
            ("payload_closure_plan", payload_closure_plan),
        )
        if isinstance(value, dict)
    ]
    if detail_selectors:
        payload["diagnostic_detail"] = {
            "kind": "agentic-workspace/lifecycle-diagnostic-detail-route/v1",
            "omitted_from_default": detail_selectors,
            "selectors": detail_selectors,
            "select_command": _lifecycle_diagnostic_select_command(
                command_name=command_name, selector=",".join(detail_selectors), cli_invoke=cli_invoke
            ),
            "verbose_command": _lifecycle_diagnostic_detail_command(command_name=command_name, cli_invoke=cli_invoke),
        }
    for key in ("warnings", "needs_review", "repair_actions", "manual_review_actions"):
        values = payload.get(key, [])
        if isinstance(values, list):
            payload[f"{key}_count"] = len(values)
            payload[key] = values[:5]
    payload["lifecycle_plan"] = {
        "status": payload.get("lifecycle_plan", {}).get("status", "available")
        if isinstance(payload.get("lifecycle_plan"), dict)
        else "available",
        "detail_command": _command_with_cli_invoke(
            command=f"agentic-workspace {payload.get('command', 'status')} --target ./repo --format json", cli_invoke=cli_invoke
        ),
    }
    payload["deeper_detail"] = {
        "config_command": _command_with_cli_invoke(command="agentic-workspace config --target ./repo --format json", cli_invoke=cli_invoke),
        "report_command": _command_with_cli_invoke(
            command="agentic-workspace report --target ./repo --verbose --format json", cli_invoke=cli_invoke
        ),
    }
    payload["cost_provenance"] = {
        "classification": "compact-after-lifecycle",
        "module_count": len(compact_reports),
        "source": "workspace lifecycle invokes selected module lifecycle reports before compact projection",
        "detail_command": _command_with_cli_invoke(
            command="agentic-workspace report --target ./repo --section operational_compression --format json", cli_invoke=cli_invoke
        ),
    }
    payload_closure_plan = payload_closure_plan if isinstance(payload_closure_plan, dict) else {}
    closure_attention = (
        isinstance(payload_closure_plan, dict)
        and str(payload_closure_plan.get("status", "")) == "attention"
        and bool(payload_closure_plan.get("payload_action_required"))
        and command_name == "doctor"
    )
    if str(payload.get("health", "")) == "healthy" and not closure_attention:
        payload["next_action"] = {"action": "no-immediate-action", "summary": "No immediate lifecycle action is required.", "commands": []}
    else:
        detail_command = _command_with_cli_invoke(
            command=f"agentic-workspace {command_name} --target ./repo --verbose --format json", cli_invoke=cli_invoke
        )
        if closure_attention:
            primary = payload_closure_plan.get("primary_next_action", {}) if isinstance(payload_closure_plan, dict) else {}
            primary_command = str(primary.get("command", "")) if isinstance(primary, dict) else ""
            commands = [primary_command] if primary_command else [detail_command]
            action = (
                str(primary.get("action", "follow-payload-closure-plan")) if isinstance(primary, dict) else "follow-payload-closure-plan"
            )
            summary = "Follow the payload_closure_summary primary action before making payload freshness or doctor-closure claims."
        elif command_name == "status":
            inspect_command = _command_with_cli_invoke(
                command="agentic-workspace doctor --target ./repo --format json", cli_invoke=cli_invoke
            )
            action = "inspect-health-with-doctor"
            summary = "Inspect attention-needed lifecycle state with the compact doctor route."
            commands = [inspect_command]
        else:
            action = "inspect-repair-or-full-detail"
            summary = "Review compact repair and manual-review actions; use full detail only when the compact lists are insufficient."
            commands = [detail_command]
        payload["next_action"] = {
            "action": action,
            "summary": summary,
            "command": commands[0],
            "run": commands[0],
            "commands": commands,
            "detail_command": detail_command,
        }
    actionability = _as_dict(payload.get("actionability")) or derive_actionability(
        command_name=command_name,
        health=str(payload.get("health") or "unknown"),
        warnings=_list_payload(payload.get("warnings")),
        repair_actions=_list_payload(payload.get("repair_actions")),
        manual_review_actions=_list_payload(payload.get("manual_review_actions")),
        proposed_next_action=_as_dict(payload.get("next_action")),
        claim_limits=_list_payload(payload.get("needs_review")),
    )
    payload["actionability"] = actionability
    payload["action_required"] = actionability["action_required"]
    payload["next_action"] = actionability["next_action"]
    return payload


def _scoped_lifecycle_health_payload(payload: dict[str, Any]) -> dict[str, Any]:
    selected_modules = set(_list_payload(payload.get("selected_modules") or payload.get("modules") or []))
    reports = payload.get("reports", [])
    selected_warning_count = 0
    selected_action_count = 0
    if isinstance(reports, list):
        for report in reports:
            if not isinstance(report, dict):
                continue
            module_name = str(report.get("module", ""))
            if selected_modules and module_name not in selected_modules:
                continue
            warnings = report.get("warnings", [])
            actions = report.get("actions", [])
            selected_warning_count += len(warnings) if isinstance(warnings, list) else int(report.get("warning_count", 0) or 0)
            if isinstance(actions, list):
                selected_action_count += sum(
                    1
                    for action in actions
                    if isinstance(action, dict) and str(action.get("kind", "")) not in {"current", "mode", "source", "source age"}
                )
            else:
                selected_action_count += int(report.get("action_count", 0) or 0)
    global_warning_count = len(payload.get("warnings", [])) if isinstance(payload.get("warnings"), list) else 0
    global_review_count = len(payload.get("needs_review", [])) if isinstance(payload.get("needs_review"), list) else 0
    selected_module_health = "attention-needed" if selected_warning_count or selected_action_count else "healthy"
    global_health = str(payload.get("health", "unknown") or "unknown")
    return {
        "kind": "agentic-workspace/scoped-lifecycle-health/v1",
        "selected_modules": payload.get("selected_modules", payload.get("modules", [])),
        "selected_module_health": selected_module_health,
        "selected_warning_count": selected_warning_count,
        "selected_action_count": selected_action_count,
        "global_workspace_health": global_health,
        "global_warning_count": global_warning_count,
        "global_review_count": global_review_count,
        "global_warnings_block_scoped_check": False,
        "rule": "Top-level health includes global workspace warnings; selected_module_health reports only the scoped module lifecycle reports.",
    }


def _cli_compatibility_warning_messages(cli_compatibility: dict[str, Any]) -> list[str]:
    status = str(cli_compatibility.get("status", ""))
    if status not in {"advisory-drift", "blocking-drift"}:
        return []
    failed = ", ".join((str(item) for item in cli_compatibility.get("failed_checks", []))) or "unknown"
    remediation = cli_compatibility.get("remediation", {})
    summary = remediation.get("summary") if isinstance(remediation, dict) else ""
    if not summary:
        summary = "Invoked CLI does not satisfy the repo-owned compatibility expectation."
    return [f"executable compatibility {status}: failed checks: {failed}; {summary}"]


def _cli_compatibility_manual_review_action(
    *, target_root: Path, cli_invoke: str, cli_compatibility: dict[str, Any]
) -> dict[str, Any] | None:
    status = str(cli_compatibility.get("status", ""))
    if status not in {"advisory-drift", "blocking-drift"}:
        return None
    remediation = cli_compatibility.get("remediation", {})
    remediation_summary = (
        str(remediation.get("summary", "")) if isinstance(remediation, dict) else "Invoked CLI compatibility drift detected."
    )
    remediation_command = str(remediation.get("command", cli_invoke)) if isinstance(remediation, dict) else cli_invoke
    severity = "error" if status == "blocking-drift" else "warning"
    action = _workspace_manual_review_action(
        id="resolve-cli-executable-drift",
        invariant="workspace.cli_executable_compatible",
        fault_class="package_affordance_fault",
        owner="repo",
        target_root=target_root,
        cli_invoke=cli_invoke,
        affected_surfaces=[".agentic-workspace/config.toml", "invoked_cli_identity"],
        current_fault_summary=remediation_summary,
        risk="lifecycle output may validate the payload known to the invoked executable while still using the wrong CLI for this repo",
        do_not=[
            "Do not treat module payload freshness as proof that the invoked executable matches repo expectations.",
            "Do not ignore blocking executable drift before trusting lifecycle output.",
        ],
    )
    action["severity"] = severity
    action["action"] = str(remediation.get("action", "manual-review")) if isinstance(remediation, dict) else "manual-review"
    action["command"] = remediation_command
    action["run"] = remediation_command
    action["cli_compatibility"] = {
        "status": status,
        "failed_checks": list(cli_compatibility.get("failed_checks", [])),
        "drift_findings": list(cli_compatibility.get("drift_findings", [])),
        "payload_drift_separate": True,
    }
    return action


def _workspace_root_startup_pointer_repair_action(*, target_root: Path, cli_invoke: str, affected_surfaces: list[str]) -> dict[str, Any]:
    target = target_root.as_posix()
    dry_run = _command_with_cli_invoke(
        command=f"agentic-workspace upgrade --target {target} --repair-root-startup-pointer --dry-run --format json",
        cli_invoke=cli_invoke,
    )
    command = _command_with_cli_invoke(
        command=f"agentic-workspace upgrade --target {target} --repair-root-startup-pointer --format json",
        cli_invoke=cli_invoke,
    )
    proof_after = [_command_with_cli_invoke(command=f"agentic-workspace doctor --target {target} --format json", cli_invoke=cli_invoke)]
    return {
        "id": "restore-root-startup-pointer-fence",
        "action": "repair-root-startup-pointer",
        "invariant": "workspace.startup_pointer_present",
        "fault_class": "agent_operation_fault",
        "severity": "warning",
        "owner": "repo",
        "safe_to_apply": True,
        "risk": "low; patches only the managed workflow fence in the configured root startup file",
        "command": command,
        "run": command,
        "dry_run": dry_run,
        "proof_after": proof_after,
        "affected_surfaces": affected_surfaces,
        "current_fault_summary": "Root startup entrypoint no longer contains the managed Agentic Workspace workflow fence.",
        "safe_patch_target": "configured root startup file managed workflow pointer fence only",
        "do_not": [
            "Do not replace repo-owned startup instructions outside the managed workflow fence.",
            "Do not widen the managed fence into a workflow handbook.",
        ],
        "repair_affordance": _workspace_pointer_repair_affordance(cli_invoke=cli_invoke),
        "recurrence": "first_seen",
    }


def _aggregate_repair_actions_from_reports(
    reports: list[dict[str, Any]], *, target_root: Path, cli_invoke: str, command_name: str
) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    repair_actions: list[dict[str, Any]] = []
    manual_review_actions: list[dict[str, Any]] = []
    for report in reports:
        for action in report.get("repair_actions", []):
            if isinstance(action, dict):
                repair_actions.append(action)
        for action in report.get("manual_review_actions", []):
            if isinstance(action, dict):
                manual_review_actions.append(action)
        if command_name == "doctor":
            module_repair = _module_safe_lifecycle_repair_action(report=report, target_root=target_root, cli_invoke=cli_invoke)
            if module_repair is not None:
                repair_actions.append(module_repair)
    return (repair_actions, manual_review_actions)


def _module_safe_lifecycle_repair_action(*, report: dict[str, Any], target_root: Path, cli_invoke: str) -> dict[str, Any] | None:
    module = str(report.get("module", "")).strip()
    if not module or module == "workspace":
        return None
    safe_planned_kinds = {"would create", "would copy", "would update", "would overwrite", "would replace"}
    affected_surfaces: list[str] = []
    for action in report.get("actions", []):
        if not isinstance(action, dict):
            continue
        kind = str(action.get("kind", ""))
        if kind not in safe_planned_kinds:
            continue
        if str(action.get("safety", "")) != "safe" and str(action.get("category", "")) != "safe-update":
            continue
        _append_unique(affected_surfaces, _display_path(action.get("path", "."), target_root))
    if not affected_surfaces:
        return None
    target = target_root.as_posix()
    dry_run = _command_with_cli_invoke(
        command=f"agentic-workspace upgrade --target {target} --modules {module} --dry-run --format json", cli_invoke=cli_invoke
    )
    command = _command_with_cli_invoke(
        command=f"agentic-workspace upgrade --target {target} --modules {module} --format json", cli_invoke=cli_invoke
    )
    proof_after = [
        _command_with_cli_invoke(
            command=f"agentic-workspace doctor --target {target} --modules {module} --format json", cli_invoke=cli_invoke
        )
    ]
    return {
        "id": f"apply-safe-{module}-lifecycle-repair",
        "action": "run-module-upgrade",
        "invariant": f"{module}.managed_surfaces_current",
        "fault_class": "agent_operation_fault",
        "severity": "warning",
        "owner": module,
        "safe_to_apply": True,
        "risk": "low; syncs target-repo module-managed payload surfaces reported by doctor; it does not upgrade the Python package being executed",
        "command": command,
        "run": command,
        "dry_run": dry_run,
        "proof_after": proof_after,
        "affected_surfaces": affected_surfaces,
        "current_fault_summary": (
            f"{module} doctor found target-repo managed payload surfaces that are stale relative to the current module payload. "
            "This is a payload sync, not a Python package upgrade."
        ),
        "do_not": [
            "Do not hand-author module-managed payload files when module upgrade can recreate them.",
            "Do not treat safe module payload repairs as proof that unrelated repo-owned content may be overwritten.",
            "Do not interpret this as dependency or executable-source drift when invoked_cli_identity.source_class is source-checkout.",
        ],
        "recurrence": "first_seen",
        "improvement_signal_candidate": {
            "when": "repeated",
            "kind": "repair_recurrence",
            "route": "agentic-workspace defaults --section improvement_intake --format json",
            "preferred_remedy": "make safe module repair availability visible from the root lifecycle surface",
        },
    }


def _local_scratch_nested_repo_paths(*, target_root: Path) -> list[str]:
    scratch_root = target_root / WORKSPACE_LOCAL_SCRATCH_ROOT_PATH
    if not scratch_root.is_dir():
        return []
    return []


def _payload_doctor_closure_plan(
    *,
    command_name: str,
    target_root: Path,
    selected_modules: list[str],
    installed_state_compatibility: dict[str, Any],
    repair_actions: list[dict[str, Any]],
    manual_review_actions: list[dict[str, Any]],
    reports: list[dict[str, Any]],
    cli_invoke: str,
) -> dict[str, Any]:
    target = target_root.as_posix()
    source_checkout = _is_agentic_workspace_source_checkout(target_root)
    payload_state = installed_state_compatibility.get("payload", {})
    payload_state = payload_state if isinstance(payload_state, dict) else {}
    action_state = installed_state_compatibility.get("action_state", {})
    action_state = action_state if isinstance(action_state, dict) else {}
    action_state_name = str(action_state.get("state") or "no_repair_needed")
    payload_status = str(payload_state.get("status", "unknown"))
    provenance = payload_state.get("provenance", {})
    provenance_status = str(provenance.get("status", "unknown")) if isinstance(provenance, dict) else "unknown"
    provenance_drift = str(payload_state.get("provenance_drift", "unknown"))
    installed_payload_needs_sync = action_state_name == "safe_payload_sync_available" or payload_status == "sync-required"
    scratch_repos = _local_scratch_nested_repo_paths(target_root=target_root)
    installed_lane_proof_commands = [
        _command_with_cli_invoke(command=f"agentic-workspace doctor --target {target} --format json", cli_invoke=cli_invoke),
        _command_with_cli_invoke(command=f"agentic-workspace status --target {target} --format json", cli_invoke=cli_invoke),
        "git diff --check",
    ]
    source_checkout_proof_commands = [
        "make test-workspace",
        "make maintainer-surfaces",
        "uv run python scripts/generate/generate_command_packages.py --check",
        "make absolute-paths",
    ]
    proof_commands = [*installed_lane_proof_commands]
    if source_checkout:
        proof_commands[2:2] = source_checkout_proof_commands
    installed_dry_run = _command_with_cli_invoke(
        command=f"agentic-workspace upgrade --target {target} --dry-run --format json", cli_invoke=cli_invoke
    )
    installed_apply = _command_with_cli_invoke(command=f"agentic-workspace upgrade --target {target} --format json", cli_invoke=cli_invoke)
    scratch_roots = [WORKSPACE_LOCAL_SCRATCH_ROOT_PATH.as_posix()] if (target_root / WORKSPACE_LOCAL_SCRATCH_ROOT_PATH).exists() else []
    scratch_scope = " ".join(scratch_roots) if scratch_roots else WORKSPACE_LOCAL_SCRATCH_ROOT_PATH.as_posix()
    scratch_dry_run_command = f"git clean -ndx -- {scratch_scope}"
    scratch_cleanup_command = f"git clean -fdx -- {scratch_scope}"
    source_mirror_paths = []
    if source_checkout:
        for relative in WORKSPACE_PAYLOAD_FILES:
            source_mirror_paths.append(_display_path(_workspace_payload_source(relative).as_posix(), target_root))
        for module_path in MODULE_UPGRADE_SOURCE_PATHS.values():
            _append_unique(source_mirror_paths, module_path.as_posix())
    surface_classes = [
        {
            "id": "installed_payload",
            "status": action_state_name if action_state_name != "no_repair_needed" else "compatible",
            "action_state": action_state,
            "dry_run_command": installed_dry_run,
            "apply_command": installed_apply,
            "rule": "Sync installed target-repo payload before claiming doctor compatibility.",
        },
        {
            "id": "source_payload_mirrors",
            "status": "check-required" if source_checkout else "not-source-checkout",
            "paths": sorted(source_mirror_paths),
            "check_command": "make maintainer-surfaces" if source_checkout else None,
            "not_applicable_reason": None
            if source_checkout
            else "Source payload mirror checks require an agentic-workspace source checkout.",
            "rule": "When the invoked CLI is a source checkout, verify source payload mirrors with the maintainer surface lane.",
        },
        {
            "id": "generated_payload_projections",
            "status": "check-required" if source_checkout else "not-source-checkout",
            "refresh_command": "uv run python scripts/generate/generate_command_packages.py" if source_checkout else None,
            "check_command": "uv run python scripts/generate/generate_command_packages.py --check" if source_checkout else None,
            "not_applicable_reason": None
            if source_checkout
            else "Generated command-package projection checks are source-checkout maintainer proof.",
            "rule": "Refresh generated command-package projections before broad tests discover stale generated targets.",
        },
        {
            "id": "local_scratch_blockers",
            "status": "ignored-local-only" if scratch_roots else "clear",
            "nested_repo_paths": scratch_repos,
            "dry_run_command": scratch_dry_run_command,
            "cleanup_command_after_review": scratch_cleanup_command,
            "rule": "Ignore AW local scratch contents for payload closure; cleanup remains explicitly scoped to local scratch roots.",
        },
        {
            "id": "provenance",
            "status": "normalize-required"
            if provenance_drift not in {"none", "unknown"} or provenance_status in {"missing", "invalid"}
            else "check-required",
            "path": WORKSPACE_PAYLOAD_PROVENANCE_PATH.as_posix(),
            "normalize_command": installed_apply,
            "hygiene_check": "make absolute-paths" if source_checkout else None,
            "hygiene_status": "source-checkout-required" if source_checkout else "not-applicable",
            "rule": "Payload provenance must stay repo-portable and free of machine-local absolute paths.",
        },
        {
            "id": "proof",
            "status": "required",
            "commands": proof_commands,
            "rule": "Run this proof lane after repair steps so later checks do not reveal omitted payload-surface work.",
        },
    ]
    repair_sequence: list[dict[str, Any]] = [
        {
            "id": "inspect_installed_payload",
            "surface_class": "installed_payload",
            "command": installed_dry_run,
            "when": "installed payload status is not compatible or doctor reports managed payload drift",
        },
        {
            "id": "apply_installed_payload",
            "surface_class": "installed_payload",
            "command": installed_apply,
            "when": "dry-run shows only managed payload sync or provenance normalization",
        },
    ]
    if source_checkout:
        repair_sequence.extend(
            [
                {
                    "id": "check_source_payload_mirrors",
                    "surface_class": "source_payload_mirrors",
                    "command": "make maintainer-surfaces",
                    "when": "running from an agentic-workspace source checkout or touching payload mirrors",
                },
                {
                    "id": "refresh_generated_projections",
                    "surface_class": "generated_payload_projections",
                    "command": "uv run python scripts/generate/generate_command_packages.py",
                    "when": "source payload mirrors or generated command-package inputs changed",
                },
            ]
        )
    repair_sequence.extend(
        [
            {
                "id": "review_local_scratch_cleanup",
                "surface_class": "local_scratch_blockers",
                "command": scratch_dry_run_command,
                "when": "manual scratch cleanup is explicitly requested",
            },
            {
                "id": "normalize_provenance",
                "surface_class": "provenance",
                "command": installed_apply,
                "when": "payload provenance is missing, invalid, stale, or contains local absolute paths",
            },
            {"id": "run_final_proof", "surface_class": "proof", "commands": proof_commands, "when": "all repair steps are complete"},
        ]
    )
    plan_status = "attention" if installed_payload_needs_sync or repair_actions or manual_review_actions else "available"
    payload_action_required = installed_payload_needs_sync or bool(repair_actions)
    if installed_payload_needs_sync:
        primary_next_action = {
            "action": "inspect-installed-payload-sync",
            "surface_class": "installed_payload",
            "command": installed_dry_run,
            "run": installed_dry_run,
            "next": installed_apply,
        }
    elif scratch_repos:
        primary_next_action = {
            "action": "review-local-scratch-cleanup",
            "surface_class": "local_scratch_blockers",
            "command": scratch_dry_run_command,
            "run": scratch_dry_run_command,
            "next": scratch_cleanup_command,
        }
    elif repair_actions:
        repair_command = str(repair_actions[0].get("dry_run") or repair_actions[0].get("command") or "")
        primary_next_action = {
            "action": str(repair_actions[0].get("action", "inspect-safe-repair")),
            "surface_class": "installed_payload",
            "command": repair_command,
            "run": repair_command,
            "next": repair_actions[0].get("command"),
        }
    else:
        primary_next_action = {
            "action": "run-payload-closure-proof",
            "surface_class": "proof",
            "command": proof_commands[0],
            "run": proof_commands[0],
            "next": proof_commands,
        }
    return {
        "kind": "agentic-workspace/payload-doctor-closure-plan/v1",
        "command": command_name,
        "status": plan_status,
        "action_state": action_state,
        "target_root": target,
        "selected_modules": list(selected_modules),
        "source_checkout": source_checkout,
        "surface_classes": surface_classes,
        "repair_sequence": repair_sequence,
        "primary_next_action": primary_next_action,
        "payload_action_required": payload_action_required,
        "repair_action_count": len(repair_actions),
        "manual_review_action_count": len(manual_review_actions),
        "report_count": len(reports),
        "rule": (
            "Payload closure is one lane: installed payload sync, source mirror checks, generated projections, "
            "scratch cleanup, provenance normalization, and proof stay visible together."
        ),
    }


def _lifecycle_cli_invoke(*, config: WorkspaceConfig, invocation_root: Path | None = None) -> str:
    if config.cli_invoke_source != "product-default":
        return config.cli_invoke
    if config.target_root is None:
        return config.cli_invoke
    invocation_root = invocation_root or Path.cwd()
    try:
        if invocation_root.resolve() == config.target_root.resolve():
            return config.cli_invoke
    except OSError:
        return config.cli_invoke
    try:
        invocation_config = config_lib.load_workspace_config(target_root=invocation_root)
    except WorkspaceUsageError:
        return config.cli_invoke
    if invocation_config.cli_invoke_source != "product-default":
        return invocation_config.cli_invoke
    return config.cli_invoke


def _lifecycle_review_remediations(
    *, review_items: list[str], warnings: list[str], target_root: Path, selected_modules: list[str], cli_invoke: str
) -> list[dict[str, Any]]:
    messages = [*review_items, *warnings]
    remediations: list[dict[str, Any]] = []
    target = target_root.as_posix()
    for module_name, relative_path in MODULE_UPGRADE_SOURCE_PATHS.items():
        if module_name not in selected_modules:
            continue
        relative = relative_path.as_posix()
        if not any(relative in message for message in messages):
            continue
        dry_run = _command_with_cli_invoke(
            command=f"agentic-workspace upgrade --target {target} --modules {module_name} --dry-run --format json",
            cli_invoke=cli_invoke,
        )
        refresh = _command_with_cli_invoke(
            command=f"agentic-workspace upgrade --target {target} --modules {module_name} --format json",
            cli_invoke=cli_invoke,
        )
        remediations.append(
            {
                "id": f"refresh-{module_name}-upgrade-source",
                "module": module_name,
                "surface": relative,
                "reason": "recorded module upgrade source metadata is stale or requires review",
                "review_first": dry_run,
                "refresh_command": refresh,
                "proof_after": _command_with_cli_invoke(
                    command=f"agentic-workspace doctor --target {target} --modules {module_name} --format json",
                    cli_invoke=cli_invoke,
                ),
                "rule": (
                    "Review the recorded source before refreshing it; use the module-specific refresh route "
                    "instead of rerunning the same broad blocked lifecycle apply."
                ),
            }
        )
    return remediations


def _lifecycle_plan_payload(
    *,
    payload: dict[str, Any],
    command_name: str,
    target_root: Path,
    selected_modules: list[str],
    dry_run: bool,
    local_only: bool,
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> dict[str, Any]:
    planned_removals: list[str] = []
    for report in payload.get("module_reports", []) + payload.get("reports", []):
        if not isinstance(report, dict):
            continue
        for action in report.get("actions", []):
            if not isinstance(action, dict):
                continue
            if str(action.get("kind", "")) in {"would remove", "removed"}:
                _append_unique(planned_removals, _display_path(action.get("path", "."), target_root))
    warnings = list(payload.get("warnings", []))
    review_items = list(payload.get("needs_review", [])) + list(payload.get("placeholders", []))
    review_required = bool(review_items or warnings or payload.get("prompt_requirement") in {"required", "recommended"})
    review_remediations = _lifecycle_review_remediations(
        review_items=review_items,
        warnings=warnings,
        target_root=target_root,
        selected_modules=selected_modules,
        cli_invoke=cli_invoke,
    )
    config_payload = payload.get("config", {})
    update_payload = config_payload.get("update", {}) if isinstance(config_payload, dict) else {}
    module_policy_payloads = update_payload.get("modules", []) if isinstance(update_payload, dict) else []
    module_update_freshness = [
        {"module": str(module.get("module", "")), "freshness": module.get("freshness", {})}
        for module in module_policy_payloads
        if isinstance(module, dict) and str(module.get("module", "")) in set(selected_modules)
    ]
    action_owner_groups: dict[str, list[str]] = {
        "memory_managed_payload": [],
        "shared_workspace_payload": [],
        "local_source_checkout_state": [],
        "package_command_or_install_state": [],
    }
    for path in list(payload.get("created", [])) + list(payload.get("updated_managed", [])) + planned_removals:
        path_text = str(path)
        if path_text.startswith(".agentic-workspace/memory/"):
            action_owner_groups["memory_managed_payload"].append(path_text)
        elif path_text.startswith(".agentic-workspace/") or path_text == DEFAULT_AGENT_INSTRUCTIONS_FILE:
            action_owner_groups["shared_workspace_payload"].append(path_text)
        elif path_text.startswith(".git/") or "source-checkout" in path_text:
            action_owner_groups["local_source_checkout_state"].append(path_text)
        else:
            action_owner_groups["package_command_or_install_state"].append(path_text)
    next_command = _lifecycle_apply_command(
        command_name=command_name, target_root=target_root, selected_modules=selected_modules, local_only=local_only, cli_invoke=cli_invoke
    )
    review_command = _lifecycle_apply_command(
        command_name=command_name,
        target_root=target_root,
        selected_modules=selected_modules,
        local_only=local_only,
        cli_invoke=cli_invoke,
        dry_run=True,
    )
    primary_action_command = (
        review_command
        if review_required
        else next_command
        if dry_run
        else _command_with_cli_invoke(
            command=f"agentic-workspace doctor --target {target_root.as_posix()} --format json", cli_invoke=cli_invoke
        )
    )
    next_status = "review-required" if review_required else "ready"
    next_reason = "Resolve review_items before applying changes." if review_required else "Dry-run plan has no review blockers."
    plan = {
        "kind": "workspace-lifecycle-plan/v1",
        "command": command_name,
        "target_root": target_root.as_posix(),
        "selected_modules": selected_modules,
        "dry_run": dry_run,
        "planned_creates": list(payload.get("created", [])),
        "planned_updates": list(payload.get("updated_managed", [])),
        "planned_removals": planned_removals,
        "preserved_files": list(payload.get("preserved_existing", [])),
        "warnings": warnings,
        "review_required": review_required,
        "review_items": review_items,
        "review_remediations": review_remediations,
        "local_only_state_interaction": "install-root" if local_only else "not-requested",
        "module_update_freshness": module_update_freshness,
        "action_owner_groups": action_owner_groups,
        "source_checkout_payload_boundary": {
            "source_class": _invoked_cli_identity_payload(target_root=target_root, compact=True).get("source_class"),
            "rule": "A source-checkout command can still report target-repo managed payload refresh; that is not a Python package upgrade.",
        },
        "mutation_safety": _lifecycle_mutation_safety_payload(
            command_name=command_name,
            dry_run=dry_run,
            local_only=local_only,
            review_required=review_required,
            planned_removals=planned_removals,
        ),
        "surface_classifications": _lifecycle_surface_classifications_payload(
            payload=payload,
            command_name=command_name,
            target_root=target_root,
            dry_run=dry_run,
            review_required=review_required,
            planned_removals=planned_removals,
        ),
        "primary_next_action": {
            "action": "resolve-lifecycle-review" if review_required else "apply-lifecycle-plan" if dry_run else "verify-lifecycle-state",
            "command": primary_action_command,
            "run": primary_action_command,
            "risk": "blocked until review items are resolved"
            if review_required
            else "may mutate repo-managed workspace surfaces"
            if dry_run
            else "read-only verification recommended after mutation",
            "required_inputs": ["target repo", "selected modules", "review items"]
            if review_required
            else ["target repo", "selected modules", "dry-run plan"],
            "next_proof": "rerun the lifecycle dry-run after resolving review items"
            if review_required
            else "run doctor after apply and inspect surface classifications",
        },
        "next_safe_command": {"status": next_status, "command": review_command if review_required else next_command, "reason": next_reason},
    }
    installed_state = payload.get("installed_state_compatibility", {})
    if isinstance(installed_state, dict) and command_name in {"doctor", "status", "upgrade"}:
        plan["payload_closure_plan"] = _payload_doctor_closure_plan(
            command_name=command_name,
            target_root=target_root,
            selected_modules=selected_modules,
            installed_state_compatibility=installed_state,
            repair_actions=[],
            manual_review_actions=[],
            reports=[report for report in payload.get("reports", []) if isinstance(report, dict)],
            cli_invoke=cli_invoke,
        )
    if command_name == "upgrade":
        plan["root_upgrade_front_door"] = _root_upgrade_front_door_payload(
            target_root=target_root,
            selected_modules=selected_modules,
            dry_run=dry_run,
            next_command=next_command,
            review_required=review_required,
            cli_invoke=cli_invoke,
        )
    return plan


def _lifecycle_surface_classifications_payload(
    *, payload: dict[str, Any], command_name: str, target_root: Path, dry_run: bool, review_required: bool, planned_removals: list[str]
) -> dict[str, Any]:
    if command_name not in {"install", "init", "adopt", "upgrade", "uninstall"}:
        return {
            "kind": "workspace-lifecycle-surface-classifications/v1",
            "rule": "Classifications explain lifecycle mutation output; read-only commands keep this detail behind mutation paths.",
            "entries": [],
            "summary_by_class": {},
            "detail_hint": "Use lifecycle mutation commands with --format json for surface classifications.",
        }
    entries: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    configured_startup_file = (
        payload.get("config", {}).get("workspace", {}).get("agent_instructions_file", DEFAULT_AGENT_INSTRUCTIONS_FILE)
        if isinstance(payload.get("config"), dict)
        else DEFAULT_AGENT_INSTRUCTIONS_FILE
    )

    def add_entry(
        *,
        path: str,
        module: str,
        action: str,
        reason_class: str,
        reason: str,
        source: str,
        ownership: str | None = None,
        review_required_for_surface: bool | None = None,
    ) -> None:
        if not path:
            return
        key = (path, action, reason_class)
        if key in seen:
            return
        seen.add(key)
        entries.append(
            {
                "path": path,
                "module": module,
                "action": action,
                "reason_class": reason_class,
                "ownership": ownership or _lifecycle_ownership_for_reason(reason_class),
                "reason": reason,
                "dry_run": dry_run,
                "review_required": review_required if review_required_for_surface is None else review_required_for_surface,
                "source": source,
            }
        )

    for report in payload.get("reports", []) + payload.get("module_reports", []):
        if not isinstance(report, dict):
            continue
        module = str(report.get("module", "workspace"))
        for action in report.get("actions", []):
            if not isinstance(action, dict):
                continue
            path = _display_path(action.get("path", "."), target_root)
            action_kind = str(action.get("kind", ""))
            detail = str(action.get("detail", ""))
            reason_class, reason = _classify_lifecycle_action(
                path=path,
                action_kind=action_kind,
                detail=detail,
                command_name=command_name,
                review_required=review_required,
                configured_startup_file=str(configured_startup_file),
            )
            add_entry(
                path=path,
                module=module,
                action=action_kind,
                reason_class=reason_class,
                reason=reason,
                source="module-report",
                review_required_for_surface=reason_class in {"ambiguous ownership manual-review", "refused destructive action"},
            )
        for warning in report.get("warnings", []):
            if not isinstance(warning, dict):
                continue
            path = _display_path(warning.get("path", "."), target_root)
            message = str(warning.get("message", "needs review"))
            reason_class, reason = _classify_lifecycle_action(
                path=path,
                action_kind="warning",
                detail=message,
                command_name=command_name,
                review_required=review_required,
                configured_startup_file=str(configured_startup_file),
            )
            add_entry(
                path=path,
                module=module,
                action="warning",
                reason_class=reason_class,
                reason=reason,
                source="module-warning",
                review_required_for_surface=reason_class == "ambiguous ownership manual-review",
            )
    for path in payload.get("preserved_existing", []):
        add_entry(
            path=str(path),
            module="workspace",
            action="preserved",
            reason_class="repo-owned preserved",
            reason="Existing repo-owned surface was preserved rather than overwritten.",
            source="summary",
            review_required_for_surface=False,
        )
    for item in payload.get("needs_review", []):
        path, _, detail = str(item).partition(": ")
        reason_class = "ambiguous ownership manual-review"
        if "legacy" in detail.lower():
            reason_class = "legacy unsupported; migration/refusal required"
        add_entry(
            path=path,
            module="workspace",
            action="manual review",
            reason_class=reason_class,
            reason=detail or "Manual review is required before applying this lifecycle change.",
            source="summary",
            review_required_for_surface=True,
        )
    local_only_paths = _local_only_surfaces(target_root=target_root)
    local_only_summary = _local_only_preservation_summary(target_root=target_root, paths=local_only_paths)
    for path in local_only_summary["sample_paths"]:
        add_entry(
            path=path,
            module="workspace",
            action="preserved",
            reason_class="local-only preserved",
            reason="Repo-local private state is preserved unless --local-only explicitly targets it.",
            source="local-only-scan-sample",
            review_required_for_surface=False,
        )
    for path in _unsupported_legacy_surfaces(target_root=target_root):
        add_entry(
            path=path,
            module="workspace",
            action="manual review",
            reason_class="legacy unsupported; migration/refusal required",
            reason="Unsupported legacy compatibility surface requires manual migration or deletion.",
            source="legacy-unsupported-scan",
            review_required_for_surface=True,
        )
    if command_name == "uninstall" and review_required:
        for path in planned_removals:
            add_entry(
                path=path,
                module="workspace",
                action="refused",
                reason_class="refused destructive action",
                reason="Destructive removal requires ownership review before apply.",
                source="destructive-safety",
                review_required_for_surface=True,
            )
    summary_by_class: dict[str, int] = {}
    for entry in entries:
        reason_class = str(entry["reason_class"])
        summary_by_class[reason_class] = summary_by_class.get(reason_class, 0) + 1
    return {
        "kind": "workspace-lifecycle-surface-classifications/v1",
        "rule": "Classifications explain lifecycle output; they do not grant mutation permission.",
        "entries": entries,
        "summary_by_class": dict(sorted(summary_by_class.items())),
        "local_only_preservation": local_only_summary,
        "detail_hint": "Use --format json for full surface classifications; text output stays compact.",
    }


def _classify_lifecycle_action(
    *, path: str, action_kind: str, detail: str, command_name: str, review_required: bool, configured_startup_file: str
) -> tuple[str, str]:
    detail_l = detail.lower()
    path_l = path.lower()
    if action_kind == "skipped":
        return ("repo-owned preserved", detail or "Existing repo-owned surface was preserved.")
    if action_kind in {"manual review", "missing"}:
        if "legacy" in detail_l:
            return ("legacy unsupported; migration/refusal required", detail or "Legacy surface requires migration or refusal.")
        return ("ambiguous ownership manual-review", detail or "Manual review is required before applying this change.")
    if action_kind in {"warning", "suggested fix"}:
        if path in {"TODO.md", "ROADMAP.md"} or "legacy" in detail_l or "compatibility" in detail_l:
            return (
                "legacy unsupported; migration/refusal required",
                detail or "Legacy compatibility surface requires manual migration or deletion.",
            )
        return ("ambiguous ownership manual-review", detail or "Warning requires review.")
    if action_kind in {"would remove", "removed"}:
        if command_name == "uninstall" and review_required:
            return ("refused destructive action", detail or "Destructive action requires review.")
        return ("product-managed replaced", detail or "Managed lifecycle payload was removed.")
    if action_kind in {"would update", "updated", "overwritten", "would overwrite", "would replace", "replaced"}:
        if "optional" in detail_l:
            return ("optional enabled", detail or "Optional managed surface is enabled or refreshed.")
        if path_l.startswith(".agentic-workspace/") or path == configured_startup_file:
            return ("core refreshed", detail or "Core managed lifecycle surface is refreshed.")
        return ("product-managed replaced", detail or "Product-managed surface is replaced.")
    if action_kind in {"created", "copied", "would create", "would copy"}:
        if "optional" in detail_l:
            return ("optional enabled", detail or "Optional managed surface is enabled.")
        return ("core refreshed", detail or "Core managed lifecycle surface is created or refreshed.")
    if "generated" in detail_l or path_l.startswith("tools/"):
        return ("generated/dev-only ignored", detail or "Generated or dev-only surface is informational.")
    return ("core refreshed", detail or "Lifecycle action is managed by the selected module.")


def _lifecycle_ownership_for_reason(reason_class: str) -> str:
    if reason_class.startswith("repo-owned"):
        return "repo-owned"
    if reason_class.startswith("local-only"):
        return "local-only"
    if reason_class.startswith("optional"):
        return "optional"
    if reason_class.startswith("generated"):
        return "generated/dev-only"
    if reason_class.startswith("ambiguous"):
        return "ambiguous"
    if reason_class.startswith("refused"):
        return "refused"
    if reason_class.startswith("legacy"):
        return "legacy"
    return "product-managed"


def _local_only_surfaces(*, target_root: Path) -> list[str]:
    paths: list[str] = []
    local_root = target_root / ".agentic-workspace" / "local"
    if not local_root.exists():
        return paths
    for path in sorted(local_root.rglob("*")):
        if path.is_file():
            paths.append(path.relative_to(target_root).as_posix())
    return paths


def _local_only_preservation_summary(*, target_root: Path, paths: list[str], sample_limit: int = 5) -> dict[str, Any]:
    sample_paths = list(paths[:sample_limit])
    return {
        "kind": "workspace-local-only-preservation-summary/v1",
        "status": "present" if paths else "absent",
        "total_file_count": len(paths),
        "sample_limit": sample_limit,
        "sample_paths": sample_paths,
        "omitted_file_count": max(0, len(paths) - len(sample_paths)),
        "roots": [
            ".agentic-workspace/local",
        ],
        "rule": "Local-only scratch and cache files are preserved by default; compact lifecycle JSON reports counts and samples instead of enumerating every file.",
        "audit_command": "git ls-files --others --ignored --exclude-standard -- .agentic-workspace/local",
        "audit_commands": [
            {
                "id": "ignored-local-only-files",
                "command": "git ls-files --others --ignored --exclude-standard -- .agentic-workspace/local",
                "covers": "ignored AW-local files under .agentic-workspace/local",
            },
            {
                "id": "unignored-local-only-files",
                "command": "git ls-files --others --exclude-standard -- .agentic-workspace/local",
                "covers": "unignored AW-local files under .agentic-workspace/local",
            },
        ],
        "cleanup_dry_run_command": "git clean -ndx -- .agentic-workspace/local",
        "cleanup_rule": "The cleanup route is a dry-run only and uses -x so ignored AW-local files are visible before any explicit cleanup; repo-root scratch is not AW-owned by default.",
    }


def _unsupported_legacy_surfaces(*, target_root: Path) -> list[str]:
    paths: list[str] = []
    for relative in (Path("TODO.md"), Path("ROADMAP.md")):
        path = target_root / relative
        if not path.is_file():
            continue
        try:
            text = path.read_text(encoding="utf-8")
        except UnicodeDecodeError:
            continue
        if "GENERATED COMPATIBILITY VIEW" in text or "authoritative source is .agentic-workspace/planning/state.toml" in text:
            paths.append(relative.as_posix())
    return paths


def _root_upgrade_front_door_payload(
    *,
    target_root: Path,
    selected_modules: list[str],
    dry_run: bool,
    next_command: str,
    review_required: bool,
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> dict[str, Any]:
    target = target_root.as_posix()
    module_args = ["--modules", ",".join(selected_modules)] if selected_modules else ["--modules", "none"]
    dry_run_command = _command_with_cli_invoke(
        command=" ".join(["agentic-workspace", "upgrade", "--target", target, *module_args, "--dry-run", "--format", "json"]),
        cli_invoke=cli_invoke,
    )
    apply_command = next_command
    return {
        "kind": "workspace-root-upgrade-front-door/v1",
        "status": "authoritative-host-repo-path",
        "selected_modules": selected_modules,
        "ordinary_sequence": [
            {
                "step": "inspect",
                "command": dry_run_command,
                "safe": True,
                "reason": "Dry-run is the first host-repo update step and reports selected modules, planned changes, review items, and the next safe command.",
            },
            {
                "step": "apply",
                "command": apply_command,
                "safe": not review_required,
                "reason": "Apply only after review_items are resolved when review is required.",
            },
            {
                "step": "verify",
                "command": _command_with_cli_invoke(
                    command=f"agentic-workspace doctor --target {target} --format json", cli_invoke=cli_invoke
                ),
                "safe": True,
                "reason": "Doctor verifies the host repo after lifecycle changes settle.",
            },
        ],
        "package_specific_upgrade_role": "fallback-debug-only",
        "fallback_rule": "Use module package CLIs only for package-local debugging or when root agentic-workspace upgrade cannot run; host-repo guidance should route through the root command first.",
        "dry_run_first": True,
        "review_required_before_apply": review_required,
    }


