def _report_section_base_payload(
    *,
    target_root: Path,
    selected_modules: list[str],
    resolved_preset: str | None,
    config: WorkspaceConfig,
) -> dict[str, Any]:
    installed_modules = _fast_installed_modules(target_root=target_root)
    if (target_root / ".agentic-workspace" / "verification" / "manifest.toml").exists() and "verification" not in installed_modules:
        installed_modules.append("verification")
    return {
        "kind": "workspace-report/v1",
        "schema": _reporting_schema_payload(),
        "command": "report",
        "target": target_root.as_posix(),
        "selected_modules": selected_modules,
        "installed_modules": installed_modules,
        "feature_tier": _feature_tier_payload(
            selected_modules=selected_modules,
            installed_modules=installed_modules,
            resolved_preset=resolved_preset,
            config=config,
        ),
        "report_profile": _report_profile_payload(cli_invoke=config.cli_invoke),
        "config": {"workspace": {"cli_invoke": config.cli_invoke}},
        "findings": [],
    }


def _contract_bool(value: Any) -> bool | None:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)) and value in {0, 1}:
        return bool(value)
    text = str(value).strip().lower().replace("-", "_") if value is not None else ""
    if text in {"true", "yes", "y", "done", "complete", "completed", "satisfied", "closed", "passed"}:
        return True
    if text in {"false", "no", "n", "open", "incomplete", "partial", "missing", "failed", "blocked"}:
        return False
    return None


def _required_continuation_present(*values: Any) -> bool:
    for value in values:
        if value is None:
            continue
        if isinstance(value, bool):
            if value:
                return True
            continue
        if isinstance(value, dict):
            if any(item is not None and item != "" and item != [] and item != {} for item in value.values()):
                return True
            continue
        if _list_payload(value):
            return True
        text = str(value).strip().lower()
        if text and text not in {"none", "false", "no", "not-required", "not_required"}:
            return True
    return False


def _first_boundary_text(*sources: dict[str, Any], keys: Sequence[str]) -> str:
    normalized_keys = {key.strip().lower().replace("_", " ") for key in keys}
    for source in sources:
        if not isinstance(source, dict):
            continue
        for raw_key, raw_value in source.items():
            key = str(raw_key).strip().lower().replace("_", " ")
            if key not in normalized_keys:
                continue
            value = str(raw_value).strip()
            if value and value.lower() not in {"none", "null", "unknown"}:
                return value
    return ""


def _completion_boundary_payload(
    *,
    active_planning_record: dict[str, Any],
    raw_planning_record: dict[str, Any] | None = None,
    closure_check: dict[str, Any] | None = None,
    intent_continuity: dict[str, Any] | None = None,
    required_continuation: dict[str, Any] | None = None,
    iterative: dict[str, Any] | None = None,
    proof_report: dict[str, Any] | None = None,
    active_milestone: dict[str, Any] | None = None,
    proof_expectations: Sequence[str] | None = None,
) -> dict[str, Any]:
    active_planning_record = active_planning_record if isinstance(active_planning_record, dict) else {}
    raw_planning_record = raw_planning_record if isinstance(raw_planning_record, dict) else {}
    boundary = active_planning_record.get("completion_boundary", {})
    if not isinstance(boundary, dict):
        boundary = {}
    raw_boundary = raw_planning_record.get("completion_boundary", {})
    if not isinstance(raw_boundary, dict):
        raw_boundary = {}
    closure_check = closure_check if isinstance(closure_check, dict) else {}
    intent_continuity = intent_continuity if isinstance(intent_continuity, dict) else {}
    required_continuation = required_continuation if isinstance(required_continuation, dict) else {}
    iterative = iterative if isinstance(iterative, dict) else {}
    proof_report = proof_report if isinstance(proof_report, dict) else {}
    active_milestone = active_milestone if isinstance(active_milestone, dict) else {}
    sources = (raw_boundary, boundary, closure_check, intent_continuity, required_continuation, iterative, proof_report, active_milestone)
    final_satisfaction = _first_boundary_text(
        *sources,
        keys=(
            "final_satisfaction",
            "final intended state",
            "final intended outcome",
            "larger intended outcome",
            "larger_intent_complete",
            "larger outcome complete",
        ),
    )
    bounded_slice_success = _first_boundary_text(
        *sources,
        keys=(
            "bounded_slice_success",
            "bounded slice success",
            "what this slice enabled",
            "slice status",
            "bounded_slice_complete",
            "done_when",
        ),
    )
    partial_close = _first_boundary_text(
        raw_boundary,
        boundary,
        closure_check,
        keys=("partial_pr_may_close", "partial pr may close", "partial slice may close", "slice may close issue"),
    ).lower()
    if partial_close in {"true", "yes", "y", "allowed"}:
        partial_pr_may_close = "yes"
    elif partial_close in {"false", "no", "n", "blocked"}:
        partial_pr_may_close = "no"
    else:
        partial_pr_may_close = "unknown"
    required_follow_up_owner = _first_boundary_text(
        *sources,
        keys=(
            "required_follow_up_owner",
            "required follow up owner",
            "required follow-up owner",
            "owner surface",
            "continuation surface",
            "owner",
        ),
    )
    required_residual_intent = _first_boundary_text(
        *sources,
        keys=(
            "required_residual_intent",
            "required residual intent",
            "required follow-on for the larger intended outcome",
            "remaining gap",
            "intentionally deferred",
            "larger intended outcome",
        ),
    )
    evidence_required = _first_boundary_text(
        *sources,
        keys=(
            "evidence_required_for_final_completion",
            "evidence required for final completion",
            "evidence carried forward",
            "acceptance reconciliation",
            "validation proof",
        ),
    )
    if not evidence_required and proof_expectations:
        evidence_required = "; ".join(str(item).strip() for item in proof_expectations if str(item).strip())
    has_specific_fields = (
        any((final_satisfaction, bounded_slice_success, required_follow_up_owner, required_residual_intent, evidence_required))
        or partial_pr_may_close != "unknown"
    )
    return {
        "kind": "agentic-workspace/completion-boundary/v1",
        "status": "present" if has_specific_fields else "guidance-only",
        "final_satisfaction": final_satisfaction,
        "bounded_slice_success": bounded_slice_success,
        "partial_pr_may_close": partial_pr_may_close,
        "required_follow_up_owner": required_follow_up_owner,
        "required_residual_intent": required_residual_intent,
        "evidence_required_for_final_completion": evidence_required,
        "issue_authoring_fields": [
            "intended_outcome",
            "acceptance",
            "non_solutions",
            "final_satisfaction",
            "bounded_slice_success",
            "partial_pr_may_close",
            "required_follow_up_owner",
            "required_residual_intent",
            "evidence_required_for_final_completion",
            "completion_rule",
        ],
        "closure_rule": (
            "Treat useful progress and final intended outcome satisfaction as separate claims. "
            "When implementing an issue, satisfy the intended end state in the ordinary path; do not preserve old ordinary-path behavior unless the issue explicitly allows it. "
            "A bounded slice may land only if remaining intent and owner are preserved; it closes the issue only when partial_pr_may_close is yes or final satisfaction evidence is present. "
            "Ask for clarification when the full intended outcome appears larger than the issue safely permits."
        ),
        "default_rule": "Direction/proposal issues default partial_pr_may_close to no unless the issue author says otherwise.",
        "sources": [
            "planning.active.raw_execplan.completion_boundary",
            "planning.active.planning_record.completion_boundary",
            "planning.active.planning_record.intent_continuity",
            "planning.active.planning_record.required_continuation",
            "planning.active.planning_record.closure_check",
        ],
    }


def _completion_contract_decision(
    *,
    active_planning_record: dict[str, Any],
    closure_check: dict[str, Any],
    intent_continuity: dict[str, Any],
    iterative: dict[str, Any],
    validation: dict[str, Any],
    external_evidence_safety: dict[str, Any],
    has_active_plan: bool,
) -> dict[str, Any]:
    if not has_active_plan:
        return {
            "decision": "guidance-only",
            "reasons": ["no active Planning record is present"],
            "evidence_state": {
                "bounded_slice_complete": "unknown",
                "larger_intent_complete": "unknown",
                "continuation_required": False,
                "proof_state": "unknown",
                "external_closeout_safe": external_evidence_safety.get("closeout_safe", "unknown"),
            },
        }
    planning_status = str(active_planning_record.get("status", "")).strip().lower().replace("-", "_")
    bounded_done = _contract_bool(closure_check.get("bounded_slice_complete", active_planning_record.get("bounded_slice_complete")))
    if bounded_done is None and planning_status in {"done", "complete", "completed", "closed"}:
        bounded_done = True
    larger_done = _contract_bool(
        intent_continuity.get(
            "larger_intent_complete",
            closure_check.get("larger_intent_complete", closure_check.get("larger_outcome_complete")),
        )
    )
    continuation_required = _required_continuation_present(
        active_planning_record.get("required_continuation"),
        intent_continuity.get("required_continuation"),
        intent_continuity.get("required_follow_on"),
        iterative.get("required_continuation"),
        iterative.get("remaining_gap"),
    )
    proof_state = (
        str(
            validation.get("proof_state")
            or validation.get("status")
            or closure_check.get("proof_state")
            or closure_check.get("validation_status")
            or "unknown"
        )
        .strip()
        .lower()
        .replace("-", "_")
    )
    external_closeout_safe = external_evidence_safety.get("closeout_safe", "unknown")
    blocked_reasons: list[str] = []
    if planning_status == "blocked" or closure_check.get("blocked_stop_condition"):
        blocked_reasons.append("Planning says work is blocked")
    if external_closeout_safe is False:
        blocked_reasons.append("external evidence blocks broad closeout")
    if proof_state in {"failed", "missing", "unavailable"}:
        blocked_reasons.append(f"proof state is {proof_state}")
    if blocked_reasons:
        decision = "blocked"
        reasons = blocked_reasons
    elif bounded_done is True and (continuation_required or larger_done is False):
        decision = "continuation-required"
        reasons = ["bounded slice is complete but larger intent or follow-on remains"]
    elif bounded_done is True and larger_done is True and proof_state not in {"failed", "missing", "unavailable"}:
        decision = "done"
        reasons = ["bounded slice, larger intent, and available proof state support closure"]
    else:
        decision = "partial"
        reasons = ["available evidence does not yet prove completion"]
    return {
        "decision": decision,
        "reasons": reasons,
        "evidence_state": {
            "bounded_slice_complete": bounded_done if bounded_done is not None else "unknown",
            "larger_intent_complete": larger_done if larger_done is not None else "unknown",
            "continuation_required": continuation_required,
            "proof_state": proof_state,
            "external_closeout_safe": external_closeout_safe,
        },
    }


def _completion_contract_payload(
    *,
    active_planning_record: dict[str, Any],
    external_evidence_safety: dict[str, Any] | None = None,
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> dict[str, Any]:
    active_planning_record = active_planning_record if isinstance(active_planning_record, dict) else {}
    has_active_plan = bool(active_planning_record) and str(active_planning_record.get("status", "")).strip().lower() != "absent"
    task = active_planning_record.get("task", {}) if isinstance(active_planning_record.get("task"), dict) else {}
    closure_check = active_planning_record.get("closure_check", {})
    closure_check = closure_check if isinstance(closure_check, dict) else {}
    intent_continuity = active_planning_record.get("intent_continuity", {})
    intent_continuity = intent_continuity if isinstance(intent_continuity, dict) else {}
    iterative = active_planning_record.get("iterative_follow_through", {})
    iterative = iterative if isinstance(iterative, dict) else {}
    delegated = active_planning_record.get("delegated_judgment", {})
    delegated = delegated if isinstance(delegated, dict) else {}
    validation = active_planning_record.get("validation", {})
    validation = validation if isinstance(validation, dict) else {}
    active_milestone = active_planning_record.get("active_milestone", {})
    active_milestone = active_milestone if isinstance(active_milestone, dict) else {}
    proof_expectations = _list_payload(
        validation.get("required_commands") or validation.get("proof") or validation.get("proof_expectations")
    )
    if not proof_expectations:
        proof_expectations = ["Select proof with `agentic-workspace proof --changed <paths> --format json` once changed paths are known."]
    must_be_true = []
    for value in (
        task.get("done_when"),
        closure_check.get("bounded_slice_complete"),
        intent_continuity.get("larger_intent_complete"),
    ):
        if value is None:
            continue
        text = str(value).strip()
        if text and text.lower() != "none":
            must_be_true.append(text)
    if not must_be_true:
        must_be_true = ["The requested slice is complete and any broader intent is either satisfied or routed to a checked-in owner."]
    constraints = [str(item).strip() for item in _list_payload(delegated.get("hard_constraints")) if str(item).strip()]
    if not constraints:
        constraints = ["Do not close broader work unless proof, intent, external evidence, and residue ownership agree."]
    out_of_bounds = [str(item).strip() for item in _list_payload(delegated.get("out_of_bounds")) if str(item).strip()]
    if not out_of_bounds:
        out_of_bounds = ["Do not introduce a separate Goals state store, PM system, or runtime orchestration layer."]
    blocked_stop = str(closure_check.get("blocked_stop_condition") or closure_check.get("reopen_trigger") or "").strip()
    if not blocked_stop:
        blocked_stop = (
            "Stop as blocked when required proof, external freshness, owner routing, or larger-intent closure cannot be established."
        )
    external_evidence_safety = external_evidence_safety if isinstance(external_evidence_safety, dict) else {}
    completion_boundary = _completion_boundary_payload(
        active_planning_record=active_planning_record,
        raw_planning_record=active_planning_record,
        closure_check=closure_check,
        intent_continuity=intent_continuity,
        required_continuation=active_planning_record.get("required_continuation", {}),
        iterative=iterative,
        proof_report=active_planning_record.get("proof_report", {}),
        active_milestone=active_milestone,
        proof_expectations=[str(item) for item in proof_expectations],
    )
    decision = _completion_contract_decision(
        active_planning_record=active_planning_record,
        closure_check=closure_check,
        intent_continuity=intent_continuity,
        iterative=iterative,
        validation=validation,
        external_evidence_safety=external_evidence_safety,
        has_active_plan=has_active_plan,
    )
    return {
        "kind": "agentic-workspace/completion-contract/v1",
        "status": "active-planning-derived" if has_active_plan else "guidance-only",
        "authority": "derived-projection",
        "planning_status": active_planning_record.get("status", "absent") if active_planning_record else "absent",
        "completion_decision": decision["decision"],
        "decision_reasons": decision["reasons"],
        "evidence_state": decision["evidence_state"],
        "must_be_true": must_be_true,
        "evidence_that_proves_it": [str(item).strip() for item in proof_expectations if str(item).strip()],
        "completion_boundary": completion_boundary,
        "constraints_to_preserve": constraints,
        "out_of_bounds": out_of_bounds,
        "iteration_when_evidence_is_insufficient": [
            "record what was inspected and what failed",
            "make the smallest focused change",
            "rerun or update the proof expectation",
            "route remaining residue to Planning, Verification, Memory, docs, or an issue",
        ],
        "blocked_stop_condition": blocked_stop,
        "external_evidence_closeout_safe": external_evidence_safety.get("closeout_safe", "unknown"),
        "owner_surfaces": [
            ".agentic-workspace/planning/state.toml",
            ".agentic-workspace/planning/execplans/<plan>.plan.json",
            ".agentic-workspace/verification/manifest.toml",
        ],
        "detail_command": _command_with_cli_invoke(
            command="agentic-workspace report --target ./repo --section completion_contract --format json",
            cli_invoke=cli_invoke,
        ),
        "rule": "This imports the useful Goal grammar as a Planning lens; AW does not add a separate Goals module or thread-scoped objective store.",
    }


def _repair_loop_residue_payload(
    *,
    active_planning_record: dict[str, Any],
    verification: dict[str, Any],
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> dict[str, Any]:
    active_planning_record = active_planning_record if isinstance(active_planning_record, dict) else {}
    execution = active_planning_record.get("execution_run", {})
    execution = execution if isinstance(execution, dict) else {}
    finished_review = active_planning_record.get("finished_run_review", {})
    finished_review = finished_review if isinstance(finished_review, dict) else {}
    iterative = active_planning_record.get("iterative_follow_through", {})
    iterative = iterative if isinstance(iterative, dict) else {}
    evidence_status = [item for item in _list_payload(verification.get("evidence_bundle_status")) if isinstance(item, dict)]
    known_gaps = [item for item in _list_payload(verification.get("known_gaps")) if isinstance(item, dict)]
    observed_problem = str(execution.get("observed_problem") or finished_review.get("observed_problem") or "").strip()
    focused_change = str(execution.get("focused_change") or execution.get("summary") or finished_review.get("summary") or "").strip()
    remaining_gap = str(iterative.get("remaining_gap") or iterative.get("deferred") or "").strip()
    if not remaining_gap and known_gaps:
        remaining_gap = str(known_gaps[0].get("reason", "")).strip()
    return {
        "kind": "agentic-workspace/repair-loop-residue/v1",
        "status": "active-evidence" if observed_problem or focused_change or evidence_status or known_gaps else "guidance-only",
        "observed_problem": observed_problem,
        "inspection_findings": _list_payload(finished_review.get("findings"))[:5],
        "focused_change_made": focused_change,
        "validation_evidence": [
            {
                "protocol_id": str(item.get("protocol_id", "")),
                "state": str(item.get("state", "")),
                "evidence_items": _list_payload(item.get("evidence_items")),
            }
            for item in evidence_status[:5]
        ],
        "remaining_gap": remaining_gap,
        "next_input_for_continuation": str(iterative.get("next_input") or iterative.get("next_action") or "").strip(),
        "stop_reason": str(active_planning_record.get("stop_reason") or finished_review.get("stop_reason") or "").strip(),
        "required_loop_fields": [
            "observed_problem",
            "inspection_findings",
            "focused_change_made",
            "validation_evidence",
            "remaining_gap",
            "next_input_for_continuation",
            "stop_reason",
        ],
        "owner_boundary": "Derived from Planning and Verification; it is not a workflow runner and does not own CI/tool execution.",
        "source_of_truth_fields": {
            "observed_problem": "planning_record.execution_run.observed_problem or finished_run_review.observed_problem",
            "focused_change_made": "planning_record.execution_run.focused_change or execution_run.summary",
            "validation_evidence": "verification.evidence_bundle_status",
            "remaining_gap": "planning_record.iterative_follow_through.remaining_gap or verification.known_gaps",
            "next_input_for_continuation": "planning_record.iterative_follow_through.next_input",
            "stop_reason": "planning_record.stop_reason or finished_run_review.stop_reason",
        },
        "detail_command": _command_with_cli_invoke(
            command="agentic-workspace report --target ./repo --section repair_loop_residue --format json",
            cli_invoke=cli_invoke,
        ),
    }


def _external_evidence_safety_payload(
    *,
    external_work_delta: dict[str, Any],
    external_work_reconciliation: dict[str, Any],
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> dict[str, Any]:
    delta_status = str(external_work_delta.get("status", "unavailable"))
    changed_count = _as_int(external_work_delta.get("changed_count"))
    new_count = _as_int(external_work_delta.get("new_count"))
    closed_count = _as_int(external_work_delta.get("closed_count"))
    open_count = _as_int(external_work_delta.get("open_count"))
    stale_evidence = delta_status in {"invalid"}
    freshness_safe: bool | str = "unknown" if delta_status in {"unavailable", "absent"} else not stale_evidence
    divergence_present = bool(changed_count or new_count or closed_count)
    closeout_blockers: list[str] = []
    if open_count:
        closeout_blockers.append("external_open_items")
    if changed_count or new_count:
        closeout_blockers.append("divergent_external_state")
    if stale_evidence:
        closeout_blockers.append("stale_external_evidence")
    closeout_safe: bool | str
    if delta_status in {"unavailable", "absent"}:
        closeout_safe = "unknown"
    else:
        closeout_safe = not closeout_blockers
    freshness = external_work_reconciliation.get("freshness", {})
    freshness = freshness if isinstance(freshness, dict) else {}
    return {
        "kind": "agentic-workspace/external-evidence-safety/v1",
        "status": "attention"
        if closeout_safe is False
        else "available"
        if delta_status not in {"unavailable", "absent"}
        else "no-external-evidence",
        "source": external_work_delta.get("source", ""),
        "fetched_at": external_work_delta.get("refreshed_at") or freshness.get("fetched_at") or freshness.get("refreshed_at") or "",
        "source_state": {
            "status": delta_status,
            "open_count": open_count,
            "new_count": new_count,
            "changed_count": changed_count,
            "closed_count": closed_count,
        },
        "freshness_safe": freshness_safe,
        "divergence_present": divergence_present,
        "local_state": {
            "primary_owner": external_work_reconciliation.get("primary_owner", ".agentic-workspace/planning/state.toml"),
            "status": external_work_reconciliation.get("status", "unavailable"),
        },
        "divergence": {
            "present": divergence_present,
            "reason": "external evidence changed since the previous snapshot"
            if divergence_present
            else "no provider-agnostic divergence detected",
            "sample_changed": external_work_delta.get("sample_changed", []),
            "sample_new": external_work_delta.get("sample_new", []),
            "sample_closed": external_work_delta.get("sample_closed", []),
        },
        "stale_after": freshness.get("stale_after", ""),
        "closeout_safe": closeout_safe,
        "closeout_blockers": closeout_blockers,
        "reason": "Resolve external closeout blockers before broad closeout."
        if closeout_safe is False
        else "Offline Planning remains primary; external evidence is advisory unless present and divergent.",
        "refresh_command": _command_with_cli_invoke(
            command="agentic-workspace external-intent refresh-github --target . --state all --format json",
            cli_invoke=cli_invoke,
        ),
        "rule": "External systems inform freshness and reconciliation; they do not become primary Planning authority.",
    }


def _structured_findings_payload(
    *,
    source_payload: dict[str, Any],
    external_evidence_safety: dict[str, Any],
    verification: dict[str, Any],
) -> dict[str, Any]:
    entries: list[dict[str, Any]] = []

    def add_entry(
        *,
        finding_id: str,
        kind: str,
        evidence: list[str],
        severity: str = "info",
        confidence: str = "medium",
        proposed_owner: str = "workspace",
        disposition: str = "review",
        path_refs: list[str] | None = None,
    ) -> None:
        entries.append(
            {
                "id": finding_id,
                "kind": kind,
                "path_refs": path_refs or [],
                "evidence": evidence,
                "severity": severity,
                "confidence": confidence,
                "proposed_owner": proposed_owner,
                "disposition": disposition,
            }
        )

    for index, finding in enumerate(item for item in _list_payload(source_payload.get("findings")) if isinstance(item, dict)):
        add_entry(
            finding_id=str(finding.get("id") or f"workspace-finding-{index + 1}"),
            kind=str(finding.get("kind") or finding.get("module") or "workspace-warning"),
            path_refs=[str(finding.get("path", "")).strip()] if str(finding.get("path", "")).strip() else [],
            evidence=[str(finding.get("message") or finding.get("summary") or finding).strip()],
            severity=str(finding.get("severity", "warning")),
            confidence=str(finding.get("confidence", "medium")),
            proposed_owner=str(finding.get("owner", "workspace")),
        )
    for container_name, default_owner in (("repo_friction", "workspace"), ("improvement_intake", "planning")):
        container = source_payload.get(container_name, {})
        container = container if isinstance(container, dict) else {}
        for index, finding in enumerate(item for item in _list_payload(container.get("findings")) if isinstance(item, dict)):
            add_entry(
                finding_id=str(finding.get("id") or f"{container_name}-finding-{index + 1}"),
                kind=str(finding.get("kind") or container_name),
                path_refs=[
                    str(path).strip() for path in _list_payload(finding.get("path_refs") or finding.get("paths")) if str(path).strip()
                ],
                evidence=[str(finding.get("evidence") or finding.get("summary") or finding.get("message") or finding).strip()],
                severity=str(finding.get("severity", "warning")),
                confidence=str(finding.get("confidence", "medium")),
                proposed_owner=str(finding.get("owner", finding.get("proposed_owner", default_owner))),
                disposition=str(finding.get("disposition", "route-or-dismiss")),
            )
    closeout_trust = source_payload.get("closeout_trust", {})
    closeout_trust = closeout_trust if isinstance(closeout_trust, dict) else {}
    package_continuation = closeout_trust.get("package_owned_continuation", {})
    package_continuation = package_continuation if isinstance(package_continuation, dict) else {}
    owner_surfaces = [str(item).strip() for item in _list_payload(package_continuation.get("owner_surfaces")) if str(item).strip()]
    if owner_surfaces:
        add_entry(
            finding_id="package-owned-continuation",
            kind="promotion-residue",
            path_refs=owner_surfaces,
            evidence=["closeout reports package-owned continuation residue"],
            severity="warning",
            confidence="high",
            proposed_owner="planning",
            disposition="route-continuation",
        )
    for gap in (item for item in _list_payload(verification.get("known_gaps")) if isinstance(item, dict)):
        add_entry(
            finding_id=str(gap.get("id", "verification-gap")),
            kind="verification-known-gap",
            evidence=[str(gap.get("reason", "")).strip()],
            severity="warning" if gap.get("blocked_claims") else "info",
            confidence="high",
            proposed_owner=str(gap.get("owner", "verification")),
            disposition="route-or-waive",
        )
    divergence = external_evidence_safety.get("divergence", {}) if isinstance(external_evidence_safety, dict) else {}
    if isinstance(divergence, dict) and divergence.get("present"):
        add_entry(
            finding_id="external-evidence-divergence",
            kind="external-evidence-freshness",
            evidence=[str(divergence.get("reason", "external evidence diverged"))],
            severity="warning",
            confidence="high",
            proposed_owner="planning",
            disposition="reconcile-before-closeout",
        )
    if isinstance(external_evidence_safety, dict) and "external_open_items" in _list_payload(
        external_evidence_safety.get("closeout_blockers")
    ):
        add_entry(
            finding_id="external-open-items",
            kind="external-evidence-closeout-blocker",
            evidence=["external evidence contains open source-owned work"],
            severity="warning",
            confidence="high",
            proposed_owner="planning",
            disposition="reconcile-before-closeout",
        )
    return {
        "kind": "agentic-workspace/structured-findings/v1",
        "status": "present" if entries else "shape-only",
        "schema": {
            "required_fields": ["id", "kind", "path_refs", "evidence", "severity", "confidence", "proposed_owner", "disposition"],
            "routing_rule": "A finding should have one primary home: Planning, Memory, Verification, canonical docs, tests, or an external issue.",
        },
        "entries": entries,
        "entry_count": len(entries),
        "promotion_guidance": [
            "promote only durable, evidenced findings with a bounded owner and next action",
            "dismiss speculative prose residue instead of preserving it beside structured state",
            "do not duplicate canonical issue tracker state; reference it when it is the owner",
        ],
    }


def _continuation_next_actions_payload(
    *,
    completion_contract: dict[str, Any],
    repair_loop_residue: dict[str, Any],
    structured_findings: dict[str, Any],
    external_evidence_safety: dict[str, Any],
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> dict[str, Any]:
    actions: list[dict[str, Any]] = []

    def add_action(
        action_id: str, rank: int, summary: str, evidence: list[str], confidence: str, validation: str, stop_condition: str
    ) -> None:
        actions.append(
            {
                "rank": rank,
                "id": action_id,
                "summary": summary,
                "evidence": evidence,
                "confidence": confidence,
                "validation": validation,
                "stop_condition": stop_condition,
            }
        )

    if external_evidence_safety.get("closeout_safe") is False:
        add_action(
            "resolve-external-closeout-blockers",
            1,
            "Resolve external evidence blockers before claiming broad completion.",
            [str(external_evidence_safety.get("reason", ""))],
            "high",
            str(external_evidence_safety.get("refresh_command", "")),
            "stop once external evidence is refreshed or explicitly marked out of scope",
        )
    if _as_int(structured_findings.get("entry_count")):
        add_action(
            "route-structured-findings",
            len(actions) + 1,
            "Promote, dismiss, or defer structured findings through their primary owner.",
            [f"{structured_findings.get('entry_count')} structured finding(s) are present"],
            "medium",
            _command_with_cli_invoke(
                command="agentic-workspace report --target ./repo --section structured_findings --format json",
                cli_invoke=cli_invoke,
            ),
            "stop when every finding has a disposition",
        )
    if repair_loop_residue.get("status") == "active-evidence":
        add_action(
            "continue-repair-loop",
            len(actions) + 1,
            "Continue from observed repair evidence and remaining gap.",
            [str(repair_loop_residue.get("remaining_gap") or "repair evidence is present")],
            "medium",
            _command_with_cli_invoke(
                command="agentic-workspace report --target ./repo --section repair_loop_residue --format json",
                cli_invoke=cli_invoke,
            ),
            "stop when validation evidence proves the focused change or the gap is routed",
        )
    add_action(
        "apply-completion-contract",
        len(actions) + 1,
        "Use the completion contract to decide whether this is done, partial, blocked, or continuation-required.",
        [str(completion_contract.get("status", ""))],
        "high" if completion_contract.get("status") == "active-planning-derived" else "medium",
        _command_with_cli_invoke(command="agentic-workspace closeout --target ./repo --format json", cli_invoke=cli_invoke),
        str(completion_contract.get("blocked_stop_condition", "")),
    )
    return {
        "kind": "agentic-workspace/continuation-next-actions/v1",
        "status": "ranked",
        "ranked_next_actions": sorted(actions, key=lambda item: int(item["rank"])),
        "rule": "Next actions are evidence-ranked suggestions. The agent still owns judgment about work shape, proof, and delegation.",
    }


