def _successful_completion_cost_payload(*, target_root: Path, cli_invoke: str) -> dict[str, Any]:
    summary_dir_relative = WORKSPACE_LOCAL_SCRATCH_ROOT_PATH / "model-cli-harness"
    summary_dir = target_root / summary_dir_relative
    summary_files = sorted(
        summary_dir.glob("*summary.json") if summary_dir.exists() else [], key=lambda path: (path.stat().st_mtime, path.name), reverse=True
    )
    summaries: list[dict[str, Any]] = []
    skipped_count = 0
    for path in summary_files[:8]:
        try:
            raw_payload = json.loads(path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            skipped_count += 1
            continue
        if not isinstance(raw_payload, dict):
            skipped_count += 1
            continue
        summaries.append(_successful_completion_cost_run_summary(payload=raw_payload, path=path, target_root=target_root))
    usage_totals = _successful_completion_cost_usage_totals(summaries)
    package_totals = _successful_completion_cost_package_totals(summaries)
    outcome_totals = _successful_completion_cost_outcome_totals(summaries)
    weakness_ledger = _successful_completion_cost_weakness_ledger(target_root=target_root)
    evidence_count = len(summaries)
    signals: list[dict[str, Any]] = []
    if outcome_totals["warning_run_count"]:
        signals.append(
            {
                "severity": "advisory",
                "id": "rework-pressure",
                "message": "Some recent runs had warnings or semantic findings; optimize for first-pass success before adding surface area.",
                "count": outcome_totals["warning_run_count"],
            }
        )
    if package_totals["largest_command_output_bytes"] > 10000:
        signals.append(
            {
                "severity": "advisory",
                "id": "large-package-output",
                "message": "At least one package command output exceeded the compact-output target.",
                "count": package_totals["largest_command_output_bytes"],
            }
        )
    if weakness_ledger.get("active_high_priority_count"):
        signals.append(
            {
                "severity": "advisory",
                "id": "active-high-priority-weaknesses",
                "message": "The weakness ledger still has high-priority active monitoring entries.",
                "count": weakness_ledger["active_high_priority_count"],
            }
        )
    return {
        "kind": "workspace-successful-completion-cost/v1",
        "status": "present" if evidence_count else "no-evidence",
        "advisory_only": True,
        "rule": "Use this as maintainer evidence for surface-cost tradeoffs. It is not a formal benchmark, CI gate, or model leaderboard.",
        "evidence": {
            "summary_dir": summary_dir_relative.as_posix(),
            "summary_count": evidence_count,
            "skipped_summary_count": skipped_count,
            "included_recent_limit": 8,
            "weakness_ledger": weakness_ledger,
        },
        "totals": {
            "token_and_request_cost": usage_totals,
            "package_read_overhead": package_totals,
            "proof_and_rework_cost": outcome_totals,
        },
        "recent_runs": [_successful_completion_cost_compact_run(summary) for summary in summaries[:3]],
        "work_shape_study_comparison": work_shape_study_comparison_evidence_payload(),
        "signals": signals,
        "decision_questions": [
            "Did the package reduce total successful-completion work, including retries and proof?",
            "Is the next optimization a smaller default output, a clearer selector, or stronger workflow guidance?",
            "Is a high-read or high-token surface still needed by default, or should it move behind a section selector?",
        ],
        "section_command": _command_with_cli_invoke(
            command="agentic-workspace report --target ./repo --section successful_completion_cost --format json", cli_invoke=cli_invoke
        ),
    }


def _successful_completion_cost_run_summary(*, payload: dict[str, Any], path: Path, target_root: Path) -> dict[str, Any]:
    usage = payload.get("usage_summary", {})
    usage = usage if isinstance(usage, dict) else {}
    package_read = payload.get("package_read_surface_summary", {})
    package_read = package_read if isinstance(package_read, dict) else {}
    finding_classification = payload.get("finding_classification", {})
    finding_classification = finding_classification if isinstance(finding_classification, dict) else {}
    capability = payload.get("capability_routing_evaluation", {})
    capability = capability if isinstance(capability, dict) else {}
    followthrough = payload.get("completion_followthrough", {})
    followthrough = followthrough if isinstance(followthrough, dict) else {}
    results = _list_payload(payload.get("results"))
    warning_result_count = 0
    failed_result_count = 0
    mutated_result_count = 0
    for result in results:
        if not isinstance(result, dict):
            continue
        warnings = _list_payload(result.get("warnings"))
        if warnings:
            warning_result_count += 1
        returncode = result.get("returncode")
        if isinstance(returncode, int) and returncode != 0:
            failed_result_count += 1
        mutation_summary = result.get("mutation_summary", {})
        mutation_summary = mutation_summary if isinstance(mutation_summary, dict) else {}
        if str(mutation_summary.get("status", "")) not in {"", "clean"}:
            mutated_result_count += 1
    finding_count = _as_int(finding_classification.get("finding_count"))
    ignored_count = _as_int(capability.get("ignored_or_misread_count"))
    result_count = _as_int(payload.get("result_count") or usage.get("result_count") or len(results))
    turn_count = _as_int(usage.get("turn_count"))
    if not turn_count:
        for result in results:
            if isinstance(result, dict):
                result_usage = result.get("usage_summary", {})
                if isinstance(result_usage, dict):
                    turn_count += _as_int(result_usage.get("turn_count"))
    try:
        evidence_ref = path.resolve().relative_to(target_root.resolve()).as_posix()
    except ValueError:
        evidence_ref = path.as_posix()
    return {
        "evidence_ref": evidence_ref,
        "adapter": payload.get("adapter", ""),
        "model": payload.get("model", ""),
        "result_count": result_count,
        "token_and_request_cost": {
            "status": usage.get("status", "absent"),
            "input_tokens": _as_int(usage.get("input_tokens")),
            "uncached_input_tokens": _as_int(usage.get("uncached_input_tokens")),
            "cached_input_tokens": _as_int(usage.get("cached_input_tokens")),
            "output_tokens": _as_int(usage.get("output_tokens")),
            "reasoning_output_tokens": _as_int(usage.get("reasoning_output_tokens")),
            "total_billable_proxy_tokens": _as_int(usage.get("total_billable_proxy_tokens")),
            "request_or_turn_count": turn_count,
        },
        "package_read_overhead": {
            "status": package_read.get("status", "absent"),
            "command_count": _as_int(package_read.get("command_count")),
            "output_bytes": _as_int(package_read.get("output_bytes")),
            "output_lines": _as_int(package_read.get("output_lines")),
            "largest_command_output_bytes": _as_int(package_read.get("largest_command_output_bytes")),
            "mixed_command_count": _as_int(package_read.get("mixed_command_count")),
            "precision": package_read.get("precision", ""),
        },
        "proof_and_rework_cost": {
            "finding_count": finding_count,
            "warning_result_count": warning_result_count,
            "failed_result_count": failed_result_count,
            "mutated_result_count": mutated_result_count,
            "capability_ignored_or_misread_count": ignored_count,
            "first_pass_proxy": "clean"
            if not (finding_count or warning_result_count or failed_result_count or ignored_count)
            else "rework-likely",
            "pushed_to_completion_status": followthrough.get("status", "not-recorded"),
        },
    }


def _successful_completion_cost_compact_run(summary: dict[str, Any]) -> dict[str, Any]:
    token_cost = summary.get("token_and_request_cost", {})
    token_cost = token_cost if isinstance(token_cost, dict) else {}
    package_cost = summary.get("package_read_overhead", {})
    package_cost = package_cost if isinstance(package_cost, dict) else {}
    proof_cost = summary.get("proof_and_rework_cost", {})
    proof_cost = proof_cost if isinstance(proof_cost, dict) else {}
    return {
        "evidence_ref": summary.get("evidence_ref", ""),
        "adapter": summary.get("adapter", ""),
        "model": summary.get("model", ""),
        "result_count": summary.get("result_count", 0),
        "token_and_request_cost": {
            "total_billable_proxy_tokens": _as_int(token_cost.get("total_billable_proxy_tokens")),
            "uncached_input_tokens": _as_int(token_cost.get("uncached_input_tokens")),
            "output_tokens": _as_int(token_cost.get("output_tokens")),
            "request_or_turn_count": _as_int(token_cost.get("request_or_turn_count")),
        },
        "package_read_overhead": {
            "command_count": _as_int(package_cost.get("command_count")),
            "output_bytes": _as_int(package_cost.get("output_bytes")),
            "largest_command_output_bytes": _as_int(package_cost.get("largest_command_output_bytes")),
        },
        "proof_and_rework_cost": {
            "finding_count": _as_int(proof_cost.get("finding_count")),
            "warning_result_count": _as_int(proof_cost.get("warning_result_count")),
            "failed_result_count": _as_int(proof_cost.get("failed_result_count")),
            "capability_ignored_or_misread_count": _as_int(proof_cost.get("capability_ignored_or_misread_count")),
            "first_pass_proxy": proof_cost.get("first_pass_proxy", "unknown"),
            "pushed_to_completion_status": proof_cost.get("pushed_to_completion_status", "not-recorded"),
        },
    }


def _successful_completion_cost_usage_totals(summaries: list[dict[str, Any]]) -> dict[str, Any]:
    totals = {
        "status": "present" if summaries else "no-evidence",
        "run_count": len(summaries),
        "input_tokens": 0,
        "uncached_input_tokens": 0,
        "cached_input_tokens": 0,
        "output_tokens": 0,
        "reasoning_output_tokens": 0,
        "total_billable_proxy_tokens": 0,
        "request_or_turn_count": 0,
    }
    for summary in summaries:
        cost = summary.get("token_and_request_cost", {})
        cost = cost if isinstance(cost, dict) else {}
        for key in (
            "input_tokens",
            "uncached_input_tokens",
            "cached_input_tokens",
            "output_tokens",
            "reasoning_output_tokens",
            "total_billable_proxy_tokens",
            "request_or_turn_count",
        ):
            totals[key] = _as_int(totals.get(key)) + _as_int(cost.get(key))
    return totals


def _successful_completion_cost_package_totals(summaries: list[dict[str, Any]]) -> dict[str, Any]:
    totals = {
        "status": "present" if summaries else "no-evidence",
        "run_count": len(summaries),
        "command_count": 0,
        "output_bytes": 0,
        "output_lines": 0,
        "largest_command_output_bytes": 0,
        "mixed_command_count": 0,
    }
    for summary in summaries:
        cost = summary.get("package_read_overhead", {})
        cost = cost if isinstance(cost, dict) else {}
        totals["command_count"] += _as_int(cost.get("command_count"))
        totals["output_bytes"] += _as_int(cost.get("output_bytes"))
        totals["output_lines"] += _as_int(cost.get("output_lines"))
        totals["largest_command_output_bytes"] = max(
            totals["largest_command_output_bytes"], _as_int(cost.get("largest_command_output_bytes"))
        )
        totals["mixed_command_count"] += _as_int(cost.get("mixed_command_count"))
    return totals


def _successful_completion_cost_outcome_totals(summaries: list[dict[str, Any]]) -> dict[str, Any]:
    totals = {
        "status": "present" if summaries else "no-evidence",
        "run_count": len(summaries),
        "result_count": 0,
        "finding_count": 0,
        "warning_result_count": 0,
        "failed_result_count": 0,
        "mutated_result_count": 0,
        "capability_ignored_or_misread_count": 0,
        "clean_first_pass_proxy_count": 0,
        "warning_run_count": 0,
        "pushed_to_completion_count": 0,
        "completion_followthrough_status_counts": {},
        "pushed_to_completion_note": "Uses model CLI harness completion_followthrough when present; older summaries may report not-recorded.",
    }
    for summary in summaries:
        proof = summary.get("proof_and_rework_cost", {})
        proof = proof if isinstance(proof, dict) else {}
        finding_count = _as_int(proof.get("finding_count"))
        warning_result_count = _as_int(proof.get("warning_result_count"))
        failed_result_count = _as_int(proof.get("failed_result_count"))
        ignored_count = _as_int(proof.get("capability_ignored_or_misread_count"))
        totals["result_count"] += _as_int(summary.get("result_count"))
        totals["finding_count"] += finding_count
        totals["warning_result_count"] += warning_result_count
        totals["failed_result_count"] += failed_result_count
        totals["mutated_result_count"] += _as_int(proof.get("mutated_result_count"))
        totals["capability_ignored_or_misread_count"] += ignored_count
        if finding_count or warning_result_count or failed_result_count or ignored_count:
            totals["warning_run_count"] += 1
        else:
            totals["clean_first_pass_proxy_count"] += 1
        status = str(proof.get("pushed_to_completion_status") or "not-recorded")
        status_counts = totals["completion_followthrough_status_counts"]
        if isinstance(status_counts, dict):
            status_counts[status] = _as_int(status_counts.get(status)) + 1
        if status == "pushed-to-completion":
            totals["pushed_to_completion_count"] += 1
    return totals


def _successful_completion_cost_weakness_ledger(*, target_root: Path) -> dict[str, Any]:
    ledger_path = target_root / "tools" / "model-cli-harness" / "model-task-weakness-ledger.json"
    if not ledger_path.exists():
        return {"status": "absent", "path": "tools/model-cli-harness/model-task-weakness-ledger.json"}
    try:
        payload = json.loads(ledger_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as exc:
        return {"status": "unreadable", "path": "tools/model-cli-harness/model-task-weakness-ledger.json", "reason": str(exc)}
    entries = _list_payload(payload.get("entries") if isinstance(payload, dict) else [])
    active_entries = [
        entry
        for entry in entries
        if isinstance(entry, dict) and str(entry.get("status", "")).lower() not in {"fixed-monitoring", "closed", "done"}
    ]
    high_priority_active = [
        entry for entry in active_entries if isinstance(entry, dict) and str(entry.get("priority", "")).lower() == "high"
    ]
    return {
        "status": "present",
        "path": "tools/model-cli-harness/model-task-weakness-ledger.json",
        "entry_count": len(entries),
        "active_count": len(active_entries),
        "active_high_priority_count": len(high_priority_active),
        "sample_active_ids": [str(entry.get("id", "")) for entry in active_entries[:5] if isinstance(entry, dict)],
    }


def _operational_compression_payload(
    *,
    report_payload: dict[str, Any],
    module_reports: list[dict[str, Any]],
    findings: list[dict[str, Any]],
    surface_value_guardrail: dict[str, Any],
) -> dict[str, Any]:
    planning_report = next((report for report in module_reports if isinstance(report, dict) and report.get("module") == "planning"), {})
    memory_report = next((report for report in module_reports if isinstance(report, dict) and report.get("module") == "memory"), {})
    planning_report = planning_report if isinstance(planning_report, dict) else {}
    memory_report = memory_report if isinstance(memory_report, dict) else {}
    report_profile = report_payload.get("report_profile", {})
    schema = report_payload.get("schema", {})
    decision_grade_fields = _list_payload(report_profile.get("decision_grade_fields") if isinstance(report_profile, dict) else [])
    high_volume_sections = _list_payload(report_profile.get("high_volume_sections") if isinstance(report_profile, dict) else [])
    shared_fields = _list_payload(schema.get("shared_fields") if isinstance(schema, dict) else [])
    section_hints = _report_section_hints({**report_payload, "operational_compression": {}})
    memory_habitual_pull = memory_report.get("habitual_pull", {}) if isinstance(memory_report, dict) else {}
    memory_evidence = memory_habitual_pull.get("evidence", {}) if isinstance(memory_habitual_pull, dict) else {}
    durable_facts = memory_report.get("durable_facts", {}) if isinstance(memory_report, dict) else {}
    durable_fact_records = _list_payload(durable_facts.get("records") if isinstance(durable_facts, dict) else [])
    ownership_review = planning_report.get("ownership_review", {}) if isinstance(planning_report, dict) else {}
    authority_surfaces = _list_payload(ownership_review.get("authority_surfaces") if isinstance(ownership_review, dict) else [])
    managed_fences = _list_payload(ownership_review.get("managed_fences") if isinstance(ownership_review, dict) else [])
    closeout_distillation = planning_report.get("closeout_distillation", {}) if isinstance(planning_report, dict) else {}
    closeout_counts = closeout_distillation.get("counts", {}) if isinstance(closeout_distillation, dict) else {}
    archived_distillation = _archived_plan_distillation_measure(target=report_payload.get("target"))
    artifact_footprint = _artifact_footprint_by_class(target=report_payload.get("target"))
    generated_footprint = _generated_output_footprint(target=report_payload.get("target"))
    archive_retention = _archive_retention_policy(archived_distillation=archived_distillation, artifact_footprint=artifact_footprint)
    output_shape_inventory = _ordinary_output_shape_inventory()
    closeout_trust = report_payload.get("closeout_trust", {})
    closeout_trust = closeout_trust if isinstance(closeout_trust, dict) else {}
    historical_reviews = closeout_trust.get("historical_review_artifacts", {})
    historical_reviews = historical_reviews if isinstance(historical_reviews, dict) else {}
    review_retention = historical_reviews.get("retention_policy", {})
    review_retention = review_retention if isinstance(review_retention, dict) else {}
    intent_validation = planning_report.get("intent_validation", {}) if isinstance(planning_report, dict) else {}
    intent_counts = intent_validation.get("counts", {}) if isinstance(intent_validation, dict) else {}
    current_external_work = intent_validation.get("current_external_work", {}) if isinstance(intent_validation, dict) else {}
    durable_metadata_records = authority_surfaces + durable_fact_records
    missing_metadata = [
        {
            "surface": str(record.get("surface") or record.get("id") or record.get("path") or ""),
            "missing": _missing_metadata_fields(record, required=("owner", "authority", "summary")),
        }
        for record in durable_metadata_records
        if isinstance(record, dict) and _missing_metadata_fields(record, required=("owner", "authority", "summary"))
    ]
    adapter_missing_removal_paths = [
        str(record.get("file") or record.get("surface") or record.get("name") or "")
        for record in managed_fences
        if isinstance(record, dict) and (not str(record.get("uninstall_policy", "")).strip())
    ]
    measures = {
        "first_line_startup_read_surface_count": {
            "status": "measured",
            "count": len(_list_payload(report_payload.get("selected_modules"))) + 1,
            "sources": ["AGENTS.md workflow pointer", "installed module routing from report.selected_modules"],
            "advisory": "New first-line startup surfaces should replace, merge, or background an existing route.",
        },
        "default_report_size_or_warning_count": {
            "status": "measured",
            "shared_field_count": len(shared_fields),
            "decision_grade_field_count": len(decision_grade_fields),
            "section_hint_count": len(section_hints),
            "high_volume_section_count": len(high_volume_sections),
            "warning_count": len(findings),
            "sources": ["report.schema.shared_fields", "report.report_profile", "report.findings"],
        },
        "routed_memory_pull_size": {
            "status": "measured" if memory_evidence else "unavailable",
            "average_routed_note_count": memory_evidence.get("average_routed_note_count"),
            "average_routed_line_count": memory_evidence.get("average_routed_line_count"),
            "durable_fact_count": memory_evidence.get("durable_fact_count", len(durable_fact_records)),
            "durable_fact_matched_case_count": memory_evidence.get("durable_fact_matched_case_count"),
            "durable_facts_smaller_or_more_precise": memory_evidence.get("durable_facts_smaller_or_more_precise"),
            "sources": ["memory.habitual_pull.evidence", "memory.durable_facts.routing_measure"],
        },
        "durable_surface_metadata": {
            "status": "measured",
            "record_count": len(durable_metadata_records),
            "missing_metadata_count": len(missing_metadata),
            "sample_missing_metadata": missing_metadata[:5],
            "required_metadata": ["owner", "authority", "summary"],
            "sources": ["planning.ownership_review.authority_surfaces", "memory.durable_facts.records"],
        },
        "additive_surface_replacement_pressure": {
            "status": "available-advisory-gate",
            "preference_count": len(_list_payload(surface_value_guardrail.get("preference_order"))),
            "value_question_count": len(_list_payload(surface_value_guardrail.get("value_questions"))),
            "review_gate": surface_value_guardrail.get("review_gate", {}),
            "sources": ["surface_value_guardrail"],
        },
        "archived_plan_distillation": {
            "status": "measured",
            "active_closeout_status": closeout_distillation.get("status", "unavailable")
            if isinstance(closeout_distillation, dict)
            else "unavailable",
            "promoted_or_routed_count": closeout_counts.get("promoted_or_routed_count"),
            "intentionally_discarded_count": closeout_counts.get("intentionally_discarded_count"),
            **archived_distillation,
            "sources": ["planning.closeout_distillation.counts", ".agentic-workspace/planning/execplans/archive/*.plan.json"],
        },
        "artifact_footprint_by_class": artifact_footprint,
        "generated_output_footprint": generated_footprint,
        "archive_retention_policy": archive_retention,
        "ordinary_output_shape_inventory": output_shape_inventory,
        "ordinary_default_output_budget": output_shape_inventory.get("ordinary_default_output_budget", {}),
        "review_retention_policy": review_retention,
        "unresolved_external_work_routing": {
            "status": current_external_work.get("status", "unavailable") if isinstance(current_external_work, dict) else "unavailable",
            "tracked_open_count": intent_counts.get("tracked_external_open_count"),
            "untracked_open_count": intent_counts.get("untracked_external_open_count"),
            "provider_rule": current_external_work.get("provider_rule", "") if isinstance(current_external_work, dict) else "",
            "sources": ["planning.intent_validation"],
        },
        "adapter_surface_lifecycle": {
            "status": "measured",
            "adapter_count": len(managed_fences),
            "missing_removal_path_count": len(adapter_missing_removal_paths),
            "sample_missing_removal_paths": adapter_missing_removal_paths[:5],
            "sources": ["planning.ownership_review.managed_fences"],
        },
    }
    advisory_signals: list[dict[str, Any]] = []
    if len(findings) > 0:
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "default_report_size_or_warning_count",
                "message": "Report findings are present; inspect warning_summary before declaring the workspace quiet.",
                "count": len(findings),
            }
        )
    if missing_metadata:
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "durable_surface_metadata",
                "message": "Some durable records do not expose owner, authority, and summary metadata.",
                "count": len(missing_metadata),
            }
        )
    if adapter_missing_removal_paths:
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "adapter_surface_lifecycle",
                "message": "Some adapter surfaces do not expose a removal path.",
                "count": len(adapter_missing_removal_paths),
            }
        )
    post_contract_missing = _as_int(archived_distillation.get("post_contract_missing_distillation_count"))
    if post_contract_missing:
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "archived_plan_distillation",
                "message": "Some post-contract archived execplans do not expose closeout distillation buckets.",
                "count": post_contract_missing,
            }
        )
    if _as_int(intent_counts.get("untracked_external_open_count")):
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "unresolved_external_work_routing",
                "message": "External work evidence has open items not tracked by active planning.",
                "count": _as_int(intent_counts.get("untracked_external_open_count")),
            }
        )
    if artifact_footprint.get("recommended_cleanup_target"):
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "artifact_footprint_by_class",
                "message": "Artifact footprint pressure is present; inspect the recommended cleanup target before expanding residue.",
                "count": artifact_footprint.get("pressure_class_count", 0),
            }
        )
    if generated_footprint.get("status") == "attention":
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "generated_output_footprint",
                "message": "Generated-output footprint has unclassified or stale candidates; inspect before expanding generated residue.",
                "count": generated_footprint.get("unclassified_generated_output_count", 0),
            }
        )
    if archive_retention.get("status") == "attention":
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "archive_retention_policy",
                "message": "Archived execplan retention pressure is present; review candidates before expanding archive residue.",
                "count": archive_retention.get("candidate_count", 0),
            }
        )
    if review_retention.get("status") == "attention":
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "review_retention_policy",
                "message": "Review artifact retention pressure is present; inspect candidates before expanding review residue.",
                "count": review_retention.get("candidate_count", 0),
            }
        )
    if output_shape_inventory.get("remaining_count"):
        advisory_signals.append(
            {
                "severity": "advisory",
                "measure": "ordinary_output_shape_inventory",
                "message": "Other ordinary outputs still need primary-decision-object compression slices.",
                "count": output_shape_inventory.get("remaining_count", 0),
            }
        )
    return {
        "kind": "workspace-operational-compression/v1",
        "status": "attention" if advisory_signals else "measured",
        "advisory_only": False,
        "rule": "These measures make surface cost inspectable. They are not a score, workflow engine, dashboard, or host-tracker policy.",
        "measures": measures,
        "signals": advisory_signals,
        "hard_failures": [],
        "review_question": "Did this change remove, merge, compress, route, or background more repeated work than it added?",
        "section_command": "agentic-workspace report --target ./repo --section operational_compression --format json",
    }


