def _memory_command_with_invoke(*, command: str, workspace_cli_invoke: str) -> str:
    command = command.replace("agentic-memory ", "agentic-workspace memory ", 1)
    return str(_command_with_cli_invoke(command=command, cli_invoke=workspace_cli_invoke))


def _memory_payload_commands_with_invoke(*, value: Any, workspace_cli_invoke: str) -> Any:
    if isinstance(value, str):
        return _memory_command_with_invoke(command=value, workspace_cli_invoke=workspace_cli_invoke)
    if isinstance(value, list):
        return [_memory_payload_commands_with_invoke(value=item, workspace_cli_invoke=workspace_cli_invoke) for item in value]
    if isinstance(value, dict):
        return {
            key: _memory_payload_commands_with_invoke(value=nested, workspace_cli_invoke=workspace_cli_invoke)
            for key, nested in value.items()
        }
    return value


def _rewrite_module_cli_commands(value: Any) -> Any:
    if isinstance(value, str):
        value = value.replace("agentic-planning reconcile ", "agentic-workspace reconcile ")
        value = value.replace("agentic-planning summary ", "agentic-workspace summary ")
        value = value.replace("agentic-planning doctor ", "agentic-workspace doctor ")
        value = value.replace("agentic-planning ", "agentic-workspace planning ")
        value = value.replace("agentic-memory ", "agentic-workspace memory ")
        return value
    if isinstance(value, list):
        return [_rewrite_module_cli_commands(item) for item in value]
    if isinstance(value, dict):
        return {key: _rewrite_module_cli_commands(nested) for key, nested in value.items()}
    return value


def _memory_consultation_protocol_payload(
    *,
    consultation_state: str,
    read_first: list[str],
    route_actions: list[dict[str, Any]],
    promotion_pressure: dict[str, Any],
    capture_helper: str,
) -> dict[str, Any]:
    promotion_status = str(promotion_pressure.get("status") or "").strip()
    promotion_samples = _list_payload(promotion_pressure.get("sample"))
    capture_candidate = bool(promotion_samples) or promotion_status in {"attention", "candidate", "promotion-required"}
    route_match_count = len(route_actions)
    if consultation_state == "not-checked":
        durable_residue_decision = "follow_up_required"
    elif capture_candidate:
        durable_residue_decision = "memory"
    elif route_match_count:
        durable_residue_decision = "none_found"
    elif consultation_state == "checked-none":
        durable_residue_decision = "none_found"
    else:
        durable_residue_decision = "none_found"
    return {
        "kind": "agentic-workspace/memory-consultation-protocol/v1",
        "protocol": "Memory Consultation / Anti-Rediscovery",
        "consultation_state": consultation_state,
        "state_vocabulary": [
            "not_checked",
            "checked_none",
            "baseline_only",
            "relevant_notes_found",
            "capture_candidate",
            "routed_elsewhere",
            "dismissed",
            "follow_up_required",
        ],
        "status_mapping": {
            "not_checked": "no Memory route, index, or structured memory surface was inspected",
            "checked_none": "Memory routing was inspected and no relevant note was found",
            "baseline_only": "only the Memory routing baseline or index matched; no task-relevant durable note was found",
            "relevant_notes_found": "existing notes or routes informed the work",
            "capture_candidate": "a durable anti-rediscovery lesson may belong in Memory",
            "routed_elsewhere": "residue belongs in Planning, docs, tests, contracts, config, review, or an issue",
            "dismissed": "the signal is one-off or too weak to keep",
            "follow_up_required": "a later owner or proof must decide the durable route",
        },
        "durable_residue_decision": durable_residue_decision,
        "owner_routing": {
            "memory_when": "durable anti-rediscovery lessons, invariants, routing hints, or recurring failure patterns",
            "planning_when": "active intent, sequencing, continuation, issue linkage, or completion claims",
            "docs_or_contracts_when": "stable canonical guidance, requirements, checks, or enforceable rules",
            "issue_when": "external follow-up work should be routable outside checked-in Planning",
            "dismiss_when": "one-off task detail, transcript residue, validation logs, or weak unrepeated signals",
        },
        "ordinary_read_rule": "Read only routed notes that can change interpretation, safe action, proof, or closeout; do not bulk-read Memory for diligence.",
        "capture_boundary": {
            "allowed": "compact reusable knowledge with future route value",
            "forbidden": [
                "active task state",
                "issue triage",
                "broad documentation copies",
                "chat transcripts",
                "validation logs",
                "plan history",
            ],
            "helper": capture_helper,
        },
        "evidence": {
            "read_first_count": len(read_first),
            "route_match_count": route_match_count,
            "promotion_status": promotion_status,
            "promotion_sample_count": len(promotion_samples),
        },
    }


def _compact_memory_consultation_protocol(value: dict[str, Any]) -> dict[str, Any]:
    return {
        key: value.get(key)
        for key in (
            "protocol",
            "consultation_state",
            "durable_residue_decision",
            "evidence",
        )
        if key in value
    }


def _memory_consult_payload(
    *, target_root: Path, changed_paths: list[str] | None = None, compact: bool = False, cli_invoke: str = DEFAULT_CLI_INVOKE
) -> dict[str, Any]:
    try:
        from repo_memory_bootstrap.installer import memory_report, route_memory
    except ImportError:
        capture_helper = _memory_command_with_invoke(
            command="agentic-workspace memory capture-note --slug <slug> --target ./repo --summary <text> --files <changed paths> --format json",
            workspace_cli_invoke=cli_invoke,
        )
        return {
            "kind": "agentic-workspace/memory-consult/v1",
            "status": "unavailable",
            "consultation_state": "not-checked",
            "reason": "memory module is not importable",
            "read_first": [],
            "max_notes": 0,
            "do_not_bulk_read": True,
            "consultation_protocol": _memory_consultation_protocol_payload(
                consultation_state="not-checked",
                read_first=[],
                route_actions=[],
                promotion_pressure={},
                capture_helper=capture_helper,
            ),
        }
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    if compact:
        read_first = [".agentic-workspace/memory/repo/index.md"]
        route_actions: list[dict[str, Any]] = []
        route_inspection_state = "not_checked"
        route_signal_count = 0
        if normalized_paths:
            route_inspection_state = "checked"
            try:
                route_result = route_memory(target=target_root, files=normalized_paths)
                for action in route_result.actions:
                    if action.role != "memory-route" or action.kind not in {"required", "optional"}:
                        continue
                    source = action.source or action.path.as_posix()
                    if source not in read_first:
                        read_first.append(source)
                    route_actions.append(
                        {"kind": action.kind, "path": source, "reason": action.detail, "match_source": action.match_source}
                    )
                    if action.match_source != "routing-baseline":
                        route_signal_count += 1
            except Exception:
                route_actions = []
                route_inspection_state = "unavailable"
        relevant_route_actions = [action for action in route_actions if action.get("match_source") != "routing-baseline"]
        if route_inspection_state == "unavailable":
            consultation_state = "unavailable"
        elif relevant_route_actions:
            consultation_state = "relevant_notes_found"
        elif route_actions or read_first:
            consultation_state = "baseline_only"
        else:
            consultation_state = "checked_none"
        return {
            "kind": "agentic-workspace/memory-consult/v1",
            "status": "recommended" if read_first else "not-recommended",
            "consultation_state": consultation_state,
            "read_first": read_first[:3],
            "max_notes": 3,
            "do_not_bulk_read": True,
            "changed_path_route_count": len(route_actions),
            "route_inspection_state": route_inspection_state,
            "route_signal_count": route_signal_count,
            "route_matches": route_actions[:3],
            "consultation_protocol": _compact_memory_consultation_protocol(
                _memory_consultation_protocol_payload(
                    consultation_state=consultation_state,
                    read_first=read_first[:3],
                    route_actions=route_actions,
                    promotion_pressure={},
                    capture_helper=_memory_command_with_invoke(
                        command=(
                            "agentic-workspace memory capture-note --slug <slug> --target ./repo "
                            "--summary <text> --files <changed paths> --format json"
                        ),
                        workspace_cli_invoke=cli_invoke,
                    ),
                )
            ),
        }
    try:
        report = memory_report(target=target_root)
    except Exception as exc:
        capture_helper = _memory_command_with_invoke(
            command="agentic-workspace memory capture-note --slug <slug> --target ./repo --summary <text> --files <changed paths> --format json",
            workspace_cli_invoke=cli_invoke,
        )
        return {
            "kind": "agentic-workspace/memory-consult/v1",
            "status": "unavailable",
            "consultation_state": "not-checked",
            "reason": f"memory report failed: {exc}",
            "read_first": [],
            "max_notes": 0,
            "do_not_bulk_read": True,
            "consultation_protocol": _memory_consultation_protocol_payload(
                consultation_state="not-checked",
                read_first=[],
                route_actions=[],
                promotion_pressure={},
                capture_helper=capture_helper,
            ),
        }
    report_payload: dict[str, Any] = cast(dict[str, Any], report) if isinstance(report, dict) else {}
    habitual_raw = report_payload.get("habitual_pull", {})
    habitual_pull: dict[str, Any] = cast(dict[str, Any], habitual_raw) if isinstance(habitual_raw, dict) else {}
    bundle_raw = habitual_pull.get("ordinary_work_bundle", {})
    bundle: dict[str, Any] = cast(dict[str, Any], bundle_raw) if isinstance(bundle_raw, dict) else {}
    always_load = _list_payload(bundle.get("always_load"))
    read_first = [str(path) for path in always_load]
    route_actions: list[dict[str, Any]] = []
    route_inspection_state = "not_checked"
    route_signal_count = 0
    if normalized_paths:
        route_inspection_state = "checked"
        try:
            route_result = route_memory(target=target_root, files=normalized_paths)
            for action in route_result.actions:
                if action.role != "memory-route" or action.kind not in {"required", "optional"}:
                    continue
                source = action.source or action.path.as_posix()
                if source not in read_first:
                    read_first.append(source)
                route_actions.append({"kind": action.kind, "path": source, "reason": action.detail, "match_source": action.match_source})
                if action.match_source != "routing-baseline":
                    route_signal_count += 1
        except Exception:
            route_actions = []
            route_inspection_state = "unavailable"
    max_notes = int(bundle.get("working_set_target", 3) or 3)
    if max_notes > 0:
        read_first = read_first[:max_notes]
    evidence = habitual_pull.get("evidence", {})
    status = str(habitual_pull.get("status", "unavailable"))
    consult_status = (
        "recommended" if read_first and status in {"ready-for-ordinary-work", "attention-needed", "needs-more-proof"} else "not-recommended"
    )
    promotion_pressure = report_payload.get("promotion_pressure", {})
    capture_helper = _memory_command_with_invoke(
        command="agentic-workspace memory capture-note --slug <slug> --target ./repo --summary <text> --files <changed paths> --format json",
        workspace_cli_invoke=cli_invoke,
    )
    relevant_route_actions = [action for action in route_actions if action.get("match_source") != "routing-baseline"]
    if route_inspection_state == "unavailable":
        consultation_state = "unavailable"
    elif relevant_route_actions:
        consultation_state = "relevant_notes_found"
    elif route_actions and read_first:
        consultation_state = "baseline_only"
    elif read_first and route_inspection_state == "not_checked":
        consultation_state = "not_checked"
    elif read_first:
        consultation_state = "baseline_only"
    else:
        consultation_state = "checked_none"
    consultation_protocol = _memory_consultation_protocol_payload(
        consultation_state=consultation_state,
        read_first=read_first,
        route_actions=route_actions,
        promotion_pressure=promotion_pressure if isinstance(promotion_pressure, dict) else {},
        capture_helper=capture_helper,
    )
    payload = {
        "kind": "agentic-workspace/memory-consult/v1",
        "status": consult_status,
        "consultation_state": consultation_state,
        "source": "memory.habitual_pull",
        "why": habitual_pull.get("summary", ""),
        "read_first": read_first,
        "max_notes": max_notes,
        "do_not_bulk_read": True,
        "selection_rule": bundle.get("route_rule", ""),
        "changed_path_route_count": len(route_actions),
        "route_inspection_state": route_inspection_state,
        "route_signal_count": route_signal_count,
        "route_matches": route_actions[:max_notes],
        "evidence": evidence if isinstance(evidence, dict) else {},
        "capture_helper": capture_helper,
        "promotion_pressure": _memory_payload_commands_with_invoke(value=promotion_pressure, workspace_cli_invoke=cli_invoke),
        "consultation_protocol": consultation_protocol,
    }
    if compact:
        payload["consultation_protocol"] = _compact_memory_consultation_protocol(consultation_protocol)
        if consult_status != "recommended":
            return {
                "kind": payload["kind"],
                "status": consult_status,
                "consultation_state": payload["consultation_state"],
                "do_not_bulk_read": True,
            }
        keys = (
            "kind",
            "status",
            "consultation_state",
            "read_first",
            "max_notes",
            "do_not_bulk_read",
            "changed_path_route_count",
            "route_inspection_state",
            "route_signal_count",
            "route_matches",
            "consultation_protocol",
        )
        keys = (*keys, "why", "selection_rule")
        return {key: payload[key] for key in keys if key in payload}
    return payload


_MEMORY_DECISION_OWNER_SURFACES = [
    "repo_memory",
    "local_memory",
    "planning",
    "docs",
    "tests",
    "contracts",
    "config",
    "review",
    "issue",
]
_MEMORY_PULL_STATUSES = {"not_checked", "checked_none", "baseline_only", "relevant_notes_found", "stale", "unavailable", "dismissed"}
_MEMORY_CAPTURE_STATUSES = {
    "not_evaluated",
    "none_found",
    "capture_candidate",
    "routed_elsewhere",
    "dismissed",
    "follow_up_required",
}
_OPERATING_LOOP_KIND = "agentic-workspace/operating-loop-decision/v1"
_OPERATING_LOOP_CLOSEOUT_STATES = {
    "no_closeout_needed",
    "ready_for_full_closure",
    "partial_claim_only",
    "blocked_missing_proof",
    "blocked_active_planning",
    "residue_routing_required",
}
_OPERATING_LOOP_SAFE_CLAIMS = {"none", "full", "partial", "blocked"}
_OPERATING_LOOP_RESIDUE_OWNERS = {"memory", "planning", "verification", "docs", "issue", "config", "none"}
_OPERATING_LOOP_REQUIRED_ACTIONS = {
    "run_or_refresh_proof",
    "continue_or_close_plan",
    "route_memory_residue",
    "route_external_residue",
}
_OPERATING_LOOP_MEMORY_STATES = {"pulled", "dismissed", "not_applicable"}
_OPERATING_LOOP_MEMORY_REASONS = {
    "matched_route",
    "no_relevant_route",
    "not_requested",
    "unavailable",
    "explicitly_dismissed",
}
_OPERATING_LOOP_MEMORY_CAPTURE = {"none", "recommended", "required"}
_OPERATING_LOOP_PLANNING_STATES = {"none", "active", "continuation", "closeout_required", "unrelated_active_plan"}
_OPERATING_LOOP_VERIFICATION_STATES = {
    "proof_not_required",
    "proof_required",
    "proof_selected",
    "proof_missing",
    "proof_stale",
    "proof_skipped",
    "proof_failed",
    "proof_passed",
}
_OPERATING_LOOP_REASON_CODES = {
    "proof_missing",
    "proof_stale",
    "proof_failed",
    "active_plan",
    "plan_closeout_required",
    "memory_capture_required",
    "external_residue",
}


def _first_ref(*values: Any) -> str | None:
    for value in values:
        if isinstance(value, str) and value.strip():
            return value.strip()
        if isinstance(value, dict):
            for key in ("ref", "path", "source", "command", "run", "id"):
                item = value.get(key)
                if isinstance(item, str) and item.strip():
                    return item.strip()
        for item in _list_payload(value):
            ref = _first_ref(item)
            if ref:
                return ref
    return None


def _operating_loop_memory_state(memory_decision_packet: dict[str, Any] | None) -> dict[str, Any]:
    packet = _as_dict(memory_decision_packet)
    pull = _as_dict(packet.get("pull"))
    capture = _as_dict(packet.get("capture"))
    pull_status = str(pull.get("status") or "").strip()
    if pull_status == "relevant_notes_found":
        memory_state = "pulled"
        reason_code = "matched_route"
    elif pull_status in {"checked_none", "baseline_only"}:
        memory_state = "dismissed"
        reason_code = "no_relevant_route"
    elif pull_status in {"stale", "unavailable"}:
        memory_state = "dismissed"
        reason_code = "unavailable"
    elif pull_status == "dismissed":
        memory_state = "dismissed"
        reason_code = "explicitly_dismissed"
    else:
        memory_state = "not_applicable"
        reason_code = "not_requested"

    capture_status = str(capture.get("status") or "").strip()
    if capture_status == "follow_up_required":
        capture_state = "required"
    elif capture_status == "capture_candidate":
        capture_state = "recommended"
    else:
        capture_state = "none"

    return {
        "state": memory_state,
        "reason_code": reason_code,
        "route_ref": _first_ref(pull.get("candidate_routes")),
        "capture": capture_state,
    }


def _operating_loop_planning_state(
    *,
    planning_safety_gate: dict[str, Any] | None = None,
    active_plan_reliance: dict[str, Any] | None = None,
    closeout_trust: dict[str, Any] | None = None,
    active_planning_record: dict[str, Any] | None = None,
) -> dict[str, Any]:
    gate = _as_dict(planning_safety_gate)
    reliance = _as_dict(active_plan_reliance or gate.get("active_plan_reliance"))
    closeout = _as_dict(closeout_trust)
    completion_gate = _as_dict(closeout.get("completion_gate"))
    active_record = _as_dict(active_planning_record)
    plan_ref = _first_ref(
        reliance.get("active_execplan"),
        reliance.get("plan_ref"),
        gate.get("planning_revision"),
        active_record.get("path"),
        active_record.get("id"),
    )

    if str(completion_gate.get("status") or "") in {"blocked", "requires-closeout", "closeout-required"}:
        return {"state": "closeout_required", "plan_ref": plan_ref, "blocks_full_closure": True}
    if _as_int(closeout.get("lower_trust_closeout_count")) > 0 or str(closeout.get("trust") or "") == "lower-trust":
        return {"state": "closeout_required", "plan_ref": plan_ref, "blocks_full_closure": True}
    if gate.get("workflow_sufficient") is False:
        return {"state": "active", "plan_ref": plan_ref, "blocks_full_closure": True}
    custody = _as_dict(gate.get("custody_planning"))
    custody_effect = _as_dict(custody.get("action_effect"))
    if str(custody_effect.get("force") or custody.get("force") or "") == "required_before_claim":
        return {
            "state": "closeout_required",
            "plan_ref": plan_ref or _first_ref(custody.get("issue_refs"), custody.get("reason_codes")),
            "blocks_full_closure": True,
            "custody": "required-before-parent-closeout",
        }
    if str(custody.get("status") or "") == "recommended":
        return {
            "state": "continuation",
            "plan_ref": plan_ref or _first_ref(custody.get("issue_refs"), custody.get("reason_codes")),
            "blocks_full_closure": True,
            "custody": "recommended",
        }
    task_switch = _as_dict(gate.get("task_switch_reconciliation"))
    if (
        str(gate.get("gate_result") or "") == "active-plan-task-switch"
        and gate.get("workflow_sufficient") is True
        and str(task_switch.get("status") or "") == "active"
    ):
        return {"state": "unrelated_active_plan", "plan_ref": plan_ref, "blocks_full_closure": False}
    if str(reliance.get("status") or "") not in {"", "no-active-plan", "not-applicable", "clear", "satisfied"}:
        return {"state": "continuation", "plan_ref": plan_ref, "blocks_full_closure": True}
    if active_record.get("status") == "present":
        return {"state": "active", "plan_ref": plan_ref, "blocks_full_closure": True}
    return {"state": "none", "plan_ref": None, "blocks_full_closure": False}


def _operating_loop_verification_state(
    *,
    proof: dict[str, Any] | None = None,
    closeout_trust: dict[str, Any] | None = None,
) -> dict[str, Any]:
    proof_payload = _as_dict(proof)
    closeout = _as_dict(closeout_trust)
    proof_confidence = _as_dict(closeout.get("proof_confidence"))
    required_commands = _tiny_required_proof_commands(proof_payload) if proof_payload else []
    proof_ref = _first_ref(required_commands, proof_confidence.get("source"), proof_confidence.get("proof_report"))

    status_values = {
        str(proof_payload.get("status") or "").strip(),
        str(proof_payload.get("state") or "").strip(),
        str(proof_confidence.get("status") or "").strip(),
        str(proof_confidence.get("state") or "").strip(),
        str(_as_dict(proof_confidence.get("validation_proof")).get("status") or "").strip(),
    }
    if status_values & {"failed", "proof_failed", "failure"}:
        return {"state": "proof_failed", "proof_ref": proof_ref, "blocks_full_closure": True}
    if status_values & {"stale", "proof_stale"}:
        return {"state": "proof_stale", "proof_ref": proof_ref, "blocks_full_closure": True}
    if status_values & {"skipped", "proof_skipped"}:
        return {"state": "proof_skipped", "proof_ref": proof_ref, "blocks_full_closure": True}
    if status_values & {"passed", "proof_passed", "recorded", "satisfied"}:
        return {"state": "proof_passed", "proof_ref": proof_ref, "blocks_full_closure": False}
    if required_commands:
        return {"state": "proof_missing", "proof_ref": proof_ref, "blocks_full_closure": True}
    if proof_payload:
        required_proof = _as_dict(_as_dict(proof_payload.get("proof_obligations")).get("required_proof"))
        if str(required_proof.get("status") or "") in {"required", "selected"}:
            return {"state": "proof_missing", "proof_ref": proof_ref, "blocks_full_closure": True}
    return {"state": "proof_not_required", "proof_ref": None, "blocks_full_closure": False}


def _operating_loop_decision_payload(
    *,
    claim_context: str = "implement",
    memory_decision_packet: dict[str, Any] | None = None,
    planning_safety_gate: dict[str, Any] | None = None,
    active_plan_reliance: dict[str, Any] | None = None,
    proof: dict[str, Any] | None = None,
    closeout_trust: dict[str, Any] | None = None,
    active_planning_record: dict[str, Any] | None = None,
) -> dict[str, Any]:
    memory = _operating_loop_memory_state(memory_decision_packet)
    planning = _operating_loop_planning_state(
        planning_safety_gate=planning_safety_gate,
        active_plan_reliance=active_plan_reliance,
        closeout_trust=closeout_trust,
        active_planning_record=active_planning_record,
    )
    verification = _operating_loop_verification_state(proof=proof, closeout_trust=closeout_trust)
    reasons: list[dict[str, Any]] = []
    required: list[str] = []

    def add_reason(code: str, owner: str, ref: str | None = None) -> None:
        if code in _OPERATING_LOOP_REASON_CODES and owner in _OPERATING_LOOP_RESIDUE_OWNERS:
            reasons.append({"code": code, "owner": owner, "ref": ref})

    verification_state = str(verification.get("state") or "")
    if verification_state in {"proof_missing", "proof_selected", "proof_required"}:
        closeout_state = "blocked_missing_proof"
        safe_claim = "blocked"
        residue_owner = "verification"
        required.append("run_or_refresh_proof")
        add_reason("proof_missing", "verification", verification.get("proof_ref"))
    elif verification_state == "proof_stale":
        closeout_state = "blocked_missing_proof"
        safe_claim = "blocked"
        residue_owner = "verification"
        required.append("run_or_refresh_proof")
        add_reason("proof_stale", "verification", verification.get("proof_ref"))
    elif verification_state in {"proof_failed", "proof_skipped"}:
        closeout_state = "blocked_missing_proof"
        safe_claim = "blocked"
        residue_owner = "verification"
        required.append("run_or_refresh_proof")
        add_reason(
            "proof_failed" if verification_state == "proof_failed" else "proof_missing", "verification", verification.get("proof_ref")
        )
    elif memory.get("capture") == "required":
        closeout_state = "residue_routing_required"
        safe_claim = "blocked"
        residue_owner = "memory"
        required.append("route_memory_residue")
        add_reason("memory_capture_required", "memory", memory.get("route_ref"))
    elif planning.get("state") == "closeout_required":
        closeout_state = "residue_routing_required"
        safe_claim = "blocked"
        residue_owner = "planning"
        required.append("continue_or_close_plan")
        add_reason("plan_closeout_required", "planning", planning.get("plan_ref"))
    elif planning.get("state") == "active":
        closeout_state = "blocked_active_planning"
        safe_claim = "blocked"
        residue_owner = "planning"
        required.append("continue_or_close_plan")
        add_reason("active_plan", "planning", planning.get("plan_ref"))
    elif planning.get("blocks_full_closure"):
        closeout_state = "partial_claim_only"
        safe_claim = "partial"
        residue_owner = "planning"
        required.append("continue_or_close_plan")
        add_reason("active_plan", "planning", planning.get("plan_ref"))
    elif memory.get("capture") == "recommended":
        closeout_state = "residue_routing_required"
        safe_claim = "partial"
        residue_owner = "memory"
        required.append("route_memory_residue")
        add_reason("memory_capture_required", "memory", memory.get("route_ref"))
    else:
        closeout_state = "ready_for_full_closure" if claim_context == "closeout" else "no_closeout_needed"
        safe_claim = "full" if claim_context == "closeout" else "none"
        residue_owner = "none"

    return {
        "kind": _OPERATING_LOOP_KIND,
        "closeout_state": closeout_state,
        "safe_claim": safe_claim,
        "residue_owner": residue_owner,
        "required_before_full_closure": _dedupe([item for item in required if item in _OPERATING_LOOP_REQUIRED_ACTIONS]),
        "memory": memory,
        "planning": planning,
        "verification": verification,
        "reasons": reasons,
    }


def _operating_loop_text_lines(packet: dict[str, Any] | None) -> list[str]:
    loop = _as_dict(packet)
    if loop.get("kind") != _OPERATING_LOOP_KIND:
        return []
    memory = _as_dict(loop.get("memory"))
    planning = _as_dict(loop.get("planning"))
    verification = _as_dict(loop.get("verification"))
    required = _list_payload(loop.get("required_before_full_closure"))
    required_text = ",".join((str(item) for item in required)) or "none"
    return [
        "loop: "
        f"Memory {memory.get('state', 'not_applicable')} · "
        f"Planning {planning.get('state', 'none')} · "
        f"Verification {verification.get('state', 'proof_not_required')}",
        "closeout: "
        f"{loop.get('closeout_state')} · "
        f"claim {loop.get('safe_claim')} · "
        f"owner {loop.get('residue_owner')} · "
        f"required {required_text}",
    ]


def _emit_implement_text(payload: dict[str, Any]) -> None:
    for line in _operating_loop_text_lines(payload.get("operating_loop") if isinstance(payload.get("operating_loop"), dict) else None):
        print(line)
    next_payload = _as_dict(payload.get("next"))
    action = str(next_payload.get("action") or next_payload.get("summary") or "").strip()
    if action:
        print(f"next: {action}")
    commands = [str(item) for item in _list_payload(next_payload.get("commands")) if str(item).strip()]
    if commands:
        print(f"proof: {commands[0]}")
        if len(commands) > 1:
            print(f"proof_more: {len(commands) - 1}")
    elif proof_payload := _as_dict(payload.get("proof")):
        proof_commands = [str(item) for item in _list_payload(proof_payload.get("required_commands")) if str(item).strip()]
        if proof_commands:
            print(f"proof: {proof_commands[0]}")
            if len(proof_commands) > 1:
                print(f"proof_more: {len(proof_commands) - 1}")
        elif proof_detail := str(proof_payload.get("detail_command") or "").strip():
            print(f"proof_detail: {proof_detail}")
    drill_down = _as_dict(payload.get("drill_down"))
    selectors = [str(item) for item in _list_payload(drill_down.get("available_selectors")) if str(item).strip()]
    if selectors:
        print("selectors: " + ", ".join(selectors[:8]))
    detail_command = str(drill_down.get("detail_command") or "").strip()
    if detail_command:
        print(f"detail: {detail_command}")


def _memory_route_command(
    *,
    cli_invoke: str,
    stage: str,
    task_text: str | None = None,
    changed_paths: list[str] | None = None,
) -> str:
    parts = ["agentic-workspace memory route --target .", f"--stage {stage}"]
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    if normalized_paths:
        parts.append("--files " + " ".join(normalized_paths))
    if task_text and task_text.strip():
        parts.append('--task "<task>"')
    parts.append("--format json")
    return _command_with_cli_invoke(command=" ".join(parts), cli_invoke=cli_invoke)


def _memory_capture_command(
    *,
    cli_invoke: str,
    task_text: str | None = None,
    changed_paths: list[str] | None = None,
) -> str:
    parts = ["agentic-workspace memory capture-note --target . --slug <slug> --summary <text>"]
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    if normalized_paths:
        parts.append("--files " + " ".join(normalized_paths))
    if task_text and task_text.strip():
        parts.append('--task "<task>"')
    parts.append("--format json")
    return _command_with_cli_invoke(command=" ".join(parts), cli_invoke=cli_invoke)


def _memory_decision_packet_payload(
    *,
    stage: str,
    cli_invoke: str,
    memory_consult: dict[str, Any] | None = None,
    changed_paths: list[str] | None = None,
    task_text: str | None = None,
    closeout_trust: dict[str, Any] | None = None,
    routine_work_context: dict[str, Any] | None = None,
    force: str | None = None,
) -> dict[str, Any]:
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    consult = _as_dict(memory_consult)
    closeout = _as_dict(closeout_trust)
    routine = _as_dict(routine_work_context)
    observed: list[str] = []
    recommends: list[str] = []
    if consult.get("status") == "recommended":
        observed.append("Memory consult reports routeable repository Memory is available.")
        recommends.append("Inspect route-matched Memory before decisions where durable knowledge may affect work shape.")
    if int(consult.get("changed_path_route_count", 0) or 0) > 0:
        observed.append("Changed paths produced Memory route matches.")
    if normalized_paths:
        observed.append("Changed paths are available for selector-backed Memory routing.")
    if closeout:
        observed.append("Closeout trust state is visible for residue and completion-claim review.")
    residue = closeout.get("durable_residue_action", {}) if isinstance(closeout, dict) else {}
    lower_trust_count = _as_int(closeout.get("lower_trust_closeout_count"))
    durable_pressure = bool(
        closeout.get("memory_decision_required")
        or lower_trust_count > 0
        or str(closeout.get("trust") or "").strip() in {"lower-trust", "unavailable"}
        or _as_int(closeout.get("promotion_candidate_count")) > 0
    )
    residue_action = str(residue.get("action") or "").strip() if isinstance(residue, dict) else ""
    residue_owner = str(
        (residue.get("owner") if isinstance(residue, dict) else "")
        or (residue.get("residue_owner") if isinstance(residue, dict) else "")
        or (residue.get("destination") if isinstance(residue, dict) else "")
        or (residue.get("route_to") if isinstance(residue, dict) else "")
        or ""
    ).strip()
    explicit_pull_status = str(closeout.get("memory_pull_status") or consult.get("pull_status") or "").strip()
    explicit_capture_status = str(closeout.get("memory_capture_status") or consult.get("capture_status") or "").strip()
    if isinstance(residue, dict) and residue_action and durable_pressure:
        recommends.append(
            "Before closeout, decide whether reusable learning should be captured, routed elsewhere, dismissed, or left unwritten."
        )
    if routine:
        for item in _list_payload(routine.get("cards")):
            if isinstance(item, dict) and str(item.get("fronted_by", "")) in {"memory_consult", "closeout_trust"}:
                observed.append(f"Routine work context fronts {item.get('fronted_by')} for this stage.")
                break

    if force is None:
        if stage == "closeout":
            force = "required_at_closeout" if durable_pressure else "not_applicable"
        elif normalized_paths and (consult.get("status") == "recommended" or int(consult.get("changed_path_route_count", 0) or 0) > 0):
            force = "recommended_before_work"
        elif consult.get("status") == "recommended":
            force = "recommended_before_work"
        else:
            force = "not_applicable"

    route_matches = [
        {
            "path": item.get("path") or item.get("source"),
            "kind": item.get("kind"),
            "reason": item.get("reason") or item.get("detail"),
            "match_source": item.get("match_source"),
        }
        for item in _list_payload(consult.get("route_matches"))
        if isinstance(item, dict)
    ]
    relevant_route_matches = [item for item in route_matches if item.get("match_source") != "routing-baseline"]
    route_inspection_state = str(consult.get("route_inspection_state") or "not_checked")
    route_signal_count = _as_int(consult.get("route_signal_count"))
    pull_status = explicit_pull_status if explicit_pull_status in _MEMORY_PULL_STATUSES else "not_checked"
    if pull_status == "not_checked" and consult.get("status") == "unavailable":
        pull_status = "unavailable"
    elif pull_status == "not_checked" and route_inspection_state == "unavailable":
        pull_status = "unavailable"
    elif pull_status == "not_checked" and route_inspection_state == "checked" and (route_signal_count > 0 or relevant_route_matches):
        pull_status = "relevant_notes_found"
    elif pull_status == "not_checked" and (
        route_inspection_state == "baseline_only" or (route_inspection_state == "checked" and route_matches and not relevant_route_matches)
    ):
        pull_status = "baseline_only"
    elif pull_status == "not_checked" and route_inspection_state == "checked":
        pull_status = "checked_none"

    capture_status = explicit_capture_status if explicit_capture_status in _MEMORY_CAPTURE_STATUSES else "not_evaluated"
    if capture_status == "not_evaluated" and stage == "closeout" and force == "not_applicable":
        capture_status = "none_found"
    elif capture_status == "not_evaluated" and stage == "closeout" and residue_action in {"dismissed", "dismiss", "no-action"}:
        capture_status = "dismissed"
    elif (
        capture_status == "not_evaluated"
        and stage == "closeout"
        and residue_owner
        and residue_owner.lower()
        not in {"memory", "repo_memory", "local_memory", ".agentic-workspace/memory", ".agentic-workspace/memory/repo"}
    ):
        capture_status = "routed_elsewhere"
    elif capture_status == "not_evaluated" and stage == "closeout" and _as_int(closeout.get("promotion_candidate_count")) > 0:
        capture_status = "capture_candidate"
    elif capture_status == "not_evaluated" and stage == "closeout" and force == "required_at_closeout":
        capture_status = "follow_up_required"
    elif capture_status == "not_evaluated" and normalized_paths:
        capture_status = "not_evaluated"

    if not observed:
        observed.append("No structured Memory or closeout signal requires a Memory decision.")
    if not recommends:
        recommends.append("Treat Memory as optional unless route inspection or closeout residue changes the work.")

    return {
        "kind": "agentic-workspace/memory-decision-packet/v1",
        "stage": stage,
        "force": force,
        "why_visible": (
            "Memory pull/capture is surfaced as an explicit agent decision; AW provides selector-backed commands and facts, not semantic conclusions."
        ),
        "pull": {
            "status": pull_status,
            "recommended_command": _memory_route_command(
                cli_invoke=cli_invoke,
                stage=stage,
                task_text=task_text,
                changed_paths=normalized_paths,
            ),
            "alternate_commands": [],
            "candidate_routes": route_matches,
            "read_budget": "selector",
            "agent_decision_required": force != "not_applicable",
        },
        "capture": {
            "status": capture_status,
            "allowed_outcomes": [
                "capture",
                "update_existing",
                "route_elsewhere",
                "dismiss",
                "follow_up_required",
            ],
            "candidate_owner_surfaces": list(_MEMORY_DECISION_OWNER_SURFACES),
            "recommended_commands": [_memory_capture_command(cli_invoke=cli_invoke, task_text=task_text, changed_paths=normalized_paths)]
            if force != "not_applicable"
            else [],
            "agent_decision_required": force in {"required_before_claim", "required_at_closeout"},
        },
        "authority_boundary": {
            "aw_observes": observed,
            "aw_recommends": recommends,
            "agent_owns": [
                "whether Memory is relevant to the current decision",
                "whether reusable learning exists",
                "whether residue belongs in Memory or a different owner surface",
            ],
            "human_owns": ["intent changes", "accepted narrowing", "policy decisions not already present in repo-owned guidance"],
        },
        "limits": [
            "No keyword-triggered Memory requirement.",
            "No hidden Memory writes.",
            "No bulk-read diligence claim.",
        ],
    }


def _compact_memory_decision_packet(packet: Any) -> dict[str, Any]:
    full = _as_dict(packet)
    pull = _as_dict(full.get("pull"))
    capture = _as_dict(full.get("capture"))
    candidate_routes = _list_payload(pull.get("candidate_routes"))
    relevant_routes = [
        item for item in candidate_routes if isinstance(item, dict) and str(item.get("match_source") or "").strip() != "routing-baseline"
    ]
    compact_pull: dict[str, Any] = {
        "status": pull.get("status"),
        "recommended_command": pull.get("recommended_command"),
        "route_count": len(candidate_routes),
        "relevant_route_count": len(relevant_routes),
        "read_budget": pull.get("read_budget"),
        "agent_decision_required": pull.get("agent_decision_required"),
    }
    if relevant_routes:
        compact_pull["candidate_routes"] = relevant_routes
    compact_capture: dict[str, Any] = {
        "status": capture.get("status"),
        "outcome_count": len(_list_payload(capture.get("allowed_outcomes"))),
        "recommended_commands": capture.get("recommended_commands", []),
        "candidate_owner_surface_count": len(_list_payload(capture.get("candidate_owner_surfaces"))),
        "agent_decision_required": capture.get("agent_decision_required"),
    }
    return {
        "kind": full.get("kind"),
        "label": "knowledge",
        "provenance": "memory",
        "stage": full.get("stage"),
        "force": full.get("force"),
        "why_visible": "Explicit agent-owned Memory pull/capture decision.",
        "pull": {key: value for key, value in compact_pull.items() if value is not None},
        "capture": {key: value for key, value in compact_capture.items() if value is not None},
        "detail_visibility": "details stay behind verbose implement context",
    }


def _memory_consult_from_payload(payload: dict[str, Any]) -> dict[str, Any]:
    memory_consult = payload.get("memory_consult", {})
    return memory_consult if isinstance(memory_consult, dict) else {}


def _maintenance_pressure_payload(
    *, report_payload: dict[str, Any], module_reports: list[dict[str, Any]], findings: list[dict[str, Any]]
) -> dict[str, Any]:
    planning_report = next((report for report in module_reports if isinstance(report, dict) and report.get("module") == "planning"), {})
    planning_report = planning_report if isinstance(planning_report, dict) else {}
    closeout_trust = report_payload.get("closeout_trust", {})
    closeout_trust = closeout_trust if isinstance(closeout_trust, dict) else {}
    external_work_delta = report_payload.get("external_work_delta", {})
    external_work_delta = external_work_delta if isinstance(external_work_delta, dict) else {}
    operational_compression = report_payload.get("operational_compression", {})
    operational_compression = operational_compression if isinstance(operational_compression, dict) else {}
    operational_measures = operational_compression.get("measures", {})
    operational_measures = operational_measures if isinstance(operational_measures, dict) else {}
    intent_validation = planning_report.get("intent_validation", {}) if isinstance(planning_report, dict) else {}
    intent_counts = intent_validation.get("counts", {}) if isinstance(intent_validation, dict) else {}
    finished_work = planning_report.get("finished_work_inspection", {}) if isinstance(planning_report, dict) else {}
    finished_counts = finished_work.get("counts", {}) if isinstance(finished_work, dict) else {}
    historical_reviews = closeout_trust.get("historical_review_artifacts", {})
    historical_reviews = historical_reviews if isinstance(historical_reviews, dict) else {}
    archived_distillation = operational_measures.get("archived_plan_distillation", {})
    archived_distillation = archived_distillation if isinstance(archived_distillation, dict) else {}
    adapter_lifecycle = operational_measures.get("adapter_surface_lifecycle", {})
    adapter_lifecycle = adapter_lifecycle if isinstance(adapter_lifecycle, dict) else {}
    closeout_check = closeout_trust.get("intent_satisfaction_check", {})
    closeout_check = closeout_check if isinstance(closeout_check, dict) else {}

    def _category(*, category_id: str, status: str, count: int, summary: str, detail_section: str, selector_hint: str) -> dict[str, Any]:
        return {
            "id": category_id,
            "status": status,
            "count": count,
            "summary": summary,
            "detail_section": detail_section,
            "section_command": f"agentic-workspace report --target ./repo --section {detail_section} --format json",
            "selector_hint": selector_hint,
        }

    warning_count = len(findings)
    historical_attention_count = _as_int(finished_counts.get("attention_count")) + _as_int(intent_counts.get("closeout_needs_audit_count"))
    archive_only_residue_count = _as_int(finished_counts.get("archive_only_durable_residue_count"))
    review_item_count = _as_int(historical_reviews.get("item_count"))
    review_retention = historical_reviews.get("retention_policy", {})
    review_retention = review_retention if isinstance(review_retention, dict) else {}
    review_retention_count = _as_int(review_retention.get("candidate_count"))
    archive_missing_count = _as_int(archived_distillation.get("post_contract_missing_distillation_count"))
    adapter_missing_count = _as_int(adapter_lifecycle.get("missing_removal_path_count"))
    external_changed_count = _as_int(external_work_delta.get("changed_count")) + _as_int(external_work_delta.get("closed_count"))
    lower_trust_count = _as_int(closeout_trust.get("lower_trust_closeout_count"))
    followup_required = str(closeout_check.get("trust", "")) == "follow-up-required"
    subcategories = [
        _category(
            category_id="current_state_stale",
            status="attention" if warning_count else "quiet",
            count=warning_count,
            summary="Current report findings are present." if warning_count else "No current report findings are present.",
            detail_section="findings",
            selector_hint="Inspect only when warning_summary or this category is attention.",
        ),
        _category(
            category_id="historical_audit",
            status="attention" if historical_attention_count else "backgrounded",
            count=historical_attention_count,
            summary="Historical audit or finished-work inspection has attention signals."
            if historical_attention_count
            else "Historical audit detail is backgrounded behind planning module selectors.",
            detail_section="module_reports",
            selector_hint="Use full profile or module reports only for audit work.",
        ),
        _category(
            category_id="archive_only_residue",
            status="attention" if archive_only_residue_count else "quiet",
            count=archive_only_residue_count,
            summary="Archived closeout residue needs routing to Memory, docs, contracts, checks, or planning."
            if archive_only_residue_count
            else "No archive-only durable residue signals are present.",
            detail_section="module_reports",
            selector_hint="Route residue to a stronger owner instead of reading more archive history.",
        ),
        _category(
            category_id="review_retention",
            status="attention" if review_retention_count else "evidence-only" if review_item_count else "quiet",
            count=review_retention_count or review_item_count,
            summary="Review artifact retention has advisory cleanup candidates."
            if review_retention_count
            else "Historical review artifacts are evidence/history, not ordinary operating input.",
            detail_section="closeout_trust",
            selector_hint="Inspect when a selected issue or audit path asks for review history.",
        ),
        _category(
            category_id="archive_retention",
            status="attention" if archive_missing_count else "measured",
            count=archive_missing_count,
            summary="Some post-contract archived execplans lack closeout distillation."
            if archive_missing_count
            else "Archive-retention pressure is measured in operational compression detail.",
            detail_section="operational_compression",
            selector_hint="Inspect for archive footprint or retention cleanup work.",
        ),
        _category(
            category_id="generated_output_footprint",
            status="attention" if adapter_missing_count else "measured",
            count=adapter_missing_count,
            summary="Some adapter/generated surfaces lack removal-path metadata."
            if adapter_missing_count
            else "Generated and adapter surface footprint is measured as detail.",
            detail_section="operational_compression",
            selector_hint="Inspect before expanding generated or adapter surfaces.",
        ),
        _category(
            category_id="external_evidence_stale",
            status="attention" if external_changed_count else str(external_work_delta.get("status", "unavailable")),
            count=external_changed_count,
            summary="External-work evidence changed since the previous snapshot."
            if external_changed_count
            else "External-work evidence is a routed snapshot/detail signal.",
            detail_section="external_work_delta",
            selector_hint="Inspect when external issue intake, closure, or refresh state matters.",
        ),
        _category(
            category_id="closeout_reconciliation",
            status="attention" if lower_trust_count or followup_required else "quiet",
            count=lower_trust_count + (1 if followup_required else 0),
            summary="Closeout reconciliation needs attention before treating broad work as closed."
            if lower_trust_count or followup_required
            else "No lower-trust closeout reconciliation signals are present.",
            detail_section="closeout_trust",
            selector_hint="Inspect before broad-work closeout or package-use trust review.",
        ),
    ]
    active = [item for item in subcategories if item["status"] in {"attention", "evidence-only"}]
    attention_count = sum((1 for item in subcategories if item["status"] == "attention"))
    if attention_count:
        status = "attention"
        recommended_next_action = (
            "Continue current execution first; inspect maintenance-pressure detail only when the active lane needs residue cleanup."
        )
    elif active:
        status = "evidence-only"
        recommended_next_action = "Treat maintenance residue as background evidence unless the current task selects it."
    else:
        status = "quiet"
        recommended_next_action = "No maintenance-pressure detail is needed for ordinary work."
    return {
        "kind": "workspace-maintenance-pressure/v1",
        "status": status,
        "rule": "One compact router for audit, retention, footprint, external-evidence, and closeout residue; current execution pressure stays separate.",
        "current_execution_separate": True,
        "attention_category_count": attention_count,
        "active_category_count": len(active),
        "subcategories": subcategories,
        "detail_sections": sorted({str(item["detail_section"]) for item in subcategories}),
        "recommended_next_action": recommended_next_action,
    }


def _missing_metadata_fields(record: dict[str, Any], *, required: tuple[str, ...]) -> list[str]:
    missing: list[str] = []
    for field in required:
        if field == "authority":
            value = record.get("authority") or record.get("authority_class")
        else:
            value = record.get(field)
        if not str(value or "").strip():
            missing.append(field)
    return missing


def _archived_plan_distillation_measure(*, target: Any) -> dict[str, Any]:
    target_text = str(target or "").strip()
    if not target_text:
        return {
            "archived_plan_count": 0,
            "with_distillation_count": 0,
            "missing_distillation_count": 0,
            "legacy_missing_distillation_count": 0,
            "post_contract_missing_distillation_count": 0,
            "distillation_contract_anchor": "",
            "sample_missing_distillation": [],
            "sample_post_contract_missing_distillation": [],
        }
    archive_dir = Path(target_text) / ".agentic-workspace" / "planning" / "execplans" / "archive"
    if not archive_dir.exists():
        return {
            "archived_plan_count": 0,
            "with_distillation_count": 0,
            "missing_distillation_count": 0,
            "legacy_missing_distillation_count": 0,
            "post_contract_missing_distillation_count": 0,
            "distillation_contract_anchor": "",
            "sample_missing_distillation": [],
            "sample_post_contract_missing_distillation": [],
        }
    archived_plans = [path for path in sorted(archive_dir.glob("*.plan.json")) if path.is_file()]
    missing: list[str] = []
    missing_with_mtime: list[tuple[str, float]] = []
    distillation_anchors: list[tuple[str, float]] = []
    with_distillation = 0
    for path in archived_plans:
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            missing.append(path.name)
            continue
        distillation = payload.get("closeout_distillation") if isinstance(payload, dict) else None
        buckets = distillation.get("buckets", {}) if isinstance(distillation, dict) else {}
        if isinstance(buckets, dict) and any((_list_payload(buckets.get(bucket)) for bucket in buckets)):
            with_distillation += 1
            distillation_anchors.append((path.name, path.stat().st_mtime))
        else:
            missing.append(path.name)
            missing_with_mtime.append((path.name, path.stat().st_mtime))
    anchor_name = ""
    anchor_mtime: float | None = None
    if distillation_anchors:
        anchor_name, anchor_mtime = min(distillation_anchors, key=lambda item: item[1])
    legacy_missing = [name for name, mtime in missing_with_mtime if anchor_mtime is None or mtime < anchor_mtime]
    post_contract_missing = [name for name, mtime in missing_with_mtime if anchor_mtime is not None and mtime >= anchor_mtime]
    return {
        "archived_plan_count": len(archived_plans),
        "with_distillation_count": with_distillation,
        "missing_distillation_count": len(missing),
        "legacy_missing_distillation_count": len(legacy_missing),
        "post_contract_missing_distillation_count": len(post_contract_missing),
        "distillation_contract_anchor": anchor_name,
        "sample_missing_distillation": missing[:5],
        "sample_post_contract_missing_distillation": post_contract_missing[:5],
    }


def _archive_retention_policy(*, archived_distillation: dict[str, Any], artifact_footprint: dict[str, Any]) -> dict[str, Any]:
    archived_count = _as_int(archived_distillation.get("archived_plan_count"))
    legacy_missing = _as_int(archived_distillation.get("legacy_missing_distillation_count"))
    post_contract_missing = _as_int(archived_distillation.get("post_contract_missing_distillation_count"))
    footprint_classes = _list_payload(artifact_footprint.get("classes"))
    archived_footprint = next((item for item in footprint_classes if isinstance(item, dict) and item.get("id") == "archived_execplans"), {})
    footprint_pressure = str(archived_footprint.get("pressure", "quiet")) if isinstance(archived_footprint, dict) else "quiet"
    sample_missing = _list_payload(archived_distillation.get("sample_missing_distillation"))
    sample_post_contract = _list_payload(archived_distillation.get("sample_post_contract_missing_distillation"))
    candidates: list[dict[str, Any]] = []
    if post_contract_missing:
        candidates.append(
            {
                "signal": "post-contract-missing-distillation",
                "count": post_contract_missing,
                "recommended_outcome": "promote-summary-elsewhere",
                "candidate_paths": sample_post_contract[:5],
                "why": "Recent archives without closeout distillation should first route durable learning to Memory, docs, contracts, checks, or issues.",
            }
        )
    if legacy_missing:
        candidates.append(
            {
                "signal": "legacy-missing-distillation",
                "count": legacy_missing,
                "recommended_outcome": "stub",
                "candidate_paths": sample_missing[:5],
                "why": "Legacy archives without distillation are candidates for retain-or-stub review after durable facts are promoted elsewhere.",
            }
        )
    if footprint_pressure == "attention":
        candidates.append(
            {
                "signal": "archive-footprint-threshold",
                "count": archived_count,
                "recommended_outcome": "shrink",
                "candidate_paths": _list_payload(archived_footprint.get("sample"))[:5] if isinstance(archived_footprint, dict) else [],
                "why": "Archive count is high enough to merit selector-driven review before adding more residue.",
            }
        )
    return {
        "kind": "workspace-archive-retention-policy/v1",
        "status": "attention" if candidates else "quiet",
        "advisory_only": True,
        "applies_to": ".agentic-workspace/planning/execplans/archive/*.plan.json",
        "outcomes": ["retain", "shrink", "stub", "delete", "promote-summary-elsewhere"],
        "default_outcome": "retain",
        "candidate_count": len(candidates),
        "candidates": candidates,
        "before_shrink_or_delete": [
            "promote durable learning to Memory, docs, contracts, checks, or issues",
            "preserve enough evidence for restart, review, trust, and continuation",
            "keep ordinary startup and active planning out of archive history",
        ],
        "rule": "Retention pressure is advisory and selector-driven; it recommends review outcomes but never deletes archived evidence automatically.",
    }


def _artifact_footprint_by_class(*, target: Any) -> dict[str, Any]:
    target_text = str(target or "").strip()
    if not target_text:
        return {
            "status": "unavailable",
            "classes": [],
            "pressure_class_count": 0,
            "recommended_cleanup_target": {},
            "rule": "Footprint classes are advisory and selector-driven; they do not delete artifacts.",
        }
    target_root = Path(target_text)

    def _count_files(relative: str, pattern: str = "*") -> tuple[int, list[str]]:
        root = target_root / relative
        if not root.exists():
            return (0, [])
        files = [
            path
            for path in repository_scan_files(
                target_root,
                relative_roots=[relative],
                include_untracked=True,
                include_managed_workspace=True,
            )
            if fnmatch.fnmatch(path.name, pattern)
        ]
        return (len(files), [_relative_posix(path, target_root) for path in files[:5]])

    def _top_level_plan_count() -> tuple[int, list[str]]:
        root = target_root / ".agentic-workspace" / "planning" / "execplans"
        if not root.exists():
            return (0, [])
        files = sorted((path for path in root.glob("*.plan.json") if path.is_file() and path.name not in {"TEMPLATE.plan.json"}))
        return (len(files), [_relative_posix(path, target_root) for path in files[:5]])

    def _durable_memory_notes() -> tuple[int, list[str]]:
        root = target_root / ".agentic-workspace" / "memory" / "repo"
        if not root.exists():
            return (0, [])
        files = [
            path
            for path in repository_scan_files(
                target_root,
                relative_roots=[".agentic-workspace/memory/repo"],
                include_untracked=True,
                include_managed_workspace=True,
                suffixes={".md"},
            )
            if ".agentic-workspace/memory/repo/current/" not in _relative_posix(path, target_root)
        ]
        return (len(files), [_relative_posix(path, target_root) for path in files[:5]])

    def _large_docs() -> tuple[int, list[str]]:
        config = config_lib.load_workspace_config(target_root=target_root)
        candidates = [path for path in [target_root / "README.md", target_root / config.agent_instructions_file] if path.is_file()]
        docs_root = target_root / "docs"
        if docs_root.exists():
            candidates.extend((path for path in docs_root.rglob("*.md") if path.is_file()))
        large: list[Path] = []
        for path in sorted(candidates):
            try:
                line_count = len(path.read_text(encoding="utf-8").splitlines())
            except OSError:
                continue
            if line_count > 400:
                large.append(path)
        return (len(large), [_relative_posix(path, target_root) for path in large[:5]])

    active_count, active_sample = _top_level_plan_count()
    archive_count, archive_sample = _count_files(".agentic-workspace/planning/execplans/archive", "*.plan.json")
    planning_review_count, planning_review_sample = _count_files(".agentic-workspace/planning/reviews", "*.review.json")
    docs_review_count, docs_review_sample = _count_files("docs/reviews")
    current_memory_count, current_memory_sample = _count_files(".agentic-workspace/memory/repo/current")
    durable_memory_count, durable_memory_sample = _durable_memory_notes()
    generated_files = _generated_output_files(target_root=target_root)
    generated_count = len(generated_files)
    generated_sample = [_relative_posix(path, target_root) for path in generated_files[:5]]
    local_count, local_sample = _count_files(".agentic-workspace/local")
    large_docs_count, large_docs_sample = _large_docs()
    classes = [
        _artifact_class(
            class_id="active_execplans",
            role="live operating state",
            count=active_count,
            sample=active_sample,
            pressure="attention" if active_count > 1 else "quiet",
            review_target=active_sample[0] if active_count > 1 and active_sample else "",
        ),
        _artifact_class(
            class_id="archived_execplans",
            role="historical evidence",
            count=archive_count,
            sample=archive_sample,
            pressure="attention" if archive_count > 100 else "measured",
            review_target=".agentic-workspace/planning/execplans/archive/" if archive_count > 100 else "",
        ),
        _artifact_class(
            class_id="review_artifacts",
            role="historical evidence",
            count=planning_review_count + docs_review_count,
            sample=(planning_review_sample + docs_review_sample)[:5],
            pressure="attention" if planning_review_count + docs_review_count else "quiet",
            review_target=(planning_review_sample + docs_review_sample)[0] if planning_review_count + docs_review_count else "",
        ),
        _artifact_class(
            class_id="current_memory_notes",
            role="legacy or optional calibration",
            count=current_memory_count,
            sample=current_memory_sample,
            pressure="attention" if current_memory_count else "quiet",
            review_target=current_memory_sample[0] if current_memory_sample else "",
        ),
        _artifact_class(
            class_id="durable_memory_notes",
            role="durable knowledge",
            count=durable_memory_count,
            sample=durable_memory_sample,
            pressure="measured" if durable_memory_count else "quiet",
            review_target="",
        ),
        _artifact_class(
            class_id="generated_outputs",
            role="derived reproducible artifact",
            count=generated_count,
            sample=generated_sample,
            pressure="measured" if generated_count else "quiet",
            review_target=generated_sample[0] if generated_sample else "",
        ),
        _artifact_class(
            class_id="local_only_state",
            role="local-only state",
            count=local_count,
            sample=local_sample,
            pressure="measured" if local_count else "quiet",
            review_target="",
        ),
        _artifact_class(
            class_id="large_docs_or_package_surfaces",
            role="large reference surface",
            count=large_docs_count,
            sample=large_docs_sample,
            pressure="attention" if large_docs_count else "quiet",
            review_target=large_docs_sample[0] if large_docs_sample else "",
        ),
    ]
    pressure_classes = [item for item in classes if item["pressure"] == "attention"]
    recommended = next((item for item in pressure_classes if item.get("review_target")), None)
    return {
        "status": "attention" if pressure_classes else "measured",
        "classes": classes,
        "pressure_class_count": len(pressure_classes),
        "recommended_cleanup_target": {
            "class_id": recommended["id"],
            "path": recommended["review_target"],
            "action": "review-shrink-route-or-retain",
        }
        if recommended
        else {},
        "rule": "Footprint classes are advisory and selector-driven; they do not delete artifacts.",
    }


def _artifact_class(*, class_id: str, role: str, count: int, sample: list[str], pressure: str, review_target: str) -> dict[str, Any]:
    return {"id": class_id, "role": role, "count": count, "pressure": pressure, "sample": sample, "review_target": review_target}


def _generated_output_files(*, target_root: Path) -> list[Path]:
    candidates = [
        path
        for path in repository_scan_files(
            target_root,
            relative_roots=["generated"],
            include_untracked=True,
            include_managed_workspace=False,
        )
        if not _is_runtime_cache_file(path)
    ]
    return sorted({path.resolve(): path for path in candidates}.values(), key=lambda path: path.as_posix())


def _is_runtime_cache_file(path: Path) -> bool:
    parts = set(path.parts)
    return "__pycache__" in parts or path.suffix in {".pyc", ".pyo"}


def _generated_output_footprint(*, target: Any) -> dict[str, Any]:
    target_text = str(target or "").strip()
    if not target_text:
        return {
            "kind": "workspace-generated-output-footprint/v1",
            "status": "unavailable",
            "artifact_count": 0,
            "generated_surfaces": [],
            "unclassified_generated_output_count": 0,
            "rule": "Generated outputs are derived reproducible footprint, not hand-authored operating state.",
        }
    target_root = Path(target_text)
    generated_files = _generated_output_files(target_root=target_root)
    generated_relatives = [_relative_posix(path, target_root) for path in generated_files]
    command_package_ir_path = target_root / "src" / "agentic_workspace" / "contracts" / "command_package_ir.json"
    command_adapter_generation_path = target_root / "src" / "agentic_workspace" / "contracts" / "command_adapter_generation.json"
    generator_path = target_root / "scripts" / "generate" / "generate_command_packages.py"
    check_path = target_root / "scripts" / "check" / "check_generated_command_packages.py"
    declared_roots: list[str] = []
    generated_surfaces: list[dict[str, Any]] = []
    role_counts: dict[str, int] = {}
    ir_payload: dict[str, Any] = {}
    if command_package_ir_path.is_file():
        try:
            loaded = json.loads(command_package_ir_path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            loaded = {}
        ir_payload = loaded if isinstance(loaded, dict) else {}
    for package in _list_payload(ir_payload.get("packages")):
        if not isinstance(package, dict):
            continue
        package_id = str(package.get("id") or "")
        program = str(package.get("program") or "")
        for target_info in _list_payload(package.get("targets")):
            if not isinstance(target_info, dict):
                continue
            root = str(target_info.get("generated_root") or "").strip().replace("\\", "/")
            if not root:
                continue
            declared_roots.append(root.rstrip("/") + "/")
            files = [path for path in generated_relatives if _relative_is_under(path, root)]
            role = _generated_target_role(target_info)
            role_counts[role] = role_counts.get(role, 0) + 1
            generated_surfaces.append(
                {
                    "id": f"{package_id}:{target_info.get('kind', '')}",
                    "program": program,
                    "kind": str(target_info.get("kind") or ""),
                    "generated_root": root,
                    "generation_status": str(target_info.get("generation_status") or ""),
                    "maturity_level_ref": str(target_info.get("maturity_level_ref") or ""),
                    "test_environment": str(target_info.get("test_environment") or ""),
                    "role": role,
                    "file_count": len(files),
                    "sample": files[:3],
                    "ordinary_startup_surface": False,
                }
            )
    declared_outputs: list[str] = []
    if command_adapter_generation_path.is_file():
        try:
            adapter_payload = json.loads(command_adapter_generation_path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            adapter_payload = {}
        if isinstance(adapter_payload, dict):
            for output in _list_payload(adapter_payload.get("generated_outputs")):
                if isinstance(output, dict):
                    path = str(output.get("path") or "").strip().replace("\\", "/")
                    if not path:
                        continue
                    declared_outputs.append(path)
                    role_counts["generated-dispatch-adapter"] = role_counts.get("generated-dispatch-adapter", 0) + 1
                    generated_surfaces.append(
                        {
                            "id": f"{output.get('program', '')}:generated-dispatch-adapter",
                            "program": str(output.get("program") or ""),
                            "kind": "python",
                            "generated_root": path,
                            "generation_status": "generated",
                            "maturity_level_ref": "generated-dispatch-adapter",
                            "test_environment": "python-dev",
                            "role": "generated-dispatch-adapter",
                            "file_count": 1 if path in generated_relatives else 0,
                            "sample": [path] if path in generated_relatives else [],
                            "ordinary_startup_surface": False,
                        }
                    )
    support_artifacts = [
        path for path in generated_relatives if path in {"generated/typescript.Dockerfile", "generated/typescript.conformance.Dockerfile"}
    ]
    if support_artifacts:
        role_counts["proof-container-support"] = role_counts.get("proof-container-support", 0) + len(support_artifacts)
        generated_surfaces.append(
            {
                "id": "typescript:proof-container-support",
                "program": "generated-typescript-packages",
                "kind": "docker",
                "generated_root": "generated",
                "generation_status": "proof-support",
                "maturity_level_ref": "proof-container-support",
                "test_environment": "docker",
                "role": "proof-container-support",
                "file_count": len(support_artifacts),
                "sample": support_artifacts[:3],
                "ordinary_startup_surface": False,
            }
        )
    classified = set(declared_outputs) | set(support_artifacts)
    for root in declared_roots:
        classified.update((path for path in generated_relatives if _relative_is_under(path, root)))
    unclassified = [path for path in generated_relatives if path not in classified]
    freshness_missing = not (generator_path.is_file() and check_path.is_file() and command_package_ir_path.is_file())
    runnable_count = sum(
        (1 for surface in generated_surfaces if surface.get("role") in {"runnable-read-only-adapter", "weak-agent-safe-adapter"})
    )
    weak_agent_safe_count = sum((1 for surface in generated_surfaces if surface.get("role") == "weak-agent-safe-adapter"))
    proof_fixture_count = sum((1 for surface in generated_surfaces if surface.get("role") == "proof-fixture"))
    status = "attention" if freshness_missing or unclassified else "measured"
    return {
        "kind": "workspace-generated-output-footprint/v1",
        "status": status,
        "advisory_only": True,
        "artifact_count": len(generated_relatives),
        "declared_surface_count": len(generated_surfaces),
        "role_counts": role_counts,
        "proof_fixture_count": proof_fixture_count,
        "runnable_adapter_count": runnable_count,
        "weak_agent_safe_adapter_count": weak_agent_safe_count,
        "unclassified_generated_output_count": len(unclassified),
        "sample_unclassified_generated_outputs": unclassified[:5],
        "freshness": {
            "status": "check-available" if not freshness_missing else "missing-check-or-source",
            "source_contract": "src/agentic_workspace/contracts/command_package_ir.json",
            "regeneration_command": "uv run python scripts/generate/generate_command_packages.py",
            "freshness_check": "uv run python scripts/check/check_generated_command_packages.py",
            "docker_proof": "uv run python scripts/check/check_generated_command_packages.py --docker --docker-conformance",
            "ordinary_report_runs_checks": False,
        },
        "guardrails": [
            "Generated outputs are reproducible derived artifacts, not durable hand-authored operating state.",
            "Weak-agent routing follows generated package maturity; proof fixtures are not runnable startup surfaces.",
            "No-direct-edit and freshness proof belong in generated package checks, not ordinary report execution.",
        ],
        "generated_surfaces": generated_surfaces[:12],
        "omitted_generated_surface_count": max(0, len(generated_surfaces) - 12),
        "rule": "Generated-output footprint is selector-driven advisory evidence; inspect it before expanding generated targets or compatibility artifacts.",
    }


def _relative_is_under(path: str, root: str) -> bool:
    normalized_path = path.replace("\\", "/")
    normalized_root = root.strip("/").replace("\\", "/")
    return normalized_path == normalized_root or normalized_path.startswith(normalized_root + "/")


def _generated_target_role(target_info: dict[str, Any]) -> str:
    status = str(target_info.get("generation_status") or "").lower()
    maturity = str(target_info.get("maturity_level_ref") or "").lower()
    if status == "deferred" or maturity == "deferred":
        return "deferred-target"
    if "weak-agent-safe" in status or "weak-agent-safe" in maturity:
        return "weak-agent-safe-adapter"
    if "runnable" in status or "runnable" in maturity:
        return "runnable-read-only-adapter"
    if "fixture" in status or "fixture" in maturity or "supported-now" in status:
        return "proof-fixture"
    return "generated-target"


def _relative_posix(path: Path, target_root: Path) -> str:
    try:
        return path.relative_to(target_root).as_posix()
    except ValueError:
        return path.as_posix()


def _list_payload(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


def _as_int(value: Any) -> int:
    try:
        return int(value)
    except (TypeError, ValueError):
        return 0


def _report_profile_payload(*, cli_invoke: str = DEFAULT_CLI_INVOKE) -> dict[str, Any]:
    return report_profile_payload(context_router=_context_router_family_payload(cli_invoke=cli_invoke, compact=True), cli_invoke=cli_invoke)


def _as_dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


def _routine_count(value: Any) -> int:
    return _as_int(value)


def _workflow_obligation_match_count(workflow_obligations: dict[str, Any]) -> int:
    match_evidence = _as_dict(workflow_obligations.get("match_evidence"))
    if "match_count" in match_evidence:
        return _routine_count(match_evidence.get("match_count"))
    return _routine_count(workflow_obligations.get("match_count"))


def _routine_detail_command(*, section: str, cli_invoke: str, target_arg: str = "./repo") -> str:
    command = f"agentic-workspace report --target {target_arg} --section {section} --format json"
    return _command_with_cli_invoke(command=command, cli_invoke=cli_invoke) or command


def _memory_manifest_notes(target_root: Path | None) -> dict[str, dict[str, Any]]:
    if target_root is None:
        return {}
    manifest_path = target_root / ".agentic-workspace/memory/repo/manifest.toml"
    if not manifest_path.is_file():
        return {}
    try:
        manifest = tomllib.loads(manifest_path.read_text(encoding="utf-8"))
    except (OSError, tomllib.TOMLDecodeError):
        return {}
    notes = manifest.get("notes", {})
    if not isinstance(notes, dict):
        return {}
    return {str(path): note for path, note in notes.items() if isinstance(note, dict)}


def _note_glob_matches(*, changed_paths: list[str], patterns: Any) -> list[dict[str, str]]:
    matches: list[dict[str, str]] = []
    for pattern in [str(item) for item in _list_payload(patterns) if str(item).strip()]:
        for changed_path in changed_paths:
            if fnmatch.fnmatch(changed_path, pattern):
                matches.append({"path": changed_path, "pattern": pattern})
                break
    return matches


def _architecture_principles_payload(
    *,
    target_root: Path | None,
    changed_paths: list[str] | None,
    cli_invoke: str,
    compact: bool = False,
) -> dict[str, Any]:
    surface_path = ".agentic-workspace/system-intent/intent.toml"
    if target_root is None:
        return {"kind": "agentic-workspace/architecture-principles-status/v1", "status": "unavailable", "matched_count": 0}
    path = target_root / surface_path
    if not path.is_file():
        return {
            "kind": "agentic-workspace/architecture-principles-status/v1",
            "status": "not-configured",
            "matched_count": 0,
            "source": surface_path,
        }
    try:
        document = tomllib.loads(path.read_text(encoding="utf-8-sig"))
    except (OSError, tomllib.TOMLDecodeError, UnicodeDecodeError) as exc:
        return {
            "kind": "agentic-workspace/architecture-principles-status/v1",
            "status": "unavailable",
            "matched_count": 0,
            "source": surface_path,
            "error": str(exc),
        }
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    matched: list[dict[str, Any]] = []
    for principle in _list_payload(document.get("architecture_principles")):
        if not isinstance(principle, dict):
            continue
        path_matches = _note_glob_matches(changed_paths=normalized_paths, patterns=principle.get("path_globs"))
        if normalized_paths and not path_matches:
            continue
        principle_id = str(principle.get("id", "")).strip()
        if not principle_id:
            continue
        matched.append(
            {
                "id": principle_id,
                "title": str(principle.get("title", "")).strip(),
                "owner": str(principle.get("owner", "")).strip(),
                "authority": str(principle.get("authority", document.get("authority", ""))).strip(),
                "source": surface_path,
                "source_kind": str(document.get("kind", "")),
                "summary": str(principle.get("summary", "")).strip(),
                "derived_from": [str(item) for item in _list_payload(principle.get("derived_from"))],
                "allowed_sources": [str(item) for item in _list_payload(principle.get("allowed_sources"))],
                "forbidden_sources": [str(item) for item in _list_payload(principle.get("forbidden_sources"))],
                "affected_decisions": [str(item) for item in _list_payload(principle.get("affected_decisions"))],
                "matched_paths": path_matches,
                "matcher": {
                    "kind": "path_glob",
                    "patterns": [str(item) for item in _list_payload(principle.get("path_globs"))],
                    "reason": "changed path matched declared architecture_principles.path_globs",
                },
                "guardrail_refs": [str(item) for item in _list_payload(principle.get("guardrail_refs"))],
                "derived_applications": [str(item) for item in _list_payload(principle.get("derived_applications"))],
                "guardrails": [
                    {
                        "id": str(guardrail.get("id", "")).strip(),
                        "summary": str(guardrail.get("summary", "")).strip(),
                        "guardrail_refs": [str(item) for item in _list_payload(guardrail.get("guardrail_refs"))],
                    }
                    for guardrail in _list_payload(principle.get("guardrails"))
                    if isinstance(guardrail, dict) and str(guardrail.get("id", "")).strip()
                ],
                "proof_expectation": str(principle.get("proof_expectation", "")).strip(),
                "review_aids": [str(item) for item in _list_payload(principle.get("review_aids"))],
                "claim_boundary": str(principle.get("claim_boundary") or "architecture-principle-preservation-claim-required").strip(),
                "closeout_question": (
                    "Was this principle preserved for the matching changed paths, or did the human owner explicitly re-scope it?"
                ),
            }
        )
    status = "attention" if matched else "clear" if normalized_paths else "available"
    payload: dict[str, Any] = {
        "kind": "agentic-workspace/architecture-principles-status/v1",
        "status": status,
        "source": surface_path,
        "source_kind": str(document.get("kind", "")),
        "owner": "repo-system-intent",
        "relationship_to_system_intent": "Architecture principles are typed subsections of the normalized system-intent record.",
        "matched_count": len(matched),
        "matched_principles": matched,
        "closeout": {
            "status": "explicit-claim-required" if matched else "not-applicable",
            "required_claim": "preserved|re-scoped-by-human|unresolved" if matched else "",
            "rule": "Principle matches are owner-surface evidence; the agent owns the preservation judgment and must not infer it from passing tests alone.",
        },
        "authority_boundary": _authority_boundary_payload(
            surface="architecture_principles",
            observed_by_aw=[
                f"source={surface_path}",
                f"changed_path_count={len(normalized_paths)}",
                f"matched_count={len(matched)}",
            ],
            recommended_by_aw=["consider matched architecture principles before implementation or closeout claims"],
            proof_hints=[str(item.get("proof_expectation", "")) for item in matched if item.get("proof_expectation")],
            agent_owned_decisions=[
                "whether the principle is semantically relevant to the change",
                "whether the implementation preserves, re-scopes, or leaves the principle unresolved",
            ],
            human_owned_decisions=["architecture principle changes or accepted re-scoping"],
            rule="AW routes declared principle metadata by structured path matches; it does not infer policy from prose keywords.",
        ),
    }
    if compact:
        if not matched:
            return {
                "kind": payload["kind"],
                "status": status,
                "matched_count": 0,
                "source": surface_path,
                "source_kind": payload["source_kind"],
            }
        return {
            "kind": payload["kind"],
            "status": status,
            "matched_count": len(matched),
            "source": surface_path,
            "source_kind": payload["source_kind"],
            "relationship_to_system_intent": payload["relationship_to_system_intent"],
            "matched_principles": [
                {
                    "id": item["id"],
                    "title": item["title"],
                    "owner": item["owner"],
                    "authority": item["authority"],
                    "matched_paths": item["matched_paths"],
                    "matcher": item["matcher"],
                    "guardrail_refs": item["guardrail_refs"],
                    "derived_applications": item["derived_applications"],
                    "guardrails": item["guardrails"],
                    "proof_expectation": item["proof_expectation"],
                    "review_aids": item["review_aids"],
                    "claim_boundary": item["claim_boundary"],
                    "closeout_question": item["closeout_question"],
                }
                for item in matched
            ],
            "closeout": payload["closeout"],
        }
    return payload


def _note_task_matches(*, task_text: str | None, values: Any) -> list[str]:
    if not task_text:
        return []
    haystack = task_text.lower()
    matches = []
    for value in [str(item).strip() for item in _list_payload(values) if str(item).strip()]:
        if value.lower() in haystack:
            matches.append(value)
    return matches


def _memory_promotion_pressure_samples(source_payload: dict[str, Any]) -> list[dict[str, Any]]:
    samples: list[dict[str, Any]] = []
    module_reports = _list_payload(source_payload.get("module_reports"))
    memory_report = next((report for report in module_reports if isinstance(report, dict) and report.get("module") == "memory"), {})
    memory_report = memory_report if isinstance(memory_report, dict) else {}
    memory_consult = _as_dict(source_payload.get("memory_consult"))
    candidate_sources = [
        _as_dict(memory_report.get("promotion_pressure")),
        _as_dict(_as_dict(memory_report.get("habitual_pull")).get("promotion_pressure")),
        _as_dict(memory_consult.get("promotion_pressure")),
    ]
    seen: set[str] = set()
    for source in candidate_sources:
        for item in _list_payload(source.get("sample")):
            if not isinstance(item, dict):
                continue
            path = str(item.get("path", "")).strip()
            if not path or path in seen:
                continue
            seen.add(path)
            samples.append(item)
    return samples


def _knowledge_authority_review_payload(
    *,
    target_root: Path | None,
    source_payload: dict[str, Any],
    changed_paths: list[str] | None,
    task_text: str | None,
    cli_invoke: str,
    compact: bool,
) -> dict[str, Any]:
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    notes = _memory_manifest_notes(target_root)
    route_matches = {
        str(match.get("path", "")).strip(): match
        for match in _list_payload(_as_dict(source_payload.get("memory_consult")).get("route_matches"))
        if isinstance(match, dict) and str(match.get("path", "")).strip()
    }
    promotion_samples = {str(item.get("path", "")).strip(): item for item in _memory_promotion_pressure_samples(source_payload)}
    matched_sources: list[dict[str, Any]] = []
    for note_path, note in notes.items():
        route_pattern_matches = _note_glob_matches(changed_paths=normalized_paths, patterns=note.get("routes_from"))
        stale_pattern_matches = _note_glob_matches(changed_paths=normalized_paths, patterns=note.get("stale_when"))
        applies_matches = _note_glob_matches(changed_paths=normalized_paths, patterns=note.get("applies_to"))
        task_matches = [
            *_note_task_matches(task_text=task_text, values=note.get("surfaces")),
            *_note_task_matches(task_text=task_text, values=note.get("subsystems")),
            *_note_task_matches(task_text=task_text, values=note.get("use_when")),
        ]
        promotion_sample = promotion_samples.get(note_path)
        applies_because = []
        if note_path in route_matches:
            applies_because.append(str(route_matches[note_path].get("reason") or "memory route matched current scope"))
        applies_because.extend(f"changed path matched route {match['pattern']}" for match in route_pattern_matches)
        applies_because.extend(f"changed path matched stale_when {match['pattern']}" for match in stale_pattern_matches)
        applies_because.extend(f"changed path matched applies_to {match['pattern']}" for match in applies_matches)
        applies_because.extend(f"task text matched {match}" for match in task_matches)
        canonicality = str(note.get("canonicality", "")).strip()
        memory_role = str(note.get("memory_role", "")).strip()
        promotion_target = str(note.get("promotion_target") or note.get("preferred_remediation") or "").strip()
        promotion_trigger = str(note.get("promotion_trigger") or note.get("improvement_note") or "").strip()
        promotion_candidate = bool(
            promotion_sample
            or canonicality == "candidate_for_promotion"
            or memory_role == "improvement_signal"
            or note.get("improvement_candidate") is True
            or promotion_target
        )
        superseded = canonicality in {"canonical_elsewhere", "deprecated"}
        if not applies_because and not promotion_sample:
            continue
        freshness_status = "needs-review" if stale_pattern_matches else "not-triggered"
        source = {
            "id": f"memory:{note_path}",
            "owner_surface": note_path,
            "authority": str(note.get("authority", "unknown")),
            "canonicality": canonicality or "unknown",
            "canonical_home": str(note.get("canonical_home", note_path)),
            "applies_because": _dedupe(applies_because)[:4],
            "evidence": [str(item) for item in _list_payload(note.get("evidence"))][:3],
            "freshness": {
                "status": freshness_status,
                "matched_stale_when": [match["pattern"] for match in stale_pattern_matches],
            },
            "promotion_pressure": {
                "status": "candidate" if promotion_candidate else "none",
                "target": promotion_target or (promotion_sample.get("promotion_target", "") if isinstance(promotion_sample, dict) else ""),
                "trigger": promotion_trigger,
            },
            "supersession": {
                "status": "attention" if superseded else "none",
                "why": "Memory manifest says canonicality is deprecated or canonical elsewhere." if superseded else "",
            },
            "claim_effect": {
                "blocks": [],
                "advises": [
                    item
                    for item in (
                        "review memory freshness before relying on this note" if freshness_status == "needs-review" else "",
                        "route promotion or dismissal during closeout" if promotion_candidate else "",
                    )
                    if item
                ],
            },
            "authority_boundary": _authority_boundary_payload(
                surface="knowledge_authority_review.memory_source",
                observed_by_aw=[
                    "Memory manifest metadata",
                    "Memory route/use_when/task-relevance match evidence",
                ],
                recommended_by_aw=["read or review the matched Memory owner surface when agent judgment finds it relevant"],
                agent_owned_decisions=[
                    "whether the matched Memory fact is semantically relevant to the task",
                    "whether to rely on, refresh, promote, or ignore the matched note",
                ],
                human_owned_decisions=["semantic acceptance of repo knowledge when Memory evidence conflicts with current intent"],
                rule="Memory matches are Memory-owned configured or learned evidence; AW reports the match and does not classify user intent.",
            ),
        }
        matched_sources.append(source)
        if len(matched_sources) >= 5:
            break
    for sample in promotion_samples.values():
        path = str(sample.get("path", "")).strip()
        if not path or any(source["owner_surface"] == path for source in matched_sources):
            continue
        matched_sources.append(
            {
                "id": f"memory:{path}",
                "owner_surface": path,
                "authority": "unknown",
                "canonicality": "unknown",
                "applies_because": ["memory promotion pressure sample"],
                "freshness": {"status": "not-triggered", "matched_stale_when": []},
                "promotion_pressure": {
                    "status": "candidate",
                    "target": str(sample.get("promotion_target") or sample.get("preferred_remediation") or ""),
                    "trigger": str(sample.get("improvement_note") or ""),
                },
                "supersession": {"status": "none", "why": ""},
                "claim_effect": {"blocks": [], "advises": ["route promotion or dismissal during closeout"]},
                "authority_boundary": _authority_boundary_payload(
                    surface="knowledge_authority_review.memory_source",
                    observed_by_aw=["Memory promotion pressure sample"],
                    recommended_by_aw=["route or dismiss the Memory promotion pressure"],
                    agent_owned_decisions=["whether the promotion pressure is semantically relevant to the current task"],
                    rule="Memory promotion pressure is Memory-owned evidence; AW does not classify user intent from it.",
                ),
            }
        )
        if len(matched_sources) >= 5:
            break
    stale_count = sum(1 for source in matched_sources if source.get("freshness", {}).get("status") == "needs-review")
    promotion_count = sum(1 for source in matched_sources if source.get("promotion_pressure", {}).get("status") == "candidate")
    supersession_count = sum(1 for source in matched_sources if source.get("supersession", {}).get("status") == "attention")
    workflow_matches = _workflow_obligation_match_count(_as_dict(source_payload.get("workflow_obligations")))
    status = "attention" if matched_sources or workflow_matches else "present"
    payload: dict[str, Any] = {
        "kind": "agentic-workspace/knowledge-authority-review/v1",
        "status": status,
        "matched_source_count": len(matched_sources),
        "workflow_obligation_match_count": workflow_matches,
        "stale_source_count": stale_count,
        "promotion_candidate_count": promotion_count,
        "supersession_attention_count": supersession_count,
        "rule": "Compose existing Memory metadata, workflow obligations, proof, and closeout effects; do not create a new knowledge owner.",
        "authority_boundary": _authority_boundary_payload(
            surface="knowledge_authority_review",
            observed_by_aw=["Memory manifest metadata", "workflow obligation match facts", "promotion pressure samples"],
            recommended_by_aw=["inspect matched owner surfaces before relying on durable repo knowledge"],
            agent_owned_decisions=[
                "semantic relevance of matched Memory/config evidence",
                "whether matched evidence changes the implementation or closeout decision",
            ],
            human_owned_decisions=["final semantic acceptance when matched durable knowledge conflicts with user intent"],
            rule="AW assembles Memory/config evidence and owner surfaces; it does not make semantic task classifications.",
        ),
        "next_actions": [],
    }
    if promotion_count:
        payload["next_actions"].append(
            {
                "id": "route-memory-promotion-pressure",
                "owner": "Memory/docs/config/checks/ADR as named by the source",
                "command": _memory_command_with_invoke(
                    command="agentic-workspace memory promotion-report --target ./repo --mode remediation --format json",
                    workspace_cli_invoke=cli_invoke,
                ),
            }
        )
    if stale_count:
        payload["next_actions"].append(
            {
                "id": "review-memory-freshness",
                "owner": "Memory",
                "command": _memory_command_with_invoke(
                    command="agentic-workspace memory sync-memory --target ./repo --files <changed paths> --format json",
                    workspace_cli_invoke=cli_invoke,
                ),
            }
        )
    if workflow_matches:
        payload["next_actions"].append(
            {
                "id": "inspect-workflow-obligations",
                "owner": "workspace config",
                "command": _command_with_cli_invoke(
                    command="agentic-workspace report --target ./repo --section workflow_obligations --format json",
                    cli_invoke=cli_invoke,
                ),
            }
        )
    if compact:
        if status != "attention":
            return {"kind": payload["kind"], "status": status}
        return {
            key: payload[key]
            for key in (
                "kind",
                "status",
                "matched_source_count",
                "workflow_obligation_match_count",
                "stale_source_count",
                "promotion_candidate_count",
                "supersession_attention_count",
                "next_actions",
            )
            if key in payload
        }
    payload["matched_sources"] = matched_sources
    return payload


def _routine_work_context_payload(
    *,
    source_payload: dict[str, Any],
    surface: str,
    cli_invoke: str,
    target_arg: str = "./repo",
    target_root: Path | None = None,
    changed_paths: list[str] | None = None,
    task_text: str | None = None,
    compact: bool = False,
) -> dict[str, Any]:
    """Assemble routine work router categories from existing owner surfaces.

    This is intentionally a projection. It does not own Memory, Planning, ADR,
    assurance, workflow-obligation, proof, or closeout state.
    """

    workflow_obligations = _as_dict(source_payload.get("workflow_obligations"))
    assurance_requirements = _as_dict(source_payload.get("assurance_requirements"))
    verification = _as_dict(source_payload.get("verification"))
    durable_intent = _as_dict(source_payload.get("durable_intent"))
    durable_subsystem = _as_dict(durable_intent.get("subsystem_intent"))
    memory_consult = _as_dict(source_payload.get("memory_consult"))
    architecture_principles = _as_dict(source_payload.get("architecture_principles"))
    decision_pressure = _as_dict(source_payload.get("decision_pressure"))
    closeout_trust = _as_dict(source_payload.get("closeout_trust"))
    closeout_inspection = _as_dict(source_payload.get("closeout_trust_inspection"))
    task_promotion = _as_dict(source_payload.get("durable_intent_promotion"))
    improvement_intake = _as_dict(source_payload.get("improvement_intake"))
    external_work = _as_dict(source_payload.get("external_work_reconciliation"))
    effective_authority = _as_dict(source_payload.get("effective_authority"))
    next_action = _as_dict(
        source_payload.get("next_action") or source_payload.get("immediate_next_allowed_action") or source_payload.get("next")
    )
    proof = _as_dict(source_payload.get("proof"))
    active_state = _as_dict(source_payload.get("active_state_summary"))
    execution_shape = _as_dict(source_payload.get("execution_shape"))

    assurance_active = _routine_count(assurance_requirements.get("active_count"))
    assurance_missing = _routine_count(assurance_requirements.get("missing_required_evidence_count"))
    verification_active = _routine_count(verification.get("active_count"))
    verification_missing = len(
        [
            item
            for item in _list_payload(verification.get("evidence_status"))
            if isinstance(item, dict) and item.get("state") == "missing-evidence"
        ]
    )
    workflow_matches = _workflow_obligation_match_count(workflow_obligations)
    architecture_principle_matches = _routine_count(architecture_principles.get("matched_count"))
    durable_matches = _routine_count(durable_subsystem.get("matched_count"))
    improvement_candidates = len(_list_payload(improvement_intake.get("improvement_signal_candidates")))
    lower_trust_count = _routine_count(closeout_trust.get("lower_trust_closeout_count"))
    proof_commands = _list_payload(proof.get("required_commands") or proof.get("required_validation_commands"))
    knowledge_review = _knowledge_authority_review_payload(
        target_root=target_root,
        source_payload=source_payload,
        changed_paths=changed_paths,
        task_text=task_text,
        cli_invoke=cli_invoke,
        compact=compact,
    )

    decision_status = str(decision_pressure.get("status", "unknown"))
    task_promotion_status = str(task_promotion.get("status", "unknown"))
    memory_status = str(memory_consult.get("status", "unknown"))
    closeout_status = str(closeout_trust.get("status") or closeout_inspection.get("status") or "unknown")
    external_status = str(external_work.get("status", "unknown"))
    active_work_status = str(active_state.get("planning_status") or execution_shape.get("status") or "unknown")

    categories = {
        "authority": {
            "question": "What source, policy, or owner governs this work?",
            "status": "attention"
            if assurance_active or workflow_matches or verification_active or architecture_principle_matches
            else "available",
            "fronts": [
                "effective_authority",
                "architecture_principles",
                "authority_hierarchy",
                "standing_intent",
                "workflow_obligations",
                "assurance_requirements",
                "verification",
                "decision_pressure",
            ],
            "signals": {
                "workflow_obligation_matches": workflow_matches,
                "architecture_principle_matches": architecture_principle_matches,
                "active_assurance_requirements": assurance_active,
                "active_verification_protocols": verification_active,
                "effective_authority_status": effective_authority.get("status", "unknown"),
                "decision_pressure_status": decision_status,
            },
            "detail_selectors": [
                "effective_authority",
                "architecture_principles",
                "authority_hierarchy",
                "workflow_obligations",
                "assurance_requirements",
                "verification",
                "decision_pressure",
            ],
        },
        "active_work": {
            "question": "What is live, done, blocked, delegated, or waiting?",
            "status": "attention"
            if active_state.get("todo_active_count") or active_state.get("active_execplan") or external_status == "attention"
            else "available",
            "fronts": ["next_action", "active_state_summary", "execution_shape", "continuation_state", "external_work_reconciliation"],
            "signals": {
                "active_state_status": active_work_status,
                "todo_active_count": _routine_count(active_state.get("todo_active_count")),
                "has_active_execplan": bool(active_state.get("active_execplan")),
                "external_work_status": external_status,
                "next_action": next_action.get("action") or next_action.get("summary") or "",
            },
            "detail_selectors": [
                "next_action",
                "active_state_summary",
                "execution_shape",
                "continuation_state",
                "external_work_reconciliation",
            ],
        },
        "evidence_proof": {
            "question": "What must be shown before a completion claim is safe?",
            "status": "attention" if assurance_missing or verification_missing or workflow_matches or lower_trust_count else "available",
            "fronts": ["proof", "verification", "assurance_requirements", "workflow_obligations", "closeout_trust", "completion_options"],
            "signals": {
                "proof_command_count": len(proof_commands),
                "active_verification_protocols": verification_active,
                "missing_verification_evidence": verification_missing,
                "active_assurance_requirements": assurance_active,
                "missing_required_assurance_evidence": assurance_missing,
                "workflow_obligation_matches": workflow_matches,
                "closeout_status": closeout_status,
                "lower_trust_closeout_count": lower_trust_count,
            },
            "detail_selectors": ["proof", "verification", "assurance_requirements", "workflow_obligations", "closeout_trust"],
        },
        "durable_knowledge": {
            "question": "What durable knowledge applies here that future agents should not rediscover?",
            "status": "attention"
            if _routine_count(memory_consult.get("changed_path_route_count"))
            or _routine_count(knowledge_review.get("matched_source_count"))
            or durable_matches
            else "available",
            "fronts": ["memory_consult", "knowledge_authority_review", "durable_intent", "standing_intent", "system_intent_mirror"],
            "signals": {
                "memory_consult_status": memory_status,
                "memory_read_first": memory_consult.get("read_first", []),
                "durable_intent_status": durable_intent.get("status", "unknown"),
                "subsystem_intent_matches": durable_matches,
                "knowledge_authority_sources": knowledge_review.get("matched_source_count", 0),
                "stale_knowledge_sources": knowledge_review.get("stale_source_count", 0),
            },
            "detail_selectors": [
                "memory_consult",
                "knowledge_authority_review",
                "durable_intent",
                "standing_intent",
                "system_intent_mirror",
            ],
        },
        "promotion_residue": {
            "question": "What should move to a stronger owner, become follow-up, or be dismissed?",
            "status": "attention"
            if task_promotion_status == "candidate"
            or decision_status == "attention"
            or improvement_candidates
            or lower_trust_count
            or _routine_count(knowledge_review.get("promotion_candidate_count"))
            or _routine_count(knowledge_review.get("supersession_attention_count"))
            else "available",
            "fronts": [
                "durable_intent_promotion",
                "improvement_intake",
                "decision_pressure",
                "closeout_trust",
                "memory promotion metadata",
            ],
            "signals": {
                "task_intent_promotion_status": task_promotion_status,
                "decision_pressure_status": decision_status,
                "improvement_candidate_count": improvement_candidates,
                "closeout_lower_trust_count": lower_trust_count,
                "knowledge_promotion_candidates": knowledge_review.get("promotion_candidate_count", 0),
                "knowledge_supersession_attention": knowledge_review.get("supersession_attention_count", 0),
            },
            "detail_selectors": [
                "durable_intent_promotion",
                "knowledge_authority_review",
                "improvement_intake",
                "decision_pressure",
                "closeout_trust",
            ],
        },
    }
    attention_categories = [key for key, value in categories.items() if value.get("status") == "attention"]
    status = "attention" if attention_categories else "present"

    payload: dict[str, Any] = {
        "kind": "agentic-workspace/routine-work-context/v1",
        "status": status,
        "surface": surface,
        "authority": "assembled-view",
        "rule": "Separate canonical owners internally; compress ordinary agent routing into routine work questions.",
        "categories": categories,
        "attention_categories": attention_categories,
        "knowledge_authority_review": knowledge_review,
        "activation": {
            "default_rule": "Surface compact categories in routine router views; keep owner detail behind selectors and report sections.",
            "small_work_rule": "If no category is attention, this projection is guidance and must not block direct bounded work.",
            "detail_command": _routine_detail_command(section="routine_work_context", cli_invoke=cli_invoke, target_arg=target_arg),
        },
    }
    if compact:
        if surface == "report":
            return {
                "kind": payload["kind"],
            }
        compact_signal_allowlist = {
            "authority": [
                "workflow_obligation_matches",
                "architecture_principle_matches",
                "active_assurance_requirements",
                "effective_authority_status",
                "decision_pressure_status",
            ],
            "active_work": [
                "active_state_status",
                "todo_active_count",
                "has_active_execplan",
                "external_work_status",
            ],
            "evidence_proof": [
                "proof_command_count",
                "active_verification_protocols",
                "missing_verification_evidence",
                "workflow_obligation_matches",
                "missing_required_assurance_evidence",
                "lower_trust_closeout_count",
            ],
            "durable_knowledge": [
                "memory_consult_status",
                "durable_intent_status",
                "subsystem_intent_matches",
                "knowledge_authority_sources",
                "stale_knowledge_sources",
            ],
            "promotion_residue": [
                "task_intent_promotion_status",
                "decision_pressure_status",
                "improvement_candidate_count",
                "closeout_lower_trust_count",
                "knowledge_promotion_candidates",
                "knowledge_supersession_attention",
            ],
        }
        compact_categories: dict[str, Any] = {}
        for key, value in categories.items():
            if not isinstance(value, dict) or value.get("status") != "attention":
                continue
            signals = value.get("signals", {})
            signal_payload = signals if isinstance(signals, dict) else {}
            compact_categories[key] = {
                "status": value.get("status"),
                "signals": {
                    signal_key: signal_payload.get(signal_key)
                    for signal_key in compact_signal_allowlist[key]
                    if signal_payload.get(signal_key) not in (None, "", [], {}, 0, False)
                },
            }
        compact_payload = {
            "kind": payload["kind"],
            "status": status,
            "surface": surface,
            "authority": "assembled-view",
            "categories": compact_categories,
        }
        if knowledge_review.get("status") == "attention":
            compact_payload["knowledge_authority_review"] = knowledge_review
        return compact_payload

    payload["owner_surface_inventory"] = [
        {
            "concept": "Memory",
            "category": "durable_knowledge",
            "classification": "canonical owner surface",
            "fronted_by": "memory_consult",
            "detail_selector": "memory_consult",
        },
        {
            "concept": "Planning",
            "category": "active_work",
            "classification": "canonical owner surface",
            "fronted_by": "active_state_summary / external_work_reconciliation",
            "detail_selector": "active_state_summary",
        },
        {
            "concept": "standing intent / effective authority",
            "category": "authority",
            "classification": "authority projection",
            "fronted_by": "effective_authority / authority_hierarchy",
            "detail_selector": "effective_authority",
        },
        {
            "concept": "assurance requirements",
            "category": "authority + evidence_proof",
            "classification": "canonical config-owned evidence gate",
            "fronted_by": "assurance_requirements",
            "detail_selector": "assurance_requirements",
        },
        {
            "concept": "workflow obligations",
            "category": "authority + evidence_proof",
            "classification": "canonical config-owned lifecycle obligation",
            "fronted_by": "workflow_obligations",
            "detail_selector": "workflow_obligations",
        },
        {
            "concept": "decision pressure / ADR routing",
            "category": "authority + promotion_residue",
            "classification": "router/projection concept",
            "fronted_by": "decision_pressure",
            "detail_selector": "decision_pressure",
        },
        {
            "concept": "closeout trust",
            "category": "evidence_proof + promotion_residue",
            "classification": "claim-boundary and lifecycle action surface",
            "fronted_by": "closeout_trust",
            "detail_selector": "closeout_trust",
        },
    ]
    payload["workflow_checkpoint_placement"] = {
        "start": ["authority", "active_work", "durable_knowledge", "promotion_residue when task text creates residue pressure"],
        "implement": ["authority for changed paths", "evidence_proof", "durable_knowledge", "promotion_residue"],
        "proof": ["evidence_proof", "authority when proof must satisfy repo-owned requirements"],
        "report": ["all categories as a compact owner-shaped review"],
        "closeout_trust": ["evidence_proof", "promotion_residue", "active_work claim boundary"],
        "completion_options": ["evidence_proof blockers and promotion_residue blockers only"],
    }
    payload["proportionality"] = {
        "default_visibility": "compact router category only",
        "detail_visibility": "owner sections remain selector/report-section detail",
        "must_stay_quiet": [
            "unmatched assurance requirements",
            "Memory notes without route/path/task match",
            "ADR or improvement candidates unrelated to current work",
        ],
        "must_surface": [
            "category changes safe next action",
            "claim gate or proof expectation changes",
            "stale, conflicting, or mis-owned knowledge can affect current work",
        ],
    }
    payload["issue_scope"] = {
        "implements": ["#1150", "#1151", "#1152"],
        "boundary": "This is a router projection over existing owners, not a new knowledge store.",
    }
    return payload


def _select_report_payload(payload: dict[str, Any], *, profile: str, section: str | None) -> dict[str, Any]:
    config_payload = payload.get("config", {})
    workspace_config = config_payload.get("workspace", {}) if isinstance(config_payload, dict) else {}
    cli_invoke = str(workspace_config.get("cli_invoke", DEFAULT_CLI_INVOKE)) if isinstance(workspace_config, dict) else DEFAULT_CLI_INVOKE
    return select_report_payload(
        payload,
        profile=profile,
        section=section,
        compact_answer=_compact_contract_answer,
        context_router=_context_router_family_payload(cli_invoke=cli_invoke, compact=True),
        cli_invoke=cli_invoke,
    )


def _report_router_payload(payload: dict[str, Any]) -> dict[str, Any]:
    config_payload = payload.get("config", {})
    workspace_config = config_payload.get("workspace", {}) if isinstance(config_payload, dict) else {}
    cli_invoke = str(workspace_config.get("cli_invoke", DEFAULT_CLI_INVOKE)) if isinstance(workspace_config, dict) else DEFAULT_CLI_INVOKE
    return report_router_payload(
        payload, context_router=_context_router_family_payload(cli_invoke=cli_invoke, compact=True), cli_invoke=cli_invoke
    )


def _report_section_hints(payload: dict[str, Any]) -> list[dict[str, Any]]:
    return report_section_hints(payload)


_COMPLETION_OPTION_IDS = (
    "run-proof",
    "claim-slice-complete",
    "claim-work-complete",
    "keep-parent-open",
    "close-parent-lane",
    "route-residue",
    "request-review",
    "stop-with-status",
)


def _completion_option(
    option_id: str,
    *,
    allowed: bool,
    why: str,
    command: str | None = None,
    owner: str | None = None,
    blocking_fields: list[str] | None = None,
    required_claim_class: str | None = None,
) -> dict[str, Any]:
    if option_id not in _COMPLETION_OPTION_IDS:
        raise ValueError(f"unknown completion option id: {option_id}")
    item: dict[str, Any] = {"id": option_id, "allowed": allowed, "why": why}
    if command is not None:
        item["command"] = command
    if owner:
        item["owner"] = owner
    if blocking_fields:
        item["blocking_fields"] = blocking_fields
    if required_claim_class:
        item["required_claim_class"] = required_claim_class
    return item


def _closeout_completion_options(
    *,
    status: str,
    trust: str,
    strict_gate: dict[str, Any],
    completion_gate: dict[str, Any] | None = None,
    intent_check: dict[str, Any],
    acceptance_reconciliation: dict[str, Any],
    intent_proof_check: dict[str, Any] | None = None,
    assurance_requirements: dict[str, Any] | None = None,
    durable_residue_action: dict[str, Any],
    lower_trust_closeout_count: int,
    cli_invoke: str,
    current_task_switch_scope: dict[str, Any] | None = None,
) -> list[dict[str, Any]]:
    closure_scope = intent_check.get("closure_scope", {}) if isinstance(intent_check, dict) else {}
    closure_scope = closure_scope if isinstance(closure_scope, dict) else {}
    validation_proof = closure_scope.get("validation_proof", {})
    validation_proof = validation_proof if isinstance(validation_proof, dict) else {}
    proof_text = " ".join(
        str(value)
        for value in (
            validation_proof.get("proof_report", ""),
            validation_proof.get("status", ""),
            validation_proof.get("proof_achieved_now", ""),
        )
        if value
    ).lower()
    proof_achieved = any(marker in proof_text for marker in ("passed", "satisfied", "achieved", "complete"))
    proof_command = _command_with_cli_invoke(command="agentic-workspace proof --target ./repo --format json", cli_invoke=cli_invoke)
    strict_blocking = bool(strict_gate.get("blocking"))
    intent_trust = str(intent_check.get("trust", "")).strip().lower()
    acceptance_trust = str(acceptance_reconciliation.get("trust", "")).strip().lower()
    intent_proof_check = intent_proof_check if isinstance(intent_proof_check, dict) else {}
    completion_gate = completion_gate if isinstance(completion_gate, dict) else {}
    current_task_switch_scope = _as_dict(current_task_switch_scope)
    current_task_switch_active = str(current_task_switch_scope.get("status") or "") == "active"
    completion_gate_status = str(completion_gate.get("status", "")).strip()
    claim_authorization = _as_dict(completion_gate.get("claim_authorization"))
    allowed_claim_classes = {
        str(item).strip() for item in _list_payload(claim_authorization.get("allowed_claim_classes")) if str(item).strip()
    }

    def structured_claim_authorized(claim_class: str) -> bool:
        if current_task_switch_active and claim_class == "slice_complete":
            return True
        return not claim_authorization or claim_class in allowed_claim_classes

    completion_gate_blocks_full = completion_gate_status in {
        "blocked",
        "continue-required",
        "clarification-required",
        "human-accepted-partial",
    }
    intent_proof_status = str(intent_proof_check.get("status", "not_recorded")).strip().lower() or "not_recorded"
    intent_proof_supports_work = intent_proof_status in {"representative", "sufficient_for_claim"}
    intent_proof_records_execution = intent_proof_status in {"regression_only", "representative", "sufficient_for_claim"}
    intent_proof_needs_review = intent_proof_status == "needs_review"
    behavior_preservation = _behavior_preservation_confidence_payload(intent_proof_check)
    unsupported_preservation = behavior_preservation.get("status") == "claim-needs-evidence"
    larger_closure = closure_scope.get("larger_intent_closure", {})
    larger_closure = larger_closure if isinstance(larger_closure, dict) else {}
    larger_status = str(larger_closure.get("status", "")).strip().lower()
    closure_decision = str(larger_closure.get("closure_decision", "")).strip().lower()
    continuation_owner = str(intent_check.get("continuation_surface", "")).strip()
    package_continuation = intent_check.get("package_owned_continuation", {})
    if not continuation_owner and isinstance(package_continuation, dict):
        owner_surfaces = [str(item).strip() for item in _list_payload(package_continuation.get("owner_surfaces")) if str(item).strip()]
        continuation_owner = owner_surfaces[0] if owner_surfaces else ""
    required_follow_on = str(intent_check.get("required_follow_on", "")).strip().lower()
    larger_intent_open = (
        intent_trust in {"follow-up-required", "needs-review"}
        or larger_status in {"open", "follow-up-required"}
        or required_follow_on in {"yes", "true"}
    )
    residue_required = (
        lower_trust_closeout_count > 0
        or trust in {"lower-trust", "unavailable"}
        or intent_trust
        in {
            "follow-up-required",
            "needs-review",
        }
    )
    acceptance_ok = acceptance_trust in {"normal", "not-applicable", ""}
    intent_satisfied = intent_trust in {"satisfied", "normal"} or (intent_trust in {"", "not-applicable"} and intent_proof_supports_work)
    close_evidence = (
        larger_status in {"closed", "complete", "completed", "done"}
        or closure_decision
        in {
            "archive-and-close",
            "close",
            "closed",
        }
        or (intent_trust in {"", "not-applicable"} and intent_proof_supports_work)
    )
    proof_achieved = proof_achieved or intent_proof_records_execution
    completion_blockers: list[str] = []
    if not proof_achieved:
        completion_blockers.append("intent_satisfaction.closure_scope.validation_proof")
    if strict_blocking:
        completion_blockers.append("strict_closeout_gate")
    if not acceptance_ok:
        completion_blockers.append("acceptance_criteria_reconciliation")
    if residue_required:
        completion_blockers.append("durable_residue")
    if larger_intent_open:
        completion_blockers.append("intent_satisfaction")
    if larger_intent_open and not continuation_owner:
        completion_blockers.append("continuation_owner")
    if not intent_proof_supports_work:
        completion_blockers.append("intent_proof")
    if unsupported_preservation:
        completion_blockers.append("behavior_preservation")
    if completion_gate_blocks_full:
        completion_blockers.append("completion_gate")
    assurance_claim_blockers = _assurance_claim_blockers(assurance_requirements)

    slice_blockers = [
        field
        for field in completion_blockers
        if field == "intent_satisfaction.closure_scope.validation_proof"
        or field not in {"intent_satisfaction", "intent_proof"}
        or intent_proof_status == "needs_review"
    ]
    if current_task_switch_active:
        slice_blockers = [field for field in slice_blockers if field not in {"strict_closeout_gate", "durable_residue", "completion_gate"}]
    slice_blockers.extend(assurance_claim_blockers.get("claim-slice-complete", []))
    work_blockers = [*completion_blockers, *assurance_claim_blockers.get("claim-work-complete", [])]
    parent_blockers = [*completion_blockers, *assurance_claim_blockers.get("close-parent-lane", [])]
    claim_slice_allowed = (
        proof_achieved
        and (current_task_switch_active or not strict_blocking)
        and acceptance_ok
        and (current_task_switch_active or not residue_required)
        and not intent_proof_needs_review
        and not unsupported_preservation
        and not assurance_claim_blockers.get("claim-slice-complete")
        and structured_claim_authorized("slice_complete")
    )
    claim_work_allowed = (
        claim_slice_allowed
        and intent_satisfied
        and (not larger_intent_open)
        and intent_proof_supports_work
        and not completion_gate_blocks_full
        and not assurance_claim_blockers.get("claim-work-complete")
        and structured_claim_authorized("full_intent_complete")
    )
    close_parent_allowed = (
        claim_work_allowed
        and close_evidence
        and not assurance_claim_blockers.get("close-parent-lane")
        and structured_claim_authorized("parent_complete")
    )
    route_residue_command = str(durable_residue_action.get("command", "")) or _command_with_cli_invoke(
        command="agentic-workspace report --target ./repo --section closeout_trust --format json", cli_invoke=cli_invoke
    )
    assurance_review_required = any(assurance_claim_blockers.values())
    request_review_allowed = (
        status in {"unavailable", "invalid"}
        or intent_trust == "needs-review"
        or intent_proof_needs_review
        or unsupported_preservation
        or completion_gate_status in {"blocked", "clarification-required"}
        or str(strict_gate.get("status", "")) == "requires-review"
        or assurance_review_required
    )
    return [
        _completion_option(
            "run-proof",
            allowed=not proof_achieved,
            command=proof_command,
            why="proof has not been recorded as executed" if not proof_achieved else "proof execution evidence is already visible",
            blocking_fields=None if proof_achieved else ["intent_satisfaction.closure_scope.validation_proof"],
        ),
        _completion_option(
            "claim-slice-complete",
            allowed=claim_slice_allowed,
            why="slice proof and closeout evidence support a bounded completion claim"
            if claim_slice_allowed
            else "slice completion is blocked until proof, strict closeout, acceptance, and residue evidence are reconciled",
            blocking_fields=slice_blockers or None,
            required_claim_class="slice_complete",
        ),
        _completion_option(
            "claim-work-complete",
            allowed=claim_work_allowed,
            why="proof, intent, residue, and closeout evidence support claiming the requested work complete"
            if claim_work_allowed
            else "work completion is blocked until proof, intent, residue, continuation, and closeout evidence support it",
            owner=continuation_owner if larger_intent_open else None,
            blocking_fields=work_blockers or None,
            required_claim_class="full_intent_complete",
        ),
        _completion_option(
            "keep-parent-open",
            allowed=larger_intent_open and bool(continuation_owner),
            why="larger intent remains open and a continuation owner is named"
            if larger_intent_open and continuation_owner
            else "no larger-intent continuation owner is currently required or named",
            owner=continuation_owner if larger_intent_open else None,
            blocking_fields=["continuation_owner"] if larger_intent_open and not continuation_owner else None,
        ),
        _completion_option(
            "close-parent-lane",
            allowed=close_parent_allowed,
            why="explicit closure evidence supports closing the parent lane"
            if close_parent_allowed
            else "parent lane closure requires satisfied larger intent and explicit closure evidence",
            owner=continuation_owner if larger_intent_open else None,
            blocking_fields=parent_blockers if parent_blockers else ["intent_satisfaction.closure_scope.larger_intent_closure"],
            required_claim_class="parent_complete",
        ),
        _completion_option(
            "route-residue",
            allowed=residue_required,
            command=route_residue_command,
            why="durable residue or lower-trust closeout signals need routing"
            if residue_required
            else "no durable residue routing is currently required by closeout_trust",
        ),
        _completion_option(
            "request-review",
            allowed=request_review_allowed,
            why="intent satisfaction, preservation proof, assurance, or strict closeout evidence requires human/domain review"
            if request_review_allowed
            else "a concrete closeout action is available without requiring review",
            blocking_fields=["intent_satisfaction"]
            if intent_trust == "needs-review"
            else ["behavior_preservation"]
            if unsupported_preservation
            else ["completion_gate"]
            if completion_gate_status in {"blocked", "clarification-required"}
            else ["assurance_requirements"]
            if assurance_review_required
            else None,
        ),
        _completion_option(
            "stop-with-status",
            allowed=True,
            why="safe exit is always available when completion cannot honestly be claimed",
            command=_command_with_cli_invoke(
                command="agentic-workspace report --target ./repo --section closeout_trust --format json", cli_invoke=cli_invoke
            ),
        ),
    ]


def _closeout_protocol_payload(
    *,
    status: str,
    trust: str,
    strict_gate: dict[str, Any],
    completion_gate: dict[str, Any],
    completion_options: list[dict[str, Any]],
    durable_residue_action: dict[str, Any],
    knowledge_authority_review: dict[str, Any],
    proof_confidence: dict[str, Any],
    verification: dict[str, Any],
    task_posture_followthrough: dict[str, Any] | None = None,
    recommended_next_action: str = "",
    cli_invoke: str,
) -> dict[str, Any]:
    strict_gate = _as_dict(strict_gate)
    completion_gate = _as_dict(completion_gate)
    durable_residue_action = _as_dict(durable_residue_action)
    knowledge_authority_review = _as_dict(knowledge_authority_review)
    proof_confidence = _as_dict(proof_confidence)
    verification = _as_dict(verification)
    task_posture_followthrough = _as_dict(task_posture_followthrough)
    options_by_id = {str(option.get("id")): option for option in completion_options if isinstance(option, dict)}
    claim_authorization = _as_dict(completion_gate.get("claim_authorization"))
    terminal_outcome_contract = _terminal_outcome_contract_payload(
        completion_gate=completion_gate,
        completion_options=completion_options,
        recommended_next_action=recommended_next_action,
        source_surface="closeout_protocol",
    )
    route_residue = _as_dict(options_by_id.get("route-residue"))
    run_proof = _as_dict(options_by_id.get("run-proof"))
    close_parent = _as_dict(options_by_id.get("close-parent-lane"))
    claim_work = _as_dict(options_by_id.get("claim-work-complete"))
    keep_parent = _as_dict(options_by_id.get("keep-parent-open"))
    blocking_option_ids = [
        option_id
        for option_id, option in options_by_id.items()
        if isinstance(option, dict) and option.get("allowed") is False and option.get("blocking_fields")
    ]
    blocking_fields = _dedupe(
        [
            str(field)
            for option in options_by_id.values()
            if isinstance(option, dict)
            for field in _list_payload(option.get("blocking_fields"))
            if str(field).strip()
        ]
    )
    readiness_status = (
        "ready" if trust == "normal" and not bool(strict_gate.get("blocking")) and not blocking_option_ids else "action-required"
    )
    if status in {"unavailable", "invalid"}:
        readiness_status = "unavailable"
    return {
        "kind": "agentic-workspace/closeout-protocol/v1",
        "protocol": "Completion Honesty / Residue Routing",
        "status": readiness_status,
        "source_surface": "closeout_trust",
        "readiness": {
            "status": readiness_status,
            "trust": trust,
            "strict_gate_status": strict_gate.get("status"),
            "blocking_option_ids": blocking_option_ids,
            "blocking_fields": blocking_fields,
            "required_next_action": recommended_next_action
            or completion_gate.get("required_next_action")
            or "reconcile proof, intent, residue, and closure permission before claiming completion",
        },
        "claim_boundary": {
            "claim_level_allowed": completion_gate.get("claim_level_allowed"),
            "allowed_claim_classes": claim_authorization.get("allowed_claim_classes", []),
            "blocked_claim_classes": claim_authorization.get("blocked_claim_classes", []),
            "rule": "Proof success, issue closure, and parent intent satisfaction are separate closeout decisions.",
        },
        "terminal_outcome_contract": terminal_outcome_contract,
        "proof_dependency": {
            "run_proof_allowed": run_proof.get("allowed"),
            "proof_confidence": proof_confidence.get("confidence") or proof_confidence.get("status"),
            "proof_status": proof_confidence.get("intent_proof_status"),
            "claim_boundary": proof_confidence.get("claim_boundary"),
            "verification_status": verification.get("status", "absent"),
            "verification_active_count": verification.get("active_count", 0),
            "rule": "Closeout consumes proof evidence; it does not replace proof selection or execution.",
        },
        "residue_routing": {
            "action": durable_residue_action.get("action"),
            "required": route_residue.get("allowed"),
            "owner": route_residue.get("owner") or durable_residue_action.get("owner"),
            "visible_states": durable_residue_action.get("visible_states", ["none-found", "capture", "route-to-owner", "dismissed"]),
            "destinations": durable_residue_action.get("destinations", []),
            "rule": durable_residue_action.get("destination_rule"),
        },
        "knowledge_route_states": {
            "state_vocabulary": [
                "consulted",
                "skipped",
                "stale",
                "unavailable",
                "dismissed",
                "captured",
                "promotion-required",
            ],
            "matched_source_count": knowledge_authority_review.get("matched_source_count", 0),
            "stale_source_count": knowledge_authority_review.get("stale_source_count", 0),
            "promotion_candidate_count": knowledge_authority_review.get("promotion_candidate_count", 0),
            "next_actions": knowledge_authority_review.get("next_actions", []),
            "rule": "Knowledge state limits closeout only when the source was governing for interpretation, proof, or residue.",
        },
        "closure_permission": {
            "claim_work_complete_allowed": claim_work.get("allowed"),
            "keep_parent_open_allowed": keep_parent.get("allowed"),
            "close_parent_lane_allowed": close_parent.get("allowed"),
            "closure_actions": claim_authorization.get("closure_actions", []),
            "closure_keyword_guard": claim_authorization.get("closure_keyword_guard", {}),
            "parent_closure_rule": "Parent/epic closure requires explicit authorization; slice proof never closes parent intent by itself.",
        },
        "task_posture_followthrough": {
            key: task_posture_followthrough.get(key)
            for key in ("status", "required_next_action", "blocking_claims", "rule")
            if key in task_posture_followthrough
        },
        "detail_command": _command_with_cli_invoke(
            command="agentic-workspace report --target ./repo --section closeout_trust --format json", cli_invoke=cli_invoke
        ),
    }


def _terminal_outcome_blocker_qualification(*, completion_gate: dict[str, Any]) -> dict[str, Any]:
    typed_external_blockers: list[dict[str, Any]] = []
    missing_requirements: list[str] = []
    for key in ("external_blockers", "terminal_blockers", "blocker_evidence"):
        for item in _list_payload(completion_gate.get(key)):
            if not isinstance(item, dict):
                continue
            blocker_type = str(item.get("type") or item.get("kind") or item.get("category") or "").strip()
            if blocker_type not in {"external", "external_action", "human_action", "user_action"}:
                continue
            evidence = str(item.get("evidence") or item.get("proof") or item.get("source") or "").strip()
            recovery = str(item.get("recovery") or item.get("recovery_action") or item.get("required_action") or "").strip()
            no_safe_continuation = bool(item.get("no_safe_continuation"))
            item_missing = []
            if not evidence:
                item_missing.append("evidence")
            if not recovery:
                item_missing.append("recovery")
            if not no_safe_continuation:
                item_missing.append("no_safe_continuation")
            if item_missing:
                missing_requirements.extend(item_missing)
                continue
            typed_external_blockers.append(
                {
                    "id": str(item.get("id") or blocker_type).strip(),
                    "type": blocker_type,
                    "evidence": evidence,
                    "recovery": recovery,
                    "no_safe_continuation": True,
                }
            )
    status = "qualified_external_blocker" if typed_external_blockers else "missing_typed_external_blocker"
    if not typed_external_blockers and not missing_requirements:
        missing_requirements = ["typed_external_blocker", "evidence", "recovery", "no_safe_continuation"]
    return {
        "status": status,
        "qualified_blockers": typed_external_blockers,
        "missing_requirements": _dedupe(missing_requirements),
        "rule": "BLOCKED requires a typed external or human-action blocker with evidence, recovery path, and proof that no safe in-scope continuation exists.",
    }


def _terminal_outcome_contract_payload(
    *,
    completion_gate: dict[str, Any],
    completion_options: list[Any] | None = None,
    recommended_next_action: str = "",
    source_surface: str = "completion_gate",
) -> dict[str, Any]:
    completion_gate = _as_dict(completion_gate)
    claim_authorization = _as_dict(completion_gate.get("claim_authorization"))
    allowed_claim_classes = {
        str(item).strip() for item in _list_payload(claim_authorization.get("allowed_claim_classes")) if str(item).strip()
    }
    options = [option for option in _list_payload(completion_options) if isinstance(option, dict)]
    allowed_option_ids = [str(option.get("id")) for option in options if option.get("allowed") is True and str(option.get("id") or "")]
    progress_option_ids = [
        option_id
        for option_id in allowed_option_ids
        if option_id not in {"stop-with-status", "request-review", "claim-work-complete", "close-parent-lane"}
    ]
    blocked_options = [
        str(option.get("id"))
        for option in options
        if option.get("allowed") is False and _list_payload(option.get("blocking_fields")) and str(option.get("id") or "")
    ]
    status = str(completion_gate.get("status") or "unknown").strip()
    required_next_action = str(completion_gate.get("required_next_action") or recommended_next_action or "").strip()
    active_intent_satisfied = bool(completion_gate.get("active_intent_satisfied"))
    human_accepted_partial = bool(completion_gate.get("human_accepted_partial"))
    full_claim_authorized = "full_intent_complete" in allowed_claim_classes
    issue_closure_authorized = "issue_closure" in allowed_claim_classes
    safe_continuation_available = bool(progress_option_ids or status == "continue-required")
    blocked_like_status = status in {"clarification-required", "blocked", "unavailable", "invalid"}
    blocker_qualification = _terminal_outcome_blocker_qualification(completion_gate=completion_gate)
    qualified_external_blocker = bool(blocker_qualification.get("qualified_blockers"))
    auto_resume_action = required_next_action or "qualify-terminal-blocker-or-continue-current-work"

    if active_intent_satisfied and full_claim_authorized:
        state = "DELIVERED"
        final_response_authorized = True
        custody_owner = "completed-outcome"
        reason = "Completion gate authorizes the requested full-intent claim."
        safe_continuation_available = False
        progress_option_ids = []
    elif human_accepted_partial:
        state = "USER_PAUSED"
        final_response_authorized = True
        custody_owner = "user"
        reason = "The human accepted a narrower or partial outcome."
    elif safe_continuation_available:
        state = "CONTINUE"
        final_response_authorized = False
        custody_owner = "agent"
        reason = "Safe in-scope continuation remains; a progress summary must not transfer execution custody to the user."
    elif blocked_like_status and qualified_external_blocker and not safe_continuation_available:
        state = "BLOCKED"
        final_response_authorized = True
        custody_owner = "external-or-human-action"
        reason = "A typed external or human-action blocker is qualified and no safe in-scope continuation is available."
    elif blocked_like_status:
        state = "CONTINUE"
        final_response_authorized = False
        custody_owner = "agent"
        reason = "Blocked-like status lacks typed blocker qualification, so a terminal final is rejected and execution custody remains with the agent."
        safe_continuation_available = True
        progress_option_ids = _dedupe([*progress_option_ids, "qualify-terminal-blocker"])
        required_next_action = auto_resume_action
    else:
        state = "CONTINUE"
        final_response_authorized = False
        custody_owner = "agent"
        reason = "The terminal outcome is not delivered, blocked, or user-paused, so execution custody remains with the agent."

    return {
        "kind": "agentic-workspace/terminal-outcome-contract/v1",
        "state": state,
        "source_surface": source_surface,
        "completion_gate_status": status,
        "final_response_authorized": final_response_authorized,
        "custody_owner": custody_owner,
        "safe_continuation_available": safe_continuation_available,
        "safe_continuation_option_ids": progress_option_ids,
        "blocked_option_ids": blocked_options,
        "required_next_action": required_next_action or ("continue-current-work" if state == "CONTINUE" else ""),
        "blocker_qualification": blocker_qualification if blocked_like_status else {"status": "not_required"},
        "final_response_enforcement": {
            "status": "authorized" if final_response_authorized else "rejected_auto_resume",
            "terminal_final_rejected": not final_response_authorized,
            "auto_resume_action": required_next_action or ("continue-current-work" if state == "CONTINUE" else ""),
            "progress_without_yield": state == "CONTINUE",
            "compaction_resume_safe": state == "CONTINUE",
            "enforcement_maturity": "adapter-only-until-host-integrated" if not final_response_authorized else "not_required",
            "ordinary_host_path_unavoidable": bool(final_response_authorized),
            "host_boundary_integrated": bool(final_response_authorized),
            "issue_2239_closure_ready": bool(final_response_authorized),
            "multi_slice_continuation": {
                "status": "preserved" if state == "CONTINUE" else "not_required",
                "resume_fields": ["state", "required_next_action", "safe_continuation_option_ids", "blocker_qualification"],
            },
            "weak_model_regression": "terminal-final-rejected-while-continuation-remains"
            if not final_response_authorized
            else "terminal-final-authorized",
        },
        "allowed_terminal_states": ["DELIVERED", "BLOCKED", "USER_PAUSED", "CONTINUE"],
        "allowed_claim_classes": sorted(allowed_claim_classes),
        "issue_closure_authorized": issue_closure_authorized,
        "reason": reason,
        "invalid_pseudo_blockers": [
            "task-size",
            "elapsed-time",
            "architectural-breadth",
            "context-pressure",
            "successful-compaction",
            "one-slice-complete",
            "work-remains",
        ],
        "terminal_response_rule": (
            "A terminal final response is authorized only for DELIVERED, BLOCKED, or USER_PAUSED. "
            "CONTINUE permits progress updates but requires selecting the next safe in-scope action."
        ),
    }


def _terminal_final_response_admission(
    *,
    terminal_outcome_contract: dict[str, Any],
    final_response_attempt: dict[str, Any],
    resume_state: dict[str, Any] | None = None,
    resume_executor: Callable[[dict[str, Any]], dict[str, Any]] | None = None,
) -> dict[str, Any]:
    terminal = _as_dict(terminal_outcome_contract)
    attempt = _as_dict(final_response_attempt)
    enforcement = _as_dict(terminal.get("final_response_enforcement"))
    state = str(terminal.get("state") or "CONTINUE")
    final_authorized = bool(terminal.get("final_response_authorized"))
    auto_resume_action = str(enforcement.get("auto_resume_action") or terminal.get("required_next_action") or "continue-current-work")
    before_state = _as_dict(resume_state)
    after_state = {
        "terminal_state": state,
        "required_next_action": auto_resume_action if not final_authorized else "",
        "safe_continuation_option_ids": _list_payload(terminal.get("safe_continuation_option_ids")),
        "blocker_qualification": terminal.get("blocker_qualification", {}),
    }
    compaction_boundary_crossed = bool(attempt.get("after_compaction"))
    resume_request = {
        "kind": "agentic-workspace/final-response-resume-request/v1",
        "source": "host-final-response-admission",
        "terminal_state": state,
        "terminal_final_rejected": not final_authorized,
        "auto_resume_action": "" if final_authorized else auto_resume_action,
        "before_state": before_state,
        "after_compaction": compaction_boundary_crossed,
        "final_response_attempt": {
            "source": str(attempt.get("source") or "model-authored-final-response"),
            "claim": str(attempt.get("claim") or attempt.get("text") or "").strip(),
        },
        "multi_slice_continuation": enforcement.get("multi_slice_continuation", {}),
    }
    executor_result: dict[str, Any] = {"status": "not_required"}
    if not final_authorized:
        executor = resume_executor or _terminal_final_response_default_resume_executor
        executor_result = _as_dict(executor(resume_request))
        after_state.update(_as_dict(executor_result.get("after_state_patch")))
    return {
        "kind": "agentic-workspace/final-response-admission/v1",
        "status": "accepted_terminal_final" if final_authorized else "rejected_auto_resumed",
        "terminal_final_rejected": not final_authorized,
        "host_admission_boundary": {
            "status": "accepted" if final_authorized else "rejected-and-resumed",
            "source": "host-final-response-admission",
            "invoked_resume_executor": not final_authorized,
            "rejects_model_obedience_only": not final_authorized,
            "rule": "The host admission boundary receives the model-authored final response and owns custody transfer.",
        },
        "attempt": {
            "source": str(attempt.get("source") or "model-authored-final-response"),
            "claim": str(attempt.get("claim") or attempt.get("text") or "").strip(),
        },
        "resume_transition": {
            "status": "not_required" if final_authorized else "executed",
            "auto_resume_action": "" if final_authorized else auto_resume_action,
            "before_state": before_state,
            "after_state": after_state,
            "compaction_boundary_crossed": compaction_boundary_crossed,
            "multi_slice_continuation": enforcement.get("multi_slice_continuation", {}),
            "resume_request": resume_request,
            "executor_result": executor_result,
        },
        "progress_without_yield": bool(enforcement.get("progress_without_yield")) and not final_authorized,
        "rule": "A model-authored terminal final is admitted only after the terminal outcome contract authorizes final-response custody transfer.",
    }


def _terminal_final_response_default_resume_executor(request: dict[str, Any]) -> dict[str, Any]:
    action = str(request.get("auto_resume_action") or "continue-current-work")
    return {
        "kind": "agentic-workspace/final-response-resume-result/v1",
        "status": "executed",
        "invoked_action": action,
        "custody": "agent",
        "after_state_patch": {
            "required_next_action": action,
            "custody_owner": "agent",
            "continuation_slice": "post-admission-resume",
        },
        "rule": "Default host executor records the deterministic resume action when no embedding host supplies a runner.",
    }


def _completion_gate_claim_authorization(
    *,
    status: str,
    active_intent_satisfied: bool,
    human_accepted_partial: bool,
    claim_level_requested: str,
    proof_status: str = "",
    issue_refs: set[str],
) -> dict[str, Any]:
    all_claim_classes = [
        "partial_progress",
        "slice_complete",
        "lane_complete",
        "parent_complete",
        "full_intent_complete",
        "issue_closure",
    ]
    rank = {
        "partial_progress": 0,
        "slice_complete": 1,
        "slice": 1,
        "lane_complete": 2,
        "lane": 2,
        "parent_complete": 3,
        "parent": 3,
        "full_intent_complete": 4,
        "work_complete": 4,
        "full": 4,
    }
    requested = str(claim_level_requested or "full-intent-complete").strip().lower().replace("-", "_")
    requested_rank = rank.get(requested, 4)
    proof_records_slice = proof_status in {
        "regression_only",
        "regression-only",
        "representative",
        "sufficient_for_claim",
        "sufficient-for-claim",
    }
    if active_intent_satisfied:
        allowed_claim_classes = [claim for claim in all_claim_classes if claim != "issue_closure" and rank.get(claim, 5) <= requested_rank]
        if requested_rank >= rank["full_intent_complete"] and issue_refs:
            allowed_claim_classes.append("issue_closure")
    elif proof_records_slice and status in {"blocked", "continue-required"} and not human_accepted_partial:
        allowed_claim_classes = ["partial_progress", "slice_complete"]
    elif human_accepted_partial or status == "continue-required":
        allowed_claim_classes = ["partial_progress"]
    else:
        allowed_claim_classes = []
    blocked_claim_classes = [claim for claim in all_claim_classes if claim not in allowed_claim_classes]
    closure_actions = [
        {
            "kind": "issue_closure",
            "target": ref,
            "authorized": "issue_closure" in allowed_claim_classes,
            "reason": "issue closure requires full-intent completion authorization from the completion gate",
        }
        for ref in sorted(issue_refs)
    ]
    issue_closure_authorized = "issue_closure" in allowed_claim_classes
    blocked_parent_or_issue = bool(
        {"lane_complete", "parent_complete", "full_intent_complete", "issue_closure"} & set(blocked_claim_classes)
    )
    closure_keyword_guard = {
        "kind": "agentic-workspace/closure-keyword-guard/v1",
        "status": "authorized" if issue_closure_authorized else "blocked",
        "severity": "strong-warning" if blocked_parent_or_issue else "advisory",
        "unsafe_when_blocked": ["close", "closes", "closed", "fix", "fixes", "fixed", "resolve", "resolves", "resolved"],
        "safe_reference_words": ["refs", "references", "related to", "progress toward"],
        "safe_reference_template": "Refs {issue}; does not close.",
        "targets": [
            {
                "target": ref,
                "closure_keywords_authorized": issue_closure_authorized,
                "safe_reference": f"Refs {ref}; does not close.",
                "unsafe_examples": [f"Closes {ref}", f"Fixes {ref}", f"Resolves {ref}"] if not issue_closure_authorized else [],
            }
            for ref in sorted(issue_refs)
        ],
        "rule": (
            "When issue_closure is blocked, renderers and PR bodies must use reference wording rather than host "
            "closure keywords. This guard is host-agnostic; listed keywords are renderer examples."
        ),
    }
    unsafe_examples = [] if active_intent_satisfied else ["done", "implemented", "complete", "finished", "all", "full intent complete"]
    if not active_intent_satisfied:
        unsafe_examples.extend(f"Closes {ref}" for ref in sorted(issue_refs))
    return {
        "kind": "agentic-workspace/claim-authorization/v1",
        "allowed_claim_classes": allowed_claim_classes,
        "blocked_claim_classes": blocked_claim_classes,
        "closure_actions": closure_actions,
        "closure_keyword_guard": closure_keyword_guard,
        "renderer_rule": (
            "Renderers must choose only templates whose required claim class and closure action are authorized here; "
            "unsafe prose examples are diagnostics, not the enforcement model."
        ),
        "diagnostics": {
            "unsafe_claim_examples": _dedupe(unsafe_examples),
            "diagnostic_only": True,
        },
    }


def _completion_gate_payload(
    *,
    active_planning_record: dict[str, Any],
    intent_check: dict[str, Any],
    acceptance_reconciliation: dict[str, Any],
    intent_proof_check: dict[str, Any] | None = None,
    parent_intent_status: dict[str, Any] | None = None,
    applicable_intent_status: dict[str, Any] | None = None,
    durable_residue_action: dict[str, Any] | None = None,
    claim_level_requested: str = "full-intent-complete",
) -> dict[str, Any]:
    active_planning_record = _as_dict(active_planning_record)
    intent_check = _as_dict(intent_check)
    acceptance_reconciliation = _as_dict(acceptance_reconciliation)
    intent_proof_check = _as_dict(intent_proof_check)
    parent_intent_status = _as_dict(parent_intent_status)
    applicable_intent_status = _as_dict(applicable_intent_status)
    durable_residue_action = _as_dict(durable_residue_action)
    intent_satisfaction = _as_dict(active_planning_record.get("intent_satisfaction"))
    intent_continuity = _as_dict(active_planning_record.get("intent_continuity"))
    required_continuation = _as_dict(active_planning_record.get("required_continuation"))
    closure_check = _as_dict(active_planning_record.get("closure_check"))
    parent_acceptance = _as_dict(active_planning_record.get("parent_acceptance"))

    def truthy(value: Any) -> bool:
        return str(value or "").strip().lower() in {"yes", "true", "accepted", "approved", "explicit", "human-accepted"}

    def present(*values: Any) -> str:
        for value in values:
            if isinstance(value, (list, tuple)):
                text = "; ".join(str(item).strip() for item in value if str(item).strip())
            else:
                text = str(value or "").strip()
            if text and text.lower() not in {"none", "no", "false", "null", "unknown", "pending", "not-recorded", "not recorded"}:
                return text
        return ""

    parent_status = str(parent_intent_status.get("status") or "").strip()
    intent_trust = str(intent_check.get("trust") or "").strip()
    acceptance_trust = str(acceptance_reconciliation.get("trust") or "").strip()
    proof_status = str(intent_proof_check.get("status") or "").strip()
    required_follow_on = str(
        required_continuation.get("required follow-on for the larger intended outcome") or intent_check.get("required_follow_on") or ""
    ).strip()
    continuation_owner = present(
        parent_intent_status.get("continuation_owner"),
        required_continuation.get("owner surface"),
        intent_check.get("continuation_surface"),
        durable_residue_action.get("owner"),
    )
    residual_intent = present(
        parent_intent_status.get("residual_parent_intent"),
        required_continuation.get("required follow-on for the larger intended outcome"),
        intent_satisfaction.get("unsolved intent passed to"),
        intent_check.get("residual_intent"),
    )
    human_accepted_partial = any(
        truthy(value)
        for value in (
            closure_check.get("human accepted partial"),
            closure_check.get("human_accepted_partial"),
            closure_check.get("human accepted narrower scope"),
            closure_check.get("human_accepted_narrower_scope"),
            parent_acceptance.get("human accepted partial"),
            parent_acceptance.get("human_accepted_partial"),
            parent_acceptance.get("human accepted narrower scope"),
            parent_acceptance.get("human_accepted_narrower_scope"),
        )
    )
    proof_supports_full = proof_status in {"representative", "sufficient_for_claim", "sufficient-for-claim"}
    parent_satisfied = parent_status in {"satisfied", "guidance-only", ""}
    intent_satisfied_field = truthy(intent_satisfaction.get("was original intent fully satisfied?")) or truthy(
        intent_continuity.get("this slice completes the larger intended outcome")
    )
    closure_status = str(closure_check.get("larger-intent status") or closure_check.get("larger_intent_status") or "").strip().lower()
    closure_decision = str(closure_check.get("closure decision") or closure_check.get("closure_decision") or "").strip().lower()
    explicit_closeout_satisfied = closure_status in {"closed", "complete", "completed", "done", ""} and (
        closure_decision in {"archive-and-close", "close", "closed", ""} or closure_decision.startswith("archive-and-close-")
    )
    no_required_follow_on = required_follow_on.lower() in {"", "no", "false", "none"}
    active_closeout_evidence_satisfied = bool(
        active_planning_record
        and (intent_satisfied_field or intent_trust in {"satisfied", "normal"})
        and no_required_follow_on
        and (parent_satisfied or explicit_closeout_satisfied)
        and acceptance_trust in {"", "normal", "not-applicable"}
        and proof_supports_full
        and not applicable_intent_status.get("closeout_blocked")
    )
    task_posture_residue = _planned_task_posture_residue(
        active_planning_record,
        active_closeout_evidence_satisfied=active_closeout_evidence_satisfied,
    )
    task_posture_residue_open = task_posture_residue.get("status") == "open"
    if task_posture_residue_open:
        posture_titles = [
            str(item.get("title") or item.get("id") or "").strip()
            for item in _list_payload(task_posture_residue.get("planned"))
            if isinstance(item, dict) and str(item.get("title") or item.get("id") or "").strip()
        ]
        continuation_owner = present(continuation_owner, task_posture_residue.get("owner_surface"))
        residual_intent = present(
            residual_intent,
            "Task posture follow-through remains unresolved: " + "; ".join(posture_titles[:4]),
        )
        required_follow_on = "yes"
        no_required_follow_on = False
    active_intent_satisfied = bool(
        active_planning_record
        and (intent_satisfied_field or intent_trust in {"satisfied", "normal"})
        and no_required_follow_on
        and (parent_satisfied or explicit_closeout_satisfied)
        and acceptance_trust in {"", "normal", "not-applicable"}
        and proof_supports_full
        and not applicable_intent_status.get("closeout_blocked")
        and not task_posture_residue_open
    )
    continuation_possible = bool(
        continuation_owner
        or residual_intent
        or task_posture_residue_open
        or required_follow_on.lower() in {"yes", "true", "required", "follow-up-required"}
    )
    ambiguous_or_blocked = (
        intent_trust == "needs-review"
        or applicable_intent_status.get("closeout_blocked")
        or required_follow_on.lower() in {"unknown", "ambiguous"}
        or str(closure_check.get("closure decision") or closure_check.get("closure_decision") or "").strip().lower()
        in {"requires-review", "blocked"}
    )
    if active_intent_satisfied:
        status = "allowed"
        claim_level_allowed = claim_level_requested
        required_next_action = "close-complete"
    elif not active_planning_record and intent_check.get("status") == "unavailable":
        status = "blocked"
        claim_level_allowed = "partial-progress"
        required_next_action = "ask-human"
    elif human_accepted_partial:
        status = "human-accepted-partial"
        claim_level_allowed = "partial-progress"
        required_next_action = "close-human-accepted-partial"
    elif ambiguous_or_blocked:
        status = "clarification-required"
        claim_level_allowed = "partial-progress"
        required_next_action = "ask-human"
    elif continuation_possible:
        status = "continue-required"
        claim_level_allowed = "partial-progress"
        required_next_action = "create-follow-on-plan" if continuation_owner else "continue-current-work"
    else:
        status = "blocked"
        claim_level_allowed = "partial-progress"
        required_next_action = "ask-human"

    issue_refs: set[str] = set()
    for reference in _list_payload(active_planning_record.get("references")):
        if isinstance(reference, dict):
            issue_refs.update(_issue_refs_from_text(str(reference.get("target") or "")))
            issue_refs.update(_issue_refs_from_text(str(reference.get("url") or "")))
            issue_refs.update(_issue_refs_from_text(str(reference.get("role") or "")))
        else:
            issue_refs.update(_issue_refs_from_text(str(reference or "")))
    for value in (
        active_planning_record.get("title"),
        present(intent_satisfaction.get("original intent"), parent_intent_status.get("original_intent")),
        present(closure_check.get("closure target"), closure_check.get("closure_target")),
    ):
        issue_refs.update(_issue_refs_from_text(str(value or "")))
    claim_authorization = _completion_gate_claim_authorization(
        status=status,
        active_intent_satisfied=active_intent_satisfied,
        human_accepted_partial=human_accepted_partial,
        claim_level_requested=claim_level_requested,
        proof_status=proof_status,
        issue_refs=issue_refs,
    )
    self_review_answer = "yes" if active_intent_satisfied else "no"
    if active_intent_satisfied:
        reason = "Recorded intent, parent status, proof, acceptance, and continuation fields support the requested completion claim."
    else:
        reason = present(
            residual_intent,
            parent_intent_status.get("residual_parent_intent"),
            intent_check.get("summary"),
            "The delivered work does not yet satisfy the active human intent at the requested claim level.",
        )
    return {
        "kind": "agentic-workspace/completion-gate/v1",
        "status": status,
        "active_intent_satisfied": active_intent_satisfied,
        "human_accepted_partial": human_accepted_partial,
        "claim_level_requested": claim_level_requested,
        "claim_level_allowed": claim_level_allowed,
        "required_next_action": required_next_action,
        "claim_authorization": claim_authorization,
        "residual_intent": "" if active_intent_satisfied else residual_intent,
        "self_review": {
            "question": "Does the delivered work satisfy the active human intent?",
            "answer": self_review_answer,
            "reason": reason,
        },
        "continuation": {
            "owner_surface": continuation_owner,
            "created_or_required": bool(
                (not active_intent_satisfied) and (continuation_possible or status in {"blocked", "clarification-required"})
            ),
            "reason": ""
            if active_intent_satisfied
            else present(
                residual_intent,
                "Intent remains unsatisfied and must continue, route durably, or be clarified before full closeout.",
            ),
        },
        "task_posture_followthrough": task_posture_residue,
        "authority_boundary": {
            "kind": "agentic-workspace/authority-boundary/v1",
            "surface": "completion_gate",
            "aw_owns": [
                "forcing the transition rule",
                "blocking unsupported structured claim classes and closure actions",
                "routing continuation",
            ],
            "agent_owns": [
                "semantic satisfaction judgment",
                "evidence interpretation",
                "next implementation decisions",
            ],
            "human_owns": [
                "accepting narrower scope",
                "changing intent",
                "accepting unresolved residual intent",
            ],
        },
        "rule": (
            "If the agent records that active_intent_satisfied=false and human_accepted_partial=false, the workflow must "
            "not terminate as done/full-complete; it must continue, route durable follow-on planning, or ask."
        ),
    }


def _planned_task_posture_residue(
    active_planning_record: dict[str, Any],
    *,
    active_closeout_evidence_satisfied: bool = False,
) -> dict[str, Any]:
    active_planning_record = _as_dict(active_planning_record)
    records = [active_planning_record]
    target_root = _target_root_from_record(active_planning_record)
    lane_refs = []
    for value in (
        active_planning_record.get("owner_surface"),
        active_planning_record.get("parent_lane_ref"),
        _as_dict(active_planning_record.get("active_milestone")).get("id"),
        active_planning_record.get("id"),
    ):
        text = str(value or "").strip()
        if text:
            lane_refs.append(text)
    if target_root is not None:
        for ref in lane_refs:
            candidate = target_root / ref
            if candidate.exists() and candidate.suffix == ".json":
                try:
                    loaded = json.loads(candidate.read_text(encoding="utf-8-sig"))
                except (OSError, json.JSONDecodeError):
                    continue
                if isinstance(loaded, dict):
                    records.append(loaded)
        lane_dir = target_root / ".agentic-workspace" / "planning" / "lanes"
        for ref in lane_refs:
            if "1392" not in ref and "task-posture" not in ref:
                continue
            candidate = lane_dir / "lane-1392-open-module-participation.lane.json"
            if candidate.exists():
                try:
                    loaded = json.loads(candidate.read_text(encoding="utf-8-sig"))
                except (OSError, json.JSONDecodeError):
                    continue
                if isinstance(loaded, dict):
                    records.append(loaded)
    planned: list[dict[str, str]] = []
    posture_markers = ("posture", "task_posture", "task-posture", "agents.md", "AGENTS.md", "packet")
    for record in records:
        for item in _list_payload(record.get("slice_sequence")):
            if not isinstance(item, dict):
                continue
            status = str(item.get("status", "")).strip().lower()
            haystack = " ".join(str(item.get(key, "")) for key in ("id", "title", "purpose_for_lane", "residual_after_slice"))
            if status in {"planned", "ready", "active", "blocked"} and any(
                marker.lower() in haystack.lower() for marker in posture_markers
            ):
                planned.append(
                    {
                        "id": str(item.get("id", "")).strip(),
                        "title": str(item.get("title", "")).strip(),
                        "status": status,
                    }
                )
    planned = [item for item in planned if item.get("id")]
    if not planned:
        return {"status": "none", "planned": [], "owner_surface": ""}
    owner = ""
    for record in records:
        owner = str(record.get("parent_decomposition_ref") or record.get("owner_surface") or "").strip()
        if record.get("kind") == "planning-lane/v1":
            owner = ".agentic-workspace/planning/lanes/" + str(record.get("id", "")).strip() + ".lane.json"
        if owner:
            break
    status = "stale-satisfied" if active_closeout_evidence_satisfied else "open"
    return {
        "status": status,
        "planned": planned,
        "owner_surface": owner or ".agentic-workspace/planning/lanes/lane-1392-open-module-participation.lane.json",
        "blocking": not active_closeout_evidence_satisfied,
        "rule": (
            "Task-posture slice residue remains visible as stale satisfied evidence because the active execplan records "
            "full intent, proof, no required continuation, and closeout satisfaction."
            if active_closeout_evidence_satisfied
            else "Full closeout is blocked while task-posture slices remain planned, active, or blocked."
        ),
    }


def _active_closeout_evidence_satisfied(
    *,
    active_planning_record: dict[str, Any],
    intent_satisfaction_check: dict[str, Any],
    acceptance_reconciliation: dict[str, Any],
    intent_proof_check: dict[str, Any],
    parent_intent_status: dict[str, Any],
    applicable_intent_status: dict[str, Any],
) -> bool:
    active_planning_record = _as_dict(active_planning_record)
    if not active_planning_record:
        return False
    intent_satisfaction = _as_dict(active_planning_record.get("intent_satisfaction"))
    intent_continuity = _as_dict(active_planning_record.get("intent_continuity"))
    required_continuation = _as_dict(active_planning_record.get("required_continuation"))
    closure_check = _as_dict(active_planning_record.get("closure_check"))
    intent_trust = str(intent_satisfaction_check.get("trust") or "").strip().lower()
    acceptance_trust = str(acceptance_reconciliation.get("trust") or "").strip().lower()
    proof_status = str(intent_proof_check.get("status") or "").strip().lower().replace("-", "_")
    parent_status = str(parent_intent_status.get("status") or "").strip().lower()
    closure_status = str(closure_check.get("larger-intent status") or closure_check.get("larger_intent_status") or "").strip().lower()
    closure_decision = str(closure_check.get("closure decision") or closure_check.get("closure_decision") or "").strip().lower()
    intent_satisfied = str(intent_satisfaction.get("was original intent fully satisfied?") or "").strip().lower() in {
        "yes",
        "true",
        "satisfied",
        "complete",
        "completed",
    } or str(intent_continuity.get("this slice completes the larger intended outcome") or "").strip().lower() in {
        "yes",
        "true",
        "satisfied",
        "complete",
        "completed",
    }
    required_follow_on = (
        str(
            required_continuation.get("required follow-on for the larger intended outcome")
            or intent_satisfaction_check.get("required_follow_on")
            or ""
        )
        .strip()
        .lower()
    )
    explicit_closeout_satisfied = closure_status in {"closed", "complete", "completed", "done", ""} and (
        closure_decision in {"archive-and-close", "close", "closed", ""} or closure_decision.startswith("archive-and-close-")
    )
    return bool(
        (intent_satisfied or intent_trust in {"satisfied", "normal"})
        and required_follow_on in {"", "no", "false", "none"}
        and (parent_status in {"satisfied", "guidance-only", ""} or explicit_closeout_satisfied)
        and acceptance_trust in {"", "normal", "not-applicable"}
        and proof_status in {"representative", "sufficient_for_claim"}
        and not applicable_intent_status.get("closeout_blocked")
    )


def _assurance_claim_blockers(assurance_requirements: dict[str, Any] | None) -> dict[str, list[str]]:
    blockers: dict[str, list[str]] = {
        "claim-slice-complete": [],
        "claim-work-complete": [],
        "close-parent-lane": [],
    }
    if not isinstance(assurance_requirements, dict):
        return blockers
    evidence_status = assurance_requirements.get("evidence_status", [])
    if not isinstance(evidence_status, list):
        return blockers
    for status in evidence_status:
        if not isinstance(status, dict):
            continue
        for gap in _list_payload(status.get("verification_known_gaps")):
            if not isinstance(gap, dict):
                continue
            gap_id = str(gap.get("id", "")).strip() or "unknown"
            for claim in [str(item).strip() for item in _list_payload(gap.get("blocked_claims")) if str(item).strip()]:
                if claim in blockers:
                    blockers[claim].append(f"verification_known_gap:{gap_id}")
        if status.get("state") not in {"missing-evidence", "review-required"}:
            continue
        force = str(status.get("force", "recommended"))
        if force not in {"required-before-closeout", "blocking"}:
            continue
        requirement_id = str(status.get("requirement_id", "")).strip() or "unknown"
        blocking_claims = [str(item).strip() for item in _list_payload(status.get("blocking_claims")) if str(item).strip()]
        if not blocking_claims and force in {"required-before-closeout", "blocking"}:
            blocking_claims = ["claim-work-complete", "close-parent-lane"]
        for claim in blocking_claims:
            if claim in blockers:
                blockers[claim].append(f"assurance_evidence:{requirement_id}")
    return {claim: _dedupe(values) for claim, values in blockers.items()}


def _closeout_strict_gate_payload(
    *, strict_closeout: bool, trust: str, reason: str = "", active_planning_record: bool = False
) -> dict[str, Any]:
    if not strict_closeout:
        status = "disabled"
        blocking = False
        summary = "Strict closeout is disabled in assurance config."
    elif not active_planning_record and trust == "normal":
        status = "not-applicable"
        blocking = False
        summary = "Strict closeout has no active planning record to gate; use normal direct-work proof and issue checks."
    elif trust == "normal":
        status = "allowed"
        blocking = False
        summary = "Strict closeout is satisfied by the available planning and closeout-trust evidence."
    elif trust == "lower-trust":
        status = "blocked"
        blocking = True
        summary = "Strict closeout blocks closure until lower-trust planning residue or package evidence is resolved."
    else:
        status = "requires-review"
        blocking = True
        summary = "Strict closeout requires review because closeout evidence is unavailable or incomplete."
    return {
        "status": status,
        "strict_closeout": strict_closeout,
        "blocking": blocking,
        "reason": reason,
        "summary": summary,
        "source": "assurance.strict_closeout",
    }


def _closeout_terminal_action_payload(*, trust: str, recommended_next_action: str, cli_invoke: str) -> dict[str, Any]:
    blocking = trust != "normal"
    return {
        "next_command": _command_with_cli_invoke(
            command="agentic-workspace report --target ./repo --section closeout_trust --format json", cli_invoke=cli_invoke
        )
        if blocking
        else "none",
        "why": "Lower-trust closeout signals need routed residue before closure is reliable."
        if trust == "lower-trust"
        else "Closeout trust is unavailable; recover planning output before claiming closure."
        if blocking
        else "No closeout trust blocker is visible; use normal proof and issue-state checks.",
        "blocking": blocking,
        "recommended_next_action": recommended_next_action,
        "changes_closure": "Route missing planning residue, rerun summary/reconcile, then close only when lower_trust_closeout_count is 0."
        if trust == "lower-trust"
        else "Recover planning closeout evidence; closure is blocked until closeout_trust is present."
        if blocking
        else "None for closeout trust; closure changes only if proof, intent satisfaction, issue state, or new residue changes.",
    }


def _closeout_durable_residue_action_payload(*, trust: str, cli_invoke: str) -> dict[str, Any]:
    action = {
        "action": "route-durable-residue",
        "visible_states": ["none-found", "capture", "route-to-owner", "dismissed"],
        "summary": "Review lower-trust closeout signals and route missing residue to planning, Memory, docs, checks, or issue follow-up."
        if trust == "lower-trust"
        else "If closeout produced reusable learning, route it to the narrowest durable owner; otherwise record no durable residue.",
        "command": _command_with_cli_invoke(
            command="agentic-workspace report --target ./repo --section closeout_trust --format json", cli_invoke=cli_invoke
        ),
        "risk": "read-only routing; mutations happen only through the selected owner surface",
        "required_inputs": ["validation result", "issue or lane scope", "future relevance of any learning"],
        "destinations": ["none", "planning", "Memory", "docs", "contracts/checks", "issue follow-up", "review/archive evidence"],
        "destination_rule": "future work goes to planning; reusable non-canonical knowledge goes to Memory; stable rules go to docs/contracts/checks; evidence-only stays in review/archive; otherwise choose none",
        "next_proof": "rerun summary/reconcile after routing residue before closing the issue or lane",
    }
    action["run"] = action["command"]
    return action


def _fast_closeout_claim_boundary_payload(
    *,
    target_root: Path,
    config: WorkspaceConfig,
    cli_invoke: str = DEFAULT_CLI_INVOKE,
) -> dict[str, Any]:
    strict_closeout = bool(config.assurance.strict_closeout)
    try:
        from repo_planning_bootstrap.installer import planning_report

        planning_module_report = planning_report(target=target_root)
    except Exception:
        planning_module_report = {"module": "planning", "health": "unknown", "findings": []}

    planning_report_payload = planning_module_report if isinstance(planning_module_report, dict) else {}
    intent_validation = planning_report_payload.get("intent_validation", {})
    intent_validation = intent_validation if isinstance(intent_validation, dict) else {}
    counts = intent_validation.get("counts", {})
    signals = intent_validation.get("signals", [])
    lower_trust_closeout_count = int(counts.get("lower_trust_closeout_count", 0) or 0) if isinstance(counts, dict) else 0
    sample_signals = [
        str(signal.get("message", "")).strip()
        for signal in signals
        if isinstance(signal, dict) and signal.get("kind") == "closed_without_planning_residue"
    ]
    sample_signals = [message for message in sample_signals if message][:3]
    package_workflow_evidence = _package_workflow_evidence_payload(planning_report=planning_report_payload)
    intent_satisfaction_check = _intent_satisfaction_check_payload(planning_report=planning_report_payload, target_root=target_root)
    acceptance_reconciliation = _acceptance_criteria_reconciliation_payload(planning_report=planning_report_payload)
    intent_proof_check = _intent_proof_check_payload(planning_report=planning_report_payload, target_root=target_root)
    active_payload = _as_dict(planning_report_payload.get("active"))
    raw_active_planning_record = _raw_active_planning_record_for_closeout(
        planning_record=active_payload.get("planning_record", {}),
        target_root=target_root,
    )
    assurance_requirements = _assurance_requirements_report_payload(
        config=config,
        target_root=target_root,
        active_planning_record=raw_active_planning_record,
    )
    verification = _verification_report_payload(
        target_root=target_root,
        active_planning_record=raw_active_planning_record,
        assurance_requirements=assurance_requirements,
    )
    assurance_requirements = _assurance_requirements_with_verification(assurance_requirements, verification)
    applicable_intent_status = _applicable_intent_status_payload(
        active_planning_record=raw_active_planning_record,
        verification=verification,
        assurance_requirements=assurance_requirements,
    )
    parent_intent_status = _parent_intent_status_payload(
        active_planning_record=raw_active_planning_record,
        intent_check=intent_satisfaction_check,
        completion_boundary=intent_satisfaction_check.get("completion_boundary", {}),
    )
    active_closeout_satisfied = _active_closeout_evidence_satisfied(
        active_planning_record=raw_active_planning_record,
        intent_satisfaction_check=intent_satisfaction_check,
        acceptance_reconciliation=acceptance_reconciliation,
        intent_proof_check=intent_proof_check,
        parent_intent_status=parent_intent_status,
        applicable_intent_status=applicable_intent_status,
    )
    active_planning_record_present = package_workflow_evidence.get("status") == "present"
    package_absence_signals: list[str] = []
    if (
        package_workflow_evidence.get("status") == "present"
        and package_workflow_evidence.get("trust") == "lower-trust"
        and not active_closeout_satisfied
    ):
        missing = ", ".join((str(item) for item in package_workflow_evidence.get("missing_expected_surfaces", [])))
        missing = missing or "package workflow evidence"
        package_absence_signals.append(
            f"Active planning record is present, but package workflow evidence is incomplete or absent: missing {missing}."
        )
    effective_lower_trust_count = lower_trust_closeout_count + len(package_absence_signals)
    if acceptance_reconciliation.get("trust") == "lower-trust":
        effective_lower_trust_count += 1
    intent_satisfaction_trust = str(intent_satisfaction_check.get("trust", ""))
    intent_satisfaction_lower_trust_count = 1 if intent_satisfaction_trust in {"follow-up-required", "needs-review"} else 0
    effective_lower_trust_count += intent_satisfaction_lower_trust_count
    intent_satisfaction_signals: list[str] = []
    if intent_satisfaction_lower_trust_count:
        continuation_surface = str(intent_satisfaction_check.get("continuation_surface", "")).strip()
        continuation_summary = f" via {continuation_surface}" if continuation_surface else ""
        intent_satisfaction_signals.append(
            f"Intent satisfaction is {intent_satisfaction_trust}{continuation_summary}; closeout needs package-owned continuation evidence before it is normal-trust."
        )
    trust = "lower-trust" if effective_lower_trust_count > 0 else "normal"
    if not intent_validation:
        trust = "unavailable"
    if trust == "lower-trust":
        recommended_next_action = str(
            intent_validation.get("recommended_next_action")
            or "Review the lower-trust closeout signals before treating planning closeout as normal."
        )
    elif trust == "unavailable":
        recommended_next_action = "Inspect planning report before trusting closeout state."
    else:
        recommended_next_action = "No extra closeout trust review is needed beyond normal report inspection."
    gate = _closeout_strict_gate_payload(
        strict_closeout=strict_closeout,
        trust=trust,
        reason="active planning record present" if active_planning_record_present else "no active planning record",
        active_planning_record=active_planning_record_present,
    )
    residue_action = _closeout_durable_residue_action_payload(trust=trust, cli_invoke=cli_invoke)
    completion_gate = _completion_gate_payload(
        active_planning_record=raw_active_planning_record,
        intent_check=intent_satisfaction_check,
        acceptance_reconciliation=acceptance_reconciliation,
        intent_proof_check=intent_proof_check,
        parent_intent_status=parent_intent_status,
        applicable_intent_status=applicable_intent_status,
        durable_residue_action=residue_action,
    )
    task_posture_followthrough = _as_dict(completion_gate.get("task_posture_followthrough"))
    proof_confidence = _proof_confidence_payload(intent_proof=intent_proof_check)
    completion_options = _closeout_completion_options(
        status="present" if trust != "unavailable" else "unavailable",
        trust=trust,
        strict_gate=gate,
        completion_gate=completion_gate,
        intent_check=intent_satisfaction_check,
        acceptance_reconciliation=acceptance_reconciliation,
        intent_proof_check=intent_proof_check,
        assurance_requirements=assurance_requirements,
        durable_residue_action=residue_action,
        lower_trust_closeout_count=effective_lower_trust_count,
        cli_invoke=cli_invoke,
    )
    closeout_protocol = _closeout_protocol_payload(
        status="present" if trust != "unavailable" else "unavailable",
        trust=trust,
        strict_gate=gate,
        completion_gate=completion_gate,
        completion_options=completion_options,
        durable_residue_action=residue_action,
        knowledge_authority_review={},
        proof_confidence=proof_confidence,
        verification=verification,
        task_posture_followthrough=task_posture_followthrough,
        recommended_next_action=recommended_next_action,
        cli_invoke=cli_invoke,
    )
    terminal_outcome_contract = _terminal_outcome_contract_payload(
        completion_gate=completion_gate,
        completion_options=completion_options,
        recommended_next_action=recommended_next_action,
        source_surface="closeout_claim_boundary.direct",
    )
    source_payload = {
        "kind": "agentic-workspace/closeout-claim-boundary-source/v1",
        "source_surface": "closeout_claim_boundary.direct",
        "status": "present" if trust != "unavailable" else "unavailable",
        "trust": trust,
        "strict_closeout_gate": gate,
        "completion_gate": completion_gate,
        "task_posture_followthrough": task_posture_followthrough,
        "lower_trust_closeout_count": effective_lower_trust_count,
        "sample_signals": [*sample_signals, *package_absence_signals, *intent_satisfaction_signals][:3],
        "intent_satisfaction_check": intent_satisfaction_check,
        "acceptance_criteria_reconciliation": acceptance_reconciliation,
        "intent_proof_check": intent_proof_check,
        "proof_confidence": proof_confidence,
        "verification": verification,
        "durable_residue_action": residue_action,
        "terminal_action": _closeout_terminal_action_payload(
            trust=trust, recommended_next_action=recommended_next_action, cli_invoke=cli_invoke
        ),
        "completion_options": completion_options,
        "terminal_outcome_contract": terminal_outcome_contract,
        "closeout_protocol": closeout_protocol,
        "recommended_next_action": recommended_next_action,
        "computation": {
            "path": "direct-compact-claim-boundary",
            "avoids_full_closeout_trust": True,
            "required_source": "planning_report",
            "omitted_full_sections": [
                "memory_consult",
                "memory_decision_packet",
                "operating_loop",
                "historical_review_artifacts",
                "architecture_decision_closeout",
            ],
            "structural_evidence": "report --section closeout_claim_boundary builds this source directly instead of calling _report_closeout_trust_payload",
        },
    }
    return closeout_claim_boundary_payload(source_payload, cli_invoke=cli_invoke, target_arg="./repo")


def _report_closeout_trust_payload(
    *,
    module_reports: list[dict[str, Any]],
    target_root: Path | None = None,
    config: WorkspaceConfig | None = None,
    cli_invoke: str = DEFAULT_CLI_INVOKE,
    task_text: str | None = None,
    changed_paths: list[str] | None = None,
) -> dict[str, Any]:
    strict_closeout = bool(config.assurance.strict_closeout) if config is not None else False
    normalized_changed_paths = _normalize_changed_paths(changed_paths or [])
    knowledge_authority_review = _knowledge_authority_review_payload(
        target_root=target_root,
        source_payload={"module_reports": module_reports},
        changed_paths=[],
        task_text=None,
        cli_invoke=cli_invoke,
        compact=True,
    )

    def strict_gate(*, trust: str, reason: str = "", active_planning_record: bool = False) -> dict[str, Any]:
        if not strict_closeout:
            status = "disabled"
            blocking = False
            summary = "Strict closeout is disabled in assurance config."
        elif not active_planning_record and trust == "normal":
            status = "not-applicable"
            blocking = False
            summary = "Strict closeout has no active planning record to gate; use normal direct-work proof and issue checks."
        elif trust == "normal":
            status = "allowed"
            blocking = False
            summary = "Strict closeout is satisfied by the available planning and closeout-trust evidence."
        elif trust == "lower-trust":
            status = "blocked"
            blocking = True
            summary = "Strict closeout blocks closure until lower-trust planning residue or package evidence is resolved."
        else:
            status = "requires-review"
            blocking = True
            summary = "Strict closeout requires review because closeout evidence is unavailable or incomplete."
        return {
            "status": status,
            "strict_closeout": strict_closeout,
            "blocking": blocking,
            "reason": reason,
            "summary": summary,
            "source": "assurance.strict_closeout",
        }

    def terminal_action(*, trust: str, recommended_next_action: str) -> dict[str, Any]:
        blocking = trust != "normal"
        return {
            "next_command": _command_with_cli_invoke(
                command="agentic-workspace report --target ./repo --section closeout_trust --format json", cli_invoke=cli_invoke
            )
            if blocking
            else "none",
            "why": "Lower-trust closeout signals need routed residue before closure is reliable."
            if trust == "lower-trust"
            else "Closeout trust is unavailable; recover planning output before claiming closure."
            if blocking
            else "No closeout trust blocker is visible; use normal proof and issue-state checks.",
            "blocking": blocking,
            "recommended_next_action": recommended_next_action,
            "changes_closure": "Route missing planning residue, rerun summary/reconcile, then close only when lower_trust_closeout_count is 0."
            if trust == "lower-trust"
            else "Recover planning closeout evidence; closure is blocked until closeout_trust is present."
            if blocking
            else "None for closeout trust; closure changes only if proof, intent satisfaction, issue state, or new residue changes.",
        }

    def durable_residue_action(*, trust: str) -> dict[str, Any]:
        action = {
            "action": "route-durable-residue",
            "visible_states": ["none-found", "capture", "route-to-owner", "dismissed"],
            "summary": "Review lower-trust closeout signals and route missing residue to planning, Memory, docs, checks, or issue follow-up."
            if trust == "lower-trust"
            else "If closeout produced reusable learning, route it to the narrowest durable owner; otherwise record no durable residue.",
            "command": _command_with_cli_invoke(
                command="agentic-workspace report --target ./repo --section closeout_trust --format json", cli_invoke=cli_invoke
            ),
            "risk": "read-only routing; mutations happen only through the selected owner surface",
            "required_inputs": ["validation result", "issue or lane scope", "future relevance of any learning"],
            "destinations": ["none", "planning", "Memory", "docs", "contracts/checks", "issue follow-up", "review/archive evidence"],
            "destination_rule": "future work goes to planning; reusable non-canonical knowledge goes to Memory; stable rules go to docs/contracts/checks; evidence-only stays in review/archive; otherwise choose none",
            "next_proof": "rerun summary/reconcile after routing residue before closing the issue or lane",
        }
        action["run"] = action["command"]
        return action

    def current_task_switch_scope() -> dict[str, Any]:
        if target_root is None or config is None or not normalized_changed_paths or not str(task_text or "").strip():
            return {"kind": "agentic-workspace/current-task-closeout-scope/v1", "status": "not-applicable"}
        execution_posture = _execution_posture_payload(
            config=config,
            changed_paths=normalized_changed_paths,
            task_text=task_text,
            target_root=target_root,
        )
        planning_safety_gate = _planning_safety_gate_payload(
            target_root=target_root,
            config=config,
            changed_paths=normalized_changed_paths,
            task_text=task_text,
            execution_posture=execution_posture,
        )
        task_switch = _as_dict(planning_safety_gate.get("task_switch_reconciliation"))
        if (
            str(planning_safety_gate.get("gate_result") or "") != "active-plan-task-switch"
            or planning_safety_gate.get("workflow_sufficient") is not True
            or str(task_switch.get("status") or "") != "active"
        ):
            return {
                "kind": "agentic-workspace/current-task-closeout-scope/v1",
                "status": "not-applicable",
                "planning_safety_gate": _selector_first_planning_safety_gate(planning_safety_gate),
            }
        return {
            "kind": "agentic-workspace/current-task-closeout-scope/v1",
            "status": "active",
            "relationship": "bounded-task-switch",
            "changed_paths": normalized_changed_paths,
            "planning_safety_gate": _selector_first_planning_safety_gate(planning_safety_gate),
            "task_switch_reconciliation": task_switch,
            "rule": "The active plan remains protected repo-wide residue; this scope only classifies current bounded-task closeout blockers.",
        }

    def current_pr_comment_repair_scope() -> dict[str, Any]:
        if target_root is None or config is None or not normalized_changed_paths or not str(task_text or "").strip():
            return {"kind": "agentic-workspace/current-task-closeout-scope/v1", "status": "not-applicable"}
        repair_context = _pr_comment_repair_context_payload(task_text=task_text, changed_paths=normalized_changed_paths)
        if repair_context.get("status") != "active":
            return {"kind": "agentic-workspace/current-task-closeout-scope/v1", "status": "not-applicable"}
        execution_posture = _execution_posture_payload(
            config=config,
            changed_paths=normalized_changed_paths,
            task_text=task_text,
            target_root=target_root,
        )
        planning_safety_gate = _planning_safety_gate_payload(
            target_root=target_root,
            config=config,
            changed_paths=normalized_changed_paths,
            task_text=task_text,
            execution_posture=execution_posture,
        )
        return {
            "kind": "agentic-workspace/current-task-closeout-scope/v1",
            "status": "active",
            "relationship": "bounded-pr-comment-repair",
            "changed_paths": normalized_changed_paths,
            "claim_class": "pr_feedback_addressed",
            "claim_boundary": repair_context.get("claim_boundary", ""),
            "planning_safety_gate": _selector_first_planning_safety_gate(planning_safety_gate),
            "pr_comment_repair_context": repair_context,
            "rule": "This scope only supports claiming PR feedback addressed with proof; it does not authorize issue, lane, parent, or full-intent completion.",
        }

    def archived_slice_closeout_evidence() -> dict[str, Any]:
        archived_record = _closeout_planning_record_for_report(active_planning_record={}, target_root=target_root, task_text=task_text)
        if not archived_record:
            return {"status": "absent", "trust": "not-applicable"}
        resolution = _as_dict(archived_record.get("_closeout_evidence_resolution"))
        if resolution:
            return resolution
        evidence_source = _as_dict(archived_record.get("_closeout_evidence_source"))
        proof_report = _as_dict(archived_record.get("proof_report"))
        closure_check = _as_dict(archived_record.get("closure_check"))
        proof_text = " ".join(
            str(value)
            for value in (
                proof_report.get("validation proof"),
                proof_report.get("proof achieved now"),
                proof_report.get('evidence for "proof achieved" state'),
            )
            if value
        ).lower()
        proof_recorded = any(marker in proof_text for marker in ("passed", "yes", "satisfied", "achieved", "complete"))
        slice_status = str(closure_check.get("slice status") or "").strip().lower()
        closure_decision = str(closure_check.get("closure decision") or "").strip().lower()
        slice_completed = slice_status in {"complete", "completed", "done", "closed", "satisfied"}
        command_owned = evidence_source.get("authority") in {"archived-planning-evidence", "retained-closeout-evidence"}
        relevance = _as_dict(evidence_source.get("relevance"))
        evidence_selection = _as_dict(evidence_source.get("selection"))
        relevance_status = str(relevance.get("status") or "relevant")
        slice_trusted = bool(command_owned and proof_recorded and slice_completed and closure_decision and relevance_status != "unrelated")
        parent_status = str(closure_check.get("larger-intent status") or "").strip().lower()
        parent_closure_blocked = parent_status not in {"closed", "complete", "completed", "done"}
        return {
            "status": "present",
            "trust": "normal" if slice_trusted else "lower-trust",
            "scope": "slice",
            "canonical_evidence": evidence_source.get("authority", "archived-planning-evidence"),
            "evidence_source_class": evidence_source.get("evidence_source_class", ""),
            "owner_surface": evidence_source.get("path", ""),
            "owner_kind": evidence_source.get("authority", "archived-planning-evidence"),
            "evidence_relationship": evidence_source.get("relationship")
            or ("retained-archive-evidence" if evidence_source.get("authority") == "archived-planning-evidence" else "closeout-evidence"),
            "relevance": relevance
            or {
                "status": "relevant",
                "relationship": evidence_source.get("relationship", ""),
                "rule": "No explicit closeout evidence relevance metadata was available; treating selected evidence as historical slice evidence.",
            },
            "evidence_selection": evidence_selection,
            "source_plan": evidence_source.get("source_plan", ""),
            "intended_archive": evidence_source.get("intended_archive", ""),
            "retention_state": evidence_source.get("retention_state", ""),
            "freshness": {
                "last_modified": evidence_source.get("last_modified", ""),
                "sort_mtime": evidence_source.get("sort_mtime", 0.0),
                "rule": "Freshness is based on the selected closeout evidence record mtime, not on issue or PR state.",
            },
            "source": evidence_source,
            "proof_recorded": proof_recorded,
            "slice_completed": slice_completed,
            "slice_status": closure_check.get("slice status", ""),
            "closure_decision": closure_check.get("closure decision", ""),
            "parent_intent_status": closure_check.get("larger-intent status", ""),
            "parent_closure_blocked": parent_closure_blocked,
            "rule": (
                "Archived closeout evidence may be trusted for the completed slice, but it does not restore active "
                "planning state or authorize parent/epic closure."
            ),
        }

    def allow_archived_slice_claim(options: list[dict[str, Any]], slice_evidence: dict[str, Any]) -> list[dict[str, Any]]:
        if slice_evidence.get("trust") != "normal":
            return options
        validation_proof_blocker = "intent_satisfaction.closure_scope.validation_proof"
        adjusted: list[dict[str, Any]] = []
        for option in options:
            if not isinstance(option, dict):
                adjusted.append(option)
                continue
            updated = dict(option)
            if updated.get("id") == "run-proof":
                updated["allowed"] = False
                updated["why"] = "archived command-owned slice closeout proof is already visible"
                updated.pop("blocking_fields", None)
                updated["evidence_owner"] = slice_evidence.get("owner_surface", "")
            elif updated.get("id") == "claim-slice-complete":
                blockers = [
                    blocker for blocker in _list_payload(updated.get("blocking_fields")) if str(blocker) != validation_proof_blocker
                ]
                updated["allowed"] = True
                updated["why"] = "archived command-owned slice closeout evidence supports a bounded slice completion claim"
                if blockers:
                    updated["blocking_fields"] = blockers
                else:
                    updated.pop("blocking_fields", None)
                updated["evidence_owner"] = slice_evidence.get("owner_surface", "")
            adjusted.append(updated)
        return adjusted

    task_switch_scope = current_task_switch_scope()
    pr_comment_repair_scope = current_pr_comment_repair_scope() if task_switch_scope.get("status") != "active" else {}
    current_bounded_scope = task_switch_scope if task_switch_scope.get("status") == "active" else pr_comment_repair_scope
    planning_report = next((report for report in module_reports if isinstance(report, dict) and report.get("module") == "planning"), None)
    if not isinstance(planning_report, dict):
        gate = strict_gate(trust="unavailable", reason="planning module is not installed", active_planning_record=False)
        intent_check = _intent_satisfaction_check_payload(planning_report={}, target_root=target_root)
        acceptance_reconciliation = _acceptance_criteria_reconciliation_payload(planning_report={})
        active_intent_contract = _active_intent_contract_payload(task_text=None, acceptance={}, active_planning_record={})
        intent_satisfaction_matrix = _intent_satisfaction_matrix_payload(
            active_intent_contract=active_intent_contract,
            acceptance={},
            proof={},
            intent_check=intent_check,
            parent_intent_status={},
        )
        intent_proof_check = _intent_proof_check_payload(planning_report={}, target_root=target_root)
        architecture_decision_closeout = _architecture_decision_closeout_payload(planning_report={}, target_root=target_root, config=config)
        assurance_requirements = _assurance_requirements_report_payload(config=config, target_root=target_root)
        verification = _verification_report_payload(
            target_root=target_root,
            assurance_requirements=assurance_requirements,
        )
        assurance_requirements = _assurance_requirements_with_verification(assurance_requirements, verification)
        residue_action = durable_residue_action(trust="unavailable")
        completion_gate = _completion_gate_payload(
            active_planning_record={},
            intent_check=intent_check,
            acceptance_reconciliation=acceptance_reconciliation,
            intent_proof_check=intent_proof_check,
            parent_intent_status={},
            applicable_intent_status={},
            durable_residue_action=residue_action,
        )
        proof_confidence = _proof_confidence_payload(intent_proof=intent_proof_check)
        completion_options = _closeout_completion_options(
            status="unavailable",
            trust="unavailable",
            strict_gate=gate,
            completion_gate=completion_gate,
            intent_check=intent_check,
            acceptance_reconciliation=acceptance_reconciliation,
            intent_proof_check=intent_proof_check,
            assurance_requirements=assurance_requirements,
            durable_residue_action=residue_action,
            lower_trust_closeout_count=1,
            cli_invoke=cli_invoke,
        )
        return {
            "status": "unavailable",
            "reason": "planning module is not installed",
            "strict_closeout_gate": gate,
            "completion_gate": completion_gate,
            "package_workflow_evidence": _package_workflow_evidence_payload(planning_report={}),
            "intent_satisfaction_check": intent_check,
            "acceptance_criteria_reconciliation": acceptance_reconciliation,
            "active_intent_contract": active_intent_contract,
            "intent_satisfaction_matrix": intent_satisfaction_matrix,
            "intent_proof_check": intent_proof_check,
            "proof_confidence": proof_confidence,
            "assurance_requirements": assurance_requirements,
            "verification": verification,
            "knowledge_authority_review": knowledge_authority_review,
            "architecture_decision_closeout": architecture_decision_closeout,
            "historical_review_artifacts": _historical_review_artifacts_policy(
                planning_report={}, intent_validation={}, target_root=target_root
            ),
            "durable_residue_action": residue_action,
            "terminal_action": terminal_action(
                trust="unavailable", recommended_next_action="Install or run planning report before trusting closeout state."
            ),
            "completion_options": completion_options,
            "closeout_protocol": _closeout_protocol_payload(
                status="unavailable",
                trust="unavailable",
                strict_gate=gate,
                completion_gate=completion_gate,
                completion_options=completion_options,
                durable_residue_action=residue_action,
                knowledge_authority_review=knowledge_authority_review,
                proof_confidence=proof_confidence,
                verification=verification,
                recommended_next_action="Install or run planning report before trusting closeout state.",
                cli_invoke=cli_invoke,
            ),
        }
    intent_validation = planning_report.get("intent_validation", {})
    if not isinstance(intent_validation, dict):
        gate = strict_gate(trust="unavailable", reason="planning intent validation is unavailable", active_planning_record=False)
        intent_check = _intent_satisfaction_check_payload(planning_report=planning_report, target_root=target_root)
        acceptance_reconciliation = _acceptance_criteria_reconciliation_payload(planning_report=planning_report)
        active_intent_contract = _active_intent_contract_payload(task_text=None, acceptance={}, active_planning_record={})
        intent_satisfaction_matrix = _intent_satisfaction_matrix_payload(
            active_intent_contract=active_intent_contract,
            acceptance={},
            proof={},
            intent_check=intent_check,
            parent_intent_status={},
        )
        intent_proof_check = _intent_proof_check_payload(planning_report=planning_report, target_root=target_root)
        architecture_decision_closeout = _architecture_decision_closeout_payload(
            planning_report=planning_report, target_root=target_root, config=config
        )
        assurance_requirements = _assurance_requirements_report_payload(config=config, target_root=target_root)
        verification = _verification_report_payload(
            target_root=target_root,
            assurance_requirements=assurance_requirements,
        )
        assurance_requirements = _assurance_requirements_with_verification(assurance_requirements, verification)
        residue_action = durable_residue_action(trust="unavailable")
        completion_gate = _completion_gate_payload(
            active_planning_record={},
            intent_check=intent_check,
            acceptance_reconciliation=acceptance_reconciliation,
            intent_proof_check=intent_proof_check,
            parent_intent_status={},
            applicable_intent_status={},
            durable_residue_action=residue_action,
        )
        proof_confidence = _proof_confidence_payload(intent_proof=intent_proof_check)
        completion_options = _closeout_completion_options(
            status="unavailable",
            trust="unavailable",
            strict_gate=gate,
            completion_gate=completion_gate,
            intent_check=intent_check,
            acceptance_reconciliation=acceptance_reconciliation,
            intent_proof_check=intent_proof_check,
            assurance_requirements=assurance_requirements,
            durable_residue_action=residue_action,
            lower_trust_closeout_count=1,
            cli_invoke=cli_invoke,
        )
        return {
            "status": "unavailable",
            "reason": "planning intent validation is unavailable",
            "strict_closeout_gate": gate,
            "completion_gate": completion_gate,
            "package_workflow_evidence": _package_workflow_evidence_payload(planning_report=planning_report),
            "intent_satisfaction_check": intent_check,
            "acceptance_criteria_reconciliation": acceptance_reconciliation,
            "active_intent_contract": active_intent_contract,
            "intent_satisfaction_matrix": intent_satisfaction_matrix,
            "intent_proof_check": intent_proof_check,
            "proof_confidence": proof_confidence,
            "assurance_requirements": assurance_requirements,
            "verification": verification,
            "knowledge_authority_review": knowledge_authority_review,
            "architecture_decision_closeout": architecture_decision_closeout,
            "historical_review_artifacts": _historical_review_artifacts_policy(
                planning_report=planning_report, intent_validation={}, target_root=target_root
            ),
            "durable_residue_action": residue_action,
            "terminal_action": terminal_action(
                trust="unavailable", recommended_next_action="Inspect planning report before trusting closeout state."
            ),
            "completion_options": completion_options,
            "closeout_protocol": _closeout_protocol_payload(
                status="unavailable",
                trust="unavailable",
                strict_gate=gate,
                completion_gate=completion_gate,
                completion_options=completion_options,
                durable_residue_action=residue_action,
                knowledge_authority_review=knowledge_authority_review,
                proof_confidence=proof_confidence,
                verification=verification,
                recommended_next_action="Inspect planning report before trusting closeout state.",
                cli_invoke=cli_invoke,
            ),
        }
    counts = intent_validation.get("counts", {})
    signals = intent_validation.get("signals", [])
    lower_trust_closeout_count = 0
    if isinstance(counts, dict):
        lower_trust_closeout_count = int(counts.get("lower_trust_closeout_count", 0) or 0)
    sample_signals = [
        str(signal.get("message", "")).strip()
        for signal in signals
        if isinstance(signal, dict) and signal.get("kind") == "closed_without_planning_residue"
    ]
    sample_signals = [message for message in sample_signals if message][:3]
    package_workflow_evidence = _package_workflow_evidence_payload(planning_report=planning_report)
    intent_satisfaction_check = _intent_satisfaction_check_payload(planning_report=planning_report, target_root=target_root)
    slice_closeout_evidence = {}
    raw_active = planning_report.get("active", {}).get("planning_record", {}) if isinstance(planning_report.get("active"), dict) else {}
    if not isinstance(raw_active, dict) or raw_active.get("status") != "present":
        slice_closeout_evidence = archived_slice_closeout_evidence()
        if slice_closeout_evidence.get("trust") == "normal":
            intent_satisfaction_check = copy.deepcopy(intent_satisfaction_check)
            intent_satisfaction_check["archived_slice_closeout_evidence"] = slice_closeout_evidence
            closure_scope = _as_dict(intent_satisfaction_check.get("closure_scope"))
            validation_proof = _as_dict(closure_scope.get("validation_proof"))
            validation_proof.update(
                {
                    "status": "recorded",
                    "proof_report": "archived command-owned closeout proof is available",
                    "proof_achieved_now": "yes",
                    "source": slice_closeout_evidence.get("owner_surface", ""),
                    "claim_boundary": "slice only",
                    "not_sufficient_for_closure": True,
                }
            )
            closure_scope["validation_proof"] = validation_proof
            intent_satisfaction_check["closure_scope"] = closure_scope
    acceptance_reconciliation = _acceptance_criteria_reconciliation_payload(planning_report=planning_report)
    intent_proof_check = _intent_proof_check_payload(planning_report=planning_report, target_root=target_root)
    architecture_decision_closeout = _architecture_decision_closeout_payload(
        planning_report=planning_report, target_root=target_root, config=config
    )
    raw_active_planning_record = _raw_active_planning_record_for_closeout(
        planning_record=planning_report.get("active", {}).get("planning_record", {})
        if isinstance(planning_report.get("active"), dict)
        else {},
        target_root=target_root,
    )
    active_intent_contract = _active_intent_contract_payload(
        task_text=None,
        acceptance={},
        active_planning_record=raw_active_planning_record
        or (planning_report.get("active", {}).get("planning_record", {}) if isinstance(planning_report.get("active"), dict) else {}),
    )
    parent_intent_status = _parent_intent_status_payload(
        active_planning_record=raw_active_planning_record
        or (planning_report.get("active", {}).get("planning_record", {}) if isinstance(planning_report.get("active"), dict) else {}),
        intent_check=intent_satisfaction_check,
        completion_boundary=intent_satisfaction_check.get("completion_boundary", {}),
    )
    intent_satisfaction_matrix = _intent_satisfaction_matrix_payload(
        active_intent_contract=active_intent_contract,
        acceptance={},
        proof={"intent_proof": intent_proof_check},
        intent_check=intent_satisfaction_check,
        parent_intent_status=parent_intent_status,
    )
    assurance_requirements = _assurance_requirements_report_payload(
        config=config,
        target_root=target_root,
        active_planning_record=raw_active_planning_record,
    )
    verification = _verification_report_payload(
        target_root=target_root,
        active_planning_record=raw_active_planning_record,
        assurance_requirements=assurance_requirements,
    )
    assurance_requirements = _assurance_requirements_with_verification(assurance_requirements, verification)
    applicable_intent_status = _applicable_intent_status_payload(
        active_planning_record=raw_active_planning_record,
        verification=verification,
        assurance_requirements=assurance_requirements,
    )
    active_closeout_satisfied = _active_closeout_evidence_satisfied(
        active_planning_record=raw_active_planning_record,
        intent_satisfaction_check=intent_satisfaction_check,
        acceptance_reconciliation=acceptance_reconciliation,
        intent_proof_check=intent_proof_check,
        parent_intent_status=parent_intent_status,
        applicable_intent_status=applicable_intent_status,
    )
    active_planning_record = package_workflow_evidence.get("status") == "present"
    package_absence_signals: list[str] = []
    if (
        package_workflow_evidence.get("status") == "present"
        and package_workflow_evidence.get("trust") == "lower-trust"
        and not active_closeout_satisfied
    ):
        missing = ", ".join((str(item) for item in package_workflow_evidence.get("missing_expected_surfaces", [])))
        missing = missing or "package workflow evidence"
        package_absence_signals.append(
            f"Active planning record is present, but package workflow evidence is incomplete or absent: missing {missing}."
        )
    retained_resolution_status = str(slice_closeout_evidence.get("status") or "")
    planning_status = _as_dict(planning_report.get("status"))
    live_planning_continuation = (
        _as_int(planning_status.get("roadmap_lane_count")) + _as_int(planning_status.get("roadmap_candidate_count")) > 0
    )
    retained_evidence_controls = (
        not raw_active_planning_record
        and not live_planning_continuation
        and retained_resolution_status
        in {
            "present",
            "ambiguous",
            "no-relevant-evidence",
        }
    )
    effective_lower_trust_count = (
        1
        if retained_evidence_controls and slice_closeout_evidence.get("trust") == "lower-trust"
        else 0
        if retained_evidence_controls
        else lower_trust_closeout_count + len(package_absence_signals)
    )
    if acceptance_reconciliation.get("trust") == "lower-trust":
        effective_lower_trust_count += 1
    intent_satisfaction_trust = str(intent_satisfaction_check.get("trust", ""))
    intent_satisfaction_lower_trust_count = 1 if intent_satisfaction_trust in {"follow-up-required", "needs-review"} else 0
    effective_lower_trust_count += intent_satisfaction_lower_trust_count
    intent_satisfaction_signals: list[str] = []
    if intent_satisfaction_lower_trust_count:
        continuation_surface = str(intent_satisfaction_check.get("continuation_surface", "")).strip()
        continuation_summary = f" via {continuation_surface}" if continuation_surface else ""
        intent_satisfaction_signals.append(
            f"Intent satisfaction is {intent_satisfaction_trust}{continuation_summary}; closeout needs package-owned continuation evidence before it is normal-trust."
        )
    trust = "lower-trust" if effective_lower_trust_count > 0 else "normal"
    if trust == "lower-trust":
        summary = f"{effective_lower_trust_count} closeout signal(s) suggest package bypass, missing package evidence, unsatisfied intent, or missing planning residue; treat closeout trust as lower until checked-in residue is visible."
        recommended_next_action = str(
            intent_validation.get("recommended_next_action")
            or "Review the lower-trust closeout signals before treating planning closeout as normal."
        )
    else:
        summary = "No lower-trust closeout signals are currently detected from planning evidence."
        recommended_next_action = "No extra closeout trust review is needed beyond normal report inspection."
    if retained_evidence_controls:
        if retained_resolution_status == "present" and slice_closeout_evidence.get("trust") == "normal":
            recommended_next_action = "Use the selected command-owned evidence for the completed slice; reconcile parent intent only when claiming parent closure."
        elif retained_resolution_status in {"ambiguous", "no-relevant-evidence"}:
            recommended_next_action = str(
                slice_closeout_evidence.get("recovery_command") or "Select relevant closeout evidence explicitly."
            )
    gate = strict_gate(
        trust=trust,
        reason="active planning record present" if active_planning_record else "no active planning record",
        active_planning_record=active_planning_record,
    )
    residue_action = durable_residue_action(trust=trust)
    completion_gate = _completion_gate_payload(
        active_planning_record=raw_active_planning_record,
        intent_check=intent_satisfaction_check,
        acceptance_reconciliation=acceptance_reconciliation,
        intent_proof_check=intent_proof_check,
        parent_intent_status=parent_intent_status,
        applicable_intent_status=applicable_intent_status,
        durable_residue_action=residue_action,
    )
    if retained_evidence_controls and retained_resolution_status in {"ambiguous", "no-relevant-evidence"}:
        completion_gate = copy.deepcopy(completion_gate)
        completion_gate.update(
            {
                "status": retained_resolution_status,
                "required_next_action": recommended_next_action,
                "residual_intent": "unknown-without-relevant-evidence",
                "continuation": {"created_or_required": False, "reason": "unrelated historical evidence cannot create continuation"},
            }
        )
    task_posture_followthrough = _as_dict(completion_gate.get("task_posture_followthrough"))
    proof_confidence = _proof_confidence_payload(intent_proof=intent_proof_check)
    completion_options = _closeout_completion_options(
        status="present",
        trust=trust,
        strict_gate=gate,
        completion_gate=completion_gate,
        intent_check=intent_satisfaction_check,
        acceptance_reconciliation=acceptance_reconciliation,
        intent_proof_check=intent_proof_check,
        assurance_requirements=assurance_requirements,
        durable_residue_action=residue_action,
        lower_trust_closeout_count=effective_lower_trust_count,
        cli_invoke=cli_invoke,
    )
    completion_options = allow_archived_slice_claim(completion_options, slice_closeout_evidence)
    terminal_outcome_contract = _terminal_outcome_contract_payload(
        completion_gate=completion_gate,
        completion_options=completion_options,
        recommended_next_action=recommended_next_action,
        source_surface="closeout_trust",
    )
    final_response_rendering = _closeout_report_final_response_rendering_payload(
        status="present",
        profile_policy={"selected_profile": "compact", "reason": "closeout_trust terminal outcome projection"},
        trust=trust,
        work_completed="",
        requested_outcome="",
        changed_surfaces="",
        validation_proof=str(proof_confidence.get("summary") or proof_confidence.get("confidence") or ""),
        completion_decision="",
        completion_boundary=_as_dict(intent_satisfaction_check.get("completion_boundary")),
        completion_options=completion_options,
        completeness={"status": "complete" if completion_gate.get("active_intent_satisfied") else "incomplete"},
        residual_risk=str(completion_gate.get("residual_intent") or ""),
        blockers=[],
        next_action=recommended_next_action,
        decision_review={},
        behavior_preservation={},
        parent_intent_status=parent_intent_status,
        applicable_intent_status=applicable_intent_status,
        workflow_obligation_contract={},
        completion_gate=completion_gate,
        review_mode="small-direct-edit",
    )
    current_task_closeout: dict[str, Any] = {"status": "not-applicable"}
    if current_bounded_scope.get("status") == "active":
        relationship = str(current_bounded_scope.get("relationship") or "bounded-task")
        current_task_gate = copy.deepcopy(gate)
        current_task_gate.update(
            {
                "status": "bounded-current-task-residue",
                "blocking": False,
                "current_task_blocking": False,
                "relationship": relationship,
                "summary": (
                    "Strict closeout still protects broader planning residue, but it is not a bounded PR-feedback-addressed blocker."
                    if relationship == "bounded-pr-comment-repair"
                    else "Strict closeout still protects the unrelated active plan, but it is not a current bounded-task slice blocker."
                ),
            }
        )
        proof_selection = _proof_selection_for_changed_paths(
            changed_paths=normalized_changed_paths,
            target_root=target_root,
            task_text=task_text,
            include_durable_intent=False,
            include_assurance_requirements=False,
            include_routine_work_context=False,
        )
        current_task_options = _closeout_completion_options(
            status="present",
            trust=trust,
            strict_gate=current_task_gate,
            completion_gate=completion_gate,
            intent_check=intent_satisfaction_check,
            acceptance_reconciliation=acceptance_reconciliation,
            intent_proof_check=intent_proof_check,
            assurance_requirements=assurance_requirements,
            durable_residue_action=residue_action,
            lower_trust_closeout_count=effective_lower_trust_count,
            cli_invoke=cli_invoke,
            current_task_switch_scope=current_bounded_scope,
        )
        if relationship == "bounded-pr-comment-repair":
            adjusted_options: list[dict[str, Any]] = []
            for option in current_task_options:
                updated = dict(option)
                if updated.get("id") == "claim-slice-complete":
                    updated["required_claim_class"] = "pr_feedback_addressed"
                    updated["bounded_claim_class"] = "pr_feedback_addressed"
                    updated["why"] = (
                        "PR feedback proof supports a bounded feedback-addressed claim"
                        if updated.get("allowed") is True
                        else "PR feedback-addressed claim is blocked until proof for the repair is visible"
                    )
                adjusted_options.append(updated)
            current_task_options = adjusted_options
        current_task_operating_loop = _operating_loop_decision_payload(
            claim_context="closeout",
            planning_safety_gate=_as_dict(current_bounded_scope.get("planning_safety_gate")),
            proof=proof_selection,
        )
        current_task_closeout = {
            "kind": "agentic-workspace/current-task-closeout/v1",
            "status": "active",
            "scope": current_bounded_scope,
            "allowed_claim_classes": [current_bounded_scope.get("claim_class", "slice_complete")]
            if current_bounded_scope.get("claim_class")
            else ["slice_complete"],
            "blocked_claim_classes": ["full_intent_complete", "issue_closure", "lane_complete", "parent_complete"],
            "strict_closeout_gate": current_task_gate,
            "completion_options": current_task_options,
            "operating_loop": current_task_operating_loop,
            "proof": proof_selection,
            "repo_wide_residue": {
                "strict_closeout_gate": gate,
                "completion_gate": completion_gate,
                "trust": trust,
                "lower_trust_closeout_count": effective_lower_trust_count,
            },
            "rule": (
                "Current-task closeout options do not authorize active-plan progress, parent closure, issue closure, "
                "or full-intent completion for bounded PR-comment repair or unrelated planning residue."
            ),
        }
    memory_consult = (
        _memory_consult_payload(target_root=target_root, compact=True, cli_invoke=cli_invoke)
        if target_root is not None
        else {"status": "unavailable", "consultation_state": "not-checked", "read_first": [], "do_not_bulk_read": True}
    )
    memory_decision_packet = _memory_decision_packet_payload(
        stage="closeout",
        cli_invoke=cli_invoke,
        memory_consult=memory_consult,
        closeout_trust={
            "trust": trust,
            "lower_trust_closeout_count": effective_lower_trust_count,
            "durable_residue_action": residue_action,
            "promotion_candidate_count": _as_int(knowledge_authority_review.get("promotion_candidate_count")),
            "memory_decision_required": effective_lower_trust_count > 0,
        },
    )
    operating_loop = _operating_loop_decision_payload(
        claim_context="closeout",
        memory_decision_packet=memory_decision_packet,
        closeout_trust={
            "trust": trust,
            "lower_trust_closeout_count": effective_lower_trust_count,
            "completion_gate": completion_gate,
            "proof_confidence": proof_confidence,
        },
        active_planning_record=raw_active_planning_record,
    )
    return {
        "status": "present",
        "trust": trust,
        "archived_slice_closeout_evidence": slice_closeout_evidence or {"status": "absent", "trust": "not-applicable"},
        "strict_closeout_gate": gate,
        "completion_gate": completion_gate,
        "task_posture_followthrough": task_posture_followthrough,
        "lower_trust_closeout_count": effective_lower_trust_count,
        "planning_residue_lower_trust_count": lower_trust_closeout_count,
        "package_evidence_lower_trust_count": len(package_absence_signals),
        "acceptance_reconciliation_lower_trust_count": 1 if acceptance_reconciliation.get("trust") == "lower-trust" else 0,
        "intent_satisfaction_lower_trust_count": intent_satisfaction_lower_trust_count,
        "summary": summary,
        "sample_signals": [*sample_signals, *package_absence_signals, *intent_satisfaction_signals][:3],
        "absence_signals": package_absence_signals,
        "package_workflow_evidence": package_workflow_evidence,
        "intent_satisfaction_check": intent_satisfaction_check,
        "acceptance_criteria_reconciliation": acceptance_reconciliation,
        "active_intent_contract": active_intent_contract,
        "intent_satisfaction_matrix": intent_satisfaction_matrix,
        "intent_proof_check": intent_proof_check,
        "proof_confidence": proof_confidence,
        "assurance_requirements": assurance_requirements,
        "verification": verification,
        "memory_consult": memory_consult,
        "memory_decision_packet": memory_decision_packet,
        "operating_loop": operating_loop,
        "current_task_closeout": current_task_closeout,
        "knowledge_authority_review": knowledge_authority_review,
        "architecture_decision_closeout": architecture_decision_closeout,
        "historical_review_artifacts": _historical_review_artifacts_policy(
            planning_report=planning_report, intent_validation=intent_validation, target_root=target_root
        ),
        "durable_residue_action": residue_action,
        "terminal_action": terminal_action(trust=trust, recommended_next_action=recommended_next_action),
        "completion_options": completion_options,
        "terminal_outcome_contract": terminal_outcome_contract,
        "final_response_rendering": final_response_rendering,
        "closeout_protocol": _closeout_protocol_payload(
            status="present",
            trust=trust,
            strict_gate=gate,
            completion_gate=completion_gate,
            completion_options=completion_options,
            durable_residue_action=residue_action,
            knowledge_authority_review=knowledge_authority_review,
            proof_confidence=proof_confidence,
            verification=verification,
            task_posture_followthrough=task_posture_followthrough,
            recommended_next_action=recommended_next_action,
            cli_invoke=cli_invoke,
        ),
        "recommended_next_action": recommended_next_action,
    }


def _historical_review_artifacts_policy(
    *, planning_report: dict[str, Any], intent_validation: dict[str, Any], target_root: Path | None = None
) -> dict[str, Any]:
    historical = intent_validation.get("historical_audit_references", {}) if isinstance(intent_validation, dict) else {}
    if not isinstance(historical, dict):
        historical = {}
    source_count = _as_int(historical.get("source_count"))
    item_count = _as_int(historical.get("item_count"))
    if source_count == 0 and isinstance(planning_report, dict):
        reconcile = planning_report.get("closeout_reconciliation", {})
        if isinstance(reconcile, dict):
            source_count = _as_int(reconcile.get("source_count"))
            item_count = _as_int(reconcile.get("item_count"))
    return {
        "status": "evidence-only",
        "role": "evidence/history, not ordinary operating input",
        "source_count": source_count,
        "item_count": item_count,
        "rule": "Do not read historical review artifacts during startup unless a selected issue, audit, or report section points there.",
        "selection_path": "agentic-workspace report --target ./repo --section closeout_trust --format json",
        "retention_policy": _review_artifact_retention_policy(target_root=target_root),
        "retention_guidance": [
            "Promote durable findings to planning, canonical docs, checks, or Memory before treating them as current authority.",
            "Shrink, stub, or delete stale review artifacts once findings are promoted, dismissed, or superseded.",
            "Keep review artifacts out of ordinary startup and compact recovery unless the selected work explicitly asks for historical evidence.",
        ],
    }


def _review_artifact_retention_policy(*, target_root: Path | None) -> dict[str, Any]:
    if target_root is None:
        return {
            "kind": "workspace-review-retention-policy/v1",
            "status": "unavailable",
            "advisory_only": True,
            "artifact_count": 0,
            "missing_retention_metadata_count": 0,
            "cleanup_candidate_count": 0,
            "candidate_count": 0,
            "candidates": [],
            "rule": "Review-retention pressure is advisory and selector-driven; it never deletes review artifacts automatically.",
        }
    roots = [
        ("planning-review-record", target_root / ".agentic-workspace" / "planning" / "reviews", "*.review.json"),
        ("docs-review-artifact", target_root / "docs" / "reviews", "*"),
    ]
    artifact_count = 0
    missing_retention: list[str] = []
    cleanup: dict[str, list[str]] = {"shrink": [], "stub": [], "delete": []}
    resolved_full_size: list[str] = []
    for artifact_class, root, pattern in roots:
        if not root.exists():
            continue
        for path in sorted((item for item in root.glob(pattern) if item.is_file())):
            artifact_count += 1
            relative = _relative_posix(path, target_root)
            try:
                text = path.read_text(encoding="utf-8")
            except OSError:
                missing_retention.append(relative)
                continue
            retention: dict[str, Any] = {}
            resolved = False
            if path.suffix == ".json":
                try:
                    payload = json.loads(text)
                except json.JSONDecodeError:
                    payload = {}
                if isinstance(payload, dict):
                    retention_value = payload.get("retention")
                    retention = retention_value if isinstance(retention_value, dict) else {}
                    resolved = _review_artifact_has_resolved_findings(payload)
            else:
                retention = _markdown_retention_metadata(text)
                resolved = _review_markdown_has_resolved_findings(text)
            shape = _review_retention_field(retention, "closeout shape", "closeout_shape", "shape")
            trigger = _review_retention_field(retention, "trigger")
            proof_surface = _review_retention_field(retention, "proof surface", "proof_surface")
            if not (shape and trigger and proof_surface):
                missing_retention.append(relative)
            outcome = _review_retention_outcome(shape)
            if outcome in cleanup:
                cleanup[outcome].append(relative)
            if artifact_class == "docs-review-artifact" and (not shape):
                cleanup["shrink"].append(relative)
            if resolved and len(text.splitlines()) > 80 and (not shape.lower().startswith("retain")):
                resolved_full_size.append(relative)
    candidates: list[dict[str, Any]] = []
    if missing_retention:
        candidates.append(
            {
                "signal": "missing-retention-metadata",
                "count": len(missing_retention),
                "recommended_outcome": "add-retention-metadata",
                "candidate_paths": missing_retention[:5],
                "why": "Review artifacts without closeout shape, trigger, and proof surface need routing metadata before they can be safely shrunk or retained.",
            }
        )
    for outcome in ("shrink", "stub", "delete"):
        paths = cleanup[outcome]
        if paths:
            candidates.append(
                {
                    "signal": f"retention-shape-{outcome}",
                    "count": len(paths),
                    "recommended_outcome": outcome,
                    "candidate_paths": paths[:5],
                    "why": f"Review artifacts whose own retention shape points to {outcome} should be revisited after findings are promoted, dismissed, or superseded.",
                }
            )
    if resolved_full_size:
        candidates.append(
            {
                "signal": "resolved-full-size-review",
                "count": len(resolved_full_size),
                "recommended_outcome": "shrink",
                "candidate_paths": resolved_full_size[:5],
                "why": "Resolved full-size reviews are candidates for compact evidence once durable findings live in planning, docs, checks, issues, or Memory.",
            }
        )
    return {
        "kind": "workspace-review-retention-policy/v1",
        "status": "attention" if candidates else "quiet",
        "advisory_only": True,
        "applies_to": [".agentic-workspace/planning/reviews/*.review.json", "docs/reviews/*"],
        "outcomes": ["retain", "shrink", "stub", "delete", "add-retention-metadata"],
        "default_outcome": "retain",
        "artifact_count": artifact_count,
        "missing_retention_metadata_count": len(missing_retention),
        "cleanup_candidate_count": sum((len(paths) for paths in cleanup.values())) + len(resolved_full_size),
        "candidate_count": len(candidates),
        "candidates": candidates,
        "before_shrink_or_delete": [
            "promote durable findings to planning, canonical docs, checks, issues, or Memory",
            "preserve enough evidence for audit, trust, and continuation",
            "keep historical reviews out of ordinary startup and compact recovery paths",
        ],
        "rule": "Review-retention pressure is advisory and selector-driven; it recommends cleanup outcomes but never deletes review artifacts automatically.",
    }


def _review_retention_field(retention: dict[str, Any], *keys: str) -> str:
    for key in keys:
        value = retention.get(key)
        if str(value or "").strip():
            return str(value).strip()
    return ""


def _review_retention_outcome(shape: str) -> str:
    normalized = shape.lower()
    if "delete" in normalized:
        return "delete"
    if "stub" in normalized:
        return "stub"
    if "shrink" in normalized or "archive" in normalized or "compact" in normalized:
        return "shrink"
    return "retain" if "retain" in normalized or "keep" in normalized else ""


def _review_artifact_has_resolved_findings(payload: dict[str, Any]) -> bool:
    try:
        text = json.dumps(
            {field: payload.get(field) for field in ("findings", "issue_classifications", "classified_items", "closeout_items")},
            sort_keys=True,
        ).lower()
    except TypeError:
        text = ""
    resolved_markers = (
        "closed by implementation",
        "evidence-present",
        '"live_state": "closed',
        'follow_up": ""',
        'follow_up": "none"',
        "resolution",
        "superseded",
        "dismiss",
        "addressed",
    )
    return any((marker in text for marker in resolved_markers))


def _markdown_retention_metadata(text: str) -> dict[str, Any]:
    metadata: dict[str, Any] = {}
    lower = text.lower()
    for line in text.splitlines():
        stripped = line.strip()
        normalized = stripped.lower()
        if normalized.startswith("closeout shape:"):
            metadata["closeout shape"] = stripped.split(":", 1)[1].strip()
        elif normalized.startswith("trigger:"):
            metadata["trigger"] = stripped.split(":", 1)[1].strip()
        elif normalized.startswith("proof surface:"):
            metadata["proof surface"] = stripped.split(":", 1)[1].strip()
    if "retention" in lower and (not metadata):
        metadata["shape"] = "retain"
    return metadata


def _review_markdown_has_resolved_findings(text: str) -> bool:
    normalized = text.lower()
    return any((marker in normalized for marker in ("closed", "implemented", "superseded", "dismissed", "addressed")))


def _package_workflow_evidence_payload(*, planning_report: dict[str, Any]) -> dict[str, Any]:
    active = planning_report.get("active", {}) if isinstance(planning_report, dict) else {}
    planning_record = active.get("planning_record", {}) if isinstance(active, dict) else {}
    execution_run_contract = active.get("execution_run_contract", {}) if isinstance(active, dict) else {}
    if not isinstance(planning_record, dict) or planning_record.get("status") != "present":
        return {
            "status": "unavailable",
            "reason": "no active planning record exposes package-use evidence",
            "required_for_broad_work": True,
        }
    proof_expectations = [str(item) for item in _list_payload(planning_record.get("proof_expectations"))]
    execution_run = planning_record.get("execution_run", {})
    if not isinstance(execution_run, dict):
        execution_run = {}
    evidence_text_parts = [
        " ".join(proof_expectations),
        str(execution_run.get("handoff source", "")),
        str(execution_run.get("validations run", "")),
        str(execution_run.get("what happened", "")),
    ]
    if isinstance(execution_run_contract, dict):
        evidence_text_parts.extend(
            [
                str(execution_run_contract.get("handoff_source", "")),
                str(execution_run_contract.get("validations_run", "")),
                str(execution_run_contract.get("what_happened", "")),
            ]
        )
    evidence_text = "\n".join(evidence_text_parts).lower()
    expected_surfaces = ["preflight", "summary", "report", "proof"]
    optional_surfaces = ["reconcile", "doctor"]
    used_surfaces = [surface for surface in expected_surfaces + optional_surfaces if f"agentic-workspace {surface}" in evidence_text]
    missing_expected_surfaces = [surface for surface in expected_surfaces if surface not in used_surfaces]
    skipped_text = str(execution_run.get("package workflow skipped", "") or execution_run.get("package_workflow_skipped", "")).strip()
    trust = "normal" if used_surfaces and (not missing_expected_surfaces) and (not skipped_text) else "lower-trust"
    if trust == "normal":
        recommended_next_action = "Package workflow use is visible in the active planning record."
    elif skipped_text:
        recommended_next_action = "Review the declared package workflow skip before trusting broad-work closeout."
    else:
        recommended_next_action = "Record package workflow surfaces used or intentionally skipped before broad-work closeout."
    return {
        "status": "present",
        "required_for_broad_work": True,
        "trust": trust,
        "used_surfaces": used_surfaces,
        "expected_surfaces": expected_surfaces,
        "optional_surfaces": optional_surfaces,
        "missing_expected_surfaces": missing_expected_surfaces,
        "evidence_quality": "complete" if trust == "normal" else "incomplete",
        "skipped": skipped_text,
        "evidence_sources": ["planning.active.planning_record.proof_expectations", "planning.active.planning_record.execution_run"],
        "recommended_next_action": recommended_next_action,
    }


def _issue_refs_from_text(value: Any) -> set[str]:
    raw = " ".join(str(item) for item in value) if isinstance(value, list) else str(value or "")
    refs = {f"#{match}" for match in re.findall(r"#(\d+)\b", raw)}
    refs.update(f"#{match}" for match in re.findall(r"\bgithub-(\d+)\b", raw, flags=re.IGNORECASE))
    refs.update(f"#{match}" for match in re.findall(r"\bGitHub\s+(\d+)\b", raw, flags=re.IGNORECASE))
    return refs


def _close_keyword_issue_refs(text: str) -> list[str]:
    refs: list[str] = []
    for line in str(text or "").splitlines():
        if not re.search(r"(?i)\b(?:close[sd]?|fix(?:e[sd])?|resolve[sd]?)\b", line):
            continue
        for match in re.findall(r"#(\d+)\b", line):
            ref = f"#{match}"
            if ref not in refs:
                refs.append(ref)
    return refs


def _pending_pr_merge_evidence_by_issue(*, target_root: Path | None) -> dict[str, dict[str, Any]]:
    if target_root is None:
        return {}
    payloads: list[dict[str, Any]] = []
    for relative in (EXTERNAL_INTENT_CACHE_RELATIVE_PATH, EXTERNAL_INTENT_PLANNING_RELATIVE_PATH):
        evidence_path = target_root / relative
        if not evidence_path.is_file():
            continue
        try:
            payload = json.loads(evidence_path.read_text(encoding="utf-8-sig"))
        except (OSError, json.JSONDecodeError):
            continue
        if isinstance(payload, dict):
            payloads.append(payload)
    if not payloads:
        return {}
    items = [item for payload in payloads for item in _list_payload(payload.get("items")) if isinstance(item, dict)]
    open_issue_ids = {str(item.get("id", "")).strip() for item in items if str(item.get("status", "")).strip().lower() == "open"}
    pending: dict[str, dict[str, Any]] = {}
    for payload in payloads:
        for pr in _list_payload(payload.get("pull_requests")):
            if not isinstance(pr, dict):
                continue
            pr_state = str(pr.get("state", "")).strip().lower()
            if pr_state in {"closed", "merged"}:
                continue
            refs = [str(ref).strip() for ref in _list_payload(pr.get("close_keyword_issue_ids")) if str(ref).strip()]
            if not refs:
                refs = _close_keyword_issue_refs(str(pr.get("body", "") or ""))
            for ref in refs:
                if ref not in open_issue_ids:
                    continue
                pending[ref] = {
                    "status": "pending-pr-merge",
                    "issue_id": ref,
                    "pr_number": str(pr.get("number", "")).strip(),
                    "pr_url": str(pr.get("url", "")).strip(),
                    "branch": str(pr.get("head_ref", pr.get("headRefName", ""))).strip(),
                    "title": str(pr.get("title", "")).strip(),
                    "reconcile_command": "agentic-workspace external-intent refresh-github --target . --state all --format json",
                    "rule": "A PR close keyword is pending evidence, not external issue closure; refresh after merge before marking residue closed.",
                }
    return pending


def _open_package_owned_continuation_payload(*, planning_report: dict[str, Any], target_root: Path | None = None) -> dict[str, Any]:
    closed_statuses = {"archive", "archived", "cancelled", "canceled", "closed", "complete", "completed", "dismissed", "done"}

    def is_open_status(value: Any) -> bool:
        normalized = str(value or "").strip().lower()
        return not normalized or normalized not in closed_statuses

    surfaces: list[dict[str, Any]] = []
    work_maturity = planning_report.get("work_maturity", {}) if isinstance(planning_report, dict) else {}
    if isinstance(work_maturity, dict):
        for bucket_name in ("ready_slices", "needs_shaping", "deferred_lanes", "blocked_items", "residue_routing_needed"):
            bucket = work_maturity.get(bucket_name, [])
            if not isinstance(bucket, list):
                continue
            for item in bucket:
                if not isinstance(item, dict) or not is_open_status(item.get("status")):
                    continue
                source_bucket = str(item.get("source_bucket", "")).strip()
                surfaces.append(
                    {
                        "kind": f"work_maturity.{bucket_name}",
                        "id": item.get("id", ""),
                        "title": item.get("title", item.get("summary", "")),
                        "status": item.get("status", ""),
                        "maturity": item.get("maturity", ""),
                        "refs": item.get("refs", item.get("issues", "")),
                        "owner_surface": ".agentic-workspace/planning/state.toml"
                        if source_bucket.startswith("roadmap.")
                        else source_bucket or ".agentic-workspace/planning/state.toml",
                        "suggested_first_slice": item.get("suggested_first_slice", ""),
                    }
                )
    roadmap = planning_report.get("roadmap", {}) if isinstance(planning_report, dict) else {}
    if isinstance(roadmap, dict):
        for bucket_name in ("candidate_lanes", "candidates"):
            bucket = roadmap.get(bucket_name, [])
            if not isinstance(bucket, list):
                continue
            for item in bucket:
                if not isinstance(item, dict) or not is_open_status(item.get("status")):
                    continue
                surfaces.append(
                    {
                        "kind": f"roadmap.{bucket_name}",
                        "id": item.get("id", ""),
                        "title": item.get("title", item.get("summary", "")),
                        "status": item.get("status", ""),
                        "maturity": item.get("maturity", ""),
                        "refs": item.get("refs", item.get("issues", "")),
                        "owner_surface": ".agentic-workspace/planning/state.toml",
                        "suggested_first_slice": item.get("suggested_first_slice", ""),
                    }
                )
    decomposition = planning_report.get("decomposition", {}) if isinstance(planning_report, dict) else {}
    if isinstance(decomposition, dict):
        for record in _list_payload(decomposition.get("records")):
            if not isinstance(record, dict) or not is_open_status(record.get("status")):
                continue
            candidate_lanes = [lane for lane in _list_payload(record.get("candidate_lanes")) if isinstance(lane, dict)]
            surfaces.append(
                {
                    "kind": "decomposition.record",
                    "id": record.get("path", ""),
                    "title": record.get("title", ""),
                    "status": record.get("status", ""),
                    "owner_surface": record.get("path", ".agentic-workspace/planning/decompositions/"),
                    "lane_count": record.get("lane_count", len(candidate_lanes)),
                    "ready_lane_count": record.get("ready_lane_count", 0),
                    "candidate_lane_ids": [str(lane.get("id", "")) for lane in candidate_lanes if str(lane.get("id", "")).strip()][:5],
                }
            )
    surfaces = [
        surface for surface in surfaces if str(surface.get("id") or surface.get("title") or surface.get("owner_surface") or "").strip()
    ]
    pending_by_issue = _pending_pr_merge_evidence_by_issue(target_root=target_root)
    pending_surfaces: list[dict[str, Any]] = []
    if pending_by_issue:
        annotated_surfaces: list[dict[str, Any]] = []
        for surface in surfaces:
            refs = (
                _issue_refs_from_text(surface.get("refs", ""))
                | _issue_refs_from_text(surface.get("title", ""))
                | _issue_refs_from_text(surface.get("id", ""))
            )
            matching = [pending_by_issue[ref] for ref in sorted(refs) if ref in pending_by_issue]
            if matching:
                surface = {
                    **surface,
                    "external_disposition": "pending-pr-merge",
                    "pending_pr_merge": matching[0],
                    "residue_explanation": "Open externally because the PR has not merged or external evidence has not been refreshed after merge.",
                }
                pending_surfaces.append(surface)
            annotated_surfaces.append(surface)
        surfaces = annotated_surfaces
    if not surfaces:
        return {
            "status": "quiet",
            "surface_count": 0,
            "surfaces": [],
            "rule": "When no active planning record exists, package-owned roadmap and decomposition surfaces are still checked before intent closeout is trusted.",
        }
    return {
        "status": "present",
        "surface_count": len(surfaces),
        "surfaces": surfaces[:5],
        "pending_pr_merge_count": len(pending_surfaces),
        "pending_pr_merge_surfaces": pending_surfaces[:5],
        "owner_surfaces": sorted(
            {str(surface.get("owner_surface", "")).strip() for surface in surfaces if str(surface.get("owner_surface", "")).strip()}
        ),
        "rule": "Open package-owned roadmap or decomposition continuation means quiet active state is not evidence of epic intent satisfaction.",
    }


def _planning_record_text_for_external_check(planning_record: dict[str, Any]) -> str:
    return json.dumps(planning_record, sort_keys=True, ensure_ascii=False)


def _negative_invariant_status(*, invariant: str, evidence_text: str) -> str:
    normalized = " ".join(invariant.lower().split())
    normalized_evidence = " ".join(evidence_text.lower().split())
    if not normalized or normalized not in normalized_evidence:
        return "unreconciled"
    for marker in ("satisfied", "deferred", "rejected"):
        if marker in normalized_evidence:
            return marker
    return "unreconciled"


def _external_intent_closeout_check(*, target_root: Path | None, planning_record: dict[str, Any]) -> dict[str, Any]:
    planning_text = _planning_record_text_for_external_check(planning_record)
    issue_refs = sorted(set(re.findall("#\\d+", planning_text)), key=lambda value: int(value.lstrip("#")))
    if not issue_refs:
        return {"status": "not-applicable", "trust": "normal", "matched_issue_ids": [], "negative_invariants": []}
    if target_root is None:
        return {
            "status": "unavailable",
            "trust": "needs-review",
            "matched_issue_ids": issue_refs,
            "reason": "external issue references are present but no target root was available for evidence comparison",
            "recommended_next_action": "Refresh external intent evidence before trusting closeout for referenced issues.",
        }
    evidence_path, evidence_relative_path, evidence_storage = _external_intent_evidence_read_location(target_root)
    if not evidence_path.is_file():
        return {
            "status": "unavailable",
            "trust": "needs-review",
            "matched_issue_ids": issue_refs,
            "source": evidence_relative_path,
            "storage": evidence_storage,
            "reason": "external intent evidence cache is absent",
            "recommended_next_action": "Refresh external intent evidence before trusting closeout for referenced issues.",
        }
    try:
        payload = json.loads(evidence_path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError) as exc:
        return {
            "status": "invalid",
            "trust": "needs-review",
            "matched_issue_ids": issue_refs,
            "source": evidence_relative_path,
            "storage": evidence_storage,
            "reason": str(exc),
            "recommended_next_action": "Repair or refresh external intent evidence before trusting closeout.",
        }
    schema_findings = _external_intent_evidence_schema_findings(target_root=target_root, payload=payload)
    if schema_findings:
        return {
            "status": "invalid",
            "trust": "needs-review",
            "matched_issue_ids": issue_refs,
            "source": evidence_relative_path,
            "storage": evidence_storage,
            "schema_findings": schema_findings,
            "recommended_next_action": "Repair or refresh external intent evidence before trusting closeout.",
        }
    items = [item for item in _list_payload(payload.get("items")) if isinstance(item, dict)]
    by_id = {str(item.get("id", "")): item for item in items if str(item.get("id", ""))}
    matched_items = [by_id[issue_ref] for issue_ref in issue_refs if issue_ref in by_id]
    missing_issue_ids = [issue_ref for issue_ref in issue_refs if issue_ref not in by_id]
    open_issue_ids = [str(item.get("id", "")) for item in matched_items if str(item.get("status", "")).strip().lower() == "open"]
    negative_checks: list[dict[str, str]] = []
    for item in matched_items:
        issue_id = str(item.get("id", ""))
        for invariant in _list_payload(item.get("negative_invariants")):
            invariant_text = str(invariant).strip()
            if invariant_text:
                negative_checks.append(
                    {
                        "issue_id": issue_id,
                        "invariant": invariant_text,
                        "status": _negative_invariant_status(invariant=invariant_text, evidence_text=planning_text),
                    }
                )
    unresolved_negative_invariants = [check for check in negative_checks if check["status"] == "unreconciled"]
    if missing_issue_ids or open_issue_ids or unresolved_negative_invariants:
        trust = "follow-up-required"
    else:
        trust = "normal"
    return {
        "status": "present",
        "trust": trust,
        "source": evidence_relative_path,
        "storage": evidence_storage,
        "matched_issue_ids": [str(item.get("id", "")) for item in matched_items],
        "missing_issue_ids": missing_issue_ids,
        "open_issue_ids": open_issue_ids,
        "negative_invariants": negative_checks,
        "unresolved_negative_invariant_count": len(unresolved_negative_invariants),
        "rule": "Referenced external issues and their negative invariants must be compared against refreshed external intent evidence before closeout can be normal-trust.",
        "recommended_next_action": "Refresh external evidence or reconcile open issues and negative invariants before trusting closeout."
        if trust != "normal"
        else "External evidence and negative invariant reconciliation are compatible with closeout.",
    }


def _intent_satisfaction_check_payload(*, planning_report: dict[str, Any], target_root: Path | None = None) -> dict[str, Any]:
    active = planning_report.get("active", {}) if isinstance(planning_report, dict) else {}
    planning_record = active.get("planning_record", {}) if isinstance(active, dict) else {}
    if not isinstance(planning_record, dict) or planning_record.get("status") != "present":
        open_continuation = _open_package_owned_continuation_payload(planning_report=planning_report, target_root=target_root)
        if open_continuation.get("status") == "present":
            owner_surfaces = [str(item) for item in _list_payload(open_continuation.get("owner_surfaces"))]
            continuation_surface = owner_surfaces[0] if owner_surfaces else ".agentic-workspace/planning/"
            completion_boundary = _completion_boundary_payload(
                active_planning_record={},
                closure_check={"larger-intent status": "open"},
                required_continuation={
                    "required follow-on for the larger intended outcome": "yes",
                    "owner surface": continuation_surface,
                },
            )
            return {
                "status": "present",
                "trust": "follow-up-required",
                "reason": "no active planning record, but package-owned continuation surfaces remain open",
                "required_for_broad_work": True,
                "larger_intent": "",
                "slice_completes_larger_intent": "unknown",
                "required_follow_on": "yes",
                "continuation_surface": continuation_surface,
                "package_owned_continuation": open_continuation,
                "completion_boundary": completion_boundary,
                "rule": "Validation success is not enough; package-owned roadmap or decomposition continuation must be routed before closeout can claim larger intent satisfaction.",
                "closure_scope": {
                    "validation_proof": {
                        "status": "separate-answer",
                        "not_sufficient_for_closure": True,
                        "rule": "Validation success proves implementation behavior, not intent closure by itself.",
                    },
                    "requested_slice": {"status": "unavailable"},
                    "lane_or_system_intent": {
                        "status": "follow-up-required",
                        "required_follow_on": "yes",
                        "continuation_surface": continuation_surface,
                        "sources": ["planning.roadmap", "planning.decomposition"],
                    },
                    "larger_intent_closure": {
                        "status": "open",
                        "closure_decision": "requires-package-owned-continuation",
                        "evidence": "open package-owned roadmap or decomposition continuation",
                        "source": "planning roadmap/decomposition state",
                        "rule": "External tracker state is evidence only; package-owned continuation controls intent satisfaction.",
                    },
                    "completion_boundary": completion_boundary,
                    "non_substitution_rule": "Validation success alone is not closure evidence.",
                },
                "recommended_next_action": "Promote, continue, or explicitly close the package-owned continuation surface before treating broad closeout as satisfied.",
            }
        completion_boundary = _completion_boundary_payload(active_planning_record={})
        return {
            "status": "unavailable",
            "reason": "no active planning record exposes intent-continuity evidence",
            "required_for_broad_work": True,
            "rule": "Validation success is not enough; closeout should say whether the larger intent is satisfied, partially satisfied, or needs follow-up.",
            "completion_boundary": completion_boundary,
            "closure_scope": {
                "validation_proof": {
                    "status": "separate-answer",
                    "not_sufficient_for_closure": True,
                    "rule": "Validation success proves implementation behavior, not intent closure by itself.",
                },
                "requested_slice": {"status": "unavailable"},
                "lane_or_system_intent": {"status": "unavailable"},
                "larger_intent_closure": {"status": "unavailable"},
                "completion_boundary": completion_boundary,
                "non_substitution_rule": "Validation success alone is not closure evidence.",
            },
        }
    intent_continuity = planning_record.get("intent_continuity", {})
    required_continuation = planning_record.get("required_continuation", {})
    raw_planning_record = _raw_active_planning_record_for_closeout(planning_record=planning_record, target_root=target_root)
    hierarchy_contract = active.get("hierarchy_contract", {}) if isinstance(active, dict) else {}
    resumable_contract = active.get("resumable_contract", {}) if isinstance(active, dict) else {}
    hierarchy_required = hierarchy_contract.get("required_continuation", {}) if isinstance(hierarchy_contract, dict) else {}
    if not isinstance(intent_continuity, dict):
        intent_continuity = {}
    if not isinstance(required_continuation, dict):
        required_continuation = {}
    if not intent_continuity and isinstance(raw_planning_record.get("intent_continuity"), dict):
        intent_continuity = raw_planning_record["intent_continuity"]
    if not required_continuation and isinstance(raw_planning_record.get("required_continuation"), dict):
        required_continuation = raw_planning_record["required_continuation"]
    if not isinstance(hierarchy_required, dict):
        hierarchy_required = {}
    if not intent_continuity and hierarchy_required:
        intent_continuity = {
            "larger intended outcome": hierarchy_required.get("larger_intended_outcome", ""),
            "this slice completes the larger intended outcome": hierarchy_required.get("slice_completes_larger_outcome", ""),
            "continuation surface": hierarchy_required.get("continuation_surface", ""),
        }
    if not required_continuation and hierarchy_required:
        required_continuation = {
            "required follow-on for the larger intended outcome": hierarchy_required.get("required_follow_on", ""),
            "owner surface": hierarchy_required.get("owner_surface", ""),
        }
    proof_expectations = [str(item) for item in _list_payload(planning_record.get("proof_expectations"))]
    if not proof_expectations and isinstance(resumable_contract, dict):
        proof_expectations = [str(item) for item in _list_payload(resumable_contract.get("proof_expectations"))]
    active_milestone = planning_record.get("active_milestone", {})
    if (not isinstance(active_milestone, dict) or not active_milestone) and isinstance(resumable_contract, dict):
        active_milestone = resumable_contract.get("active_milestone", {})
    if not isinstance(active_milestone, dict):
        active_milestone = {}
    completion_criteria = [str(item) for item in _list_payload(planning_record.get("completion_criteria"))]
    if not completion_criteria and isinstance(resumable_contract, dict):
        completion_criteria = [str(item) for item in _list_payload(resumable_contract.get("completion_criteria"))]
    proof_report = planning_record.get("proof_report", {})
    if not isinstance(proof_report, dict):
        proof_report = {}
    if not proof_report and isinstance(raw_planning_record.get("proof_report"), dict):
        proof_report = raw_planning_record["proof_report"]
    closure_check = planning_record.get("closure_check", {})
    if not isinstance(closure_check, dict):
        closure_check = {}
    if not closure_check and isinstance(raw_planning_record.get("closure_check"), dict):
        closure_check = raw_planning_record["closure_check"]
    hierarchy_closure = hierarchy_contract.get("closure_check", {}) if isinstance(hierarchy_contract, dict) else {}
    if not closure_check and isinstance(hierarchy_closure, dict):
        closure_check = hierarchy_closure
    completes = str(intent_continuity.get("this slice completes the larger intended outcome", "")).strip().lower()
    continuation = str(required_continuation.get("required follow-on for the larger intended outcome", "")).strip().lower()
    external_closeout = _external_intent_closeout_check(target_root=target_root, planning_record=planning_record)
    applicable_intents = _applicable_intent_status_payload(active_planning_record=raw_planning_record or planning_record)
    if completes in {"yes", "true"} and continuation in {"no", "false", "none"}:
        trust = "satisfied"
        recommended_next_action = "Closeout may claim intent satisfaction if proof also passed."
    elif completes in {"no", "false"} or continuation in {"yes", "true"}:
        trust = "follow-up-required"
        recommended_next_action = "Record or preserve the continuation surface before treating this closeout as complete."
    else:
        trust = "needs-review"
        recommended_next_action = "Name whether the larger intent is satisfied or requires follow-up before broad-work closeout."
    if trust == "satisfied" and external_closeout.get("trust") != "normal":
        trust = "follow-up-required"
        recommended_next_action = str(external_closeout.get("recommended_next_action") or recommended_next_action)
    if applicable_intents.get("closeout_blocked"):
        trust = "needs-review"
        recommended_next_action = "Resolve applicable-intent conflict, missing authority, or manual verification before broad closeout."
    completion_boundary = _completion_boundary_payload(
        active_planning_record=planning_record,
        raw_planning_record=raw_planning_record,
        closure_check=closure_check,
        intent_continuity=intent_continuity,
        required_continuation=required_continuation,
        iterative=planning_record.get("iterative_follow_through", {}),
        proof_report=proof_report,
        active_milestone=active_milestone,
        proof_expectations=proof_expectations,
    )
    return {
        "status": "present",
        "required_for_broad_work": True,
        "trust": trust,
        "larger_intent": intent_continuity.get("larger intended outcome", ""),
        "slice_completes_larger_intent": intent_continuity.get("this slice completes the larger intended outcome", ""),
        "required_follow_on": required_continuation.get("required follow-on for the larger intended outcome", ""),
        "continuation_surface": intent_continuity.get("continuation surface", required_continuation.get("owner surface", "")),
        "completion_boundary": completion_boundary,
        "rule": "Proof and validation answer whether the implementation works; this check answers whether the intended outcome is actually closed.",
        "closure_scope": {
            "validation_proof": {
                "status": "separate-answer",
                "not_sufficient_for_closure": True,
                "proof_expectation_count": len(proof_expectations),
                "proof_report": proof_report.get("validation proof", ""),
                "sources": ["planning.active.planning_record.proof_expectations", "planning.active.planning_record.proof_report"],
                "rule": "Validation success proves implementation behavior, not intent closure by itself.",
            },
            "requested_slice": {
                "status": active_milestone.get("status", ""),
                "milestone_id": active_milestone.get("id", ""),
                "completion_criteria_count": len(completion_criteria),
                "sources": ["planning.active.planning_record.active_milestone", "planning.active.resumable_contract.completion_criteria"],
                "rule": "Slice landing is narrower than lane or larger-intent satisfaction.",
            },
            "lane_or_system_intent": {
                "status": trust,
                "larger_intent": intent_continuity.get("larger intended outcome", ""),
                "slice_completes_larger_intent": intent_continuity.get("this slice completes the larger intended outcome", ""),
                "required_follow_on": required_continuation.get("required follow-on for the larger intended outcome", ""),
                "continuation_surface": intent_continuity.get("continuation surface", required_continuation.get("owner surface", "")),
                "sources": [
                    "planning.active.planning_record.intent_continuity",
                    "planning.active.planning_record.required_continuation",
                    "planning.active.hierarchy_contract.required_continuation",
                ],
            },
            "larger_intent_closure": {
                "status": closure_check.get("larger-intent status", ""),
                "closure_decision": closure_check.get("closure decision", ""),
                "evidence": closure_check.get("evidence carried forward", ""),
                "reopen_trigger": closure_check.get("reopen trigger", ""),
                "source": "planning.active.hierarchy_contract.closure_check",
                "rule": "Only explicit closure-check evidence may close the larger intent.",
            },
            "completion_boundary": completion_boundary,
            "external_intent_evidence": external_closeout,
            "applicable_intent_status": applicable_intents,
            "non_substitution_rule": "Validation success alone is not closure evidence.",
        },
        "external_intent_evidence": external_closeout,
        "applicable_intent_status": applicable_intents,
        "recommended_next_action": recommended_next_action,
    }


def _acceptance_criteria_reconciliation_payload(*, planning_report: dict[str, Any]) -> dict[str, Any]:
    active = planning_report.get("active", {}) if isinstance(planning_report, dict) else {}
    planning_record = active.get("planning_record", {}) if isinstance(active, dict) else {}
    if not isinstance(planning_record, dict) or planning_record.get("status") != "present":
        return {
            "status": "unavailable",
            "trust": "not-applicable",
            "required_for_bounded_or_broad_work": True,
            "reason": "no active planning record exposes acceptance reconciliation evidence",
            "rule": "Validation success and self-authored tests do not prove that requested outcomes were delivered.",
            "required_closeout_shape": [
                "requested requirement or criterion",
                "delivered behavior or surface",
                "proof covering it",
                "gap or intentional deviation",
            ],
        }
    active_milestone = planning_record.get("active_milestone", {})
    if not isinstance(active_milestone, dict):
        active_milestone = {}
    completion_criteria = [str(item).strip() for item in _list_payload(planning_record.get("completion_criteria")) if str(item).strip()]
    proof_expectations = [str(item).strip() for item in _list_payload(planning_record.get("proof_expectations")) if str(item).strip()]
    proof_report = planning_record.get("proof_report", {})
    if not isinstance(proof_report, dict):
        proof_report = {}
    closure_check = planning_record.get("closure_check", {})
    if not isinstance(closure_check, dict):
        closure_check = {}
    evidence_text = "\n".join(
        [
            str(proof_report.get("validation proof", "")),
            str(proof_report.get("acceptance reconciliation", "")),
            str(closure_check.get("acceptance reconciliation", "")),
            str(closure_check.get("criteria satisfied", "")),
        ]
    ).lower()
    evidence_present = any(
        (marker in evidence_text for marker in ("requested", "delivered", "acceptance", "criteria", "requirement", "deviation"))
    )
    criteria_count = len(completion_criteria) or (1 if active_milestone else 0)
    trust = "normal" if evidence_present and (criteria_count or proof_expectations) else "lower-trust"
    return {
        "status": "present",
        "trust": trust,
        "required_for_bounded_or_broad_work": True,
        "completion_criteria_count": criteria_count,
        "proof_expectation_count": len(proof_expectations),
        "evidence_present": evidence_present,
        "rule": "Before closeout, reconcile each requested outcome or planning criterion against delivered behavior and proof.",
        "required_closeout_shape": [
            "requested requirement or criterion",
            "delivered behavior or surface",
            "proof covering it",
            "gap or intentional deviation",
        ],
        "recommended_next_action": "Acceptance reconciliation is visible in planning closeout evidence."
        if trust == "normal"
        else "Record requested->delivered->proof->gap reconciliation before claiming successful closeout.",
        "sources": [
            "planning.active.planning_record.completion_criteria",
            "planning.active.planning_record.proof_expectations",
            "planning.active.planning_record.proof_report",
            "planning.active.planning_record.closure_check",
        ],
    }


def _target_root_from_record(active_planning_record: dict[str, Any]) -> Path | None:
    active_planning_record = _as_dict(active_planning_record)
    for key in ("_target_root", "target_root"):
        value = str(active_planning_record.get(key) or "").strip()
        if value:
            return Path(value)
    source = _as_dict(active_planning_record.get("_closeout_evidence_source"))
    path = str(source.get("path") or "").strip()
    if path:
        try:
            resolved = Path(path).resolve()
        except OSError:
            resolved = Path(path)
        for parent in resolved.parents:
            if (parent / ".agentic-workspace").exists():
                return parent
    return None


def _recent_archived_planning_record_for_closeout(*, target_root: Path | None) -> dict[str, Any]:
    if target_root is None:
        return {}
    archive_root = target_root / ".agentic-workspace" / "planning" / "execplans" / "archive"
    if not archive_root.is_dir():
        return {}
    candidates: list[tuple[float, Path, dict[str, Any]]] = []
    target_resolved = target_root.resolve()
    for record_path in archive_root.glob("*.json"):
        try:
            resolved = record_path.resolve()
            resolved.relative_to(target_resolved)
        except (OSError, ValueError):
            continue
        try:
            payload = json.loads(record_path.read_text(encoding="utf-8-sig"))
        except (OSError, json.JSONDecodeError):
            continue
        if not isinstance(payload, dict):
            continue
        evidence_fields = (
            payload.get("execution_run"),
            payload.get("proof_report"),
            payload.get("closure_check"),
            payload.get("finished_run_review"),
        )
        if not any(isinstance(field, dict) and field for field in evidence_fields):
            continue
        try:
            mtime = resolved.stat().st_mtime
        except OSError:
            mtime = 0.0
        candidates.append((mtime, resolved, payload))
    if not candidates:
        return {}
    mtime, record_path, payload = max(candidates, key=lambda item: item[0])
    relative = record_path.relative_to(target_resolved).as_posix()
    payload = copy.deepcopy(payload)
    payload["_closeout_evidence_source"] = {
        "authority": "archived-planning-evidence",
        "evidence_source_class": "stale-archived-execplan-evidence",
        "path": relative,
        "sort_mtime": mtime,
        "last_modified": datetime.fromtimestamp(mtime, timezone.utc).isoformat() if mtime else "",
        "selection": {
            "basis": "archive-fallback",
            "selected_source_class": "stale-archived-execplan-evidence",
            "ineligible_fresher_source_class": "none",
            "rule": "Archived execplans are fallback closeout evidence only when retained closeout-evidence records are absent or ineligible.",
        },
        "rule": "Archived closeout evidence may inform user-facing reports, but it does not restore active planning state.",
    }
    return payload


_CLOSEOUT_EVIDENCE_RELEVANCE_PRIORITY = {
    "current-slice": 500,
    "latest-cleaned-plan-evidence": 450,
    "same-lineage": 400,
    "parent-lane": 300,
    "older-related": 200,
    "retained-closeout-evidence": 100,
    "unrelated": 0,
}


def _closeout_evidence_lineage(payload: dict[str, Any]) -> dict[str, Any]:
    lineage = _as_dict(payload.get("lineage"))
    relationship = str(
        lineage.get("relationship") or lineage.get("evidence_relationship") or payload.get("evidence_relationship") or ""
    ).strip()
    if not relationship:
        retention_state = str(_as_dict(payload.get("retention")).get("state") or "").strip()
        relationship = (
            "latest-cleaned-plan-evidence" if retention_state == "cleanup-distilled-without-full-archive" else "retained-closeout-evidence"
        )
    relationship = relationship.replace("_", "-").lower()
    if relationship in {"parent", "lane", "parent-lane-closure", "lane-closure"}:
        relationship = "parent-lane"
    elif relationship in {"related", "older", "older-slice", "older-related-slice"}:
        relationship = "older-related"
    elif relationship in {"same-lineage-latest", "lineage", "same-lineage-cleanup"}:
        relationship = "same-lineage"
    elif relationship in {"unrelated-retained-closeout-evidence", "historical-unrelated"}:
        relationship = "unrelated"
    return {
        "relationship": relationship,
        "lineage_id": str(lineage.get("lineage_id") or payload.get("plan_id") or "").strip(),
        "plan_id": str(payload.get("plan_id") or "").strip(),
        "source_plan": str(payload.get("source_plan") or "").strip(),
        "intended_archive": str(payload.get("intended_archive") or "").strip(),
        "rule": "Explicit closeout evidence lineage/relevance is used before mtime; mtime only orders records with the same relevance.",
    }


def _closeout_evidence_relevance_summary(*, lineage: dict[str, Any], mtime: float) -> dict[str, Any]:
    relationship = str(lineage.get("relationship") or "retained-closeout-evidence")
    priority = _CLOSEOUT_EVIDENCE_RELEVANCE_PRIORITY.get(relationship, _CLOSEOUT_EVIDENCE_RELEVANCE_PRIORITY["retained-closeout-evidence"])
    status = "unrelated" if relationship == "unrelated" else "relevant"
    return {
        "status": status,
        "relationship": relationship,
        "priority": priority,
        "lineage_id": lineage.get("lineage_id", ""),
        "plan_id": lineage.get("plan_id", ""),
        "sort_mtime": mtime,
        "rule": "Closeout trust treats relevance as stronger than freshness; newer unrelated evidence stays historical context.",
    }


def _recent_retained_closeout_evidence_for_report(*, target_root: Path | None) -> dict[str, Any]:
    if target_root is None:
        return {}
    evidence_root = target_root / ".agentic-workspace" / "planning" / "closeout-evidence"
    if not evidence_root.is_dir():
        return {}
    candidates: list[tuple[int, float, Path, dict[str, Any], dict[str, Any]]] = []
    target_resolved = target_root.resolve()
    for record_path in evidence_root.glob("*.closeout.json"):
        try:
            resolved = record_path.resolve()
            resolved.relative_to(target_resolved)
        except (OSError, ValueError):
            continue
        try:
            payload = json.loads(record_path.read_text(encoding="utf-8-sig"))
        except (OSError, json.JSONDecodeError):
            continue
        if not isinstance(payload, dict) or payload.get("kind") != "planning-closeout-evidence/v1":
            continue
        evidence_fields = (
            payload.get("execution_run"),
            payload.get("proof_report"),
            payload.get("closure_check"),
            payload.get("finished_run_review"),
        )
        if not any(isinstance(field, dict) and field for field in evidence_fields):
            continue
        try:
            mtime = resolved.stat().st_mtime
        except OSError:
            mtime = 0.0
        lineage = _closeout_evidence_lineage(payload)
        relevance = _closeout_evidence_relevance_summary(lineage=lineage, mtime=mtime)
        candidates.append((int(relevance["priority"]), mtime, resolved, payload, relevance))
    if not candidates:
        return {}
    priority, mtime, record_path, payload, relevance = max(candidates, key=lambda item: (item[0], item[1]))
    relative = record_path.relative_to(target_resolved).as_posix()
    payload = copy.deepcopy(payload)
    retention = _as_dict(payload.get("retention"))
    retention_state = str(retention.get("state") or "").strip()
    relationship = str(relevance.get("relationship") or "").strip()
    candidate_summary = [
        {
            "path": path.relative_to(target_resolved).as_posix(),
            "relationship": candidate_relevance.get("relationship", ""),
            "relevance_status": candidate_relevance.get("status", ""),
            "priority": candidate_priority,
            "sort_mtime": candidate_mtime,
        }
        for candidate_priority, candidate_mtime, path, _candidate_payload, candidate_relevance in sorted(
            candidates, key=lambda item: (item[0], item[1]), reverse=True
        )[:5]
    ]
    payload["_closeout_evidence_source"] = {
        "authority": "retained-closeout-evidence",
        "evidence_source_class": "fresh-closeout-evidence",
        "path": relative,
        "source_plan": str(payload.get("source_plan") or ""),
        "intended_archive": str(payload.get("intended_archive") or ""),
        "retention_state": retention_state,
        "relationship": relationship,
        "relevance": relevance,
        "selection": {
            "basis": "relevance-then-mtime",
            "selected_source_class": "fresh-closeout-evidence",
            "selected_priority": priority,
            "candidate_count": len(candidates),
            "newer_unrelated_count": sum(
                1
                for _candidate_priority, candidate_mtime, _path, _candidate_payload, candidate_relevance in candidates
                if candidate_mtime > mtime and candidate_relevance.get("status") == "unrelated"
            ),
            "candidate_summary": candidate_summary,
            "rule": "Select retained closeout evidence by explicit lineage/relevance first, then mtime within the same relevance class.",
        },
        "sort_mtime": mtime,
        "last_modified": datetime.fromtimestamp(mtime, timezone.utc).isoformat() if mtime else "",
        "rule": "Retained closeout evidence may inform user-facing reports when full archive retention was skipped; it does not restore active planning state.",
    }
    return payload


def _closeout_candidate_identity(payload: dict[str, Any]) -> str:
    return " ".join(
        str(value)
        for value in (
            payload.get("plan_id"),
            payload.get("title"),
            payload.get("source_plan"),
            payload.get("intended_archive"),
            _as_dict(payload.get("lineage")).get("lineage_id"),
        )
        if value
    ).lower()


def _explicit_closeout_candidate_match(*, payload: dict[str, Any], task_text: str) -> bool:
    identity = _closeout_candidate_identity(payload)
    issue_refs = {match.lstrip("#") for match in re.findall(r"#\d+", task_text)}
    if issue_refs and any(re.search(rf"(?:^|[^0-9]){re.escape(ref)}(?:[^0-9]|$)", identity) for ref in issue_refs):
        return True
    normalized = re.sub(r"[^a-z0-9]+", "-", task_text.lower()).strip("-")
    return bool(normalized and (normalized in identity.replace("_", "-") or identity.replace("_", "-") in normalized))


def _closeout_planning_record_for_report(
    *, active_planning_record: dict[str, Any], target_root: Path | None, task_text: str | None = None
) -> dict[str, Any]:
    active_planning_record = active_planning_record if isinstance(active_planning_record, dict) else {}
    if active_planning_record:
        record = copy.deepcopy(active_planning_record)
        record.setdefault(
            "_closeout_evidence_source",
            {
                "authority": "active-planning-evidence",
                "path": str(_as_dict(record.get("task")).get("surface") or ""),
                "rule": "Active planning evidence is current workflow state.",
            },
        )
        return record
    if target_root is None:
        return {}
    target_resolved = target_root.resolve()
    context_path = target_root / ".agentic-workspace" / "local" / "planning-last-closeout.json"
    if context_path.is_file() and not str(task_text or "").strip():
        try:
            context = json.loads(context_path.read_text(encoding="utf-8-sig"))
            if context.get("status") == "no-retained-evidence":
                return {
                    "_closeout_evidence_resolution": {
                        "status": "no-relevant-evidence",
                        "trust": "not-applicable",
                        "selected_plan_id": str(context.get("plan_id") or ""),
                        "candidates": [],
                        "recovery_command": _command_with_cli_invoke(
                            command='agentic-workspace report --target ./repo --section closeout_trust --task "<task, plan, or lane id>" --format json',
                            cli_invoke=DEFAULT_CLI_INVOKE,
                        ),
                        "rule": "The latest terminal Planning command produced no retained evidence; an older cursor cannot control closeout trust.",
                    }
                }
            selected = (target_root / str(context.get("evidence_path") or "")).resolve()
            selected.relative_to(target_resolved)
            payload = json.loads(selected.read_text(encoding="utf-8-sig"))
            if isinstance(payload, dict):
                payload = copy.deepcopy(payload)
                payload["_closeout_evidence_source"] = {
                    "authority": "retained-closeout-evidence"
                    if payload.get("kind") == "planning-closeout-evidence/v1"
                    else "archived-planning-evidence",
                    "evidence_source_class": "command-owned-last-closeout",
                    "path": selected.relative_to(target_resolved).as_posix(),
                    "source_plan": str(payload.get("source_plan") or context.get("source_plan") or ""),
                    "intended_archive": str(payload.get("intended_archive") or ""),
                    "relationship": "current-slice",
                    "relevance": {"status": "relevant", "relationship": "current-slice", "plan_id": context.get("plan_id", "")},
                    "selection": {
                        "basis": "planning-terminal-command-context",
                        "selected_plan_id": context.get("plan_id", ""),
                        "context_path": context_path.relative_to(target_resolved).as_posix(),
                    },
                    "rule": "The terminal Planning command retained the identity of the evidence it just produced.",
                }
                return payload
        except (OSError, ValueError, json.JSONDecodeError):
            pass

    if str(task_text or "").strip():
        matches: list[tuple[Path, dict[str, Any]]] = []
        roots = [
            target_root / ".agentic-workspace" / "planning" / "closeout-evidence",
            target_root / ".agentic-workspace" / "planning" / "execplans" / "archive",
        ]
        for root in roots:
            if not root.is_dir():
                continue
            for path in [*root.glob("*.closeout.json"), *root.glob("*.plan.json")]:
                try:
                    payload = json.loads(path.read_text(encoding="utf-8-sig"))
                except (OSError, json.JSONDecodeError):
                    continue
                if isinstance(payload, dict) and _explicit_closeout_candidate_match(payload=payload, task_text=str(task_text)):
                    matches.append((path, payload))
        if len(matches) == 1:
            path, payload = matches[0]
            payload = copy.deepcopy(payload)
            relationship = str(_closeout_evidence_lineage(payload).get("relationship") or "same-lineage")
            payload["_closeout_evidence_source"] = {
                "authority": "retained-closeout-evidence"
                if payload.get("kind") == "planning-closeout-evidence/v1"
                else "archived-planning-evidence",
                "evidence_source_class": "explicit-task-selection",
                "path": path.relative_to(target_resolved).as_posix(),
                "source_plan": str(payload.get("source_plan") or ""),
                "intended_archive": str(payload.get("intended_archive") or ""),
                "retention_state": str(_as_dict(payload.get("retention")).get("state") or ""),
                "relationship": relationship,
                "relevance": {"status": "relevant", "relationship": relationship, "plan_id": payload.get("plan_id", "")},
                "selection": {"basis": "explicit-task-provenance", "task": str(task_text)},
                "sort_mtime": path.stat().st_mtime,
                "last_modified": datetime.fromtimestamp(path.stat().st_mtime, timezone.utc).isoformat(),
            }
            return payload
        if len(matches) > 1:
            return {
                "_closeout_evidence_resolution": {
                    "status": "ambiguous",
                    "trust": "not-applicable",
                    "candidates": [path.relative_to(target_resolved).as_posix() for path, _ in matches[:5]],
                    "recovery_command": _command_with_cli_invoke(
                        command='agentic-workspace report --target ./repo --section closeout_trust --task "<exact plan id>" --format json',
                        cli_invoke=DEFAULT_CLI_INVOKE,
                    ),
                    "rule": "Multiple retained records match the requested task; none may control closeout trust until selection is exact.",
                }
            }
    return {
        "_closeout_evidence_resolution": {
            "status": "no-relevant-evidence",
            "trust": "not-applicable",
            "candidates": [],
            "recovery_command": _command_with_cli_invoke(
                command='agentic-workspace report --target ./repo --section closeout_trust --task "<task, plan, or lane id>" --format json',
                cli_invoke=DEFAULT_CLI_INVOKE,
            ),
            "rule": "No command-owned current-task identity or uniquely matching retained evidence was available; unrelated history cannot control the claim.",
        }
    }


def _intent_proof_check_payload(*, planning_report: dict[str, Any], target_root: Path | None = None) -> dict[str, Any]:
    active = planning_report.get("active", {}) if isinstance(planning_report, dict) else {}
    planning_record = active.get("planning_record", {}) if isinstance(active, dict) else {}
    planning_record = planning_record if isinstance(planning_record, dict) else {}
    raw_planning_record = _raw_active_planning_record_for_closeout(planning_record=planning_record, target_root=target_root)
    if planning_record.get("status") != "present" and not raw_planning_record:
        return {
            "kind": "agentic-workspace/intent-proof-check/v1",
            "status": "not_recorded",
            "claim_boundary": "work",
            "trust": "missing",
            "warning": "no active planning record exposes intent-proof strength",
            "rule": "Proof execution and intent-proof strength are separate; broad completion claims need representative or sufficient intent proof.",
        }
    proof_report = planning_record.get("proof_report", {})
    proof_report = proof_report if isinstance(proof_report, dict) else {}
    raw_proof_report = raw_planning_record.get("proof_report", {}) if isinstance(raw_planning_record, dict) else {}
    raw_proof_report = raw_proof_report if isinstance(raw_proof_report, dict) else {}
    raw_intent_proof = planning_record.get(
        "intent_proof",
        proof_report.get(
            "intent_proof",
            proof_report.get(
                "intent proof",
                raw_planning_record.get(
                    "intent_proof",
                    raw_proof_report.get("intent_proof", raw_proof_report.get("intent proof", {})),
                ),
            ),
        ),
    )
    if isinstance(raw_intent_proof, str):
        try:
            parsed = json.loads(raw_intent_proof)
        except json.JSONDecodeError:
            try:
                parsed = ast.literal_eval(raw_intent_proof)
            except (SyntaxError, ValueError):
                parsed = {"status": raw_intent_proof}
        raw_intent_proof = parsed
    raw_intent_proof = raw_intent_proof if isinstance(raw_intent_proof, dict) else {}
    raw_status = str(raw_intent_proof.get("status", "")).strip().lower().replace("-", "_")
    status = (
        raw_status
        if raw_status in {"not_recorded", "regression_only", "representative", "sufficient_for_claim", "needs_review"}
        else "not_recorded"
    )
    claim_boundary = str(raw_intent_proof.get("claim_boundary", "work")).strip() or "work"
    trust = "normal" if status in {"representative", "sufficient_for_claim"} else "review" if status == "needs_review" else "weak"
    warning = ""
    if status == "not_recorded":
        warning = "proof execution may be recorded, but intent-proof strength was not recorded"
    elif status == "regression_only":
        warning = "proof may cover a local regression without representative user, consumer, boundary, or negative behavior"
    elif status == "needs_review":
        warning = "human/domain review is required to judge whether proof covers the intended behavior"
    return {
        "kind": "agentic-workspace/intent-proof-check/v1",
        "status": status,
        "claim_boundary": claim_boundary,
        "trust": trust,
        "warning": warning,
        "intended_behavior": [str(item) for item in _list_payload(raw_intent_proof.get("intended_behavior")) if str(item).strip()][:5],
        "proof_dimensions": [str(item) for item in _list_payload(raw_intent_proof.get("proof_dimensions")) if str(item).strip()][:5],
        "unproven_after_tests": [str(item) for item in _list_payload(raw_intent_proof.get("unproven_after_tests")) if str(item).strip()][
            :5
        ],
        "preservation_claims": [str(item) for item in _list_payload(raw_intent_proof.get("preservation_claims")) if str(item).strip()][:5],
        "allowed_behavior_changes": [
            str(item) for item in _list_payload(raw_intent_proof.get("allowed_behavior_changes")) if str(item).strip()
        ][:5],
        "unknown_behavior": [str(item) for item in _list_payload(raw_intent_proof.get("unknown_behavior")) if str(item).strip()][:5],
        "human_confirmation_needed": [
            str(item) for item in _list_payload(raw_intent_proof.get("human_confirmation_needed")) if str(item).strip()
        ][:5],
        "proof_classes": [str(item) for item in _list_payload(raw_intent_proof.get("proof_classes")) if str(item).strip()][:8],
        "preservation_evidence": [str(item) for item in _list_payload(raw_intent_proof.get("preservation_evidence")) if str(item).strip()][
            :5
        ],
        "evidence": str(raw_intent_proof.get("evidence", raw_intent_proof.get("reason", ""))),
        "rule": "Proof execution and intent-proof strength are separate; broad completion claims need representative or sufficient intent proof.",
        "sources": [
            "planning.active.planning_record.intent_proof",
            "planning.active.planning_record.proof_report.intent_proof",
            "planning.active.task.surface.raw_execplan.intent_proof",
            "planning.active.task.surface.raw_execplan.proof_report.intent_proof",
        ],
    }


def _external_work_delta_payload(*, target_root: Path) -> dict[str, Any]:
    evidence_path, evidence_relative_path, evidence_storage = _external_intent_evidence_read_location(target_root)
    provider_rule = "Core planning consumes provider-agnostic external work evidence; provider adapters may refresh it."
    if not evidence_path.is_file():
        return {
            "status": "unavailable",
            "reason": "external intent evidence cache is absent",
            "provider_rule": provider_rule,
            "storage": evidence_storage,
            "open_count": 0,
            "changed_count": 0,
            "closed_count": 0,
            "recommended_next_lane": {},
        }
    try:
        payload = json.loads(evidence_path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError) as exc:
        return {
            "status": "invalid",
            "reason": str(exc),
            "provider_rule": provider_rule,
            "storage": evidence_storage,
            "open_count": 0,
            "changed_count": 0,
            "closed_count": 0,
            "recommended_next_lane": {},
        }
    schema_findings = _external_intent_evidence_schema_findings(target_root=target_root, payload=payload)
    if schema_findings:
        return {
            "status": "invalid",
            "reason": "external intent evidence schema validation failed: " + "; ".join(schema_findings),
            "schema_findings": schema_findings,
            "provider_rule": provider_rule,
            "storage": evidence_storage,
            "open_count": 0,
            "changed_count": 0,
            "closed_count": 0,
            "recommended_next_lane": {},
        }
    items = [item for item in _list_payload(payload.get("items")) if isinstance(item, dict)]
    previous_items = [item for item in _list_payload(payload.get("previous_items")) if isinstance(item, dict)]
    refresh_metadata = payload.get("refresh_metadata", {}) if isinstance(payload.get("refresh_metadata"), dict) else {}
    open_items = [item for item in items if str(item.get("status", "")).lower() == "open"]
    previous_by_id = {str(item.get("id", "")): item for item in previous_items if str(item.get("id", ""))}
    current_by_id = {str(item.get("id", "")): item for item in items if str(item.get("id", ""))}
    new_items = [item for item in items if str(item.get("id", "")) and str(item.get("id", "")) not in previous_by_id]
    closed_items = [
        item
        for item_id, item in current_by_id.items()
        if item_id in previous_by_id
        and str(previous_by_id[item_id].get("status", "")).lower() == "open"
        and (str(item.get("status", "")).lower() == "closed")
    ]
    changed_items = [item for item_id, item in current_by_id.items() if item_id in previous_by_id and item != previous_by_id[item_id]]
    recommended = open_items[0] if open_items else {}
    pending_pr_merge = _pending_pr_merge_evidence_by_issue(target_root=target_root)
    status = "delta-present" if previous_items else "snapshot-only"
    return {
        "status": status,
        "provider_rule": provider_rule,
        "source": evidence_relative_path,
        "storage": evidence_storage,
        "refreshed_at": str(payload.get("refreshed_at", "") or refresh_metadata.get("refreshed_at", "")),
        "refresh_metadata": {
            "adapter": str(refresh_metadata.get("adapter", "")),
            "repository": str(refresh_metadata.get("repository", "")),
            "item_count": int(refresh_metadata.get("item_count", len(items)) or 0),
            "open_count": int(refresh_metadata.get("open_count", len(open_items)) or 0),
            "closed_count": int(refresh_metadata.get("closed_count", 0) or 0),
        },
        "item_count": len(items),
        "open_count": len(open_items),
        "new_count": len(new_items) if previous_items else 0,
        "changed_count": len(changed_items) if previous_items else 0,
        "closed_count": len(closed_items) if previous_items else 0,
        "sample_new": [_external_work_summary(item) for item in new_items[:5]] if previous_items else [],
        "sample_changed": [_external_work_summary(item) for item in changed_items[:5]] if previous_items else [],
        "sample_closed": [_external_work_summary(item) for item in closed_items[:5]] if previous_items else [],
        "pending_pr_merge_count": len(pending_pr_merge),
        "pending_pr_merge": list(pending_pr_merge.values())[:5],
        "recommended_next_lane": _external_work_summary(recommended) if recommended else {},
        "delta_rule": "When previous_items is present, compare provider-agnostic item ids and statuses; otherwise report a compact current snapshot only.",
    }


def _external_work_reconciliation_payload(
    *, module_reports: list[dict[str, Any]], external_work_delta: dict[str, Any], cli_invoke: str = DEFAULT_CLI_INVOKE
) -> dict[str, Any]:
    planning_report = next((report for report in module_reports if isinstance(report, dict) and report.get("module") == "planning"), {})
    intent_validation = planning_report.get("intent_validation", {}) if isinstance(planning_report, dict) else {}
    planning_reconciliation = intent_validation.get("external_work_reconciliation", {}) if isinstance(intent_validation, dict) else {}
    payload: dict[str, Any]
    if isinstance(planning_reconciliation, dict) and planning_reconciliation:
        payload = copy.deepcopy(planning_reconciliation)
    else:
        payload = {
            "kind": "planning-external-work-reconciliation/v1",
            "status": "unavailable",
            "primary_owner": ".agentic-workspace/planning/state.toml",
            "provider_rule": "Core planning consumes provider-agnostic external work evidence; provider-specific refresh belongs in optional adapters.",
            "recommended_next_action": "Install or run planning summary before trusting external-work reconciliation.",
        }
    payload["workspace_report_view"] = {
        "kind": "workspace-external-work-reconciliation-view/v1",
        "section_command": "agentic-workspace report --target ./repo --section external_work_reconciliation --format json",
        "delta_section": "external_work_delta",
        "delta_status": external_work_delta.get("status", "unavailable"),
        "delta_counts": {
            "new_count": external_work_delta.get("new_count", 0),
            "changed_count": external_work_delta.get("changed_count", 0),
            "closed_count": external_work_delta.get("closed_count", 0),
        },
    }
    if "promotion_action" not in payload:
        external_state = payload.get("external_work_state", {}) if isinstance(payload.get("external_work_state"), dict) else {}
        untracked_open = int(external_state.get("untracked_open_count", 0) or 0)
        promotion_action = {
            "action": "promote-external-work-to-planning",
            "summary": "Create one checked-in active execplan/state entry for selected untracked external work."
            if untracked_open
            else "No external-work promotion is currently needed.",
            "command": _command_with_cli_invoke(command="agentic-workspace summary --format json", cli_invoke=cli_invoke),
            "risk": "planning mutation; inspect selected external items before editing checked-in planning state",
            "required_inputs": ["selected external item ids", "requested outcome", "proof expectations", "owner surface"],
            "target_surfaces": [".agentic-workspace/planning/state.toml", ".agentic-workspace/planning/execplans/<lane>.plan.json"],
            "state_rule": "Represent promoted work once as the active item and point it at one execplan; do not duplicate active state.",
            "provider_neutral": True,
            "next_proof": "rerun summary and planning doctor after promotion; active_count should be one for a broad active lane",
        }
        promotion_action["run"] = promotion_action["command"]
        payload["promotion_action"] = promotion_action
    elif isinstance(payload.get("promotion_action"), dict):
        action = payload["promotion_action"]
        command = str(action.get("command", "")).strip()
        if command:
            action["command"] = _command_with_cli_invoke(command=command, cli_invoke=cli_invoke)
            action["run"] = action["command"]
    payload.setdefault(
        "routine_reconciliation",
        {
            "kind": "planning/github-planning-routine-reconciliation/v1",
            "status": "available",
            "after_events": [
                "issue created or updated",
                "issue closed or reopened",
                "pull request opened, merged, or updated",
                "planning state changed after external work changed",
            ],
            "command": _command_with_cli_invoke(
                command="agentic-workspace external-intent refresh-github --target . --state all --format json",
                cli_invoke=cli_invoke,
            ),
            "then": _command_with_cli_invoke(command="agentic-workspace summary --format json", cli_invoke=cli_invoke),
            "rule": "Refreshing GitHub evidence is routine after tracker mutations; checked-in planning remains the primary owner.",
        },
    )
    payload.setdefault("detail_sections", ["current_external_work", "closeout_reconciliation", "landed_open_issue_reconciliation"])
    return payload


def _external_work_summary(item: dict[str, Any]) -> dict[str, Any]:
    return {
        "id": str(item.get("id", "")),
        "title": str(item.get("title", "")),
        "status": str(item.get("status", "")),
        "kind": str(item.get("kind", "")),
        "parent_id": str(item.get("parent_id", "")),
        "reopens": [str(entry).strip() for entry in _list_payload(item.get("reopens")) if str(entry).strip()],
    }


def _stale_cleanup_payload(*, target_root: Path, cli_invoke: str = DEFAULT_CLI_INVOKE) -> dict[str, Any]:
    return _workspace_runtime_core._stale_cleanup_payload(target_root=target_root, cli_invoke=cli_invoke)


def _external_intent_evidence_path(target_root: Path) -> Path:
    return target_root / EXTERNAL_INTENT_CACHE_RELATIVE_PATH


def _external_intent_planning_evidence_path(target_root: Path) -> Path:
    return target_root / EXTERNAL_INTENT_PLANNING_RELATIVE_PATH


def _external_intent_evidence_write_location(target_root: Path, storage: str) -> tuple[Path, str, str]:
    if storage == "cache":
        return (target_root / EXTERNAL_INTENT_CACHE_RELATIVE_PATH, EXTERNAL_INTENT_CACHE_RELATIVE_PATH.as_posix(), "cache")
    if storage == "planning":
        return (target_root / EXTERNAL_INTENT_PLANNING_RELATIVE_PATH, EXTERNAL_INTENT_PLANNING_RELATIVE_PATH.as_posix(), "planning")
    raise WorkspaceUsageError("--storage must be one of: cache, planning.")


def _external_intent_evidence_read_location(target_root: Path) -> tuple[Path, str, str]:
    cache_path = target_root / EXTERNAL_INTENT_CACHE_RELATIVE_PATH
    planning_path = target_root / EXTERNAL_INTENT_PLANNING_RELATIVE_PATH
    if cache_path.exists() and planning_path.exists():
        cache_timestamp = _external_intent_evidence_file_timestamp(cache_path)
        planning_timestamp = _external_intent_evidence_file_timestamp(planning_path)
        if planning_timestamp and (cache_timestamp is None or planning_timestamp > cache_timestamp):
            return (planning_path, EXTERNAL_INTENT_PLANNING_RELATIVE_PATH.as_posix(), "planning")
    if cache_path.exists():
        return (cache_path, EXTERNAL_INTENT_CACHE_RELATIVE_PATH.as_posix(), "cache")
    return (planning_path, EXTERNAL_INTENT_PLANNING_RELATIVE_PATH.as_posix(), "planning-legacy")


def _external_intent_evidence_file_timestamp(path: Path) -> datetime | None:
    try:
        payload = json.loads(path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError):
        return None
    if not isinstance(payload, dict):
        return None
    metadata = payload.get("refresh_metadata", {})
    metadata = metadata if isinstance(metadata, dict) else {}
    return _parse_external_intent_timestamp(payload.get("refreshed_at")) or _parse_external_intent_timestamp(metadata.get("refreshed_at"))


def _ensure_external_intent_cache_if_available(target_root: Path) -> dict[str, Any]:
    cache_path = target_root / EXTERNAL_INTENT_CACHE_RELATIVE_PATH
    if cache_path.exists():
        return {"status": "present", "path": EXTERNAL_INTENT_CACHE_RELATIVE_PATH.as_posix()}
    try:
        return _refresh_github_external_intent_evidence(
            target_root=target_root, repo=None, limit=None, state=None, storage="cache", dry_run=False
        )
    except WorkspaceUsageError as exc:
        return {
            "status": "unavailable",
            "reason": str(exc),
            "path": EXTERNAL_INTENT_CACHE_RELATIVE_PATH.as_posix(),
            "provider_rule": "GitHub reconstruction is optional; missing gh leaves offline planning usable.",
        }


def _run_gh_json(args: list[str], *, cwd: Path) -> Any:
    command = ["gh", *args]
    try:
        result = subprocess.run(command, cwd=cwd, capture_output=True, text=True, encoding="utf-8", check=False)
    except FileNotFoundError as exc:
        raise WorkspaceUsageError("GitHub external-intent refresh requires the optional `gh` CLI to be installed.") from exc
    if result.returncode != 0:
        stderr = result.stderr.strip() or result.stdout.strip() or f"`gh {' '.join(args)}` failed"
        raise WorkspaceUsageError(stderr)
    try:
        return json.loads(result.stdout or "null")
    except json.JSONDecodeError as exc:
        raise WorkspaceUsageError(f"`gh {' '.join(args)}` did not return valid JSON: {exc}") from exc


def _resolve_github_repo_for_external_intent(*, target_root: Path, repo: str | None) -> str:
    if repo and repo.strip():
        return repo.strip()
    payload = _run_gh_json(["repo", "view", "--json", "nameWithOwner"], cwd=target_root)
    if isinstance(payload, dict) and isinstance(payload.get("nameWithOwner"), str) and payload["nameWithOwner"].strip():
        return str(payload["nameWithOwner"]).strip()
    raise WorkspaceUsageError("Could not resolve GitHub repository; pass --repo owner/name.")


def _github_label_names(raw_labels: Any) -> list[str]:
    labels: list[str] = []
    for raw_label in _list_payload(raw_labels):
        if isinstance(raw_label, dict):
            name = str(raw_label.get("name", "")).strip()
        else:
            name = str(raw_label).strip()
        if name and name not in labels:
            labels.append(name)
    return labels


def _github_comments_count(raw_comments: Any) -> int:
    if isinstance(raw_comments, list):
        return len(raw_comments)
    try:
        return int(raw_comments or 0)
    except (TypeError, ValueError):
        return 0


def _github_planning_residue_expected(labels: list[str]) -> str:
    normalized = {label.lower() for label in labels}
    if normalized & {"planning-residue-required", "requires-planning-residue"}:
        return "required"
    if normalized & {"planning-residue-none", "no-planning-residue"}:
        return "none"
    return "optional"


def _markdown_section_value(body: str, heading: str) -> str:
    lines = body.splitlines()
    heading_normalized = heading.strip().lower()
    for index, line in enumerate(lines):
        stripped = line.strip().lstrip("#").strip().lower()
        if stripped != heading_normalized:
            continue
        values: list[str] = []
        for candidate in lines[index + 1 :]:
            candidate_stripped = candidate.strip()
            if candidate_stripped.startswith("##"):
                break
            if candidate_stripped:
                values.append(candidate_stripped)
        return "\n".join(values).strip()
    return ""


def _infer_external_issue_kind(*, body: str) -> str:
    issue_kind = _markdown_section_value(body, "Issue kind").lower()
    if "child" in issue_kind or "slice" in issue_kind:
        return "slice"
    if "parent" in issue_kind or "lane" in issue_kind:
        return "lane"
    return "issue"


def _infer_external_issue_parent_id(body: str) -> str:
    section_value = _markdown_section_value(body, "Parent issue or lane")
    section_match = re.search("#(\\d+)\\b", section_value)
    if section_match:
        return f"#{section_match.group(1)}"
    for pattern in ("(?im)^\\s*parent(?:\\s+issue|\\s+lane)?\\s*[:#]\\s*#?(\\d+)\\b", "(?im)^\\s*belongs\\s+to\\s*[:#]?\\s*#?(\\d+)\\b"):
        match = re.search(pattern, body)
        if match:
            return f"#{match.group(1)}"
    return ""


def _infer_external_issue_reopens(body: str) -> list[str]:
    refs: list[str] = []
    for heading in ("Closed lane(s) to revisit", "Closed lanes to revisit", "Reopens"):
        section_value = _markdown_section_value(body, heading)
        for match in re.finditer("#(\\d+)\\b", section_value):
            ref = f"#{match.group(1)}"
            if ref not in refs:
                refs.append(ref)
    return refs


def _infer_external_issue_negative_invariants(*, body: str, comments: Any) -> list[str]:
    text_blocks = [body]
    if isinstance(comments, list):
        for comment in comments:
            if isinstance(comment, dict):
                text_blocks.append(str(comment.get("body", "") or ""))
            else:
                text_blocks.append(str(comment or ""))
    invariants: list[str] = []
    for text in text_blocks:
        for heading in ("Negative invariants", "Negative invariant", "Must not", "Must never"):
            section_value = _markdown_section_value(text, heading)
            for line in section_value.splitlines():
                normalized = line.strip().lstrip("-*").strip()
                if normalized and normalized not in invariants:
                    invariants.append(normalized)
        for match in re.finditer("(?im)^\\s*(?:negative invariant|must not|must never)\\s*[:\\-]\\s*(.+?)\\s*$", text):
            normalized = match.group(1).strip()
            if normalized and normalized not in invariants:
                invariants.append(normalized)
    return invariants


def _github_issue_to_external_intent_item(*, issue: dict[str, Any], repo: str) -> dict[str, Any] | None:
    number = issue.get("number")
    if number is None:
        return None
    try:
        issue_number = int(number)
    except (TypeError, ValueError):
        return None
    state = str(issue.get("state", "")).strip().lower()
    if state not in {"open", "closed"}:
        state = "closed" if bool(issue.get("closed")) else "open"
    labels = _github_label_names(issue.get("labels"))
    body = str(issue.get("body", "") or "")
    return {
        "system": "github",
        "id": f"#{issue_number}",
        "title": str(issue.get("title", "")).strip(),
        "status": state,
        "kind": _infer_external_issue_kind(body=body),
        "parent_id": _infer_external_issue_parent_id(body),
        "reopens": _infer_external_issue_reopens(body),
        "planning_residue_expected": _github_planning_residue_expected(labels),
        "negative_invariants": _infer_external_issue_negative_invariants(body=body, comments=issue.get("comments")),
        "url": str(issue.get("url", "")).strip(),
        "source_repository": repo,
        "labels": labels,
        "created_at": str(issue.get("createdAt", "")).strip(),
        "updated_at": str(issue.get("updatedAt", "")).strip(),
        "closed_at": str(issue.get("closedAt", "") or "").strip(),
        "comments_count": _github_comments_count(issue.get("comments")),
    }


def _normalize_external_intent_issue_refs(raw_issue_refs: list[str] | None) -> list[str]:
    normalized: list[str] = []
    for raw_ref in raw_issue_refs or []:
        text = str(raw_ref or "").strip()
        if not text:
            continue
        refs = sorted(_issue_refs_from_text(text), key=lambda value: int(value.lstrip("#")))
        if not refs and text.isdigit():
            refs = [f"#{text}"]
        for ref in refs:
            if ref not in normalized:
                normalized.append(ref)
    return normalized


def _fetch_github_external_intent_issue_items(*, target_root: Path, repo: str, issue_refs: list[str]) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    for issue_ref in issue_refs:
        issue_number = issue_ref.lstrip("#")
        raw_issue = _run_gh_json(
            [
                "issue",
                "view",
                issue_number,
                "--repo",
                repo,
                "--json",
                "number,title,state,url,labels,createdAt,updatedAt,closedAt,body,comments",
            ],
            cwd=target_root,
        )
        if not isinstance(raw_issue, dict):
            raise WorkspaceUsageError(f"GitHub issue view for {issue_ref} did not return a JSON object.")
        item = _github_issue_to_external_intent_item(issue=raw_issue, repo=repo)
        if item is not None:
            items.append(item)
    return items


def _declared_lane_pull_request_numbers(*, target_root: Path) -> list[int]:
    numbers: set[int] = set()
    lane_dir = target_root / ".agentic-workspace/planning/lanes"
    for lane_path in sorted(lane_dir.glob("*.lane.json")) if lane_dir.is_dir() else []:
        try:
            lane = json.loads(lane_path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            continue
        for child in _list_payload(lane.get("children")):
            if not isinstance(child, dict):
                continue
            match = re.fullmatch(r"(?:PR\s*)?#(\d+)", str(child.get("pr_ref") or "").strip(), flags=re.IGNORECASE)
            if match:
                numbers.add(int(match.group(1)))
    return sorted(numbers)


def _github_current_pull_request_evidence(*, target_root: Path, repo: str) -> list[dict[str, Any]]:
    evidence: list[dict[str, Any]] = []
    for number in _declared_lane_pull_request_numbers(target_root=target_root):
        raw_pr = _run_gh_json(
            ["pr", "view", str(number), "--repo", repo, "--json", "number,title,state,url"],
            cwd=target_root,
        )
        if not isinstance(raw_pr, dict) or raw_pr.get("number") is None:
            raise WorkspaceUsageError(f"GitHub PR view for declared lane reference #{number} did not return a JSON object.")
        evidence.append(
            {
                "system": "github",
                "number": int(raw_pr.get("number") or 0),
                "title": str(raw_pr.get("title", "")).strip(),
                "state": str(raw_pr.get("state", "")).strip().lower(),
                "url": str(raw_pr.get("url", "")).strip(),
            }
        )
    return evidence


def _planning_candidate_priority_from_labels(labels: Sequence[str]) -> str | None:
    normalized = {str(label).strip().lower() for label in labels}
    if "priority/high" in normalized:
        return "P1"
    if "priority/medium" in normalized:
        return "P2"
    if "priority/low" in normalized:
        return "P3"
    if "priority/lowest" in normalized:
        return "P4"
    return None


def _planning_candidate_priority_from_item(item: dict[str, Any]) -> tuple[str | None, str]:
    priority = _planning_candidate_priority_from_labels([str(label) for label in item.get("labels", [])])
    if priority is not None:
        return priority, "label"
    if str(item.get("kind", "")) == "lane":
        return "P1", "inferred-lane"
    if str(item.get("kind", "")) == "slice":
        return "P2", "inferred-slice"
    labels = {str(label).strip().lower() for label in item.get("labels", []) if str(label).strip()}
    if "planning" in labels:
        return "P2", "inferred-planning"
    return None, "missing"


def _existing_planning_candidate_refs(*, target_root: Path) -> set[str]:
    state_path = target_root / ".agentic-workspace" / "planning" / "state.toml"
    if not state_path.exists():
        return set()
    try:
        payload = tomllib.loads(state_path.read_text(encoding="utf-8"))
    except (OSError, tomllib.TOMLDecodeError):
        return set()
    refs: set[str] = set()
    roadmap = payload.get("roadmap", {}) if isinstance(payload, dict) else {}
    candidates = roadmap.get("candidates", []) if isinstance(roadmap, dict) else []
    for candidate in candidates if isinstance(candidates, list) else []:
        if not isinstance(candidate, dict):
            continue
        raw_refs = str(candidate.get("refs", ""))
        refs.update(f"#{match}" for match in re.findall(r"#(\d+)\b", raw_refs))
    return refs


def _planning_candidate_suggestions_from_external_items(*, target_root: Path, items: list[dict[str, Any]]) -> dict[str, Any]:
    existing_refs = _existing_planning_candidate_refs(target_root=target_root)
    candidates: list[dict[str, str]] = []
    for item in items:
        if item.get("status") != "open":
            continue
        labels = [str(label) for label in item.get("labels", []) if str(label).strip()]
        if "status/deferred" in labels:
            continue
        priority, priority_source = _planning_candidate_priority_from_item(item)
        if priority is None:
            continue
        ref = str(item.get("id", "")).strip()
        if not ref or ref in existing_refs:
            continue
        number_slug = ref.lstrip("#")
        title = str(item.get("title", "")).strip()
        slug = re.sub(r"[^a-z0-9]+", "-", title.lower()).strip("-")[:48] or f"issue-{number_slug}"
        candidates.append(
            {
                "id": f"github-{number_slug}-{slug}",
                "maturity": "candidate",
                "status": "next",
                "priority": priority,
                "refs": f"GitHub {ref}",
                "title": title,
                "outcome": "Route the upstream issue into a bounded Agentic Workspace slice before implementation.",
                "reason": "Open prioritized upstream issue from refreshed external intent evidence."
                if priority_source == "label"
                else f"Open upstream issue from refreshed external intent evidence; priority {priority} inferred from {priority_source}.",
                "promotion_signal": "Promote when this issue is selected for implementation or grouped into a bounded lane.",
                "suggested_first_slice": "Inspect the issue body, choose the smallest workflow shape, and record exact proof before closeout.",
            }
        )
    return {
        "kind": "planning-candidate-suggestions/v1",
        "status": "suggestions-ready" if candidates else "no-new-prioritized-candidates",
        "rule": "Use these schema-valid rows as command-owned intake suggestions; do not hand-edit planning state without checking for duplicate refs.",
        "excluded": [
            "closed issues",
            "unprioritized non-planning issues",
            "status/deferred issues",
            "refs already in planning candidates",
        ],
        "candidate_count": len(candidates),
        "candidates": candidates,
    }


def _external_issue_grouping_hints(*, items: list[dict[str, Any]], candidates: list[dict[str, Any]] | None = None) -> dict[str, Any]:
    open_items = [item for item in items if isinstance(item, dict) and str(item.get("status", "")).strip() == "open"]
    by_id = {str(item.get("id", "")).strip(): item for item in open_items if str(item.get("id", "")).strip()}
    candidate_refs: set[str] = set()
    for candidate in candidates or []:
        refs = str(candidate.get("refs", "")).strip()
        candidate_refs.update(f"#{match}" for match in re.findall(r"#(\d+)\b", refs))
    parent_lanes: list[dict[str, Any]] = []
    child_clusters: dict[str, dict[str, Any]] = {}
    standalone: list[dict[str, Any]] = []
    for item in open_items:
        ref = str(item.get("id", "")).strip()
        title = str(item.get("title", "")).strip()
        kind = str(item.get("kind", "")).strip()
        parent_id = str(item.get("parent_id", "")).strip()
        compact_item = {
            "id": ref,
            "title": title,
            "kind": kind or "issue",
            "has_planning_candidate": ref in candidate_refs,
        }
        if kind in {"lane", "epic"}:
            parent_lanes.append(compact_item)
            continue
        if parent_id:
            cluster = child_clusters.setdefault(
                parent_id,
                {
                    "parent_id": parent_id,
                    "parent_title": str(by_id.get(parent_id, {}).get("title", "")).strip(),
                    "child_count": 0,
                    "children": [],
                },
            )
            cluster["child_count"] += 1
            if len(cluster["children"]) < 3:
                cluster["children"].append(compact_item)
            continue
        standalone.append(compact_item)
    parent_lanes = sorted(parent_lanes, key=lambda item: int(str(item.get("id", "0")).lstrip("#") or "0"))[:3]
    clusters = sorted(child_clusters.values(), key=lambda item: (-int(item.get("child_count", 0)), str(item.get("parent_id", ""))))[:3]
    standalone = sorted(standalone, key=lambda item: int(str(item.get("id", "0")).lstrip("#") or "0"))[:3]
    return {
        "kind": "external-issue-grouping-hints/v1",
        "status": "present" if open_items else "none",
        "open_item_count": len(open_items),
        "parent_lane_count": sum(1 for item in open_items if str(item.get("kind", "")).strip() in {"lane", "epic"}),
        "child_slice_count": sum(1 for item in open_items if str(item.get("parent_id", "")).strip()),
        "standalone_count": sum(
            1
            for item in open_items
            if str(item.get("kind", "")).strip() not in {"lane", "epic"} and not str(item.get("parent_id", "")).strip()
        ),
        "candidate_backed_count": len(candidate_refs),
        "parent_lanes": parent_lanes,
        "child_issue_clusters": clusters,
        "standalone_candidates": standalone,
        "detail_selector": "open_issue_intake.grouping_hints",
        "rule": "Grouping hints are compact routing clues from provider-agnostic evidence, not a priority decision or full issue list.",
    }


def _toml_inline_string(value: str) -> str:
    return json.dumps(value, ensure_ascii=True)


def _planning_candidate_toml_row(candidate: dict[str, str]) -> str:
    fields = (
        "id",
        "maturity",
        "status",
        "priority",
        "refs",
        "title",
        "outcome",
        "reason",
        "promotion_signal",
        "suggested_first_slice",
    )
    rendered = ", ".join(f"{field} = {_toml_inline_string(str(candidate.get(field, '')))}" for field in fields)
    return f"  {{ {rendered} }}"


def _append_planning_candidate_rows(*, target_root: Path, candidates: list[dict[str, str]], dry_run: bool) -> dict[str, Any]:
    state_path = target_root / ".agentic-workspace" / "planning" / "state.toml"
    relative_path = ".agentic-workspace/planning/state.toml"
    if not candidates:
        return {"status": "nothing-to-apply", "path": relative_path, "applied_count": 0, "candidate_ids": []}
    if not state_path.exists():
        return {"status": "blocked", "path": relative_path, "reason": "planning state is missing", "applied_count": 0, "candidate_ids": []}
    original = state_path.read_text(encoding="utf-8")
    rows = [_planning_candidate_toml_row(candidate) for candidate in candidates]

    roadmap_match = re.search(r"(?m)^\[roadmap\]\s*$", original)
    if roadmap_match is None:
        updated = original.rstrip() + "\n\n[roadmap]\nlanes = []\ncandidates = [\n" + ",\n".join(rows) + "\n]\n"
    else:
        roadmap_body = original[roadmap_match.end() :]
        empty_inline_candidates_match = re.search(r"(?m)^candidates\s*=\s*\[\s*\]\s*$", roadmap_body)
        candidates_match = re.search(r"(?ms)^candidates\s*=\s*\[(.*?)^\]", roadmap_body)
        if empty_inline_candidates_match is not None:
            block_start = roadmap_match.end() + empty_inline_candidates_match.start()
            block_end = roadmap_match.end() + empty_inline_candidates_match.end()
            replacement = "candidates = [\n" + ",\n".join(rows) + "\n]"
            updated = original[:block_start] + replacement + original[block_end:]
        elif candidates_match is None:
            insert_at = roadmap_match.end()
            has_lanes = bool(re.search(r"(?m)^lanes\s*=", roadmap_body))
            prefix = "\ncandidates = [\n" if has_lanes else "\nlanes = []\ncandidates = [\n"
            updated = original[:insert_at] + prefix + ",\n".join(rows) + "\n]\n" + original[insert_at:]
        else:
            block_start = roadmap_match.end() + candidates_match.start()
            block_end = roadmap_match.end() + candidates_match.end()
            block = original[block_start:block_end]
            has_existing = bool(re.search(r"\{", block))
            prefix = block[:-1].rstrip()
            if prefix.endswith(","):
                prefix = prefix[:-1].rstrip()
            separator = ",\n" if has_existing else "\n"
            replacement = prefix + separator + ",\n".join(rows) + "\n]"
            updated = original[:block_start] + replacement + original[block_end:]
    try:
        tomllib.loads(updated)
    except tomllib.TOMLDecodeError as exc:
        return {
            "status": "blocked",
            "path": relative_path,
            "reason": "candidate append would make planning state invalid",
            "parser_error": str(exc),
            "error_location": {"line": getattr(exc, "lineno", None), "column": getattr(exc, "colno", None)},
            "recovery": "Inspect the reported TOML location, then ensure [roadmap] has one candidates array before rerunning.",
            "applied_count": 0,
            "candidate_ids": [candidate["id"] for candidate in candidates],
        }
    if not dry_run:
        state_path.write_text(updated, encoding="utf-8")
    return {
        "status": "dry-run" if dry_run else "applied",
        "path": relative_path,
        "applied_count": len(candidates),
        "candidate_ids": [candidate["id"] for candidate in candidates],
        "proof_after": "uv run agentic-workspace summary --target . --format json",
    }


def _candidate_refs(candidate: dict[str, Any]) -> set[str]:
    refs: set[str] = set()
    for field in ("refs", "issues"):
        raw_value = candidate.get(field, "")
        if isinstance(raw_value, list):
            raw_text = " ".join(str(item) for item in raw_value)
        else:
            raw_text = str(raw_value)
        refs.update(f"#{match}" for match in re.findall(r"#(\d+)\b", raw_text))
    return refs


def _candidate_has_local_continuation(candidate: dict[str, Any]) -> bool:
    text = " ".join(str(candidate.get(field, "")) for field in ("reason", "outcome", "promotion_signal", "suggested_first_slice")).lower()
    return any(
        marker in text
        for marker in (
            "local continuation",
            "package-owned work remains open",
            "remains open locally",
            "keep open locally",
            "local work remains",
        )
    )


def _stale_planning_candidate_reconciliation(
    *, target_root: Path, items: list[dict[str, Any]], apply: bool, dry_run: bool
) -> dict[str, Any]:
    state_path = target_root / ".agentic-workspace" / "planning" / "state.toml"
    relative_path = ".agentic-workspace/planning/state.toml"
    closed_refs = {str(item.get("id", "")).strip() for item in items if str(item.get("status", "")).lower() == "closed"}
    open_refs = {str(item.get("id", "")).strip() for item in items if str(item.get("status", "")).lower() == "open"}
    if not state_path.exists() or not closed_refs:
        return {"status": "no-stale-candidates", "path": relative_path, "stale_count": 0, "stale_candidates": [], "applied_count": 0}
    try:
        state = tomllib.loads(state_path.read_text(encoding="utf-8"))
    except (OSError, tomllib.TOMLDecodeError) as exc:
        return {
            "status": "blocked",
            "path": relative_path,
            "reason": f"planning state is unreadable: {exc}",
            "stale_count": 0,
            "stale_candidates": [],
            "applied_count": 0,
        }
    roadmap = state.get("roadmap", {}) if isinstance(state, dict) else {}
    raw_candidates = roadmap.get("candidates", []) if isinstance(roadmap, dict) else []
    stale: list[dict[str, Any]] = []
    for candidate in raw_candidates if isinstance(raw_candidates, list) else []:
        if not isinstance(candidate, dict):
            continue
        if str(candidate.get("status", "")).strip().lower() != "next":
            continue
        refs = _candidate_refs(candidate)
        if not refs or refs.intersection(open_refs) or not refs.issubset(closed_refs):
            continue
        if _candidate_has_local_continuation(candidate):
            continue
        stale.append(
            {
                "id": str(candidate.get("id", "")),
                "refs": sorted(refs),
                "title": str(candidate.get("title", "")),
                "reconcile_command": "uv run agentic-workspace external-intent refresh-github --target . --state closed --storage cache --apply-planning-candidates --format json",
            }
        )
    if not stale:
        return {"status": "no-stale-candidates", "path": relative_path, "stale_count": 0, "stale_candidates": [], "applied_count": 0}
    if not apply:
        return {
            "status": "stale-candidates-found",
            "path": relative_path,
            "stale_count": len(stale),
            "stale_candidates": stale,
            "applied_count": 0,
        }
    if dry_run:
        return {"status": "dry-run", "path": relative_path, "stale_count": len(stale), "stale_candidates": stale, "applied_count": 0}

    stale_ids = {item["id"] for item in stale}
    text = state_path.read_text(encoding="utf-8")
    filtered_lines: list[str] = []
    removed = 0
    for line in text.splitlines():
        candidate_match = re.search(r'\{\s*id\s*=\s*"([^"]+)"', line)
        if candidate_match and candidate_match.group(1) in stale_ids:
            removed += 1
            continue
        filtered_lines.append(line)
    updated = "\n".join(filtered_lines).rstrip() + "\n"
    try:
        tomllib.loads(updated)
    except tomllib.TOMLDecodeError as exc:
        return {
            "status": "blocked",
            "path": relative_path,
            "reason": f"stale-candidate removal would make planning state invalid: {exc}",
            "stale_count": len(stale),
            "stale_candidates": stale,
            "applied_count": 0,
        }
    state_path.write_text(updated, encoding="utf-8")
    return {"status": "applied", "path": relative_path, "stale_count": len(stale), "stale_candidates": stale, "applied_count": removed}


def _load_existing_external_intent_evidence(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {"kind": "planning-external-intent-evidence/v1", "items": []}
    try:
        payload = json.loads(path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError) as exc:
        raise WorkspaceUsageError(f"Cannot refresh invalid external intent evidence at {path.as_posix()}: {exc}") from exc
    if not isinstance(payload, dict) or payload.get("kind") != "planning-external-intent-evidence/v1":
        raise WorkspaceUsageError(f"{path.as_posix()} must contain kind planning-external-intent-evidence/v1.")
    schema_findings = _external_intent_evidence_schema_findings(target_root=_workspace_root_for_evidence_path(path), payload=payload)
    if schema_findings:
        raise WorkspaceUsageError(f"Cannot refresh invalid external intent evidence at {path.as_posix()}: " + "; ".join(schema_findings))
    return payload


def _workspace_root_for_evidence_path(path: Path) -> Path:
    for parent in path.parents:
        if parent.name == ".agentic-workspace":
            return parent.parent
    return path.parent


def _external_intent_evidence_schema_findings(*, target_root: Path, payload: object) -> list[str]:
    if not isinstance(payload, dict):
        return ["external intent evidence must be a JSON object"]
    evidence_payload = cast(dict[str, Any], payload)
    schema_path = target_root / ".agentic-workspace" / "planning" / "schemas" / "planning-external-intent-evidence.schema.json"
    findings = _external_intent_evidence_consistency_findings(evidence_payload)
    if not schema_path.exists():
        return findings
    try:
        from jsonschema import Draft202012Validator
    except ImportError:
        return findings
    try:
        schema = json.loads(schema_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as exc:
        return [f"schema is missing or invalid JSON: {exc}", *findings]
    errors = sorted(Draft202012Validator(schema).iter_errors(payload), key=lambda error: list(error.path))
    for error in errors:
        location = ".".join((str(part) for part in error.path)) or "<root>"
        findings.append(f"{location}: {error.message}")
    return findings


def _external_intent_evidence_consistency_findings(payload: dict[str, Any]) -> list[str]:
    metadata = payload.get("refresh_metadata", {})
    if not isinstance(metadata, dict):
        return []
    items = [item for item in _list_payload(payload.get("items")) if isinstance(item, dict)]
    expected_counts = {
        "item_count": len(items),
        "open_count": sum((1 for item in items if str(item.get("status", "")).strip().lower() == "open")),
        "closed_count": sum((1 for item in items if str(item.get("status", "")).strip().lower() == "closed")),
    }
    findings: list[str] = []
    for field, expected in expected_counts.items():
        if field in metadata and metadata.get(field) != expected:
            findings.append(f"refresh_metadata.{field} must equal {expected} from items, got {metadata.get(field)!r}")
    return findings


def _parse_external_intent_timestamp(value: object) -> datetime | None:
    if not isinstance(value, str) or not value.strip():
        return None
    raw_value = value.strip()
    if raw_value.endswith("Z"):
        raw_value = raw_value[:-1] + "+00:00"
    try:
        parsed = datetime.fromisoformat(raw_value)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _checked_in_planning_issue_refs(target_root: Path) -> set[str]:
    planning_root = target_root / ".agentic-workspace" / "planning"
    if not planning_root.exists():
        return set()
    refs: set[str] = set()
    ref_patterns = (re.compile("(?<![\\w/-])#(\\d+)\\b"), re.compile("/issues/(\\d+)\\b"))
    for path in planning_root.rglob("*"):
        if not path.is_file() or path.suffix.lower() not in {".json", ".toml", ".md"}:
            continue
        try:
            text = path.read_text(encoding="utf-8-sig")
        except UnicodeDecodeError:
            continue
        for pattern in ref_patterns:
            refs.update((f"#{match}" for match in pattern.findall(text)))
    return refs


def _compact_external_intent_cache_items(
    *, items: list[dict[str, Any]], target_root: Path, refreshed_at: str
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    refreshed_at_datetime = _parse_external_intent_timestamp(refreshed_at) or datetime.now(timezone.utc).replace(microsecond=0)
    cutoff = refreshed_at_datetime - timedelta(days=EXTERNAL_INTENT_CACHE_CLOSED_RETENTION_DAYS)
    referenced_ids = _checked_in_planning_issue_refs(target_root)
    compacted: list[dict[str, Any]] = []
    retained_recent_closed = 0
    retained_referenced_closed = 0
    dropped_closed = 0
    for item in items:
        if str(item.get("status", "")).strip().lower() != "closed":
            compacted.append(item)
            continue
        item_id = str(item.get("id", "")).strip()
        closed_at = _parse_external_intent_timestamp(item.get("closed_at"))
        updated_at = _parse_external_intent_timestamp(item.get("updated_at"))
        recency_timestamp = closed_at or updated_at
        is_recent = recency_timestamp is None or recency_timestamp >= cutoff
        is_referenced = item_id in referenced_ids
        if is_recent or is_referenced:
            compacted.append(item)
            if is_recent:
                retained_recent_closed += 1
            if is_referenced:
                retained_referenced_closed += 1
        else:
            dropped_closed += 1
    return (
        compacted,
        {
            "enabled": True,
            "storage": "cache",
            "closed_retention_days": EXTERNAL_INTENT_CACHE_CLOSED_RETENTION_DAYS,
            "cutoff": cutoff.replace(microsecond=0).isoformat(),
            "retained_item_count": len(compacted),
            "dropped_closed_count": dropped_closed,
            "retained_recent_closed_count": retained_recent_closed,
            "retained_referenced_closed_count": retained_referenced_closed,
            "referenced_issue_count": len(referenced_ids),
        },
    )


def _refresh_github_external_intent_evidence(
    *,
    target_root: Path,
    repo: str | None,
    limit: int | None,
    state: str | None,
    storage: str,
    dry_run: bool,
    apply_planning_candidates: bool = False,
    issue_refs: list[str] | None = None,
) -> dict[str, Any]:
    evidence_path, evidence_relative_path, storage_class = _external_intent_evidence_write_location(target_root, storage)
    previous_payload = _load_existing_external_intent_evidence(evidence_path)
    normalized_issue_refs = _normalize_external_intent_issue_refs(issue_refs)
    resolved_state = str(state).strip() if state is not None else ""
    state_source = "explicit" if resolved_state else "default"
    if not resolved_state:
        resolved_state = "all"
        state_source = "product_default"
    if resolved_state not in {"open", "closed", "all"}:
        raise WorkspaceUsageError("--state must be one of: open, closed, all.")
    resolved_limit = limit
    limit_source = "explicit" if resolved_limit is not None else "default"
    if resolved_limit is None:
        resolved_limit = 1000
        limit_source = "product_default"
    if resolved_limit <= 0:
        raise WorkspaceUsageError("--limit must be greater than 0.")
    resolved_repo = _resolve_github_repo_for_external_intent(target_root=target_root, repo=repo)
    fetch_mode = "issue-view" if normalized_issue_refs else "issue-list"
    if normalized_issue_refs:
        fetched_items = _fetch_github_external_intent_issue_items(
            target_root=target_root,
            repo=resolved_repo,
            issue_refs=normalized_issue_refs,
        )
        previous_items_for_merge = [item for item in _list_payload(previous_payload.get("items")) if isinstance(item, dict)]
        by_id = {str(item.get("id", "")).strip(): item for item in previous_items_for_merge if str(item.get("id", "")).strip()}
        for item in fetched_items:
            by_id[str(item.get("id", "")).strip()] = item
        items = list(by_id.values())
    else:
        raw_issues = _run_gh_json(
            [
                "issue",
                "list",
                "--repo",
                resolved_repo,
                "--state",
                resolved_state,
                "--limit",
                str(resolved_limit),
                "--json",
                "number,title,state,url,labels,createdAt,updatedAt,closedAt,body,comments",
            ],
            cwd=target_root,
        )
        if not isinstance(raw_issues, list):
            raise WorkspaceUsageError("GitHub issue list did not return a JSON list.")
        fetched_items = [
            item
            for item in (
                _github_issue_to_external_intent_item(issue=issue, repo=resolved_repo) for issue in raw_issues if isinstance(issue, dict)
            )
            if item is not None
        ]
        items = fetched_items
    pull_requests = _github_current_pull_request_evidence(target_root=target_root, repo=resolved_repo)
    items.extend(
        {
            "system": "github",
            "id": f"PR #{pr['number']}",
            "title": pr["title"],
            "status": pr["state"],
            "kind": "pull-request",
            "parent_id": "",
            "reopens": [],
            "planning_residue_expected": "optional",
        }
        for pr in pull_requests
    )
    items.sort(key=lambda item: (str(item.get("kind", "")), int(re.sub(r"\D", "", str(item["id"])) or "0")))
    previous_count = len([item for item in _list_payload(previous_payload.get("items")) if isinstance(item, dict)])
    refreshed_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat()
    fetched_item_count = len(items)
    fetched_open_count = sum((1 for item in items if item["status"] == "open"))
    fetched_closed_count = sum((1 for item in items if item["status"] == "closed"))
    cache_compaction: dict[str, Any] | None = None
    if storage_class == "cache":
        items, cache_compaction = _compact_external_intent_cache_items(items=items, target_root=target_root, refreshed_at=refreshed_at)
    refresh_metadata: dict[str, Any] = {
        "adapter": "github-gh-cli",
        "repository": resolved_repo,
        "refreshed_at": refreshed_at,
        "item_count": len(items),
        "open_count": sum((1 for item in items if item["status"] == "open")),
        "closed_count": sum((1 for item in items if item["status"] == "closed")),
        "fetched_item_count": fetched_item_count,
        "fetched_open_count": fetched_open_count,
        "fetched_closed_count": fetched_closed_count,
        "limit": resolved_limit,
        "state": resolved_state,
        "state_source": state_source,
        "limit_source": limit_source,
        "issue_refs": normalized_issue_refs,
        "fetch_mode": fetch_mode,
        "command": (
            "; ".join(
                f"gh issue view {ref.lstrip('#')} --json number,title,state,url,labels,createdAt,updatedAt,closedAt,body,comments"
                for ref in normalized_issue_refs
            )
            if normalized_issue_refs
            else f"gh issue list --state {resolved_state} --json number,title,state,url,labels,createdAt,updatedAt,closedAt,body,comments"
        ),
    }
    next_payload: dict[str, Any] = {
        "kind": "planning-external-intent-evidence/v1",
        "systems": ["github"],
        "refreshed_at": refreshed_at,
        "refresh_metadata": refresh_metadata,
        "items": items,
    }
    previous_items = [item for item in _list_payload(previous_payload.get("items")) if isinstance(item, dict)]
    if previous_items:
        next_payload["previous_items"] = previous_items
    if cache_compaction is not None:
        next_payload["refresh_metadata"]["cache_compaction"] = cache_compaction
    issue_items = [item for item in items if item.get("kind") != "pull-request"]
    planning_candidate_suggestions = _planning_candidate_suggestions_from_external_items(target_root=target_root, items=issue_items)
    planning_candidate_grouping = _external_issue_grouping_hints(
        items=issue_items,
        candidates=[
            candidate for candidate in _list_payload(planning_candidate_suggestions.get("candidates")) if isinstance(candidate, dict)
        ],
    )
    stale_planning_candidate_reconciliation = _stale_planning_candidate_reconciliation(
        target_root=target_root,
        items=items,
        apply=apply_planning_candidates,
        dry_run=dry_run,
    )
    if not dry_run:
        evidence_path.parent.mkdir(parents=True, exist_ok=True)
        evidence_path.write_text(json.dumps(next_payload, indent=2, ensure_ascii=True) + "\n", encoding="utf-8")
    planning_candidate_apply = (
        _append_planning_candidate_rows(
            target_root=target_root,
            candidates=planning_candidate_suggestions["candidates"],
            dry_run=dry_run,
        )
        if apply_planning_candidates
        else {
            "status": "not-requested",
            "path": ".agentic-workspace/planning/state.toml",
            "applied_count": 0,
            "candidate_ids": [],
        }
    )
    return {
        "kind": "external-intent-refresh/v1",
        "provider": "github",
        "adapter": "github-gh-cli",
        "target": target_root.as_posix(),
        "storage": storage_class,
        "path": evidence_relative_path,
        "dry_run": dry_run,
        "written": not dry_run,
        "repository": resolved_repo,
        "refreshed_at": refreshed_at,
        "item_count": len(items),
        "open_count": next_payload["refresh_metadata"]["open_count"],
        "closed_count": next_payload["refresh_metadata"]["closed_count"],
        "fetched_item_count": fetched_item_count,
        "fetched_open_count": fetched_open_count,
        "fetched_closed_count": fetched_closed_count,
        "previous_item_count": previous_count,
        "cache_compaction": cache_compaction,
        "state": resolved_state,
        "limit": resolved_limit,
        "state_source": state_source,
        "limit_source": limit_source,
        "issue_refs": normalized_issue_refs,
        "fetch_mode": fetch_mode,
        "planning_candidate_suggestions": planning_candidate_suggestions,
        "planning_candidate_grouping": planning_candidate_grouping,
        "planning_candidate_apply": planning_candidate_apply,
        "stale_planning_candidate_reconciliation": stale_planning_candidate_reconciliation,
        "provider_rule": "Core planning consumes only provider-agnostic external intent evidence; GitHub access stays in this optional adapter.",
    }


def _tiny_preflight_payload(payload: dict[str, Any], *, config: WorkspaceConfig) -> dict[str, Any]:
    active_state = payload.get("active_planning_state", {})
    todo = active_state.get("todo", {}) if isinstance(active_state, dict) else {}
    execplans = active_state.get("execplans", {}) if isinstance(active_state, dict) else {}
    planning_record = active_state.get("planning_record", {}) if isinstance(active_state, dict) else {}
    active_execplans = execplans.get("active_execplans", []) if isinstance(execplans, dict) else []
    branch_posture = payload.get("branch_workflow_posture", {})
    if isinstance(branch_posture, dict):
        branch_posture = {
            key: branch_posture.get(key)
            for key in (
                "status",
                "current_branch",
                "default_branch",
                "risk",
                "recommended_next_action",
                "upstream_divergence",
                "shared_state_mutation_risk",
            )
            if key in branch_posture
        }
    local_memory = payload.get("local_memory", {})
    if isinstance(local_memory, dict):
        local_memory = {key: local_memory.get(key) for key in ("status", "path", "rule") if key in local_memory}
    closeout = payload.get("closeout_obligations", {})
    if isinstance(closeout, dict):
        closeout = {key: closeout.get(key) for key in ("status", "activation_rule", "detail_command") if key in closeout}
    posture = payload.get("operating_posture", {})
    if isinstance(posture, dict):
        posture = {key: posture.get(key) for key in ("status", "required_behavior_summary", "detail_command") if key in posture}
    intent = payload.get("durable_intent", {})
    if isinstance(intent, dict):
        subsystem = intent.get("subsystem_intent", {})
        intent = {
            "status": intent.get("status", "unknown"),
            "subsystem_intent": {
                "status": subsystem.get("status", "unknown") if isinstance(subsystem, dict) else "unknown",
                "matched_count": subsystem.get("matched_count", 0) if isinstance(subsystem, dict) else 0,
            },
            "inspect": intent.get("inspect", ""),
        }
    return {
        "kind": payload.get("kind", "preflight-response/v1"),
        "mode": "tiny-takeover-router",
        "target": payload.get("target", ""),
        "issued_at": payload.get("issued_at", ""),
        "preflight_token": payload.get("preflight_token", ""),
        "timestamp_hint": payload.get("timestamp_hint", ""),
        "branch_workflow_posture": branch_posture,
        "local_memory": local_memory,
        "workflow_obligations": {
            "status": payload.get("workflow_obligations", {}).get("status", "unknown")
            if isinstance(payload.get("workflow_obligations"), dict)
            else "unknown",
            "match_count": payload.get("workflow_obligations", {}).get("match_count", 0)
            if isinstance(payload.get("workflow_obligations"), dict)
            else 0,
            "detail_command": "agentic-workspace preflight --verbose --format json",
        },
        "closeout_obligations": closeout,
        "operating_posture": posture,
        "durable_intent": intent,
        "active_state_summary": {
            "todo_active_count": todo.get("active_count", 0) if isinstance(todo, dict) else 0,
            "active_execplan_count": len(active_execplans) if isinstance(active_execplans, list) else 0,
            "planning_status": planning_record.get("status", "unavailable") if isinstance(planning_record, dict) else "unavailable",
        },
        "detail_commands": {
            "full_takeover": f"{config.cli_invoke} preflight --target . --verbose --format json",
            "active_state": f"{config.cli_invoke} preflight --target . --active-only --verbose --format json",
            "startup": f'{config.cli_invoke} start --target . --task "<task>" --format json',
            "config": f"{config.cli_invoke} config --target . --format json",
            "summary": f"{config.cli_invoke} summary --target . --format json",
        },
    }


def _tiny_preflight_payload_fast(
    *,
    target_root: Path,
    config: WorkspaceConfig,
    issued_at: str,
    preflight_token: str,
    task_text: str | None,
    changed_paths: list[str] | None,
) -> dict[str, Any]:
    active_summary = _fast_planning_active_summary(target_root=target_root)
    active_execplan_count = 1 if active_summary.get("active_execplan") else 0
    durable_intent: dict[str, Any] = {
        "status": "not-evaluated",
        "subsystem_intent": {"status": "not-evaluated", "matched_count": 0},
        "inspect": f'{config.cli_invoke} start --target . --task "<task>" --format json',
    }
    if task_text or changed_paths:
        durable_intent = _intent_decision_projection(
            target_root=target_root, config=config, task_text=task_text, changed_paths=changed_paths, compact=True
        )
        subsystem = durable_intent.get("subsystem_intent", {})
        durable_intent = {
            "status": durable_intent.get("status", "unknown"),
            "subsystem_intent": {
                "status": subsystem.get("status", "unknown") if isinstance(subsystem, dict) else "unknown",
                "matched_count": subsystem.get("matched_count", 0) if isinstance(subsystem, dict) else 0,
            },
            "inspect": durable_intent.get("inspect", ""),
        }
    detail_commands = {
        "full_takeover": f"{config.cli_invoke} preflight --target . --verbose --format json",
        "active_state": f"{config.cli_invoke} preflight --target . --active-only --verbose --format json",
        "startup": f'{config.cli_invoke} start --target . --task "<task>" --format json',
        "config": f"{config.cli_invoke} config --target . --format json",
        "summary": f"{config.cli_invoke} summary --target . --format json",
    }
    next_action = {
        "action": "recover-orientation",
        "summary": "Use the compact recovery routes below; request full takeover context only if active state or obligations are unclear.",
        "command": f'{config.cli_invoke} start --target . --task "<task>" --format json',
        "run": f'{config.cli_invoke} start --target . --task "<task>" --format json',
        "risk": "read-only recovery routing",
        "required_inputs": ["current task"],
        "next_proof": "select proof after changed paths are known",
    }
    return {
        "kind": "preflight-response/v1",
        "mode": "tiny-takeover-router",
        "target": target_root.as_posix(),
        "issued_at": issued_at,
        "preflight_token": preflight_token,
        "next": next_action,
        "context": {
            "timestamp_hint": "Use this compact answer to recover orientation; request full takeover context only when needed.",
            "branch_workflow_posture": {
                key: value
                for key, value in _branch_workflow_posture_payload(target_root=target_root).items()
                if key
                in {
                    "status",
                    "current_branch",
                    "default_branch",
                    "risk",
                    "recommended_next_action",
                    "upstream_divergence",
                    "shared_state_mutation_risk",
                }
            },
            "local_memory": {
                key: value for key, value in _local_memory_payload(config=config).items() if key in {"status", "path", "rule"}
            },
            "workflow_obligations": {
                "status": "not-evaluated",
                "match_count": 0,
                "detail_command": f"{config.cli_invoke} preflight --verbose --format json",
            },
            "closeout_obligations": {
                "status": "present",
                "activation_rule": "closeout obligations apply after implementation or lane closeout",
                "detail_command": f"{config.cli_invoke} report --target ./repo --section closeout_trust --format json",
            },
            "operating_posture": _operating_posture_payload(config=config, surface="preflight", compact=True),
            "durable_intent": durable_intent,
            "active_state_summary": {
                "todo_active_count": int(active_summary.get("todo_active_count", 0) or 0),
                "active_execplan_count": active_execplan_count,
                "planning_status": active_summary.get("planning_status", "unavailable"),
            },
        },
        "drill_down": {
            "ordinary_profile": "primary=next;context=recovery state;detail=verbose or selectors",
            "detail_commands": detail_commands,
            "available_selectors": [
                "next",
                "context.active_state_summary",
                "context.branch_workflow_posture",
                "context.local_memory",
                "context.workflow_obligations",
                "context.closeout_obligations",
                "context.operating_posture",
                "context.durable_intent",
            ],
        },
    }


def _run_preflight_command(
    *,
    target_root: Path,
    active_only: bool = False,
    task_text: str | None = None,
    changed_paths: list[str] | None = None,
    profile: str = "tiny",
) -> dict[str, Any]:
    """Get compact takeover-safe context: startup + config + active state.

    If active_only=True, returns only active planning state without startup/config.
    This supports two use cases:
    1. First-contact preflight: bundle startup guidance + config + active state
    2. Active state polling: query current state without startup overhead
    """
    config = _load_workspace_config(target_root=target_root)
    issued_epoch = int(time.time())
    issued_at = datetime.fromtimestamp(issued_epoch, tz=timezone.utc).replace(microsecond=0).isoformat()
    preflight_token = _build_preflight_token(issued_at_epoch=issued_epoch)
    if profile == "tiny" and (not active_only):
        return _tiny_preflight_payload_fast(
            target_root=target_root,
            config=config,
            issued_at=issued_at,
            preflight_token=preflight_token,
            task_text=task_text,
            changed_paths=changed_paths,
        )
    active_state = _preflight_active_state_payload(target_root=target_root)
    planning_record = active_state.get("planning_record", {"status": "unavailable"})
    branch_workflow_posture = _branch_workflow_posture_payload(target_root=target_root)
    local_memory = _local_memory_payload(config=config)
    active_count = int(active_state.get("todo", {}).get("active_count", 0) or 0)
    obligation_record = (
        planning_record if isinstance(planning_record, dict) and (planning_record.get("status") == "present" or active_count > 0) else None
    )
    workflow_obligations = _workflow_obligations_report_payload(
        config=config, active_planning_record=obligation_record, task_text=task_text, changed_paths=changed_paths
    )
    closeout_obligations = _closeout_workflow_obligations_payload(workflow_obligations)
    durable_intent = _intent_decision_projection(target_root=target_root, config=config, compact=True)
    execution_posture = _execution_posture_payload(
        config=config,
        changed_paths=_normalize_changed_paths(changed_paths or []),
        task_text=task_text,
        target_root=target_root,
    )
    planning_safety_gate = _planning_safety_gate_payload(
        target_root=target_root,
        config=config,
        changed_paths=_normalize_changed_paths(changed_paths or []),
        task_text=task_text,
        execution_posture=execution_posture,
    )
    active_parent_record = _active_planning_record_for_report_section(target_root=target_root)
    active_parent_boundary = _completion_boundary_payload(active_planning_record=active_parent_record)
    parent_intent_status = _parent_intent_status_payload(
        active_planning_record=active_parent_record,
        intent_check={},
        completion_boundary=active_parent_boundary,
    )
    applicable_intent_status = _applicable_intent_status_payload(active_planning_record=active_parent_record)
    if active_only:
        active_payload = {
            "kind": "preflight-response/v1",
            "mode": "active-state-only",
            "target": target_root.as_posix(),
            "issued_at": issued_at,
            "preflight_token": preflight_token,
            "planning_revision": planning_safety_gate.get("planning_revision", {}),
            "active_plan_reliance": planning_safety_gate.get("active_plan_reliance", {}),
            "timestamp_hint": "Run this periodically to poll current active state without startup overhead.",
            "branch_workflow_posture": branch_workflow_posture,
            "local_memory": local_memory,
            "memory_consult": _memory_consult_payload(target_root=target_root, compact=True, cli_invoke=config.cli_invoke),
            "workflow_obligations": workflow_obligations,
            "closeout_obligations": closeout_obligations,
            "operating_posture": _operating_posture_payload(config=config, surface="preflight", compact=True),
            "durable_intent": durable_intent,
            "skill_routing": _startup_skill_routing_payload(target_root=target_root, cli_invoke=config.cli_invoke),
            "active_planning_state": active_state,
            "planning_record": planning_record if isinstance(planning_record, dict) else {"status": "unavailable"},
            "parent_intent_status": parent_intent_status,
            "applicable_intent_status": applicable_intent_status,
        }
        return active_payload
    startup_payload = _defaults_payload().get("startup", {})
    tiny_safe_model = startup_payload.get("tiny_safe_model", {})
    first_compact_queries = [
        _command_with_cli_invoke(command=str(query), cli_invoke=config.cli_invoke)
        for query in tiny_safe_model.get("first_compact_queries", [])
    ]
    escalation_rules = _guidance_with_cli_invoke(value=startup_payload.get("escalation_cues", [])[:2], cli_invoke=config.cli_invoke)
    skill_routing = _guidance_with_cli_invoke(
        value=_startup_skill_routing_payload(
            cli_invoke=config.cli_invoke, enabled_advanced_features=config.advanced_features, target_root=target_root
        ),
        cli_invoke=config.cli_invoke,
    )
    planning_record_present = isinstance(planning_record, dict) and (
        planning_record.get("status") == "present"
        or active_state.get("todo", {}).get("active_count", 0)
        or active_state.get("execplans", {}).get("active_execplans")
    )
    preflight_primary_command = (
        _command_with_cli_invoke(command="agentic-workspace summary --format json", cli_invoke=config.cli_invoke)
        if planning_record_present
        else None
    )
    config_payload = _config_payload(config=config)
    startup_guidance = {
        "kind": "preflight-response/v1",
        "mode": "full-takeover-context",
        "target": target_root.as_posix(),
        "issued_at": issued_at,
        "preflight_token": preflight_token,
        "planning_revision": planning_safety_gate.get("planning_revision", {}),
        "active_plan_reliance": planning_safety_gate.get("active_plan_reliance", {}),
        "timestamp_hint": "Use this to bootstrap into an interrupted or takeover recovery.",
        "startup_guidance": {
            "context_router": _context_router_family_payload(cli_invoke=config.cli_invoke, compact=True),
            "entrypoint": startup_payload.get("default_canonical_agent_instructions_file", "AGENTS.md"),
            "entry_query": _command_with_cli_invoke(
                command=str(tiny_safe_model.get("entry_query", 'agentic-workspace start --task "<task>" --format json')),
                cli_invoke=config.cli_invoke,
            ),
            "primary_next_action": {
                "action": "continue-active-planning-record" if planning_record_present else "use-preflight-context",
                "summary": str(planning_record.get("next_action", "") or "Continue from the active planning record.")
                if planning_record_present
                else "Use this preflight answer as takeover context; run more commands only when a listed route is needed.",
                "command": preflight_primary_command,
                "run": preflight_primary_command,
                "risk": "read-only routing",
                "required_inputs": ["target repo", "current task"],
                "next_proof": "select proof after changed paths are known",
            },
            "first_compact_queries": first_compact_queries,
            "work_intent_gate": _guidance_with_cli_invoke(value=startup_payload.get("work_intent_gate", {}), cli_invoke=config.cli_invoke),
            "escalation_rules": escalation_rules,
            "skill_routing": skill_routing,
        },
        "resolved_config": {
            "workspace_config": config_payload.get("workspace", {}),
            "config_enforcement": config_payload.get("config_enforcement", {}),
            "optimization_bias": config_payload.get("optimization_bias"),
            "agent_instructions_file": config_payload.get("workspace", {}).get("agent_instructions_file", "AGENTS.md"),
        },
        "branch_workflow_posture": branch_workflow_posture,
        "local_memory": local_memory,
        "memory_consult": _memory_consult_payload(target_root=target_root, compact=True, cli_invoke=config.cli_invoke),
        "workflow_obligations": workflow_obligations,
        "closeout_obligations": closeout_obligations,
        "operating_posture": _operating_posture_payload(config=config, surface="preflight"),
        "durable_intent": durable_intent,
        "active_planning_state": active_state,
        "parent_intent_status": parent_intent_status,
        "applicable_intent_status": applicable_intent_status,
    }
    vague_orientation = _vague_outcome_orientation_payload(task_text=task_text, cli_invoke=config.cli_invoke)
    if vague_orientation["applies_to_current_task"]:
        startup_guidance["startup_guidance"]["vague_outcome_orientation"] = vague_orientation
    if profile == "tiny":
        return _tiny_preflight_payload(startup_guidance, config=config)
    return startup_guidance


def _branch_workflow_posture_payload(*, target_root: Path) -> dict[str, Any]:
    rule = "Staying on the current branch is separate from being safe to implement, commit, or push there; surface default-branch posture before broad implementation or push."
    git_dir = _git_metadata_dir(target_root=target_root)
    if git_dir is None:
        return {
            "status": "unavailable",
            "reason": "target is not a git worktree or git metadata is unavailable",
            "advisory_only": True,
            "rule": rule,
        }
    current_branch = _read_symbolic_ref(git_dir=git_dir, ref_name="HEAD", prefix="refs/heads/")
    default_branch = _read_symbolic_ref(git_dir=git_dir, ref_name="refs/remotes/origin/HEAD", prefix="refs/remotes/origin/")
    sources = [".git/HEAD"]
    if default_branch:
        sources.append(".git/refs/remotes/origin/HEAD")
    shared_state_risk = _workspace_shared_state_mutation_risk(target_root=target_root)
    upstream_divergence = _git_upstream_divergence(target_root=target_root)
    if not current_branch:
        return {
            "status": "detached-or-unknown",
            "current_branch": "",
            "default_branch": default_branch or "",
            "on_default_branch": False,
            "risk": "unknown",
            "advisory_only": True,
            "rule": rule,
            "sources": sources,
            "upstream_divergence": upstream_divergence,
            "shared_state_mutation_risk": shared_state_risk,
            "recommended_next_action": "Inspect git branch state before implementation, commit, or push.",
        }
    default_branch_known = bool(default_branch)
    on_default_branch = default_branch_known and current_branch == default_branch
    likely_default_name = current_branch in {"main", "master", "trunk"}
    risk = "default-branch-commit-risk" if on_default_branch or (not default_branch_known and likely_default_name) else "normal"
    if shared_state_risk["risk"] == "high":
        recommended_next_action = str(shared_state_risk["recommended_next_action"])
    elif risk == "default-branch-commit-risk":
        recommended_next_action = "Make the default-branch posture explicit before implementation, commit, or push; do not switch branches unless the user decides."
    else:
        recommended_next_action = "Continue normal branch-aware workflow; keep commit and push posture explicit before closeout."
    branch_mutation_policy = {
        "status": "present",
        "advisory_only": True,
        "rule": "Branch switching, cross-branch merging, and pushing from a different branch than startup require explicit user intent.",
        "guarded_actions": [
            "switch-branch",
            "create-branch",
            "merge-from-other-branch",
            "rebase-onto-other-branch",
            "push-different-branch",
        ],
        "current_branch_is_execution_branch": bool(current_branch),
        "requires_user_intent_before": [
            "changing the execution branch",
            "merging another branch into the execution branch",
            "pushing work from a branch other than the execution branch",
        ],
    }
    return {
        "status": "present",
        "current_branch": current_branch,
        "default_branch": default_branch or "",
        "default_branch_known": default_branch_known,
        "on_default_branch": on_default_branch,
        "risk": risk,
        "advisory_only": True,
        "rule": rule,
        "branch_mutation_policy": branch_mutation_policy,
        "upstream_divergence": upstream_divergence,
        "shared_state_mutation_risk": shared_state_risk,
        "sources": sources,
        "recommended_next_action": recommended_next_action,
    }


def _workspace_shared_state_mutation_risk(*, target_root: Path) -> dict[str, Any]:
    changed_paths = _git_status_short_paths(target_root=target_root)
    surfaces = [_workspace_shared_state_surface(path) for path in changed_paths]
    surfaces = [surface for surface in surfaces if surface is not None]
    if not surfaces:
        return {
            "kind": "workspace-shared-state-mutation-risk/v1",
            "status": "clear",
            "risk": "low",
            "changed_surface_count": 0,
            "surfaces": [],
            "recommended_next_action": "No changed Agentic Workspace shared-state surfaces detected.",
            "rule": "Shared-state risk is merge pressure, not a lock or concurrency guarantee.",
        }
    high_classes = {"planning-live-state", "active-planning-execplan", "workspace-policy", "durable-memory-note"}
    risk = "high" if any((surface["class"] in high_classes for surface in surfaces)) else "medium"
    first = surfaces[0]
    return {
        "kind": "workspace-shared-state-mutation-risk/v1",
        "status": "attention",
        "risk": risk,
        "changed_surface_count": len(surfaces),
        "surfaces": surfaces[:12],
        "recommended_next_action": f"Review changed shared workspace surface {first['path']} before closeout or push; confirm it is intentional branch-local state or durable shared knowledge.",
        "rule": "Shared-state risk is merge pressure, not a lock or concurrency guarantee.",
    }


def _workspace_shared_state_surface(path: str) -> dict[str, str] | None:
    normalized = path.replace("\\", "/")
    if normalized == ".agentic-workspace/planning/state.toml":
        return {"path": normalized, "class": "planning-live-state", "why": "selects active or queued future work and is a shared hot file"}
    if normalized.startswith(".agentic-workspace/planning/execplans/") and "/archive/" not in normalized:
        return {
            "path": normalized,
            "class": "active-planning-execplan",
            "why": "active execution contracts can conflict when multiple branches edit the same plan",
        }
    if normalized in {".agentic-workspace/config.toml", ".agentic-workspace/OWNERSHIP.toml"}:
        return {
            "path": normalized,
            "class": "workspace-policy",
            "why": "config and ownership changes are rare but high-impact shared policy edits",
        }
    if normalized == ".agentic-workspace/config.local.toml":
        return {
            "path": normalized,
            "class": "local-only-config",
            "why": "local config should normally remain uncommitted and machine-local",
        }
    if normalized == ".agentic-workspace/config.local.toml.example":
        return {
            "path": normalized,
            "class": "local-config-example",
            "why": "shared examples must remain portable and free of user-specific settings",
        }
    if normalized.startswith(".agentic-workspace/memory/repo/") and normalized.endswith(".md"):
        return {
            "path": normalized,
            "class": "durable-memory-note",
            "why": "durable shared knowledge can conflict when branches update the same note",
        }
    if normalized.startswith(".agentic-workspace/") and (
        normalized.endswith(".toml") or normalized.endswith(".json") or normalized.endswith(".md")
    ):
        return {
            "path": normalized,
            "class": "workspace-surface",
            "why": "checked-in workspace surface participates in ordinary git merge semantics",
        }
    return None


def _git_status_short_paths(*, target_root: Path) -> list[str]:
    if _git_metadata_dir(target_root=target_root) is None:
        return []
    try:
        completed = subprocess.run(
            ["git", "-C", str(target_root), "status", "--short", "--untracked-files=all"],
            capture_output=True,
            text=True,
            encoding="utf-8",
            check=False,
            timeout=10,
        )
    except (OSError, subprocess.SubprocessError):
        return []
    if completed.returncode != 0:
        return []
    paths: list[str] = []
    for line in completed.stdout.splitlines():
        if len(line) < 4:
            continue
        raw_path = line[3:].strip()
        if " -> " in raw_path:
            raw_path = raw_path.split(" -> ", 1)[1].strip()
        normalized = raw_path.replace("\\", "/")
        if normalized:
            paths.append(normalized)
    return paths


def _git_upstream_divergence(*, target_root: Path) -> dict[str, Any]:
    if _git_metadata_dir(target_root=target_root) is None:
        return {"status": "unavailable", "ahead": None, "behind": None}
    try:
        completed = subprocess.run(
            ["git", "-C", str(target_root), "rev-list", "--left-right", "--count", "HEAD...@{upstream}"],
            capture_output=True,
            text=True,
            encoding="utf-8",
            check=False,
            timeout=10,
        )
    except (OSError, subprocess.SubprocessError):
        return {"status": "unknown", "ahead": None, "behind": None}
    if completed.returncode != 0:
        return {"status": "unknown", "ahead": None, "behind": None}
    parts = completed.stdout.strip().split()
    if len(parts) != 2 or not all((part.isdigit() for part in parts)):
        return {"status": "unknown", "ahead": None, "behind": None}
    ahead = int(parts[0])
    behind = int(parts[1])
    return {
        "status": "diverged" if ahead and behind else "ahead" if ahead else "behind" if behind else "in-sync",
        "ahead": ahead,
        "behind": behind,
    }


def _git_metadata_dir(*, target_root: Path) -> Path | None:
    git_path = target_root / ".git"
    if git_path.is_dir():
        return git_path
    if not git_path.is_file():
        return None
    text = git_path.read_text(encoding="utf-8", errors="replace").strip()
    if not text.startswith("gitdir:"):
        return None
    raw_path = text.split(":", 1)[1].strip()
    git_dir = Path(raw_path)
    if not git_dir.is_absolute():
        git_dir = (target_root / git_dir).resolve()
    return git_dir if git_dir.exists() else None


def _read_symbolic_ref(*, git_dir: Path, ref_name: str, prefix: str) -> str:
    ref_path = git_dir / ref_name
    if not ref_path.exists():
        return ""
    text = ref_path.read_text(encoding="utf-8", errors="replace").strip()
    if not text.startswith("ref:"):
        return ""
    ref_target = text.split(":", 1)[1].strip()
    if not ref_target.startswith(prefix):
        return ""
    return ref_target[len(prefix) :].strip()


def _package_boundary_payload(*, target_root: Path) -> dict[str, Any]:
    cwd = Path.cwd().resolve()
    try:
        relative_cwd = cwd.relative_to(target_root)
    except ValueError:
        return {"status": "outside-target", "cwd": cwd.as_posix(), "warning": "Current working directory is outside the target root."}
    parts = relative_cwd.parts
    if len(parts) >= 2 and parts[0] == "packages":
        package_root = Path(parts[0]) / parts[1]
        return {
            "status": "inside-package",
            "cwd": relative_cwd.as_posix() or ".",
            "package_root": package_root.as_posix(),
            "warning": "Read package-local AGENTS.md before editing inside this package boundary.",
        }
    return {"status": "repo-root-or-subdir", "cwd": relative_cwd.as_posix() or ".", "warning": None}


def _authority_marker_for_path(path_text: str, *, agent_instructions_file: str = DEFAULT_AGENT_INSTRUCTIONS_FILE) -> dict[str, Any]:
    normalized = _normalize_changed_paths([path_text])[0] if _normalize_changed_paths([path_text]) else path_text
    if normalized == agent_instructions_file:
        return _authority_marker_payload(marker_id="root-agent-instructions", normalized=normalized)
    if normalized.startswith(".agentic-workspace/planning/"):
        return _authority_marker_payload(marker_id="planning-surface", normalized=normalized)
    if normalized.startswith(".agentic-workspace/memory/"):
        return _authority_marker_payload(marker_id="memory-surface", normalized=normalized)
    if "/bootstrap/" in normalized or normalized.endswith("/bootstrap"):
        return _authority_marker_payload(marker_id="package-bootstrap-payload", normalized=normalized)
    if normalized.startswith("src/agentic_workspace/") or normalized.startswith("packages/"):
        return _authority_marker_payload(marker_id="source", normalized=normalized)
    if normalized.startswith(".agentic-workspace/"):
        return _authority_marker_payload(marker_id="managed-workspace-surface", normalized=normalized)
    return _authority_marker_payload(marker_id="repo-owned", normalized=normalized)


def _authority_marker_payload(*, marker_id: str, normalized: str) -> dict[str, Any]:
    marker = _authority_marker_policy_by_id()[marker_id]
    return {
        "path": normalized,
        "authority": marker["authority"],
        "canonical_source": _authority_marker_canonical_source(marker=marker, normalized=normalized),
        "safe_to_edit": marker["safe_to_edit"],
        "refresh_command": marker["refresh_command"],
    }


def _authority_marker_policy_by_id() -> dict[str, dict[str, Any]]:
    return {marker["id"]: marker for marker in authority_markers_manifest()["markers"]}


def _authority_marker_canonical_source(*, marker: dict[str, Any], normalized: str) -> str:
    canonical_source = marker["canonical_source"]
    kind = canonical_source["kind"]
    if kind == "fixed":
        return str(canonical_source["value"])
    if kind == "path":
        return normalized
    if kind == "package-root-source":
        package_root = "/".join(normalized.split("/")[:2]) if normalized.startswith("packages/") else "package"
        return f"{package_root}/src/"
    raise WorkspaceUsageError(f"Unsupported authority marker canonical source kind: {kind}")


def _boundary_warning_for_path(path_text: str, *, agent_instructions_file: str = DEFAULT_AGENT_INSTRUCTIONS_FILE) -> dict[str, Any]:
    marker = _authority_marker_for_path(path_text, agent_instructions_file=agent_instructions_file)
    normalized = str(marker["path"])
    warning: str | None = None
    if marker["authority"] == "payload":
        warning = (
            "Package bootstrap payload is not live authority; reflect durable behavior in package source and sync payload before closeout."
        )
    elif normalized.startswith(".agentic-workspace/") and marker["authority"] not in {"canonical", "managed"}:
        warning = "Installed workspace surfaces are shared operational state; verify ownership before editing."
    elif normalized.startswith("packages/") and "/src/" in normalized:
        warning = "Package source edits may need matching payload or installed-surface proof before closeout."
    elif marker["authority"] == "generated-adapter":
        warning = "Generated adapter content should be refreshed from its canonical source rather than hand-edited."
    return {"path": normalized, "authority": marker["authority"], "warning": warning, "requires_attention": warning is not None}


def _authority_markers_for_startup(
    *, active_execplan: str | None = None, agent_instructions_file: str = DEFAULT_AGENT_INSTRUCTIONS_FILE
) -> list[dict[str, Any]]:
    paths = [agent_instructions_file, ".agentic-workspace/WORKFLOW.md", ".agentic-workspace/OWNERSHIP.toml"]
    if active_execplan:
        paths.append(active_execplan)
    return [_authority_marker_for_path(path, agent_instructions_file=agent_instructions_file) for path in paths]


def _read_budget_payload(*, profile: str, current_need: str, required_sections: list[str], optional_sections: list[str]) -> dict[str, Any]:
    if profile == "tiny":
        max_detail = "next-action packet only"
    elif profile == "compact":
        max_detail = "current-state packet"
    else:
        max_detail = "full diagnostic packet"
    return {
        "profile": profile,
        "current_need": current_need,
        "max_detail": max_detail,
        "required_sections": required_sections,
        "optional_sections": optional_sections,
        "raw_file_reads": "only after a detail command or active plan points there",
    }


def _adaptive_routing_payload(
    *,
    surface: str,
    profile: str,
    current_need: str,
    why_this_packet: str,
    required_sections: list[str],
    optional_sections: list[str],
    detail_commands: dict[str, str],
    when_to_escalate: list[str],
    not_needed_now: list[str],
) -> dict[str, Any]:
    return {
        "kind": "agentic-workspace/adaptive-routing/v1",
        "surface": surface,
        "current_need": current_need,
        "read_budget": _read_budget_payload(
            profile=profile, current_need=current_need, required_sections=required_sections, optional_sections=optional_sections
        ),
        "why_this_packet": why_this_packet,
        "when_to_escalate": when_to_escalate,
        "not_needed_now": not_needed_now,
        "detail_commands": detail_commands,
        "rule": "Return the smallest packet that supports the next correct action; escalate detail only when a listed condition applies.",
    }


def _tiny_adaptive_routing_payload(
    *,
    surface: str,
    profile: str = "tiny",
    current_need: str,
    why_this_packet: str,
    detail_commands: dict[str, str],
    when_to_escalate: list[str],
    not_needed_now: list[str],
) -> dict[str, Any]:
    return {
        "current_need": current_need,
        "read_budget": {"profile": profile, "raw_file_reads": "only after a detail command points there"},
        "why": why_this_packet,
        "escalate_when": when_to_escalate[:3],
        "not_needed_now": not_needed_now[:3],
        "detail_commands": detail_commands,
    }


def _preferred_cli_effect(preferred_cli: str) -> str:
    try:
        tokens = shlex.split(preferred_cli)
    except ValueError:
        tokens = preferred_cli.split()
    semantic_tokens: list[str] = []
    skip_option_value = False
    for token in tokens:
        if skip_option_value:
            skip_option_value = False
            continue
        if token.startswith("--"):
            if "=" not in token:
                skip_option_value = True
            continue
        semantic_tokens.append(token)
    if any(token in {"proof", "pytest", "test", "lint", "ruff"} for token in semantic_tokens):
        return "validating"
    if any(token in {"promote-to-plan", "new-plan", "archive-plan", "close-item", "delegation-decision"} for token in semantic_tokens):
        return "mutating"
    if any(token in {"report", "summary", "status", "doctor", "start", "preflight", "skills"} for token in semantic_tokens):
        return "reporting"
    return "read-only"


def _read_only_allowance_packet(
    *,
    implementation_allowed: bool,
    completion_claim_allowed: bool,
    gate_result: str,
    required_next_action: str,
) -> dict[str, Any]:
    implementation_state = "allowed" if implementation_allowed else "blocked-until-planning-ownership"
    completion_state = "allowed-after-proof" if completion_claim_allowed else "blocked-until-proof-and-acceptance"
    return {
        "read_only_allowed": True,
        "exploration_allowed": True,
        "allowed_read_only_actions": [
            "inspect files and planning state",
            "review issues, PRs, logs, docs, and command output",
            "run read-only AW commands only when named by next_safe_action, task posture, or drill-down selectors",
            "draft review, triage, evaluation, or implementation recommendations without editing source",
        ],
        "claim_boundary": {
            "implementation": implementation_state,
            "completion_claim": completion_state,
            "gate_result": gate_result,
            "required_before_implementation": [] if implementation_allowed else [required_next_action],
            "rule": (
                "Read-only exploration/review may continue; implementation and completion claims still need gate, proof, and acceptance."
            ),
        },
    }


def _next_safe_action_packet(
    *,
    immediate: dict[str, Any],
    workflow_sufficiency: dict[str, Any] | None,
    skill_routing: dict[str, Any] | None,
    memory_consult: dict[str, Any] | None,
) -> dict[str, Any]:
    action = str(immediate.get("action", "") or "inspect-current-workflow-context")
    command = str(immediate.get("command", "") or "")
    read_first = [str(item) for item in _list_payload(immediate.get("read_first")) if str(item).strip()]
    preferred_cli = command or (read_first[0] if read_first else "")
    proof_hint = str(immediate.get("next_proof", "") or "")
    decision = str((workflow_sufficiency or {}).get("sufficiency_result") or (workflow_sufficiency or {}).get("decision") or "")
    preferred_routes = (skill_routing or {}).get("preferred_routes", [])
    skill = ""
    if action in {"ask-intent-discovery-question", "ask-work-shape-clarification"}:
        skill = "workspace-intent-discovery"
    elif action == "present-lane-shaping-prompt":
        skill = "planning-decompose"
    elif action != "choose-smallest-workflow-shape" and isinstance(preferred_routes, list):
        for route in preferred_routes:
            if isinstance(route, dict) and route.get("skill"):
                skill = str(route.get("skill"))
                break
    if action.startswith(("create", "promote", "checkpoint", "update", "validate-planning", "continue-active-planning")):
        module_slot = "planning"
    elif "closeout" in action:
        module_slot = "planning.closeout"
    elif "proof" in action or "validation" in proof_hint:
        module_slot = "workspace.proof"
    elif "intent-discovery" in action:
        module_slot = "workspace.intent"
    elif "memory" in action:
        module_slot = "memory"
    else:
        module_slot = "workspace"
    forbidden_actions: list[str] = []
    if action in {"create-prep-only-planning-state", "promote-or-create-active-execplan", "create-or-promote-active-execplan"}:
        forbidden_actions.extend(["edit product source", "claim implementation complete"])
    if action in {"continue-active-planning-record", "run summary"}:
        forbidden_actions.extend(["open raw planning files before compact summary", "claim completion"])
    if action in {"ask-intent-discovery-question", "ask-work-shape-clarification"}:
        forbidden_actions.extend(["begin implementation", "create planning artifact before clarified intent is captured"])
    if action == "present-lane-shaping-prompt":
        forbidden_actions.extend(
            [
                "begin implementation",
                "promote or create a slice before lane shaping is recorded",
            ]
        )
    if action == "run-bounded-work-shape-study":
        forbidden_actions.extend(
            [
                "begin implementation",
                "create shape-specific planning artifact before study evidence is sufficient",
            ]
        )
    if action == "run-installed-payload-target-upgrade":
        forbidden_actions.extend(
            [
                "begin ordinary workspace work before installed payload target is satisfied",
                "claim installed payload target satisfied before recheck passes",
            ]
        )
    if "closeout" in action:
        forbidden_actions.append("claim completion before closeout trust is reconciled")
    if decision in {
        "active-execplan-required",
        "candidate-lane-promotion-required",
        "lane-shaping-required",
        "lane-owner-artifact-required",
        "parent-decomposition-decision-required",
        "planning-escalation-required",
        "implementation-owner-missing",
        "information-gathering-required",
        "planning-shape-owner-required",
        "planning-shape-human-decision-required",
    }:
        forbidden_actions.append("continue implementation without active planning ownership")
    memory_status = str((memory_consult or {}).get("status", "unknown"))
    command_effect = "none"
    if preferred_cli:
        command_effect = _preferred_cli_effect(preferred_cli)
    closure_blockers = sorted(set(forbidden_actions))
    continuation_owner_required = action in {
        "inspect-closeout-trust-before-completion-answer",
        "create-prep-only-planning-state",
        "promote-or-create-active-execplan",
        "create-or-promote-active-execplan",
    }
    allowed_next_actions = [action]
    if preferred_cli:
        allowed_next_actions.append("run-preferred-cli")
    proof_required = bool(
        proof_hint
        and proof_hint not in {"select proof after changed paths are known", "no file proof unless the task later becomes an edit"}
    )
    if skill in {"planning-reporting", "planning-autopilot", "planning-decompose", "planning-new-plan-tighten"}:
        proof_required = True
    task_switch_route_choice = action == "choose-task-switch-route" and decision == "active-plan-task-switch"
    implementation_allowed = not forbidden_actions and (task_switch_route_choice or not skill.startswith("planning"))
    completion_claim_allowed = not forbidden_actions and action not in {"choose-smallest-workflow-shape"}
    gate_result = decision or action
    read_only_allowance = _read_only_allowance_packet(
        implementation_allowed=implementation_allowed,
        completion_claim_allowed=completion_claim_allowed,
        gate_result=gate_result,
        required_next_action=action,
    )
    authority_boundary = _authority_boundary_payload(
        surface="next_safe_action",
        enforced_by_aw=[
            *sorted(set(forbidden_actions)),
            "proof required before completion claim" if proof_required else "",
            "continuation owner required before closeout" if continuation_owner_required else "",
        ],
        observed_by_aw=[
            f"preferred_cli_effect={command_effect}",
            f"module_slot={module_slot}",
            f"memory_consultation_status={memory_status}",
            f"read_only_allowed={read_only_allowance['read_only_allowed']}",
        ],
        recommended_by_aw=[action, skill, preferred_cli],
        proof_hints=[proof_hint],
        agent_owned_decisions=[
            "semantic work shape when no forbidden action applies",
            "whether advisory skill routing fits the task",
            "final completion judgment after proof and acceptance reconciliation",
        ],
        human_owned_decisions=["missing intent or acceptance boundary when next_safe_action asks for clarification"]
        if action == "ask-intent-discovery-question"
        else ["lane intent, decomposition shape, and acceptable first slice"]
        if action == "present-lane-shaping-prompt"
        else [],
        rule=(
            "next_safe_action may enforce forbidden actions and completion gates; otherwise it is structured guidance "
            "for the agent's own route choice."
        ),
    )
    return {
        "kind": "agentic-workspace/next-safe-action/v1",
        "next_safe_action": action,
        "why": str(immediate.get("summary", "") or (workflow_sufficiency or {}).get("reason", "")),
        "required_skill": skill,
        "preferred_cli": preferred_cli,
        "preferred_cli_effect": command_effect,
        "cli_availability": "unknown" if preferred_cli else "not-needed",
        "module_slot": module_slot,
        "allowed_next_actions": allowed_next_actions,
        "forbidden_actions": sorted(set(forbidden_actions)),
        "implementation_allowed": implementation_allowed,
        "read_only_allowed": read_only_allowance["read_only_allowed"],
        "exploration_allowed": read_only_allowance["exploration_allowed"],
        "allowed_read_only_actions": read_only_allowance["allowed_read_only_actions"],
        "proof_required": proof_required,
        "completion_claim_allowed": completion_claim_allowed,
        "claim_boundary": read_only_allowance["claim_boundary"],
        "closure_blockers": closure_blockers,
        "continuation_owner_required": continuation_owner_required,
        "memory_consultation_status": memory_status,
        "authority_boundary": authority_boundary,
        "fallback_if_cli_unavailable": "Use generated or documented workflow fallback for the same module slot; preserve forbidden actions and do not mutate managed state by hand.",
        "source_fields": ["immediate_next_allowed_action", "workflow_sufficiency", "skill_routing", "memory_consult"],
    }


def _compact_action_signals_payload(
    *,
    surface: str,
    allowed_next_action: str,
    hard_blockers: Sequence[str] | None = None,
    implementation_allowed: bool | None = None,
    read_only_allowed: bool | None = None,
    proof_required: bool = False,
    proof_commands: Sequence[str] | None = None,
    changed_signals: Sequence[str] | None = None,
    advisory_selectors: Sequence[str] | None = None,
    agent_judgment: str = "Agent owns semantic fit and final completion judgment.",
) -> dict[str, Any]:
    blockers = [str(item) for item in (hard_blockers or []) if str(item).strip()]
    commands = [str(item) for item in (proof_commands or []) if str(item).strip()]
    signals = [str(item) for item in (changed_signals or []) if str(item).strip()]
    selectors = [str(item) for item in (advisory_selectors or []) if str(item).strip()]
    return {
        "kind": "agentic-workspace/action-signals/v1",
        "surface": surface,
        "hard_blockers": blockers,
        "allowed_next_action": allowed_next_action,
        "implementation_allowed": implementation_allowed,
        "read_only_allowed": read_only_allowed,
        "proof_required": proof_required,
        "proof_commands": commands,
        "changed_signals": signals,
        "advisory_detail": {
            "selectors": selectors,
            "rule": "Use selectors.",
        },
        "agent_judgment": agent_judgment,
        "order": [
            "hard_blockers",
            "allowed_next_action",
            "proof_required",
            "changed_signals",
            "advisory_detail",
            "agent_judgment",
        ],
    }


def _startup_closeout_report_route(closeout_inspection: dict[str, Any]) -> dict[str, Any]:
    trust = str(closeout_inspection.get("trust", "")).strip().lower()
    detail_command = str(closeout_inspection.get("required_next_inspection") or closeout_inspection.get("detail_command") or "")
    closeout_report_command = detail_command.replace("--section closeout_trust", "--section closeout_report")
    if not closeout_report_command or closeout_report_command == detail_command:
        closeout_report_command = "agentic-workspace report --target ./repo --section closeout_report --format json"
    closeout_trust_command = detail_command or closeout_report_command.replace("--section closeout_report", "--section closeout_trust")
    return {
        "kind": "agentic-workspace/closeout-report-route/v1",
        "status": "available",
        "profile": "audit" if trust == "lower-trust" or closeout_inspection.get("status") == "required" else "compact",
        "reason": str(closeout_inspection.get("reason") or "completion/status startup should route through closeout report"),
        "escalation_source": "closeout_trust_inspection" if closeout_inspection.get("status") == "required" else "startup-route",
        "next_command": closeout_report_command,
        "selector": "closeout_report",
        "ordinary_route": {
            "status": "mandatory-before-completion-claim",
            "first_inspection": closeout_trust_command,
            "closeout_report": closeout_report_command,
            "applies_to": ["implementation closeout", "read-only GitHub status", "repo-maintenance completion"],
            "rule": "Run the closeout route and reconcile its result before claiming completion; startup/proof commands do not close work by themselves.",
        },
        "top_level_closeout_command": {
            "status": "not-available",
            "substitute_command": closeout_report_command,
            "why": "Agentic Workspace exposes closeout through report sections and planning closeout/archive commands rather than a generic top-level closeout command.",
        },
    }


def _startup_continuation_view_payload(*, target_root: Path) -> dict[str, Any]:
    try:
        from repo_planning_bootstrap.installer import planning_summary

        summary = planning_summary(target=target_root, profile="tiny")
    except Exception:
        return {
            "kind": "agentic-planning/continuation-view/v1",
            "status": "unavailable",
            "reason": "Planning summary continuation view could not be loaded.",
            "detail_command": "agentic-workspace summary --format json",
        }
    if not isinstance(summary, dict):
        return {
            "kind": "agentic-planning/continuation-view/v1",
            "status": "unavailable",
            "reason": "Planning summary did not return a structured payload.",
            "detail_command": "agentic-workspace summary --format json",
        }
    view = summary.get("continuation_view")
    if isinstance(view, dict):
        return _compact_start_continuation_view(view)
    return {
        "kind": "agentic-planning/continuation-view/v1",
        "status": "quiet",
        "reason": "Planning summary did not report active continuation pressure.",
        "detail_command": "agentic-workspace summary --format json",
    }


def _compact_start_continuation_view(view: dict[str, Any]) -> dict[str, Any]:
    def _clip(value: Any, *, limit: int = 180) -> Any:
        if not isinstance(value, str) or len(value) <= limit:
            return value
        return value[: limit - 1].rstrip() + "..."

    answers = view.get("answers", {}) if isinstance(view.get("answers"), dict) else {}
    compact_answers = {
        key: _clip(answers.get(key))
        for key in ("preserved_intent", "claim_allowed", "next_safe_action", "trust_basis")
        if answers.get(key) not in ("", None)
    }
    claim_boundary = view.get("claim_boundary", {}) if isinstance(view.get("claim_boundary"), dict) else {}
    resume_predicate = view.get("resume_predicate", {}) if isinstance(view.get("resume_predicate"), dict) else {}
    stale_projections = view.get("stale_projections", []) if isinstance(view.get("stale_projections"), list) else []
    compact_stale = [
        {
            key: _clip(item.get(key), limit=120)
            for key in ("field", "stale_value", "chosen_value", "reason")
            if isinstance(item, dict) and key in item
        }
        for item in stale_projections[:2]
        if isinstance(item, dict)
    ]
    compact = {
        "kind": view.get("kind", "agentic-planning/continuation-view/v1"),
        "status": view.get("status", "unknown"),
        "answers": compact_answers,
        "claim_boundary": {
            key: claim_boundary.get(key)
            for key in (
                "status",
                "claim_level_allowed",
                "required_next_action",
                "active_intent_satisfied",
            )
            if key in claim_boundary
        },
        "resume_predicate": {
            key: resume_predicate.get(key) for key in ("status", "failed", "required_next_action") if key in resume_predicate
        },
        "stale_projections": compact_stale,
        "drill_down": {
            "full_view": "agentic-workspace summary --select continuation_view --format json",
        },
    }
    return {key: value for key, value in compact.items() if value not in ({}, [], "", None)}


def _continuation_reorientation_payload(
    *,
    config: WorkspaceConfig,
    target_root: Path,
    active_planning_present: bool,
    payload: dict[str, Any],
    task_text: str | None,
    active_planning_record: dict[str, Any] | None = None,
    active_intent_contract: dict[str, Any] | None = None,
    intent_evidence: dict[str, Any] | None = None,
) -> dict[str, Any]:
    repo_posture = _compact_repo_posture_projection(_repo_posture_payload(config=config, surface="start", compact=True))
    if not active_planning_present:
        return {
            "kind": "agentic-workspace/continuation-reorientation/v1",
            "status": "not-triggered",
            "trigger": {
                "source": "planning.continuation_view",
                "condition": "active-planning-present",
                "present": False,
            },
            "repo_posture": repo_posture,
            "normal_startup_rule": "Normal first-contact startup carries only repo_posture ref/digest/reminder unless continuation pressure is present or the selector is requested.",
        }

    active_planning_record = _as_dict(active_planning_record)
    active_intent_contract = _as_dict(active_intent_contract)
    continuation_view = _as_dict(payload.get("continuation_view"))
    claim_boundary = _as_dict(continuation_view.get("claim_boundary"))
    answers = _as_dict(continuation_view.get("answers"))
    custody = _intent_custody_payload(
        task_text=task_text,
        task_intent=_as_dict(payload.get("task_intent")),
        intent_evidence=_as_dict(intent_evidence) or _as_dict(payload.get("intent_evidence")),
        active_intent_contract=active_intent_contract,
        active_planning_record=active_planning_record,
        durable_intent=_as_dict(payload.get("durable_intent")),
        cli_invoke=config.cli_invoke,
    )
    completion_boundaries = _list_payload(_as_dict(custody.get("startup_projection")).get("completion_boundaries"))
    anti_goals = _list_payload(_as_dict(custody.get("startup_projection")).get("anti_goals"))
    if not anti_goals:
        anti_goals = [
            "do not claim parent, issue, or initiative closure from startup projection alone",
            "do not treat this packet as a durable intent store",
        ]
    immediate = _as_dict(payload.get("immediate_next_allowed_action"))
    proof = _as_dict(payload.get("proof"))
    proof_boundary = (
        proof.get("summary") or proof.get("next_proof") or immediate.get("next_proof") or "select proof after changed paths are known"
    )
    next_safe_action = {
        key: immediate.get(key)
        for key in ("action", "summary", "command", "risk", "next_proof")
        if immediate.get(key) not in ("", None, [], {})
    }
    return {
        "kind": "agentic-workspace/continuation-reorientation/v1",
        "status": "required",
        "trigger": {
            "source": "planning.continuation_view",
            "condition": "active-planning-present",
            "present": True,
            "rule": "Active Planning continuation/resume state upgrades startup from compact posture reminder to explicit reorientation packet.",
            "detail_command": _command_with_cli_invoke(
                command="agentic-workspace summary --select continuation_view --format json",
                cli_invoke=config.cli_invoke,
            ),
        },
        "repo_posture": repo_posture,
        "active_intent_refs": _list_payload(custody.get("active_intent_refs")),
        "completion_boundary": completion_boundaries[:4],
        "anti_goals_or_omissions": anti_goals[:4],
        "proof_claim_boundary": {
            "proof": proof_boundary,
            "claim_boundary": {
                key: claim_boundary.get(key)
                for key in ("status", "claim_level_allowed", "required_next_action", "active_intent_satisfied")
                if claim_boundary.get(key) not in ("", None)
            },
            "claim_allowed": answers.get("claim_allowed"),
        },
        "next_safe_action": next_safe_action,
        "startup_role": "projection-routing-only",
        "not_durable_store": True,
        "routing": {
            "detail_selectors": ["continuation_view", "repo_posture", "intent_custody", "active_intent_contract"],
            "owner_surface": "Planning active state and summary continuation_view",
        },
    }


def _compact_task_posture_packet_projection(task_posture_packet: dict[str, Any]) -> dict[str, Any]:
    compact = {
        "kind": task_posture_packet.get("kind"),
        "operating_posture": task_posture_packet.get("operating_posture", {}),
        "workflow_obligations": task_posture_packet.get("workflow_obligations", []),
        "workflow_obligation_effects": task_posture_packet.get("workflow_obligation_effects", []),
        "improvement_pressure_evaluation": task_posture_packet.get("improvement_pressure_evaluation", {}),
        "improvement_obligations": task_posture_packet.get("improvement_obligations", []),
        "dogfooding_signal_status": task_posture_packet.get("dogfooding_signal_status", {}),
        "dogfooding_obligations": task_posture_packet.get("dogfooding_obligations", []),
        "optimization_effect": task_posture_packet.get("optimization_effect", {}),
        "operational_effectiveness": task_posture_packet.get("operational_effectiveness", {}),
        "skill_routes": task_posture_packet.get("skill_routes", []),
        "allowed_actions": task_posture_packet.get("allowed_actions", []),
        "forbidden_actions": task_posture_packet.get("forbidden_actions", []),
        "proof_boundaries": task_posture_packet.get("proof_boundaries", []),
        "closeout_boundaries": task_posture_packet.get("closeout_boundaries", []),
        "read_budget": task_posture_packet.get("read_budget", {}),
        "authority_boundaries": task_posture_packet.get("authority_boundaries", [])[:2],
        "knowledge_gates": task_posture_packet.get("knowledge_gates", []),
        "gate_summary": task_posture_packet.get("gate_summary", {}),
        "blocked_actions": task_posture_packet.get("blocked_actions", []),
        "next_allowed_action": task_posture_packet.get("next_allowed_action", ""),
        "output_shape_requirements": task_posture_packet.get("output_shape_requirements", []),
        "review_rubrics": task_posture_packet.get("review_rubrics", []),
        "module_contributions": task_posture_packet.get("module_contributions", [])[:3],
        "provenance": task_posture_packet.get("provenance", []),
        "dynamic_instruction_projection": task_posture_packet.get("dynamic_instruction_projection", {}),
        "posture_adherence": task_posture_packet.get("posture_adherence", {}),
    }
    if not compact["knowledge_gates"]:
        for key in ("knowledge_gates", "gate_summary", "blocked_actions", "next_allowed_action"):
            compact.pop(key, None)
    return compact


def _configured_lane_shaping_target(config: WorkspaceConfig) -> dict[str, Any] | None:
    for target in config.local_override.delegation_targets:
        method_set = set(target.execution_methods)
        capability_set = set(target.capability_classes) | set(target.safe_task_classes)
        if "manual" in method_set and target.location in {"external", "either"} and "boundary-shaping" in capability_set:
            return {
                "name": target.name,
                "target_kind": "manual-external",
                "strength": target.strength,
                "location": target.location,
                "execution_methods": list(target.execution_methods),
                "capability_classes": list(target.capability_classes),
            }
    return None


def _lane_shaping_gate_payload(
    *,
    config: WorkspaceConfig,
    planning_safety_gate: dict[str, Any],
    delegation_decision: dict[str, Any],
    task_text: str | None,
    changed_paths: list[str],
    cli_invoke: str,
) -> dict[str, Any]:
    if changed_paths:
        return {
            "kind": "agentic-workspace/lane-shaping-gate/v1",
            "status": "not-applicable",
            "reason": "changed paths already define a local proof surface",
        }
    if planning_safety_gate.get("gate_result") != "candidate-lane-promotion-required":
        return {
            "kind": "agentic-workspace/lane-shaping-gate/v1",
            "status": "not-applicable",
            "reason": "planning safety did not require candidate lane promotion",
        }
    route_evidence = delegation_decision.get("route_evidence", {}) if isinstance(delegation_decision, dict) else {}
    candidate_pressure = planning_safety_gate.get("candidate_pressure", {}) if isinstance(planning_safety_gate, dict) else {}
    scope_signal = str(route_evidence.get("scope_signal") or candidate_pressure.get("work_shape") or "unknown")
    if scope_signal not in {"lane", "epic"}:
        return {"kind": "agentic-workspace/lane-shaping-gate/v1", "status": "not-applicable", "reason": "scope signal is not lane or epic"}

    target = _configured_lane_shaping_target(config)
    if target is None:
        return {
            "kind": "agentic-workspace/lane-shaping-gate/v1",
            "status": "not-applicable",
            "reason": "no configured manual external boundary-shaping target",
        }
    candidate_ids = [str(item) for item in candidate_pressure.get("candidate_ids", []) if str(item).strip()]
    issue_refs = [str(item) for item in planning_safety_gate.get("issue_refs", []) if str(item).strip()]
    evidence = [
        f"planning_gate={planning_safety_gate.get('gate_result')}",
        f"scope_signal={scope_signal}",
        f"candidate_count={candidate_pressure.get('candidate_count', 0)}",
        "active_planning_present=False",
    ]
    evidence.append("manual_external_boundary_shaping_target=configured")
    questions = [
        "What is the larger intended outcome, in host-repo terms?",
        "What evidence would show the larger intent is fully satisfied, not merely advanced?",
        "Which bounded first slice is acceptable, and what must remain explicitly open?",
        "Which proof owner should validate each retained or changed behavior?",
        "What stop conditions should prevent implementation from continuing?",
    ]
    prompt_lines = [
        "You are being consulted before implementation or slice promotion.",
        "",
        f"Task: {task_text.strip() if task_text else '(no task text supplied)'}",
        "",
        "AW observed a broad unshaped lane and no active planning owner.",
        "Use the evidence below to shape the lane, but do not treat it as a decision.",
        "",
        "Observed evidence:",
        *[f"- {item}" for item in evidence],
    ]
    if candidate_ids:
        prompt_lines.extend(["", "Candidate planning refs:", *[f"- {item}" for item in candidate_ids[:8]]])
    if issue_refs:
        prompt_lines.extend(["", "External refs mentioned in task:", *[f"- {item}" for item in issue_refs[:8]]])
    prompt_lines.extend(
        [
            "",
            "Questions to answer:",
            *[f"- {item}" for item in questions],
            "",
            "Return a compact shaping answer only. Leave final reasoning, implementation choices, and proof judgment to the coding agent and human operator.",
        ]
    )
    return {
        "kind": "agentic-workspace/lane-shaping-gate/v1",
        "status": "required",
        "gate_result": "lane-shaping-required",
        "required_next_action": "present-lane-shaping-prompt",
        "implementation_allowed": False,
        "reason": "Broad unshaped lane work needs a shaping answer before implementation or slice promotion.",
        "target": target,
        "observed_evidence": evidence,
        "questions": questions,
        "candidate_ids": candidate_ids[:8],
        "external_refs": issue_refs[:8],
        "ready_to_forward_prompt": {
            "kind": "agentic-workspace/lane-shaping-prompt/v1",
            "target": target["name"],
            "copy_paste": "\n".join(prompt_lines),
            "constraints": [
                "Do not write implementation steps.",
                "Do not assume an external tracker defines AW lane semantics.",
                "State uncertainty and choices explicitly.",
                "Keep decisions available to the coding agent and human operator.",
            ],
            "return_to": "Paste the shaping answer back into the current agent session before promotion or implementation.",
        },
        "recording_options": [
            _command_with_cli_invoke(
                command="agentic-workspace planning new-plan --id <id> --title <title> --target . --activate --format json",
                cli_invoke=cli_invoke,
            ),
            "record an explicit bounded-slice exception that does not claim parent or lane closure",
        ],
        "authority_boundary": _authority_boundary_payload(
            surface="lane_shaping_gate",
            enforced_by_aw=["lane-shaping-required"],
            observed_by_aw=evidence,
            recommended_by_aw=["present-lane-shaping-prompt"],
            agent_owned_decisions=[
                "whether the shaping answer is sufficient",
                "which lane or slice shape to record",
                "which proof owner validates the chosen scope",
            ],
            human_owned_decisions=["larger intent, acceptable first slice, and stop conditions"],
            rule="AW surfaces the shaping question and evidence; it does not decide the lane semantics.",
        ),
    }


def _apply_lane_shaping_gate_to_start_payload(
    *,
    payload: dict[str, Any],
    config: WorkspaceConfig,
    planning_safety_gate: dict[str, Any],
    task_text: str | None,
    changed_paths: list[str],
    startup_template: dict[str, Any],
) -> None:
    lane_gate = _lane_shaping_gate_payload(
        config=config,
        planning_safety_gate=planning_safety_gate,
        delegation_decision=payload.get("delegation_decision", {}),
        task_text=task_text,
        changed_paths=changed_paths,
        cli_invoke=config.cli_invoke,
    )
    if lane_gate.get("status") != "required":
        return
    payload["lane_shaping_gate"] = lane_gate
    payload["workflow_sufficiency"] = _workflow_sufficiency_payload(
        surface="start",
        decision="lane-shaping-required",
        reason=str(lane_gate.get("reason", "")),
        required_next_action="present-lane-shaping-prompt",
        evidence_required=["captured lane shaping answer before implementation or slice promotion"],
    )
    payload["immediate_next_allowed_action"] = {
        "action": "present-lane-shaping-prompt",
        "summary": str(lane_gate.get("reason", "")),
        "command": None,
        "run": None,
        "risk": "lane-shaping-required-before-implementation",
        "required_inputs": ["larger intent", "acceptable first slice", "proof owner", "stop conditions"],
        "next_proof": "record the shaping answer in Planning or an explicit bounded-slice exception before implementation",
        "read_first": [],
        "open_execplan_only_when": startup_template["open_execplan_only_when"],
        "lane_shaping_prompt": lane_gate.get("ready_to_forward_prompt", {}),
    }


def _compact_startup_installed_state_signal(installed_state: dict[str, Any]) -> dict[str, Any]:
    action_state = _as_dict(installed_state.get("action_state"))
    executable = _as_dict(installed_state.get("executable"))
    payload = _as_dict(installed_state.get("payload"))
    generated_artifacts = _as_dict(installed_state.get("generated_artifacts"))
    compact = {
        "kind": installed_state.get("kind", "agentic-workspace/installed-state-compatibility/v1"),
        "status": installed_state.get("status", ""),
        "reason": installed_state.get("reason", ""),
        "authority": installed_state.get("authority", "repo-state-authoritative"),
        "action_state": {
            key: action_state.get(key)
            for key in (
                "kind",
                "state",
                "status",
                "reason",
                "repair_mechanism",
                "action_id",
                "command",
                "dry_run_command",
                "apply_command",
                "safe_to_apply",
                "mutates_on_start",
            )
            if action_state.get(key) not in (None, "", [], {})
        },
        "executable": {
            key: executable.get(key)
            for key in ("compatibility_status", "classification", "failed_checks")
            if executable.get(key) not in (None, "", [])
        },
        "payload": {
            key: payload.get(key)
            for key in ("status", "provenance_drift", "stale_generated_surfaces")
            if payload.get(key) not in (None, "", [])
        },
        "generated_artifacts": {
            key: generated_artifacts.get(key) for key in ("status", "stale_surfaces") if generated_artifacts.get(key) not in (None, "", [])
        },
        "selector": "installed_state_compatibility",
        "detail_command": "agentic-workspace start --target . --select installed_state_compatibility --format json",
        "detail_visibility": "full executable, payload provenance, generated-artifact, and adapter details stay behind selector",
    }
    if installed_state.get("next_action"):
        compact["next_action"] = installed_state.get("next_action")
    return compact


def _attach_start_router_fields(payload: dict[str, Any]) -> None:
    if "next_safe_action" not in payload:
        immediate = payload.get("immediate_next_allowed_action")
        if not isinstance(immediate, dict):
            immediate = {}
        payload["next_safe_action"] = _next_safe_action_packet(
            immediate=immediate,
            workflow_sufficiency=payload.get("workflow_sufficiency"),
            skill_routing=payload.get("skill_routing"),
            memory_consult=payload.get("memory_consult"),
        )
    if "action_signals" not in payload:
        next_safe_action = payload["next_safe_action"] if isinstance(payload.get("next_safe_action"), dict) else {}
        payload["action_signals"] = _compact_action_signals_payload(
            surface="start",
            allowed_next_action=str(next_safe_action.get("next_safe_action", "")),
            hard_blockers=next_safe_action.get("closure_blockers", []),
            implementation_allowed=bool(next_safe_action.get("implementation_allowed")),
            read_only_allowed=bool(next_safe_action.get("read_only_allowed")),
            proof_required=bool(next_safe_action.get("proof_required")),
            proof_commands=_tiny_required_proof_commands(payload.get("proof", {})) if isinstance(payload.get("proof"), dict) else [],
            advisory_selectors=["skill_routing", "workflow_sufficiency"],
            agent_judgment="Agent owns work-shape unless blocked.",
        )


def _compact_start_proof_payload(proof: dict[str, Any]) -> dict[str, Any]:
    compact = {
        key: proof.get(key)
        for key in ("kind", "changed_paths", "selected_lanes", "required_commands", "required_validation_commands")
        if key in proof
    }
    cli_authority_review = proof.get("cli_authority_review", {})
    if isinstance(cli_authority_review, dict):
        compact["cli_authority_review"] = {
            "status": cli_authority_review.get("status", "unknown"),
            "classifications": cli_authority_review.get("classifications", []),
            "detail_command": "agentic-workspace proof --verbose --changed <paths> --format json",
            "detail_command_template": {
                "kind": "agentic-workspace/command-template/v1",
                "template": "agentic-workspace proof --verbose --changed <paths> --format json",
                "runnable": False,
                "placeholders": {"paths": proof.get("changed_paths", [])},
                "instantiation_required": [] if proof.get("changed_paths") else ["paths"],
                "rule": "Do not run templates containing angle-bracket placeholders until all placeholders are substituted.",
            },
        }
    runtime_symbol_working_set = proof.get("runtime_symbol_working_set", {})
    if isinstance(runtime_symbol_working_set, dict) and runtime_symbol_working_set.get("status") == "present":
        compact["runtime_symbol_working_set"] = tiny_runtime_symbol_working_set_payload(runtime_symbol_working_set)
    changed = proof.get("changed_paths", [])
    if isinstance(changed, list) and changed:
        compact["detail_command"] = "agentic-workspace proof --verbose --changed <paths> --format json"
        compact["detail_command_template"] = {
            "kind": "agentic-workspace/command-template/v1",
            "template": "agentic-workspace proof --verbose --changed <paths> --format json",
            "runnable": False,
            "placeholders": {"paths": changed},
            "instantiation_required": [],
            "rule": "Do not run templates containing angle-bracket placeholders until all placeholders are substituted.",
        }
    return compact


def _tiny_durable_intent(value: dict[str, Any]) -> dict[str, Any]:
    subsystem = value.get("subsystem_intent", {}) if isinstance(value.get("subsystem_intent"), dict) else {}
    ownership = subsystem.get("ownership_registry", {}) if isinstance(subsystem.get("ownership_registry"), dict) else {}
    return {
        "kind": value.get("kind", "agentic-workspace/durable-intent-decision/v1"),
        "status": value.get("status", "unknown"),
        "subsystem_intent": {
            "status": subsystem.get("status", "unknown"),
            "surface": subsystem.get("surface", ".agentic-workspace/system-intent/subsystems.toml"),
            "matched_count": subsystem.get("matched_count", 0),
            "ownership_registry": {key: ownership.get(key) for key in ("status", "surface", "subsystem_count") if key in ownership},
            "matches": [
                {key: match.get(key) for key in ("id", "match_source", "needs_review") if isinstance(match, dict) and key in match}
                for match in subsystem.get("matches", [])[:4]
                if isinstance(match, dict)
            ],
        },
        "inspect": value.get("inspect", "agentic-workspace report --target ./repo --section durable_intent --format json"),
    }


def _candidate_route_label(candidate: dict[str, Any]) -> Any:
    return candidate.get("candidate_route") or candidate.get("route_candidate")


def _candidate_with_canonical_route(candidate: dict[str, Any]) -> dict[str, Any]:
    route = _candidate_route_label(candidate)
    if route in (None, ""):
        return dict(candidate)
    return {**candidate, "candidate_route": route}


def _compact_route_candidate(candidate: dict[str, Any]) -> dict[str, Any]:
    compact = {key: candidate.get(key) for key in ("lane_id", "title", "readiness", "owner_surface", "proof") if key in candidate}
    route = _candidate_route_label(candidate)
    if route not in (None, ""):
        compact["candidate_route"] = route
    return compact


def _tiny_route_candidate(candidate: dict[str, Any]) -> dict[str, Any]:
    compact = {key: candidate.get(key) for key in ("lane_id", "title", "owner_surface", "candidate_route") if key in candidate}
    route = _candidate_route_label(candidate)
    if route not in (None, ""):
        compact["candidate_route"] = route
    return compact


def _compact_start_delegation_decision(value: Any, *, include_manual_handoff_detail: bool = True) -> dict[str, Any]:
    if not isinstance(value, dict):
        return {"status": "unavailable"}
    common_keys = (
        "kind",
        "status",
        "mode",
        "clarification_mode",
        "recommended_route",
        "authority_boundary",
        "route_evidence",
        "token_savings_guidance",
        "required_next_action",
        "effort_guidance",
    )
    compact = {key: value.get(key) for key in common_keys if key in value}
    compact.setdefault("recommended_route", value.get("recommended_route") or value.get("decision"))
    decision = str(value.get("recommended_route") or value.get("decision") or "")
    if not include_manual_handoff_detail and decision == "stay-local":
        compact.pop("authority_boundary", None)
    if "authority_boundary" in compact:
        compact["authority_boundary"] = _compact_authority_boundary(compact["authority_boundary"])
    if isinstance(compact.get("route_evidence"), dict):
        factors = compact["route_evidence"]
        compact["route_evidence"] = {
            key: factors.get(key)
            for key in ("proof_review_pressure", "proof_pressure", "scope_signal", "agent_judgment_required")
            if factors.get(key) not in (None, "")
        }
    if isinstance(compact.get("token_savings_guidance"), dict):
        savings = compact["token_savings_guidance"]
        compact["token_savings_guidance"] = {
            key: savings.get(key) for key in ("signal", "agent_judgment_required") if savings.get(key) not in (None, "")
        }
    if isinstance(compact.get("effort_guidance"), dict):
        compact["effort_guidance"] = _compact_effort_guidance(compact["effort_guidance"])
    suppress_manual_detail = not include_manual_handoff_detail and decision in {"manual-handoff", "ask-human"}
    config_effect = value.get("config_effect")
    manual_external_relay = value.get("manual_external_relay")
    config_changes_effective_behavior = isinstance(config_effect, dict) and (
        config_effect.get("configured_delegation_mode") != config_effect.get("delegation_mode")
        or config_effect.get("disabled_reason") not in (None, "")
        or (config_effect.get("configured_delegation_mode") == "auto" and config_effect.get("safe_to_auto_run_commands") is False)
        or (
            isinstance(manual_external_relay, dict)
            and manual_external_relay.get("target_kind") == "manual-external"
            and (manual_external_relay.get("status") == "appropriate")
            and (decision != "stay-local")
        )
    )
    if decision != "stay-local" or value.get("required_next_action") != "continue-local" or config_changes_effective_behavior:
        routed_keys = ("route_obligation", "config_effect")
        if decision == "stay-local" and value.get("required_next_action") == "continue-local":
            routed_keys = ("config_effect",)
        for routed_key in routed_keys:
            if routed_key in value:
                routed_value = value.get(routed_key)
                if routed_key == "route_obligation" and isinstance(routed_value, dict):
                    if suppress_manual_detail:
                        compact[routed_key] = {"must": routed_value.get("must")}
                        continue
                    compact[routed_key] = {
                        key: routed_value.get(key) for key in ("must", "report_if_skipped") if routed_value.get(key) not in ("", None)
                    }
                elif routed_key == "config_effect" and isinstance(routed_value, dict):
                    config_keys = (
                        "authority",
                        "source_path",
                        "configured_delegation_mode",
                        "delegation_mode",
                        "safe_to_auto_run_commands",
                        "disabled_reason",
                        "execution_authority",
                    )
                    if suppress_manual_detail:
                        config_keys = (
                            "authority",
                            "source_path",
                            "configured_delegation_mode",
                            "delegation_mode",
                            "safe_to_auto_run_commands",
                            "disabled_reason",
                            "execution_authority",
                        )
                    compact[routed_key] = {key: routed_value.get(key) for key in config_keys if key in routed_value}
                else:
                    compact[routed_key] = routed_value
    if decision in {"suggest-delegation", "suggest-downroute", "suggest-escalation", "delegate-bounded-slice"}:
        compact["target"] = value.get("target")
        compact["reason"] = value.get("reason")
    decomposition_delegation = value.get("decomposition_delegation")
    delegation_candidates = [item for item in value.get("delegation_candidates", []) if isinstance(item, dict)]
    delegation_candidate_detail_allowed = decision in {"suggest-delegation", "suggest-downroute", "delegate-bounded-slice"}
    include_decomposition = (
        isinstance(decomposition_delegation, dict)
        and decomposition_delegation.get("status") in {"present", "available-without-active-planning"}
        and (delegation_candidate_detail_allowed or config_changes_effective_behavior)
        and (
            decision == "suggest-delegation"
            or bool(delegation_candidates)
            or _compact_authority_boundary(value.get("authority_boundary")).get("candidate_routes")
        )
    )
    if include_decomposition:
        compact["decomposition_delegation"] = {
            key: decomposition_delegation.get(key)
            for key in ("kind", "status", "reason", "candidate_count", "rule")
            if key in decomposition_delegation
        }
        candidates = [item for item in decomposition_delegation.get("candidates", []) if isinstance(item, dict)]
        if candidates:
            compact["decomposition_delegation"]["candidates"] = [_tiny_route_candidate(candidate) for candidate in candidates[:1]]
    if delegation_candidates and (decision == "suggest-delegation" or include_decomposition):
        compact["delegation_candidates"] = [_tiny_route_candidate(candidate) for candidate in delegation_candidates[:1]]
    auto_delegation_audit = value.get("auto_delegation_audit")
    if isinstance(auto_delegation_audit, dict) and auto_delegation_audit.get("status") == "skipped":
        compact["auto_delegation_audit"] = {
            key: auto_delegation_audit.get(key)
            for key in ("kind", "status", "configured_mode", "effective_mode", "execution_permitted", "must_report_if_not_run")
            if key in auto_delegation_audit
        }
        skipped_targets = [item for item in auto_delegation_audit.get("skipped_targets", []) if isinstance(item, dict)]
        if skipped_targets and (decision != "stay-local" or include_decomposition):
            compact["auto_delegation_audit"]["skipped_targets"] = [
                {key: target.get(key) for key in ("name", "reasons", "execution_methods") if key in target}
                for target in skipped_targets[:2]
            ]
    if (
        isinstance(manual_external_relay, dict)
        and manual_external_relay.get("target_kind") == "manual-external"
        and (manual_external_relay.get("status") == "appropriate" or decision in {"suggest-escalation", "manual-handoff"})
    ):
        relay = manual_external_relay
        compact["manual_external_relay"] = {
            key: relay.get(key) for key in ("kind", "status", "target_kind", "target", "interrupt_cost", "reason", "rule") if key in relay
        }
    if decision in {"suggest-delegation", "suggest-escalation", "delegate-bounded-slice", "manual-handoff", "ask-human"}:
        if value.get("handoff_command"):
            compact["handoff_command"] = value.get("handoff_command")
        if (include_manual_handoff_detail or decision in {"manual-handoff", "ask-human"}) and value.get("manual_prompt"):
            compact["manual_prompt"] = value.get("manual_prompt")
        if value.get("delegation_next_step"):
            next_step = value.get("delegation_next_step")
            next_step_keys = (
                "status",
                "action",
                "target",
                "command",
                "execution_methods",
                "must_report_if_not_run",
                "handoff_contract_status",
                "precondition",
                "return_contract",
            )
            if suppress_manual_detail:
                next_step_keys = ("status", "action", "command", "must_report_if_not_run", "handoff_contract_status", "precondition")
            compact["delegation_next_step"] = (
                {key: next_step.get(key) for key in next_step_keys if key in next_step} if isinstance(next_step, dict) else next_step
            )
    return compact


def _delegation_decision_requires_attention(value: Any) -> bool:
    if not isinstance(value, dict):
        return False
    route = value.get("recommended_route") or value.get("decision")
    required = value.get("required_next_action")
    if route not in {"", None, "stay-local"} or required not in {"", None, "continue-local"}:
        return True
    config_effect = value.get("config_effect", {})
    if isinstance(config_effect, dict) and (
        config_effect.get("configured_delegation_mode") != config_effect.get("delegation_mode")
        or config_effect.get("disabled_reason") not in (None, "")
        or (config_effect.get("configured_delegation_mode") == "auto" and config_effect.get("safe_to_auto_run_commands") is False)
    ):
        return True
    audit = value.get("auto_delegation_audit", {})
    return isinstance(audit, dict) and audit.get("must_report_if_not_run") is True


def _compact_effort_guidance(value: dict[str, Any]) -> dict[str, Any]:
    return {
        key: value.get(key)
        for key in ("orchestrator", "planner", "implementer", "validator", "cost_posture")
        if value.get(key) not in (None, "")
    }


def _compact_start_prep_only_handoff(value: Any) -> dict[str, Any]:
    if not isinstance(value, dict):
        return {"status": "unavailable"}
    keys = (
        "status",
        "first_command",
        "reference_command",
        "preferred_mutation_command_template",
        "after_write",
        "stop_after_summary",
        "open_execplan_after_creation",
        "manual_execplan_tightening",
        "allowed_write_scope",
        "allowed_after_new_plan",
        "forbidden_until_implementation_requested",
    )
    return {key: value.get(key) for key in keys if key in value}


def _is_prep_only_handoff_task(task_text: str | None) -> bool:
    _ = task_text
    return False


def _is_config_posture_task(task_text: str | None) -> bool:
    _ = task_text
    return False


def _is_completion_status_task(task_text: str | None) -> bool:
    _ = task_text
    return False


def _completion_closeout_inspection_payload(
    *, target_root: Path, config: WorkspaceConfig, task_text: str | None, explicit_request: bool = False
) -> dict[str, Any]:
    target_arg = _command_target_arg(target_root)
    command = _command_with_cli_invoke(
        command=f"agentic-workspace report --target {target_arg} --section closeout_trust --format json", cli_invoke=config.cli_invoke
    )
    if not explicit_request and not _is_completion_status_task(task_text):
        return {
            "status": "not-applicable",
            "reason": "task-text semantics are agent-owned; AW does not infer completion/status posture from prompt keywords",
            "detail_command": command,
            "agent_owned_decision": "whether the user is asking for completion, status, or closeout judgment",
            "action_effect": {
                "force": "advisory",
                "allowed_now": "continue-without-closeout-trust-inspection",
                "blocked_until_reconciled": [],
                "claim_boundary": "agent-owned-decision-whether-closeout-status-is-being-claimed",
                "resolution_selector": "closeout_trust_inspection",
                "resolution_command": command,
            },
        }
    try:
        from repo_planning_bootstrap.installer import planning_report
    except ImportError:
        return {
            "status": "required",
            "trust": "unavailable",
            "reason": "completion/status question requires closeout trust, but the planning module is not importable",
            "detail_command": command,
            "required_next_inspection": command,
            "action_effect": {
                "force": "required_before_claim",
                "allowed_now": "inspect-or-restore-closeout-trust-before-status-claim",
                "blocked_until_reconciled": ["claim-broad-work-complete", "claim-lane-closeable", "claim-issue-closure-safe"],
                "claim_boundary": "do-not-answer-broad-completion-or-closeout-status-without-closeout-trust",
                "resolution_selector": "closeout_trust_inspection",
                "resolution_command": command,
            },
        }
    planning_payload = planning_report(target=target_root)
    closeout = _report_closeout_trust_payload(
        module_reports=[planning_payload], target_root=target_root, config=config, cli_invoke=config.cli_invoke
    )
    strict_gate = closeout.get("strict_closeout_gate", {}) if isinstance(closeout.get("strict_closeout_gate"), dict) else {}
    intent_check = closeout.get("intent_satisfaction_check", {}) if isinstance(closeout.get("intent_satisfaction_check"), dict) else {}
    closeout_protocol = closeout.get("closeout_protocol", {}) if isinstance(closeout.get("closeout_protocol"), dict) else {}
    trust = str(closeout.get("trust") or closeout.get("status") or "unavailable")
    lower_trust_count = _as_int(closeout.get("lower_trust_closeout_count"))
    gate_blocking = bool(strict_gate.get("blocking"))
    needs_surface = trust != "normal" or lower_trust_count > 0 or gate_blocking
    action_effect = {
        "force": "required_before_claim" if needs_surface else "advisory",
        "allowed_now": "inspect-closeout-trust-before-broad-status-claim" if needs_surface else "continue-closeout-status-answer",
        "blocked_until_reconciled": ["claim-broad-work-complete", "claim-lane-closeable", "claim-issue-closure-safe"]
        if needs_surface
        else [],
        "claim_boundary": (
            "broad-completion-and-closeout-claims-blocked-until-closeout-trust-is-reconciled"
            if needs_surface
            else "closeout-trust-clear-does-not-replace-proof-and-acceptance-reconciliation"
        ),
        "resolution_selector": "closeout_trust_inspection",
        "resolution_command": command,
    }
    return {
        "status": "required" if needs_surface else "clear",
        "reason": "explicit closeout_trust inspection found residue to reconcile before claiming broad work is done"
        if needs_surface
        else "explicit closeout_trust inspection found no lower-trust blocker",
        "trust": trust,
        "lower_trust_closeout_count": lower_trust_count,
        "strict_closeout_gate": {key: strict_gate.get(key) for key in ("status", "blocking", "summary", "reason") if key in strict_gate},
        "intent_satisfaction": {
            key: intent_check.get(key)
            for key in ("status", "trust", "reason", "recommended_next_action", "continuation_surface")
            if key in intent_check
        },
        "sample_signals": closeout.get("sample_signals", [])[:2] if isinstance(closeout.get("sample_signals"), list) else [],
        "closeout_protocol": {
            key: closeout_protocol.get(key)
            for key in (
                "kind",
                "protocol",
                "status",
                "readiness",
                "claim_boundary",
                "residue_routing",
                "knowledge_route_states",
                "closure_permission",
                "detail_command",
            )
            if key in closeout_protocol
        },
        "required_next_inspection": command,
        "detail_command": command,
        "action_effect": action_effect,
        "rule": "Do not answer done/complete/closeable for lane, epic, or broad work without reconciling this surface when agent judgment says the user is asking for closeout status.",
        "authority_boundary": _authority_boundary_payload(
            surface="closeout_trust_inspection",
            observed_by_aw=["closeout_trust report facts", "strict closeout gate state"],
            recommended_by_aw=["inspect closeout_trust before broad completion/status claims"],
            agent_owned_decisions=["whether the user is asking for a completion/status judgment"],
            rule="AW reports closeout residue when asked; it does not infer completion/status intent from prompt keywords.",
        ),
    }


def _prep_only_handoff_payload(*, config: WorkspaceConfig) -> dict[str, Any]:
    planning_command = _command_with_cli_invoke(command="agentic-workspace planning --format json", cli_invoke=config.cli_invoke)
    summary_command = _command_with_cli_invoke(command="agentic-workspace summary --verbose --format json", cli_invoke=config.cli_invoke)
    new_plan_template = _command_with_cli_invoke(
        command="agentic-workspace planning new-plan --id <id> --title <title> --target . --activate --prep-only --format json",
        cli_invoke=config.cli_invoke,
    )
    return {
        "kind": "agentic-workspace/prep-only-handoff-route/v1",
        "status": "required",
        "reason": "The task asks for durable continuation state before implementation.",
        "first_command": new_plan_template,
        "reference_command": planning_command,
        "preferred_mutation_command_template": new_plan_template,
        "after_write": summary_command,
        "required_action": "Create or continue canonical checked-in Planning state with new-plan --prep-only, verify with compact summary, then stop.",
        "minimal_success_criteria": [
            "a prep-only execplan is registered in Planning state",
            "summary verification exits successfully",
            "no product, test, dependency, README feature, or handoff files were created",
        ],
        "stop_after_summary": True,
        "open_execplan_after_creation": "no, unless compact summary reports a blocking Planning problem",
        "manual_execplan_tightening": "defer unless summary reports a blocking Planning problem",
        "allowed_write_scope": [
            ".agentic-workspace/planning/state.toml",
            ".agentic-workspace/planning/execplans/",
            ".agentic-workspace/planning/decompositions/",
        ],
        "allowed_after_new_plan": [
            "run the after_write summary command",
            "make only the smallest schema-preserving Planning edit if summary reports a blocking problem",
            "otherwise stop and report the canonical Planning state created",
        ],
        "forbidden_until_implementation_requested": [
            "product source files",
            "tests or fixtures",
            "README feature docs",
            "package/dependency/app scaffold files",
            "freehand PLAN/HANDOFF/ARCHITECTURE docs",
            "manual JSON polishing or ad hoc validation loops",
        ],
    }


def _compact_repair_plan_profile(*, changed_paths: list[str], task_text: str | None, proof_command: str) -> dict[str, Any]:
    normalized_task = " ".join((task_text or "").lower().split())
    narrow_paths = len(changed_paths) <= 2
    repair_terms = ("ci", "docs", "doc", "schema-reference", "proof", "validation", "repair", "fix check", "fix checks")
    repair_task = any(term in normalized_task for term in repair_terms)
    repair_paths = all(
        path.startswith("docs/")
        or path.endswith(".md")
        or "/schemas/" in path
        or path.startswith("src/agentic_workspace/contracts/schemas/")
        for path in changed_paths
    )
    direct = bool(changed_paths and narrow_paths and (repair_task or repair_paths))
    return {
        "kind": "agentic-workspace/compact-repair-plan-profile/v1",
        "status": "direct-no-plan" if direct else "not-repair-profile",
        "fit_criteria": [
            "CI, docs, schema-reference, proof, or tiny validation repair",
            "one or two touched surfaces",
            "no parent intent change",
            "obvious proof command",
            "no durable continuation except PR/CI result",
        ],
        "required_record": {
            "changed_paths": changed_paths,
            "proof_command": proof_command,
            "continuation_owner": "PR/CI result",
        },
        "rule": "Keep narrow repair work direct when checked-in continuity adds more cleanup than safety; preserve exact proof and continuation honesty.",
    }


