def _emit_startup_report(*, format_name: str, target_root: Path, descriptors: dict[str, ModuleDescriptor], config: WorkspaceConfig) -> None:
    from repo_planning_bootstrap.installer import planning_report

    plan_report = planning_report(target=target_root)
    active_record = plan_report.get("active", {}).get("planning_record", {})
    manifest_path = target_root / ".agentic-workspace" / "planning" / "agent-manifest.json"
    manifest = {}
    if manifest_path.exists():
        try:
            manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
        except Exception:
            pass
    tiny_safe_model = _defaults_payload()["startup"]["tiny_safe_model"].copy()
    tiny_safe_model["cli_invoke"] = config.cli_invoke
    tiny_safe_model["first_compact_queries"] = [
        query.replace("agentic-workspace", config.cli_invoke) for query in tiny_safe_model["first_compact_queries"]
    ]
    payload = {
        "kind": "startup-report/v1",
        "invoked_cli_identity": _invoked_cli_identity_payload(target_root=target_root, compact=True),
        "active_intent": active_record.get("requested_outcome") or "No active intent",
        "immediate_next_action": active_record.get("next_action") or "No next action",
        "tiny_safe_model": tiny_safe_model,
        "module_boundaries": _defaults_payload()["startup"]["top_level_capabilities"],
        "critical_invariants": manifest.get("invariants") or [],
        "escalation_boundaries": active_record.get("escalate_when") or [],
        "relevant_handoff_context": plan_report.get("active", {}).get("handoff_contract") or {},
    }
    cli_compatibility = _cli_compatibility_payload(config=config, compact=True)
    if cli_compatibility["configured"]:
        payload["cli_compatibility"] = cli_compatibility
    _emit_payload(payload=payload, format_name=format_name)


def _build_lifecycle_handoff_prompt(payload: dict[str, Any]) -> str:
    prompt_command = str(payload["prompt_command"])
    target = str(payload["target"])
    lines = [f"Run the Agentic Workspace {prompt_command} flow in {target}.", "", "Selected modules:"]
    lines.extend((f"- {module_name}" for module_name in payload["modules"]))
    lines.extend(
        [
            "",
            "Use the workspace CLI as the lifecycle entrypoint for this repo shape.",
            "Keep module-specific lifecycle implementation package-local; do not switch to package CLIs unless package-local debugging is required.",
        ]
    )
    if payload.get("non_interactive"):
        lines.extend(
            [
                "Run this flow with `--non-interactive` and avoid command paths that would wait for human confirmation.",
                "Keep the lifecycle pass prompt-free and safe for unattended Windows/PowerShell execution.",
            ]
        )
    config_payload = payload.get("config")
    if isinstance(config_payload, dict) and config_payload.get("exists"):
        lines.extend(
            [
                "",
                f"Respect the repo-owned config at {config_payload['config_path']}.",
                "Treat that file as the source of lifecycle defaults and module update intent.",
            ]
        )
        selected_policy_lines = []
        for module_policy in config_payload.get("update", {}).get("modules", []):
            if module_policy.get("module") in payload["modules"]:
                selected_policy_lines.append(f"- {module_policy['module']}: {module_policy['source_type']} {module_policy['source_ref']}")
        if selected_policy_lines:
            lines.extend(["Configured update sources:"])
            lines.extend(selected_policy_lines)
    review_items = []
    for heading in ("updated_managed", "preserved_existing", "needs_review", "warnings"):
        review_items.extend(payload.get(heading, []))
    intent_payload = payload.get("intent")
    if isinstance(intent_payload, dict):
        confirmed_intent = intent_payload.get("confirmed_intent")
        interpreted_intent = intent_payload.get("interpreted_intent")
        if isinstance(confirmed_intent, dict) and isinstance(interpreted_intent, dict):
            lines.extend(
                [
                    "",
                    "Intent:",
                    f"- confirmed: {confirmed_intent.get('summary', intent_payload.get('summary', ''))}",
                    f"- interpreted: {interpreted_intent.get('summary', intent_payload.get('summary', ''))}",
                ]
            )
    if review_items:
        lines.extend(["", "Review before applying:"])
        lines.extend((f"- {item}" for item in review_items))
    lines.extend(["", "Validation:"])
    lines.extend((f"- {step}" for step in payload["next_steps"] if step))
    return "\n".join(lines)


def _default_handoff_prompt_path(*, target_root: Path) -> Path:
    return (target_root / WORKSPACE_BOOTSTRAP_HANDOFF_PATH).resolve()


def _default_handoff_record_path(*, target_root: Path) -> Path:
    return (target_root / WORKSPACE_BOOTSTRAP_HANDOFF_RECORD_PATH).resolve()


def _write_prompt_file(*, prompt_path: Path, prompt_text: str, dry_run: bool) -> Path:
    if not dry_run:
        prompt_path.parent.mkdir(parents=True, exist_ok=True)
        prompt_path.write_text(prompt_text + "\n", encoding="utf-8")
    return prompt_path


def _write_json_file(*, destination: Path, payload: dict[str, Any], dry_run: bool) -> Path:
    if not dry_run:
        destination.parent.mkdir(parents=True, exist_ok=True)
        destination.write_text(json.dumps(serialise_value(payload), indent=2) + "\n", encoding="utf-8")
    return destination


def _emit_modules(*, format_name: str, target_root: Path | None, profile: str = "tiny", section: str | None = None) -> None:
    descriptors = _module_operations()
    registry = _module_registry(descriptors=descriptors, target_root=target_root)
    full_payload = {
        "package_footprint": copy.deepcopy(_PACKAGE_FOOTPRINT),
        "participation_model": copy.deepcopy(_MODULE_PARTICIPATION_MODEL),
        "component_model": copy.deepcopy(_MODULE_COMPONENT_MODEL),
        "workspace_components": copy.deepcopy(_WORKSPACE_COMPONENTS),
        "terminology": copy.deepcopy(_MODULE_REGISTRY_MANIFEST.get("terminology", {})),
        "advanced_features": copy.deepcopy(list(_ADVANCED_FEATURE_ENTRIES)),
        "modules": [
            {
                "name": entry.name,
                "description": entry.description,
                "kind": entry.kind,
                "default_enabled": entry.default_enabled,
                "commands": list(entry.lifecycle_commands),
                "lifecycle_hook_expectations": list(entry.lifecycle_hook_expectations),
                "autodetects_installation": entry.autodetects_installation,
                "installed": entry.installed,
                "install_signals": [path.as_posix() for path in entry.install_signals],
                "workflow_surfaces": [path.as_posix() for path in entry.workflow_surfaces],
                "generated_artifacts": [path.as_posix() for path in entry.generated_artifacts],
                "dry_run_commands": list(entry.dry_run_commands),
                "force_commands": list(entry.force_commands),
                "capabilities": list(entry.capabilities),
                "dependencies": list(entry.dependencies),
                "conflicts": list(entry.conflicts),
                "participation": copy.deepcopy(_MODULE_REGISTRY_ENTRIES.get(entry.name, {}).get("participation", {})),
                "components": copy.deepcopy(_MODULE_REGISTRY_ENTRIES.get(entry.name, {}).get("components", {})),
                "result_contract": {
                    "schema_version": entry.result_contract.schema_version,
                    "guaranteed_fields": list(entry.result_contract.guaranteed_fields),
                    "action_fields": list(entry.result_contract.action_fields),
                    "warning_fields": list(entry.result_contract.warning_fields),
                },
                "command_args": {name: list(args) for name, args in descriptors[entry.name].command_args.items()},
            }
            for entry in registry
        ],
    }
    sections = sorted(full_payload)
    target_arg = " --target ." if target_root is not None else ""
    section_commands = {name: f"agentic-workspace modules{target_arg} --section {name} --format json" for name in sections}
    if section:
        selected = str(section).strip()
        payload = {
            "kind": "agentic-workspace/modules-router/v1",
            "profile": "section",
            "target": target_root.as_posix() if target_root is not None else None,
            "selector": {"section": selected},
            "matched": selected in full_payload,
            "section": selected,
            "answer": copy.deepcopy(full_payload.get(selected, {})),
            "available_sections": sections,
            "detail_commands": {
                "compact": f"agentic-workspace modules{target_arg} --format json",
                "full": f"agentic-workspace modules{target_arg} --verbose --format json",
            },
        }
        _emit_payload(payload=payload, format_name=format_name)
        return
    if profile == "tiny":
        installed = [entry for entry in registry if entry.installed]
        payload = {
            "kind": "agentic-workspace/modules-router/v1",
            "profile": "tiny",
            "target": target_root.as_posix() if target_root is not None else None,
            "active_module_count": len(installed),
            "active_modules": [entry.name for entry in installed],
            "default_enabled_modules": [entry.name for entry in registry if entry.default_enabled],
            "selection_rule": "Repo intent is [modules].enabled; installed files are reported as state evidence.",
            "available_sections": sections,
            "section_commands": section_commands,
            "detail_commands": {
                "package_footprint": section_commands["package_footprint"],
                "participation_model": section_commands["participation_model"],
                "full": f"agentic-workspace modules{target_arg} --verbose --format json",
                "status": "agentic-workspace status --target . --format json",
            },
        }
    else:
        payload = {**full_payload, "available_sections": sections}
    _emit_payload(payload=payload, format_name=format_name)


def _startup_skill_routing_payload(
    *,
    cli_invoke: str = DEFAULT_CLI_INVOKE,
    enabled_advanced_features: Sequence[str] = (),
    compact: bool = False,
    target_root: Path | None = None,
    task_text: str | None = None,
) -> dict[str, Any]:
    skill_command = _command_with_cli_invoke(
        command=_proof_command_for_target(
            command='agentic-workspace skills --target ./repo --task "<task>" --format json',
            target_root=target_root,
        ),
        cli_invoke=cli_invoke,
    )
    core_routes = []
    intent_discovery_route_first = False
    if task_text and task_text.strip():
        intent_discovery = _intent_discovery_dialogue_payload(
            task_text=task_text,
            vague_orientation=_vague_outcome_orientation_payload(task_text=task_text, cli_invoke=cli_invoke),
            cli_invoke=cli_invoke,
        )
        intent_discovery_route_first = intent_discovery.get("status") == "ask-human"
    if intent_discovery_route_first:
        core_routes.append(
            {
                "fit_signal": "vague, broad, high-stakes, or under-specified human intent before implementation or Planning",
                "skill": "workspace-intent-discovery",
                "fallback": "agentic-workspace start --task <task> --select intent_discovery_dialogue --format json",
            }
        )
    core_routes.extend(
        [
            {
                "fit_signal": "active planning report, restart, or proof posture",
                "skill": "planning-reporting",
                "fallback": "agentic-workspace summary --format json",
            },
            {
                "fit_signal": "managed planning bootstrap upgrade",
                "skill": "bootstrap-upgrade",
                "fallback": "agentic-workspace doctor --target ./repo --modules planning --format json",
            },
        ]
    )
    configured_features = set(enabled_advanced_features)
    available_advanced_routes = [
        {
            "fit_signal": "active planned work or autopilot execution",
            "skill": "planning-autopilot",
            "feature": "autopilot_loops",
            "fallback": "agentic-workspace summary --format json, then the active execplan",
        },
        {
            "fit_signal": "external issue or tracker intake",
            "skill": "planning-intake-upstream-task",
            "feature": "external_adapters",
            "fallback": ".agentic-workspace/planning/upstream-task-intake.md plus checked-in planning state",
        },
        {
            "fit_signal": "bounded review or finding capture",
            "skill": "planning-review-pass",
            "feature": "review_artifacts",
            "fallback": "agentic-workspace report --target ./repo --format json before selecting any review artifact",
        },
    ]
    advanced_routes = [route for route in available_advanced_routes if str(route.get("feature", "")) in configured_features]
    payload: dict[str, Any] = {
        "status": "advisory",
        "rule": "Prefer task-specific package skills when the runtime supports them; keep compact CLI as the ordinary route and workflow docs as conservative no-CLI recovery. Advanced host-repo diagnostics are opt-in.",
        "query": skill_command,
        "advanced_route_rule": "Review and external-intake skills are surfaced only when the repo enables the matching reusable diagnostic feature. Source-checkout-only maintainer skills stay outside shipped core modules.",
        "fallback_when_skills_unavailable": [
            "follow AGENTS.md, and use .agentic-workspace/WORKFLOW.md only as conservative no-CLI recovery",
            'use agentic-workspace start --task "<task>" --format json for ordinary first contact',
            "use agentic-workspace summary --format json before raw planning reads",
        ],
        "preferred_routes": core_routes + advanced_routes,
    }
    if configured_features:
        payload["enabled_advanced_routes"] = [route["feature"] for route in advanced_routes]
    else:
        payload["available_advanced_route_command"] = _proof_command_for_target(
            command="agentic-workspace modules --target ./repo --format json",
            target_root=target_root,
        )
    if task_text and task_text.strip():
        payload["task_search"] = {
            "status": "available-explicitly",
            "rule": "Startup does not rank skills from prompt text; run the catalog command only when task-specific skill search is useful.",
            "command": _command_with_cli_invoke(
                command=_proof_command_for_target(
                    command=f"agentic-workspace skills --target ./repo --task {_shell_quote(task_text)} --format json",
                    target_root=target_root,
                ),
                cli_invoke=cli_invoke,
            ),
        }
    if compact:
        fallback_items = payload.pop("fallback_when_skills_unavailable", [])
        payload["preferred_routes"] = [
            {"fit_signal": route["fit_signal"], "skill": route["skill"]} for route in payload["preferred_routes"] if isinstance(route, dict)
        ]
        payload["fallback_when_skills_unavailable_count"] = len(fallback_items) if isinstance(fallback_items, list) else 0
        payload["fallback_detail"] = "Use compact CLI routers if skills are unavailable."
    return payload


def _task_skill_recommendations_payload(
    *, target_root: Path | None, task_text: str | None, cli_invoke: str, compact: bool = False
) -> dict[str, Any]:
    skill_command = _command_with_cli_invoke(
        command=_proof_command_for_target(
            command='agentic-workspace skills --target ./repo --task "<task>" --format json',
            target_root=target_root,
        ),
        cli_invoke=cli_invoke,
    )
    if not task_text or not task_text.strip():
        return {
            "status": "not-requested",
            "command": skill_command,
            "hint": "Pass --task with the current user request to include task-specific skill recommendations in startup output.",
        }
    if target_root is None:
        return {"status": "unavailable", "command": skill_command, "reason": "target_root is required for skill discovery"}
    skills_payload = _skills_payload(target_root=target_root, task_text=task_text)
    recommendations = skills_payload.get("recommendations", [])
    compact_items = [
        {
            "id": str(item.get("id", "")),
            "path": str(item.get("path", "")),
            "summary": str(item.get("summary", "")),
            "score": item.get("score"),
            **({"reasons": item.get("reasons", [])[:2]} if not compact else {}),
        }
        for item in recommendations[:3]
        if isinstance(item, dict)
    ]
    return {
        "status": "recommended" if compact_items else "no-match",
        "task": task_text,
        "command": _command_with_cli_invoke(
            command=_proof_command_for_target(
                command=f"agentic-workspace skills --target ./repo --task {_shell_quote(task_text)} --format json",
                target_root=target_root,
            ),
            cli_invoke=cli_invoke,
        ),
        "top_recommendations": compact_items,
        "catalog_summary": _skill_catalog_summary_from_payload(skills_payload),
        "warning_count": len(skills_payload.get("warnings", [])) if isinstance(skills_payload.get("warnings", []), list) else 0,
    }


def _vague_outcome_orientation_payload(*, task_text: str | None, cli_invoke: str = DEFAULT_CLI_INVOKE) -> dict[str, Any]:
    applies = False
    task_present = bool(str(task_text or "").strip())
    return {
        "status": "available",
        "applies_to_current_task": applies,
        "rule": "AW does not infer vague-outcome status from prompt keywords; the agent owns whether this guidance applies.",
        "first_surface": "startup_guidance.primary_next_action from preflight or immediate_next_allowed_action from start",
        "compact_commands": [
            _command_with_cli_invoke(command='agentic-workspace preflight --target . --task "<task>" --format json', cli_invoke=cli_invoke),
            _command_with_cli_invoke(command='agentic-workspace start --target . --task "<task>" --format json', cli_invoke=cli_invoke),
            _command_with_cli_invoke(command='agentic-workspace skills --target . --task "<task>" --format json', cli_invoke=cli_invoke),
        ],
        "answer_contract": [
            "state the inferred intended outcome",
            "state the concrete first slice and non-goals before editing",
            "say you will proceed on that interpretation unless corrected",
            "name the first repo-visible surface or compact command to inspect",
            "define satisfaction evidence before choosing an implementation",
            "separate one possible solution from the intended outcome",
        ],
        "raw_read_rule": "Open raw .agentic-workspace files only after compact output points there or the CLI is unavailable.",
        "task_text_available": task_present,
    }


def _intent_discovery_dialogue_payload(
    *, task_text: str | None, vague_orientation: dict[str, Any] | None = None, cli_invoke: str = DEFAULT_CLI_INVOKE
) -> dict[str, Any]:
    task = str(task_text or "").strip()
    _ = vague_orientation
    skill_command = _command_with_cli_invoke(
        command=f"agentic-workspace skills --target . --task {_shell_quote(task or '<task>')} --format json",
        cli_invoke=cli_invoke,
    )
    output_shape = {
        "fields": [
            "inferred_intent",
            "uncertainty",
            "candidate_interpretations",
            "likely_non_goals",
            "stakes_if_wrong",
            "proposed_first_slice",
            "question_to_user",
            "proceed_without_answer_when",
            "captured_intent_after_reply",
            "promotion_target",
            "intent_records",
        ],
        "intent_record_levels": ["task", "initiative", "repo", "system", "completion-boundary", "anti-goal", "unresolved-assumption"],
        "promotion_targets": ["task_intent", "acceptance", "durable_intent", "Memory", "Planning", "issue"],
        "compact_custody_target": "intent_custody",
        "residue_rule": "Promote only the clarified intent, non-goals, first slice, and proof expectations; do not store raw brainstorming unless it materially helps continuation.",
    }
    examples = [
        {
            "id": "ask",
            "prompt_shape": "Make onboarding better.",
            "decision": "ask-human",
            "why": "Outcome, audience, non-goals, and first slice are all under-specified.",
        },
        {
            "id": "acknowledge-and-proceed",
            "prompt_shape": "Implement #1234 from the detailed issue body.",
            "decision": "proceed-with-stated-assumption",
            "why": "An external issue can own detail; state the interpretation and correction point before editing.",
        },
        {
            "id": "direct-work",
            "prompt_shape": "Fix the typo in README.md.",
            "decision": "silent-ok",
            "why": "The target, outcome, and proof are obvious enough that clarification would interrupt direct work.",
        },
    ]
    if not task:
        return {
            "kind": "agentic-workspace/intent-discovery-dialogue/v1",
            "status": "available",
            "applies_to_current_task": False,
            "skill": "workspace-intent-discovery",
            "skill_command": skill_command,
            "output_shape": output_shape,
            "examples": examples,
        }

    return {
        "kind": "agentic-workspace/intent-discovery-dialogue/v1",
        "status": "available",
        "applies_to_current_task": False,
        "skill": "workspace-intent-discovery",
        "skill_command": skill_command,
        "inferred_intent_confidence": "agent-owned",
        "stakes_if_wrong": "agent-owned",
        "required_next_action": "agent-decides-whether-intent-discovery-is-needed",
        "candidate_interpretations": [],
        "likely_non_goals": [
            "Do not silently choose a convenient implementation slice.",
            "Do not create Planning state until the intended outcome is clear enough.",
            "Do not store raw brainstorming when a compact clarified-intent record is enough.",
        ],
        "dialogue_packet": {
            "why_it_matters": "High-ambiguity work can look bounded while missing the user's desired outcome.",
            "desired_outcome": "<capture after reply>",
            "non_goals": "<capture after reply>",
            "acceptable_first_slice": "<capture after reply>",
            "uncertainty": "agent-owned",
            "question_to_user": "",
            "proceed_without_answer_when": "After one bounded question, proceed only if the first slice is low-risk, reversible, and the stated assumptions are visible.",
            "intent_records": [
                {
                    "intent_ref": "<stable compact identifier>",
                    "level": "task|initiative|repo|system|completion-boundary|anti-goal|unresolved-assumption",
                    "statement": "<intent or boundary>",
                    "completion_boundary": "<closure condition>",
                    "anti_goals": [],
                    "unresolved_assumptions": [],
                    "provenance": ["chat|issue|Planning|Memory|config|system-intent"],
                    "freshness": "current|stale|unknown",
                }
            ],
        },
        "output_shape": output_shape,
        "loop_control": {
            "max_questions_before_progress": 1,
            "proceed_rule": "Ask one compact intent question, then either proceed with visible assumptions or route unresolved ambiguity to Planning/issue residue.",
            "stop_rule": "Do not keep asking if the user has supplied enough why/outcome/non-goals/first-slice detail.",
        },
        "visible_residue_when_proceeding_without_answer": [
            "inferred_intent",
            "candidate_interpretation_chosen",
            "non_goals_or_deferred_scope",
            "first_slice",
            "correction_point",
            "promotion_target",
            "intent_records",
        ],
        "examples": examples,
        "authority_boundary": _authority_boundary_payload(
            surface="intent_discovery_dialogue",
            observed_by_aw=["task_text_available=True"],
            recommended_by_aw=["use workspace-intent-discovery skill when agent judgment finds intent ambiguity"],
            agent_owned_decisions=[
                "whether intent is ambiguous enough to ask",
                "whether visible assumptions are sufficient to proceed",
            ],
            human_owned_decisions=["clarified intent when the agent cannot choose a bounded first slice"],
            rule="AW exposes an intent-discovery contract; it does not classify prompt ambiguity from keywords.",
        ),
    }


def _workspace_defaults_payload_path() -> Path:
    return Path(__file__).resolve().parent / "contracts" / "workspace_defaults" / "payload.json"


def _defaults_payload() -> dict[str, Any]:
    payload = json.loads(_workspace_defaults_payload_path().read_text(encoding="utf-8"))
    if not isinstance(payload, dict):
        raise RuntimeError("workspace defaults payload must be a JSON object")
    return payload


def _selector_refs(*, command: str, answer: Any) -> list[str]:
    refs = [compact_contract_manifest()["canonical_doc"], command]
    if isinstance(answer, dict):
        for key in ("canonical_doc", "command", "path", "surface", "ledger_path"):
            value = answer.get(key)
            if isinstance(value, str) and value not in refs:
                refs.append(value)
    return refs


def _compact_contract_answer(
    *,
    surface: str,
    selector: dict[str, Any],
    answer: Any,
    refs: list[str],
    matched: bool = True,
    target: str | None = None,
) -> dict[str, Any]:
    payload: dict[str, Any] = {
        "profile": "compact-contract-answer/v1",
        "surface": surface,
        "selector": selector,
        "matched": matched,
        "answer": answer,
        "refs": refs,
        "payload_locations": {
            "kind": "agentic-workspace/output-wrapper-locations/v1",
            "primary_payload_field": "answer",
            "selected_payload_paths": {"answer": "answer"},
            "rule": "Compact contract answers store the selected payload under answer; --select output stores payloads under values.<selector>.",
        },
    }
    if target is not None:
        payload["target"] = target
    return payload


def _emit_compact_answer_text(payload: dict[str, Any]) -> None:
    print(f"Profile: {payload.get('profile')}")
    print(f"Surface: {payload.get('surface')}")
    print(f"Selector: {json.dumps(payload.get('selector', {}), sort_keys=True)}")
    print(f"Matched: {payload.get('matched')}")
    answer = payload.get("answer")
    operating_loop = answer.get("operating_loop") if isinstance(answer, dict) else None
    for line in _operating_loop_text_lines(operating_loop):
        print(line)
    print("Answer:")
    print(json.dumps(serialise_value(answer), indent=2))
    refs = payload.get("refs", [])
    if refs:
        print("Refs:")
        for ref in refs:
            print(f"- {ref}")


def _select_defaults_section(payload: dict[str, Any], *, section: str) -> dict[str, Any]:
    normalized = section.strip()
    if normalized not in payload:
        supported = ", ".join(sorted(payload))
        raise WorkspaceUsageError(f"defaults --section must match one of: {supported}.")
    answer = payload[normalized]
    return _compact_contract_answer(
        surface="defaults",
        selector={"section": normalized},
        answer=answer,
        refs=_selector_refs(command="agentic-workspace defaults --format json", answer=answer),
    )


def _tiny_defaults_payload(payload: dict[str, Any]) -> dict[str, Any]:
    sections = sorted((str(key) for key in payload))
    return {
        "kind": "agentic-workspace/defaults-router/v1",
        "profile": "tiny",
        "summary": "Default-route contract sections are available on demand; request one section or full detail instead of loading the whole contract.",
        "available_sections": sections,
        "common_sections": [
            "startup",
            "proof_surfaces",
            "memory_routing",
            "capability_routing",
            "closeout_trust",
            "compact_contract_profile",
            "workflow_sufficiency",
            "authority_hierarchy",
            "compliance_economics",
        ],
        "detail_commands": {
            "section": "agentic-workspace defaults --section <section> --format json",
            "full": "agentic-workspace defaults --verbose --format json",
        },
    }


def _emit_defaults(*, format_name: str, section: str | None = None, profile: str = "tiny", select: str | None = None) -> None:
    payload = _defaults_payload()
    if section is not None:
        payload = _select_defaults_section(payload, section=section)
    elif profile == "tiny":
        payload = _tiny_defaults_payload(payload)
    if select is not None:
        payload = _select_payload_fields(payload, select=select, source_command="defaults")
    if format_name == "json":
        print(json.dumps(serialise_value(payload), indent=2))
