def _emit_tiny_defaults_text(payload: dict[str, Any]) -> None:
    view = _workspace_output_view("defaults-router.text")
    if not view:
        print(str(payload["summary"]))
        print("Common sections:")
        for section in payload.get("common_sections", []):
            print(f"- {section}")
        print("Detail commands:")
        detail_commands = payload.get("detail_commands", {})
        if isinstance(detail_commands, dict):
            for name, command in detail_commands.items():
                print(f"- {name}: {command}")
        return
    for section in _list_payload(view.get("sections")):
        if not isinstance(section, dict):
            continue
        label = str(section.get("label") or "")
        field = str(section.get("field") or "")
        item_prefix = str(section.get("item_prefix") or "")
        value = payload.get(field)
        if label:
            print(label)
        if isinstance(value, dict):
            for name, item in value.items():
                print(f"{item_prefix}{name}: {item}")
        elif isinstance(value, list):
            for item in value:
                print(f"{item_prefix}{item}")
        elif value is not None:
            print(str(value))


def _workspace_output_view(view_id: str) -> dict[str, Any]:
    path = Path(__file__).resolve().parent / "contracts" / "workspace_output_views.json"
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return {}
    for view in _list_payload(payload.get("views")):
        if isinstance(view, dict) and view.get("id") == view_id:
            return view
    return {}


def _setup_orientation_surfaces(*, target_root: Path) -> tuple[Path, ...]:
    config = config_lib.load_workspace_config(target_root=target_root)
    return (
        target_root / config.agent_instructions_file,
        target_root / ".agentic-workspace/planning/state.toml",
        target_root / "tools" / "AGENT_QUICKSTART.md",
        target_root / "tools" / "AGENT_ROUTING.md",
        target_root / "memory" / "index.md",
    )


def _repo_looks_setup_mature(*, target_root: Path) -> bool:
    return all((path.exists() for path in _setup_orientation_surfaces(target_root=target_root)))


def _host_repo_orientation_payload(*, target_root: Path) -> dict[str, Any]:
    candidates: list[dict[str, Any]] = []

    def _add(path: str, *, reason: str, confidence: float) -> None:
        surface = target_root / path
        if not surface.exists():
            return
        candidates.append(
            {
                "surface": path,
                "reason": reason,
                "confidence": confidence,
                "refs": [path],
            }
        )

    _add("README.md", reason="host repo overview and setup context", confidence=0.94)
    _add("docs/architecture.md", reason="host architecture and ownership context", confidence=0.9)
    _add("docs", reason="host documentation directory", confidence=0.82)
    _add("pyproject.toml", reason="Python project metadata and test or tooling hints", confidence=0.88)
    _add("package.json", reason="Node project metadata and script hints", confidence=0.88)
    _add("Cargo.toml", reason="Rust project metadata and test or tooling hints", confidence=0.88)
    _add("go.mod", reason="Go module metadata and test or tooling hints", confidence=0.88)
    _add("src", reason="host source tree", confidence=0.78)
    _add("tests", reason="host test suite", confidence=0.78)

    return {
        "status": "present" if candidates else "absent",
        "candidate_count": len(candidates),
        "candidates": candidates,
        "rule": "Host orientation candidates are read-only setup hints; setup must not seed Memory, Planning, assurance, or verification state from them without agent judgment.",
    }


def _setup_payload(
    *,
    target_root: Path,
    selected_modules: list[str],
    resolved_preset: str | None,
    descriptors: dict[str, ModuleDescriptor],
    config: WorkspaceConfig,
) -> dict[str, Any]:
    status_payload = _run_lifecycle_command(
        command_name="status",
        target_root=target_root,
        local_only_repo_root=None,
        selected_modules=selected_modules,
        resolved_preset=resolved_preset,
        descriptors=descriptors,
        dry_run=False,
        non_interactive=False,
        config=config,
        compact_status=False,
    )
    installed_modules = [entry["name"] for entry in status_payload.get("registry", []) if entry.get("installed")]
    setup_warnings: list[str] = []
    optional_module_notices: list[str] = []
    for warning in status_payload.get("warnings", []):
        warning_text = str(warning)
        if "installed module 'verification' is not enabled" in warning_text and "verification" in installed_modules:
            optional_module_notices.append(
                "Verification is installed and available as an optional module; it is not part of the default enabled module set."
            )
        else:
            setup_warnings.append(warning_text)
    setup_status_payload = {**status_payload, "warnings": setup_warnings}
    installed_state_compatibility = status_payload.get("installed_state_compatibility", {})
    if not isinstance(installed_state_compatibility, dict):
        installed_state_compatibility = {}
    installed_state_attention: dict[str, Any] | None = None
    if installed_state_compatibility.get("status") not in {None, "", "compatible"}:
        action_state = installed_state_compatibility.get("action_state", {})
        action_state = action_state if isinstance(action_state, dict) else {}
        action_effect = installed_state_compatibility.get("action_effect", {})
        action_effect = action_effect if isinstance(action_effect, dict) else {}
        installed_state_attention = {
            "kind": "agentic-workspace/setup-installed-state-attention/v1",
            "status": installed_state_compatibility.get("status", "unknown"),
            "reason": installed_state_compatibility.get("reason") or action_state.get("reason", ""),
            "selector": "installed_state_compatibility",
            "detail_command": _command_with_cli_invoke(
                command="agentic-workspace start --target . --select installed_state_compatibility --format json",
                cli_invoke=config.cli_invoke,
            ),
            "dry_run_command": action_state.get("dry_run_command", ""),
            "apply_command": action_state.get("apply_command", ""),
            "recheck_command": action_state.get("recheck_command", ""),
            "claim_boundary": action_effect.get(
                "claim_boundary", "installed-state compatibility must be reconciled before setup freshness claims"
            ),
            "rule": "Setup is read-only discovery; installed-state drift is surfaced for action pressure but setup does not mutate payload surfaces.",
        }
    discovery = setup_discovery_payload(
        target_root=target_root, status_payload=setup_status_payload, active_todo_surface=_active_todo_surface(target_root=target_root)
    )
    proof_route_hints = _load_proof_route_hints(target_root=target_root)
    findings_input = _setup_findings_input_payload(target_root=target_root)
    host_orientation = _host_repo_orientation_payload(target_root=target_root)
    assurance_onboarding = _assurance_onboarding_payload(assurance=config.assurance)
    verification_guidance = _verification_enablement_guidance(target_root=target_root, config=config)
    onboarding_routes = {
        "assurance": {
            "status": assurance_onboarding.get("status", "absent"),
            "command": "agentic-workspace defaults --section assurance_onboarding --format json",
            "report_command": "agentic-workspace report --target ./repo --section assurance_requirements --format json",
            "seed_when": "only after inspected host-owned evidence names the requirement, proof route, evidence label, or claim boundary",
            "candidate_seed_surfaces": assurance_onboarding.get("candidate_seed_surfaces", []),
        },
        "verification": {
            "status": verification_guidance["status"],
            "command": "agentic-workspace defaults --section verification_onboarding --format json",
            "report_command": "agentic-workspace report --target ./repo --section verification --format json",
            "seed_when": "only for repeatable host proof needs not already expressed by ordinary tests or proof selection",
            "enablement": verification_guidance,
            "candidate_seed_surfaces": [
                ".agentic-workspace/verification/manifest.toml",
                ".agentic-workspace/verification/proof-strategy.toml",
                ".agentic-workspace/verification/proof-decision.json",
            ],
        },
        "rule": "Setup surfaces onboarding questions and seed candidates; the agent decides whether host evidence is strong enough to write anything.",
    }
    mature_repo = _repo_looks_setup_mature(target_root=target_root)
    if mature_repo:
        startup_file = config.agent_instructions_file
        orientation: dict[str, Any] = {
            "mode": "no-new-seed-surfaces-needed",
            "summary": "No new seed surfaces are needed; the repo already has the core setup orientation surfaces.",
            "reason": f"{startup_file}, .agentic-workspace/planning/state.toml, .agentic-workspace/planning/agent-manifest.json, and .agentic-workspace/memory/repo/index.md are already present.",
        }
        next_action = {
            "summary": "No new core seed surfaces needed; inspect onboarding routes before adding assurance or verification seeds",
            "commands": [
                "agentic-workspace report --target ./repo --format json",
                "agentic-workspace defaults --section assurance_onboarding --format json",
                "agentic-workspace defaults --section verification_onboarding --format json",
            ],
        }
    else:
        prioritized = discovery["memory_candidates"] + discovery["planning_candidates"] + discovery["ambiguous"]
        prioritized.sort(key=lambda item: item["confidence"], reverse=True)
        best = prioritized[0] if prioritized else None
        orientation = {
            "mode": "bounded-orientation-needed",
            "summary": "Review the strongest current surface candidates before seeding anything new.",
        }
        if best is not None:
            orientation["surface"] = best["surface"]
            orientation["reason"] = best["reason"]
        next_action = {
            "summary": "Review the compact report surfaces",
            "commands": [
                "agentic-workspace report --target ./repo --format json",
                "agentic-workspace defaults --section assurance_onboarding --format json",
                "agentic-workspace defaults --section verification_onboarding --format json",
            ],
        }
    if findings_input.get("status") == "loaded":
        promotable_count = sum((len(items) for items in findings_input["promotable"].values()))
        if promotable_count:
            next_action = {
                "summary": "Review promotable setup findings before seeding or promoting anything durable",
                "commands": [
                    "agentic-workspace setup --target ./repo --format json",
                    "agentic-workspace report --target ./repo --format json",
                ],
            }
    if installed_state_attention is not None:
        commands = [
            str(installed_state_attention.get("dry_run_command") or "").strip(),
            str(installed_state_attention.get("detail_command") or "").strip(),
        ]
        next_action = {
            "summary": "Resolve installed-state compatibility before durable setup seeding or payload freshness claims",
            "commands": [command for command in commands if command],
        }
    return {
        "kind": "workspace-setup/v1",
        "schema": _reporting_schema_payload(),
        "command": "setup",
        "target": target_root.as_posix(),
        "selected_modules": selected_modules,
        "health": status_payload["health"],
        "orientation": orientation,
        "findings_promotion": {
            "canonical_doc": "docs/setup-findings-contract.md",
            "artifact_path": SETUP_FINDINGS_PATH.as_posix(),
            "schema_path": "src/agentic_workspace/contracts/schemas/setup_findings.schema.json",
            "accepted_kind": SETUP_FINDINGS_KIND,
            "accepted_classes": [_setup_finding_class_payload(finding_class) for finding_class in SUPPORTED_SETUP_FINDING_CLASSES],
            "rule": "Accept agent-produced setup findings as optional input, preserve only the classes that reduce rediscovery, and keep low-value or weakly grounded findings transient.",
        },
        "analysis_input": findings_input,
        "host_orientation": host_orientation,
        **({"installed_state_compatibility": installed_state_compatibility} if installed_state_attention is not None else {}),
        **({"installed_state_attention": installed_state_attention} if installed_state_attention is not None else {}),
        "proof_route_hints": {
            "path": PROOF_ROUTE_HINTS_PATH.as_posix(),
            "status": proof_route_hints["status"],
            "hint_count": len(proof_route_hints.get("hints", [])),
            "rule": "Setup reports lifecycle-discovered advisory proof route hints; proof still live-confirms them before command selection.",
        },
        "onboarding_routes": onboarding_routes,
        "next_action": next_action,
        "discovery": discovery,
        "current": {
            "installed_modules": installed_modules,
            "warnings": setup_warnings,
            "optional_module_notices": optional_module_notices,
            "needs_review": [item for item in status_payload.get("needs_review", []) if str(item) in setup_warnings],
            "stale_generated_surfaces": list(status_payload.get("stale_generated_surfaces", [])),
            **({"installed_state_status": installed_state_attention["status"]} if installed_state_attention is not None else {}),
        },
    }


def _emit_setup(
    *,
    format_name: str,
    target_root: Path,
    selected_modules: list[str],
    resolved_preset: str | None,
    descriptors: dict[str, ModuleDescriptor],
    config: WorkspaceConfig,
) -> None:
    payload = _setup_payload(
        target_root=target_root, selected_modules=selected_modules, resolved_preset=resolved_preset, descriptors=descriptors, config=config
    )
    if format_name == "json":
        print(json.dumps(serialise_value(payload), indent=2))
        return
    print(f"Target: {payload['target']}")
    print("Setup:")
    print(f"- command: {payload['command']}")
    print(f"- mode: {payload['orientation']['mode']}")
    print(f"- summary: {payload['orientation']['summary']}")
    if payload["orientation"].get("surface"):
        print(f"- surface: {payload['orientation']['surface']}")
    if payload["orientation"].get("reason"):
        print(f"- reason: {payload['orientation']['reason']}")
    if payload.get("host_orientation", {}).get("candidates"):
        print("Host orientation candidates:")
        for item in payload["host_orientation"]["candidates"]:
            print(f"- {item['surface']}: {item['reason']}")
    print(f"- next action: {payload['next_action']['summary']}")
    for command in payload["next_action"]["commands"]:
        print(f"  - {command}")
    if payload["current"]["warnings"]:
        print("Current warnings:")
        for warning in payload["current"]["warnings"]:
            print(f"- {warning}")


def _select_proof_payload(
    payload: dict[str, Any], *, target_root: Path, route: str | None, current_only: bool, changed_paths: list[str] | None = None
) -> dict[str, Any]:
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    selector_count = sum((1 for selected in (bool(route), current_only, bool(normalized_paths)) if selected))
    if selector_count > 1:
        raise WorkspaceUsageError("proof selectors are mutually exclusive; use only one of --route, --current, or --changed.")
    if normalized_paths:
        answer = _proof_selection_for_changed_paths(changed_paths=normalized_paths, target_root=target_root)
        refs = [compact_contract_manifest()["canonical_doc"], payload["command"], payload["canonical_doc"]]
        return _compact_contract_answer(
            surface="proof", selector={"changed": normalized_paths}, answer=answer, refs=refs, target=payload["target"]
        )
    if route:
        answer = {"id": route, "command": payload["default_routes"].get(route)}
        matched = answer["command"] is not None
        refs = [compact_contract_manifest()["canonical_doc"], payload["command"], payload["canonical_doc"]]
        return _compact_contract_answer(
            surface="proof", selector={"route": route}, answer=answer, refs=refs, matched=matched, target=payload["target"]
        )
    if current_only:
        current_selection = _proof_selection_for_changed_paths(changed_paths=[], target_root=target_root)
        planning_present = current_selection.get("planning_assurance", {}).get("status") == "present"
        active_requirements = current_selection.get("assurance_requirements", {}).get("active_count", 0)
        answer = {**current_selection, "current": payload["current"]} if planning_present or active_requirements else payload["current"]
        refs = [compact_contract_manifest()["canonical_doc"], payload["command"], payload["canonical_doc"]]
        return _compact_contract_answer(surface="proof", selector={"current": True}, answer=answer, refs=refs, target=payload["target"])
    return payload


_TINY_DETAIL_PROOF_COMMAND_FRAGMENTS = ("tests/test_workspace_proof_generated_packages_cli.py",)


def _compact_tiny_required_proof_commands(commands: Any) -> list[str]:
    required_commands = [str(command) for command in _list_payload(commands)]
    if len(required_commands) <= 1:
        return required_commands
    compacted = [
        command for command in required_commands if not any(fragment in command for fragment in _TINY_DETAIL_PROOF_COMMAND_FRAGMENTS)
    ]
    return compacted or required_commands


def _tiny_required_proof_commands(answer: dict[str, Any]) -> list[str]:
    required_commands = _compact_tiny_required_proof_commands(answer.get("required_commands"))
    verification_commands = {
        str(command)
        for lane in _list_payload(answer.get("selected_lanes"))
        if isinstance(lane, dict) and str(lane.get("id", "")).startswith("verification:")
        for command in _list_payload(lane.get("required_commands"))
    }
    if not verification_commands:
        return required_commands
    non_verification_commands = [command for command in required_commands if command not in verification_commands]
    return _compact_tiny_required_proof_commands(non_verification_commands or required_commands)


PROOF_RECEIPT_RELATIVE_PATH = Path(".agentic-workspace") / "local" / "proof-receipts" / "last.json"
PROOF_RECEIPT_HISTORY_RELATIVE_PATH = Path(".agentic-workspace") / "local" / "proof-receipts" / "history.jsonl"


def _proof_receipt_result_failed(result: str) -> bool:
    normalized = re.sub(r"[^a-z0-9]+", "-", str(result or "").strip().lower()).strip("-")
    if not normalized:
        return False
    failure_tokens = {
        "fail",
        "failed",
        "failure",
        "error",
        "errored",
        "timeout",
        "timed-out",
        "cancelled",
        "canceled",
    }
    if normalized in failure_tokens:
        return True
    parts = {part for part in normalized.split("-") if part}
    return bool(parts & failure_tokens)


def _proof_receipt_focused_commands(changed_paths: list[str]) -> list[str]:
    test_paths = [path for path in _normalize_changed_paths(changed_paths) if path.startswith("tests/") and path.endswith(".py")]
    if not test_paths:
        return []
    return [f"uv run pytest {' '.join(test_paths)} -q"]


def _proof_receipt_log_source(*, target_root: Path, receipt_log: str) -> tuple[str, dict[str, Any]] | None:
    raw = str(receipt_log or "").strip()
    if not raw:
        return None
    candidate = Path(raw)
    if not candidate.is_absolute():
        candidate = target_root / candidate
    try:
        resolved = candidate.resolve()
        target_resolved = target_root.resolve()
        relative = resolved.relative_to(target_resolved).as_posix()
    except (OSError, ValueError):
        resolved = None
        relative = ""
    if resolved is not None and resolved.is_file():
        text = resolved.read_text(encoding="utf-8", errors="replace")
        return text[:200_000], {
            "kind": "repo-local-path",
            "path": relative,
            "truncated": len(text) > 200_000,
            "rule": "Full logs remain accessible at the referenced path; this payload stores only a compact summary.",
        }
    return raw[:200_000], {
        "kind": "caller-supplied-excerpt",
        "truncated": len(raw) > 200_000,
        "rule": "Caller supplied an excerpt; retain the original terminal or log artifact for audit.",
    }


def _pytest_failure_cluster_from_line(line: str) -> dict[str, str] | None:
    stripped = line.strip()
    match = re.search(r"\bFAILED\s+([^\s]+?)(?:\s+-|\s*$)", stripped)
    if not match:
        return None
    node_id = match.group(1)
    path = node_id.split("::", 1)[0]
    test_name = node_id.split("::")[-1] if "::" in node_id else ""
    return {
        "cluster_key": path,
        "likely_root": path,
        "representative": stripped,
        "node_id": node_id,
        "test_name": test_name,
        "focused_command": f"uv run pytest {node_id} -q",
    }


def _traceback_failure_cluster_from_lines(lines: list[str]) -> dict[str, str] | None:
    for line in lines:
        match = re.search(r'File "([^"]+)", line \d+', line)
        if not match:
            continue
        path = Path(match.group(1)).as_posix()
        if "/site-packages/" in path or "\\site-packages\\" in path:
            continue
        return {
            "cluster_key": path,
            "likely_root": path,
            "representative": line.strip(),
            "node_id": "",
            "test_name": "",
            "focused_command": "",
        }
    return None


def _proof_failure_summary(
    *,
    command: str,
    result: str,
    changed_paths: list[str],
    log_text: str,
    log_source: dict[str, Any],
) -> dict[str, Any] | None:
    if not _proof_receipt_result_failed(result) or not log_text.strip():
        return None
    lines = log_text.splitlines()
    clusters: dict[str, dict[str, Any]] = {}
    for line in lines:
        cluster = _pytest_failure_cluster_from_line(line)
        if cluster is None:
            continue
        key = cluster["cluster_key"]
        entry = clusters.setdefault(
            key,
            {
                "likely_root": cluster["likely_root"],
                "representative": cluster["representative"],
                "node_ids": [],
                "focused_commands": [],
                "occurrences": 0,
            },
        )
        entry["occurrences"] += 1
        if cluster["node_id"] and cluster["node_id"] not in entry["node_ids"]:
            entry["node_ids"].append(cluster["node_id"])
        if cluster["focused_command"] and cluster["focused_command"] not in entry["focused_commands"]:
            entry["focused_commands"].append(cluster["focused_command"])
    if not clusters:
        cluster = _traceback_failure_cluster_from_lines(lines)
        if cluster is not None:
            clusters[cluster["cluster_key"]] = {
                "likely_root": cluster["likely_root"],
                "representative": cluster["representative"],
                "node_ids": [],
                "focused_commands": [],
                "occurrences": 1,
            }
    top_clusters = sorted(
        clusters.values(),
        key=lambda item: (-int(item.get("occurrences", 0)), str(item.get("likely_root", ""))),
    )[:5]
    focused_commands: list[str] = []
    for cluster in top_clusters:
        for focused in cluster.get("focused_commands", []):
            if focused not in focused_commands:
                focused_commands.append(str(focused))
    if not focused_commands:
        focused_commands = _proof_receipt_focused_commands(changed_paths)
    failure_lines = [line.strip() for line in lines if re.search(r"\b(FAILED|ERROR|FAILURES?|Traceback)\b", line)]
    log_source_kind = str(log_source.get("kind") or "")
    summary_trust = {
        "level": "higher" if log_source_kind == "repo-local-path" else "lower",
        "source_kind": log_source_kind,
        "rule": (
            "Repo-local log references preserve audit access."
            if log_source_kind == "repo-local-path"
            else "Caller-supplied excerpts are useful repair hints but lower trust than repo-local logs."
        ),
    }
    return {
        "kind": "agentic-workspace/proof-failure-summary/v1",
        "status": "available" if top_clusters else "unclustered",
        "failed_command": command,
        "result": result,
        "log_source": log_source,
        "summary_trust": summary_trust,
        "failure_line_count": len(failure_lines),
        "cluster_count": len(top_clusters),
        "top_root_cause_clusters": top_clusters,
        "focused_rerun_commands": focused_commands,
        "full_suite_rerun_premature": bool(focused_commands),
        "full_log_access": log_source,
        "guardrails": [
            "Do not infer semantic correctness from log text.",
            "Use the referenced full log or original terminal output for audit.",
            "Run full selected proof before completion even when focused reruns pass.",
        ],
    }


def _proof_receipt_retry_ladder(*, command: str, result: str, changed_paths: list[str]) -> dict[str, Any] | None:
    if not _proof_receipt_result_failed(result):
        return None
    focused_commands = _proof_receipt_focused_commands(changed_paths)
    steps: list[dict[str, Any]] = [
        {
            "order": 1,
            "scope": "focused-failure",
            "intent": "Reproduce or repair the first failing regression, nearest unit test, or nearest contract test before another broad rerun.",
        },
        {
            "order": 2,
            "scope": "affected-subset",
            "intent": "Run the smallest affected package or workspace subset after the focused failure is fixed.",
        },
        {
            "order": 3,
            "scope": "full-selected-proof",
            "command": command,
            "intent": "Rerun the full originally selected proof only after focused checks pass, unless the failure is clearly cross-cutting.",
        },
    ]
    if focused_commands:
        steps[0]["commands"] = focused_commands
    else:
        steps[0]["command_source"] = "failure log node id, nearest changed test, or nearest contract test"
    steps[1]["command_source"] = "smallest affected package or workspace subset after the focused failure passes"
    return {
        "kind": "agentic-workspace/proof-repair-retry-ladder/v1",
        "status": "available",
        "trigger": "failed-proof-receipt",
        "failed_command": command,
        "full_selected_proof": command,
        "full_proof_still_required": True,
        "full_rerun_premature": True,
        "focused_commands": focused_commands,
        "steps": steps,
        "override_rule": "Agents may skip ahead for cross-cutting failures, but should report why the focused/subset ladder was not useful.",
        "closeout_rule": "The ladder guides repair iteration only; it does not replace the originally selected proof required before completion.",
    }


def _record_proof_receipt_payload(
    *,
    target_root: Path,
    command: str,
    result: str,
    changed_paths: list[str],
    plan_id: str = "",
    receipt_log: str = "",
    dry_run: bool = False,
) -> dict[str, Any]:
    command = str(command or "").strip()
    result = str(result or "").strip()
    if not command:
        raise WorkspaceUsageError("--receipt-command is required with --record-receipt.")
    if not result:
        raise WorkspaceUsageError("--receipt-result is required with --record-receipt.")
    receipt_path = target_root / PROOF_RECEIPT_RELATIVE_PATH
    receipt: dict[str, Any] = {
        "kind": "agentic-workspace/proof-receipt/v1",
        "command": command,
        "result": result,
        "recorded_at": datetime.now(timezone.utc).replace(microsecond=0).isoformat(),
        "changed_paths": _normalize_changed_paths(changed_paths),
        "plan_id": str(plan_id or "").strip(),
        "rule": "This receipt records actual validation evidence supplied by the caller; proof recommendations alone must not create receipts.",
    }
    admission = proof_receipt_admission(receipt)
    if not admission["admitted"]:
        raise WorkspaceUsageError(f"Proof receipt rejected ({admission['reason']}): {admission['safe_recovery']}")
    receipt["admission"] = admission
    repair_retry_ladder = _proof_receipt_retry_ladder(command=command, result=result, changed_paths=changed_paths)
    if repair_retry_ladder is not None:
        receipt["repair_retry_ladder"] = repair_retry_ladder
    log_source = _proof_receipt_log_source(target_root=target_root, receipt_log=receipt_log)
    failure_summary = None
    if log_source is not None:
        log_text, log_source_payload = log_source
        failure_summary = _proof_failure_summary(
            command=command,
            result=result,
            changed_paths=changed_paths,
            log_text=log_text,
            log_source=log_source_payload,
        )
    if failure_summary is not None:
        receipt["failure_summary"] = failure_summary
    if not dry_run:
        receipt_path.parent.mkdir(parents=True, exist_ok=True)
        receipt_path.write_text(json.dumps(receipt, indent=2, ensure_ascii=True) + "\n", encoding="utf-8")
        history_path = target_root / PROOF_RECEIPT_HISTORY_RELATIVE_PATH
        with history_path.open("a", encoding="utf-8") as stream:
            stream.write(json.dumps(receipt, sort_keys=True, ensure_ascii=True) + "\n")
    payload = {
        "kind": "agentic-workspace/proof-receipt-write/v1",
        "status": "dry-run" if dry_run else "written",
        "path": PROOF_RECEIPT_RELATIVE_PATH.as_posix(),
        "history_path": PROOF_RECEIPT_HISTORY_RELATIVE_PATH.as_posix(),
        "receipt": receipt,
        "closeout_command": "agentic-workspace planning closeout --target . --proof-from last --format json",
    }
    if repair_retry_ladder is not None:
        payload["repair_retry_ladder"] = repair_retry_ladder
    if failure_summary is not None:
        payload["failure_summary"] = failure_summary
    return payload


def _emit_proof(
    *,
    format_name: str,
    target_root: Path,
    descriptors: dict[str, ModuleDescriptor],
    route: str | None = None,
    current_only: bool = False,
    changed_paths: list[str] | None = None,
    task_text: str | None = None,
    profile: str = "full",
    select: str | None = None,
    record_receipt: bool = False,
    receipt_command: str = "",
    receipt_result: str = "",
    receipt_plan: str = "",
    receipt_log: str = "",
    dry_run: bool = False,
) -> None:
    normalized_paths = _normalize_changed_paths(changed_paths or [])
    config = _load_workspace_config(target_root=target_root)
    if disabled_payload := _workspace_disabled_payload(target_root=target_root, command_name="proof", config=config):
        _emit_payload(payload=disabled_payload, format_name=format_name)
        return
    if record_receipt:
        payload = _record_proof_receipt_payload(
            target_root=target_root,
            command=receipt_command,
            result=receipt_result,
            changed_paths=normalized_paths,
            plan_id=receipt_plan,
            receipt_log=receipt_log,
            dry_run=dry_run,
        )
        if select:
            payload = _select_payload_fields(payload, select=select, source_command="proof")
        if format_name == "json":
            print(json.dumps(serialise_value(payload), indent=2))
        else:
            _emit_compact_answer_text(payload)
        return
    if profile == "tiny" and normalized_paths:
        answer = _proof_selection_for_changed_paths(
            changed_paths=normalized_paths,
            target_root=target_root,
            include_durable_intent=False,
            task_text=task_text,
        )
        full_payload = {
            "profile": "compact-contract-answer/v1",
            "surface": "proof",
            "target": target_root.as_posix(),
            "selector": {"changed": normalized_paths},
            "answer": answer,
            **answer,
        }
        payload = _tiny_proof_payload(
            full_payload,
            cli_invoke=config.cli_invoke,
        )
        if task_text:
            payload["task_context"] = {"status": "applied", "task": task_text}
        if select:
            full_payload.setdefault("sufficiency", payload.get("sufficiency", answer.get("sufficiency")))
            full_payload.setdefault("next", payload.get("next"))
            payload = _select_payload_fields(full_payload, select=select, source_command="proof")
        if format_name == "json":
            print(json.dumps(serialise_value(payload), indent=2))
            return
        _emit_compact_answer_text(payload)
        return
    payload = _proof_payload(target_root=target_root, descriptors=descriptors)
    payload = _select_proof_payload(payload, target_root=target_root, route=route, current_only=current_only, changed_paths=changed_paths)
    if task_text and changed_paths:
        payload["task_context"] = {"status": "applied", "task": task_text}
    if profile == "tiny":
        payload = _tiny_proof_payload(payload, cli_invoke=config.cli_invoke)
    if select:
        payload = _select_payload_fields(payload, select=select, source_command="proof")
    if format_name == "json":
        print(json.dumps(serialise_value(payload), indent=2))
        return
    if route or current_only or changed_paths:
        _emit_compact_answer_text(payload)
        return
    print(f"Target: {payload['target']}")
    print(f"Rule: {payload['rule']}")
    print(f"Doc: {payload['canonical_doc']}")
    print("Routes:")
    for label, command in payload["default_routes"].items():
        print(f"- {label}: {command}")
    print("Current:")
    installed_modules = payload["current"]["installed_modules"]
    print(f"- installed modules: {(', '.join(installed_modules) if installed_modules else 'none')}")
    print(f"- status health: {payload['current']['status_health']}")
    print(f"- doctor health: {payload['current']['doctor_health']}")
    if payload["current"]["warnings"]:
        print("Warnings:")
        for warning in payload["current"]["warnings"]:
            print(f"- {warning}")
    if payload["current"]["needs_review"]:
        print("Needs review:")
        for item in payload["current"]["needs_review"]:
            print(f"- {item}")
    if payload["current"]["stale_generated_surfaces"]:
        print("Stale generated surfaces:")
        for item in payload["current"]["stale_generated_surfaces"]:
            print(f"- {item}")


def _run_summary_report_adapter(args: argparse.Namespace) -> int:
    target_root = _resolve_target_root(args.target) if args.target else _resolve_target_root(None)
    _validate_target_root(command_name="summary", target_root=target_root)

    config = _load_workspace_config(target_root=target_root)
    if disabled_payload := _workspace_disabled_payload(target_root=target_root, command_name="summary", config=config):
        _emit_payload(payload=disabled_payload, format_name=args.format)
        return 0
    from repo_planning_bootstrap.installer import format_summary_json, planning_summary
    from repo_planning_bootstrap.runtime_projection import _print_summary

    changed_paths = list(getattr(args, "changed", []) or [])
    if getattr(args, "select", None):
        closeout_inspection = _completion_closeout_inspection_payload(
            target_root=target_root,
            config=config,
            task_text=getattr(args, "task", None),
            explicit_request=_selector_requests(getattr(args, "select", None), "closeout_trust_inspection"),
        )
        payload = _select_summary_payload(
            target_root=target_root,
            select=getattr(args, "select"),
            task_text=getattr(args, "task", None),
            changed_paths=changed_paths,
            planning_summary=planning_summary,
            cli_invoke=config.cli_invoke,
        )
        if closeout_inspection["status"] in {"required", "clear"} and "closeout_trust_inspection" in getattr(args, "select"):
            payload.setdefault("values", {})
            closeout_source = {"closeout_trust_inspection": closeout_inspection}
            resolved_closeout_selectors: list[str] = []
            for selector in _selector_tokens(getattr(args, "select", None)):
                if selector != "closeout_trust_inspection" and not selector.startswith("closeout_trust_inspection."):
                    continue
                found, value = _field_by_path(closeout_source, selector)
                if found:
                    payload["values"][selector] = value
                    resolved_closeout_selectors.append(selector)
            if resolved_closeout_selectors and payload.get("missing"):
                payload["missing"] = [item for item in payload.get("missing", []) if item not in set(resolved_closeout_selectors)]
                if not payload["missing"]:
                    payload.pop("missing", None)
                    payload.pop("selector_rule", None)
                    payload.pop("available_selectors", None)
        _emit_payload(payload=payload, format_name=args.format)
    else:
        summary_profile = _diagnostic_profile(args, default="tiny") if args.format == "json" else "full"
        reuse_query = {
            "profile": summary_profile,
            "format": str(args.format),
            "task": str(getattr(args, "task", None) or ""),
            "changed": changed_paths,
            "external_freshness_required": os.environ.get("AW_PROJECTION_EXTERNAL_STATE", "").lower() in {"1", "true", "yes"},
        }
        reuse_context: dict[str, Any] | None = None
        if args.format == "json" and summary_profile == "tiny":
            full_detail_command = _command_with_cli_invoke(
                command=f"agentic-workspace summary --target {target_root.as_posix()} --verbose --format json",
                cli_invoke=config.cli_invoke,
            )
            reused, reuse_context = lookup_projection_reuse(
                root=target_root,
                operation="summary",
                query=reuse_query,
                full_detail_command=full_detail_command,
            )
            if reused is not None:
                _emit_payload(payload=reused, format_name=args.format)
                return 0
        summary = planning_summary(
            target=target_root.as_posix(), profile=summary_profile, task_text=getattr(args, "task", None), changed_paths=changed_paths
        )
        if isinstance(summary, dict):
            if summary_profile == "full":
                summary["memory_consult"] = _memory_consult_payload(
                    target_root=target_root, changed_paths=changed_paths, compact=False, cli_invoke=config.cli_invoke
                )
            elif changed_paths:
                summary["memory_consult"] = _memory_consult_payload(
                    target_root=target_root, changed_paths=changed_paths, compact=True, cli_invoke=config.cli_invoke
                )
            else:
                summary["memory_consult"] = _tiny_memory_consult_payload(config=config)
            closeout_inspection = _completion_closeout_inspection_payload(
                target_root=target_root, config=config, task_text=getattr(args, "task", None)
            )
            if closeout_inspection["status"] in {"required", "clear"}:
                summary["closeout_trust_inspection"] = closeout_inspection
            if _task_posture_packet_relevant(
                task_text=getattr(args, "task", None),
                changed_paths=changed_paths,
                surface="summary",
            ):
                _attach_summary_task_posture_packet(
                    summary=summary,
                    target_root=target_root,
                    task_text=getattr(args, "task", None),
                    changed_paths=changed_paths,
                    cli_invoke=config.cli_invoke,
                )
        summary = _rewrite_module_cli_commands(summary)
        if reuse_context is not None:
            record_projection_reuse(root=target_root, operation="summary", query=reuse_query, context=reuse_context, payload=summary)
        if args.format == "json":
            print(format_summary_json(summary))
        else:
            _print_summary(summary)
    return 0


